def normalize_category(value: str) -> str:
    value = (value or "").strip().lower()
    for src, dst in {"à": "a", "è": "e", "é": "e", "ì": "i", "ò": "o", "ù": "u"}.items():
        value = value.replace(src, dst)
    return value


