def safe_read_pdf_text(path: str, max_pages: int = 4, max_chars: int = 12000) -> str:
    try:
        if Path(path).suffix.lower() != ".pdf":
            return ""
        reader = PdfReader(path)
        chunks = []
        for page in reader.pages[:max_pages]:
            try:
                chunks.append(page.extract_text() or "")
            except Exception:
                continue
        return "\n".join(chunks)[:max_chars]
    except Exception:
        return ""


def safe_read_document_text(path: str, max_chars: int = 16000) -> str:
    """Legge testo utile da PDF, TXT/CSV, DOCX e XLSX senza bloccare il programma.
    Se il contenuto non e' leggibile, resta comunque attivo il riconoscimento dal titolo/nome file.
    """
    try:
        p = Path(path)
        ext = p.suffix.lower()
        if ext == ".pdf":
            return safe_read_pdf_text(str(p), max_pages=6, max_chars=max_chars)
        if ext in {".txt", ".csv", ".md", ".rtf", ".json", ".xml"}:
            raw = p.read_bytes()[: max_chars * 4]
            for enc in ("utf-8", "latin-1", "cp1252"):
                try:
                    return raw.decode(enc, errors="ignore")[:max_chars]
                except Exception:
                    continue
            return ""
        if ext == ".docx":
            import zipfile
            parts = []
            with zipfile.ZipFile(p) as zf:
                names = [n for n in zf.namelist() if n.startswith("word/") and n.endswith(".xml")]
                for name in names[:8]:
                    try:
                        xml = zf.read(name).decode("utf-8", errors="ignore")
                        xml = re.sub(r"<[^>]+>", " ", xml)
                        parts.append(html.unescape(xml))
                    except Exception:
                        continue
            return "\n".join(parts)[:max_chars]
        if ext in {".xlsx", ".xlsm"}:
            try:
                from openpyxl import load_workbook
                wb = load_workbook(str(p), read_only=True, data_only=True)
                parts = []
                for ws in wb.worksheets[:4]:
                    parts.append(str(ws.title))
                    for row in ws.iter_rows(max_row=180, max_col=35, values_only=True):
                        vals = [str(v) for v in row if v is not None and str(v).strip()]
                        if vals:
                            parts.append(" | ".join(vals))
                        if len("\n".join(parts)) >= max_chars:
                            break
                    if len("\n".join(parts)) >= max_chars:
                        break
                try:
                    wb.close()
                except Exception:
                    pass
                return "\n".join(parts)[:max_chars]
            except Exception:
                pass
            try:
                import zipfile
                parts = []
                with zipfile.ZipFile(p) as zf:
                    names = [n for n in zf.namelist() if n.startswith("xl/") and n.endswith(".xml")]
                    for name in names[:12]:
                        try:
                            xml = zf.read(name).decode("utf-8", errors="ignore")
                            xml = re.sub(r"<[^>]+>", " ", xml)
                            if xml.strip():
                                parts.append(html.unescape(xml))
                        except Exception:
                            continue
                return "\n".join(parts)[:max_chars]
            except Exception:
                return ""
        return ""
    except Exception:
        return ""


def infer_document_category(path: str, fallback: str = "Altro", title: str = "") -> tuple[str, str]:
    p = Path(path)
    ext = p.suffix.lower()
    title_hay = normalize_category(f"{title or ''} {p.stem.replace('_', ' ').replace('-', ' ')}")
    content_hay = normalize_category(safe_read_document_text(str(p)))

    # Segnali molto forti nel titolo/nome file.
    strong_title_patterns = [
        ("Centrale Rischi", r"\bcr\s*20\d{4,}|\bcr\d{6,}|centrale\s+rischi", "titolo/nome file tipico Centrale Rischi"),
        ("Visura camerale", r"visura|camerale|cciaa", "titolo/nome file tipico Visura camerale"),
        ("Bilancio", r"\bbilancio\b|stato\s+patrimoniale|conto\s+economico|nota\s+integrativa", "titolo/nome file tipico Bilancio"),
        ("Preventivi", r"preventivo|offerta|proposta\s+economica|quotazione", "titolo/nome file tipico Preventivo"),
        ("Dichiarazioni", r"dichiarazione|modello\s+redditi|f24|irap|iva|unico", "titolo/nome file tipico dichiarazione/fisco"),
        ("Estratti conto", r"estratt[oi]\s+conto|movimenti\s+conto|conto\s+corrente", "titolo/nome file tipico estratto conto"),
        ("Esposizioni Mensili", r"esposizion[ei]\s+mensil|piano\s+ammortamento|leasing|mutuo|finanziament[oi]", "titolo/nome file tipico esposizioni/finanziamenti"),
        ("Esposizioni Tributarie", r"esposizion[ei]\s+tributar|agenzia\s+entrate|rateazione|cartella", "titolo/nome file tipico esposizioni tributarie"),
        ("Documenti Identità", r"carta\s+identita|patente|passaporto|tessera\s+sanitaria|codice\s+fiscale", "titolo/nome file tipico documento identita"),
        ("Relazione Investimento", r"relazione\s+investimento|piano\s+investimento|business\s+plan|progetto", "titolo/nome file tipico investimento/progetto"),
        ("Presentazione Aziendale", r"presentazione\s+aziendale|company\s+profile|profilo\s+aziendale|brochure", "titolo/nome file tipico presentazione aziendale"),
        ("Verbali", r"verbale|assemblea|delibera|consiglio\s+di\s+amministrazione|\bcda\b", "titolo/nome file tipico verbale/delibera"),
        ("Report", r"report|scoring|rating|merito\s+creditizio", "titolo/nome file tipico report/scoring"),
    ]
    for category, pattern, reason in strong_title_patterns:
        try:
            if re.search(pattern, title_hay):
                return category, reason
        except Exception:
            pass

    # Regole pesate su titolo + contenuto. Il titolo pesa di piu', il contenuto aiuta quando il nome file e' generico.
    rules = [
        ("Centrale Rischi", [("centrale rischi", 8), ("banca d italia", 5), ("accordato", 4), ("utilizzato", 4), ("sconfin", 4), ("garanzie ricevute", 4), ("rischi a revoca", 5), ("crif centrale rischi", 6)], "indicatori Centrale Rischi / Banca d'Italia"),
        ("Visura camerale", [("visura camerale", 9), ("camera di commercio", 7), ("cciaa", 7), ("registro imprese", 5), ("rea", 4), ("ateco", 4), ("amministratori", 3), ("capitale sociale", 3)], "dati camerali/REA"),
        ("Bilancio", [("bilancio", 8), ("stato patrimoniale", 8), ("conto economico", 8), ("nota integrativa", 7), ("bilancio d esercizio", 9), ("xbrl", 6), ("attivo circolante", 5), ("patrimonio netto", 5), ("valore della produzione", 5), ("ebitda", 4), ("utile esercizio", 4)], "stato patrimoniale/conto economico/bilancio"),
        ("Bozza Bilancio", [("bozza bilancio", 10), ("bilancio provvisorio", 8), ("bozza", 4)], "bozza o bilancio provvisorio"),
        ("Situazione aggiornata", [("situazione contabile", 8), ("situazione aggiornata", 8), ("situazione al", 4), ("situazione infrannuale", 8), ("bilancino", 8), ("partitario", 4), ("mastrino", 4)], "situazione contabile/infrannuale"),
        ("Estratti conto", [("estratto conto", 9), ("estratti conto", 9), ("conto corrente", 5), ("saldo contabile", 6), ("saldo disponibile", 6), ("movimenti conto", 8), ("data valuta", 5), ("dare avere", 5), ("iban", 3)], "movimenti/saldi bancari"),
        ("Esposizioni Mensili", [("esposizioni mensili", 9), ("esposizione mensile", 9), ("rate finanziamenti", 6), ("piano ammortamento", 7), ("debito residuo", 6), ("scadenziario finanziamenti", 8), ("leasing", 4), ("mutuo", 4), ("rata", 2)], "rate, leasing, mutui o esposizioni"),
        ("Esposizioni Tributarie", [("esposizioni tributarie", 9), ("agenzia entrate riscossione", 8), ("agenzia delle entrate", 5), ("cartella", 5), ("estratto di ruolo", 8), ("rateazione", 6), ("debito tributario", 7), ("f24", 4), ("iva", 2)], "posizioni tributarie/fiscali"),
        ("Dichiarazioni", [("dichiarazione", 8), ("modello redditi", 8), ("irap", 5), ("iva", 4), ("unico", 5), ("f24", 4), ("730", 4)], "dichiarazioni/fisco"),
        ("Documenti Identità", [("carta identita", 8), ("patente", 7), ("passaporto", 7), ("documento identita", 8), ("codice fiscale", 5), ("tessera sanitaria", 6)], "documenti persona"),
        ("Preventivi", [("preventivo", 9), ("offerta", 7), ("proposta economica", 8), ("quotazione", 7), ("listino", 4)], "preventivo/offerta"),
        ("Relazione Investimento", [("relazione investimento", 9), ("investimento", 5), ("progetto", 4), ("business plan", 8), ("piano investimento", 8), ("piano industriale", 6)], "relazione investimento/progetto"),
        ("Presentazione Aziendale", [("presentazione aziendale", 9), ("company profile", 8), ("profilo aziendale", 8), ("brochure", 6)], "presentazione aziendale"),
        ("Verbali", [("verbale", 8), ("assemblea", 5), ("delibera", 7), ("consiglio di amministrazione", 7), ("cda", 4)], "verbali/delibere"),
        ("Report", [("report", 7), ("analisi", 3), ("rating", 6), ("scoring", 6), ("merito creditizio", 8), ("probabilita di default", 8), ("creditizio", 5)], "report/scoring/rating"),
    ]

    best_category = None
    best_score = 0
    best_reason = ""
    best_hits = []
    for category, keys, reason in rules:
        score = 0
        hits = []
        for phrase, weight in keys:
            title_hits = title_hay.count(phrase)
            content_hits = content_hay.count(phrase)
            if title_hits or content_hits:
                score += (title_hits * weight * 3) + (content_hits * weight)
                hits.append(phrase)
        if score > best_score:
            best_category = category
            best_score = score
            best_reason = reason
            best_hits = hits

    if best_category and best_score >= 6:
        hit_text = ", ".join(best_hits[:4])
        return best_category, f"{best_reason}; parole rilevate: {hit_text}"

    if ext in {".xls", ".xlsx", ".xlsm", ".csv"} and normalize_category(fallback) == normalize_category("Altro"):
        return "Situazione aggiornata", "file tabellare senza segnali forti: classificazione prudenziale come dati contabili/finanziari"
    return fallback or "Altro", "nessuna parola chiave forte in titolo/contenuto: mantenuta categoria selezionata"

def ensure_scoring_plus_tables(db) -> None:
    try:
        db.conn.executescript("""
            CREATE TABLE IF NOT EXISTS scoring_plus_documents (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                client_id INTEGER NOT NULL,
                category TEXT,
                original_filename TEXT,
                stored_path TEXT,
                notes TEXT,
                uploaded_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY(client_id) REFERENCES clients(id) ON DELETE CASCADE
            );
        """)
        db.conn.commit()
    except Exception:
        pass

def scoring_plus_category(category: str) -> str:
    return SCORING_PLUS_CATEGORY_MAP.get(normalize_category(category), category or "Altro")

def mirror_document_to_scoring_plus(db, client_id: int, category: str, original_filename: str, stored_path: str, notes: str = "") -> None:
    try:
        ensure_scoring_plus_tables(db)
        db.conn.execute(
            """
            INSERT INTO scoring_plus_documents (client_id, category, original_filename, stored_path, notes)
            VALUES (?, ?, ?, ?, ?)
            """,
            (client_id, scoring_plus_category(category), original_filename, stored_path, notes),
        )
        db.conn.commit()
    except Exception:
        pass


def normalize_traffic_light(value: str | None) -> str:
    raw = (value or "").strip()
    lowered = raw.lower()
    if "🔴" in raw or "rosso" in lowered or "red" in lowered:
        return "🔴"
    if "🟢" in raw or "verde" in lowered or "green" in lowered:
        return "🟢"
    if "🟡" in raw or "giallo" in lowered or "yellow" in lowered:
        return "🟡"
    return ""


def traffic_light_hex(value: str | None) -> str:
    normalized = normalize_traffic_light(value)
    if normalized == "🔴":
        return "#d84a3a"
    if normalized == "🟢":
        return "#1f8f5f"
    if normalized == "🟡":
        return "#d4a100"
    return "#9aa4b2"


def normalize_request_status(value: str | None, default: str = "inevasa") -> str:
    raw = (value or "").strip()
    lowered = raw.lower()
    if not lowered:
        return default
    if lowered in {"tutte", "tutti", "all", "qualsiasi"}:
        return ""
    if "parz" in lowered:
        return "parziale"
    if "inevas" in lowered or "apert" in lowered or "pend" in lowered:
        return "inevasa"
    if "evas" in lowered or "chius" in lowered or "complet" in lowered:
        return "evasa"
    for option in REQUEST_STATUS_OPTIONS:
        if option in lowered:
            return option
    return default


def request_status_to_light(value: str | None) -> str:
    status = normalize_request_status(value)
    return {"inevasa": "🔴", "parziale": "🟡", "evasa": "🟢"}.get(status, "")


def traffic_light_to_request_status(value: str | None) -> str:
    light = normalize_traffic_light(value)
    return {"🔴": "inevasa", "🟡": "parziale", "🟢": "evasa"}.get(light, "inevasa")


def request_status_style(value: str | None) -> tuple[str, str, str, str]:
    status = normalize_request_status(value)
    if status == "evasa":
        return ("EVASA", "#dcfce7", "#166534", "🟢")
    if status == "parziale":
        return ("PARZIALE", "#fef3c7", "#92400e", "🟡")
    return ("INEVASA", "#fee2e2", "#991b1b", "🔴")


def create_traffic_dot_images(master=None, size: int = 14) -> dict[str, object | None]:
    images: dict[str, object | None] = {"": None}
    dot_colors = {"🔴": "#d84a3a", "🟡": "#d4a100", "🟢": "#1f8f5f"}
    if PIL_AVAILABLE and Image is not None and ImageTk is not None:
        for key, color in dot_colors.items():
            img = Image.new("RGBA", (size, size), (255, 255, 255, 0))
            from PIL import ImageDraw
            draw = ImageDraw.Draw(img)
            draw.ellipse((1, 1, size - 2, size - 2), fill=color, outline="#7f8a99")
            images[key] = ImageTk.PhotoImage(img, master=master)
        return images
    try:
        for key, color in dot_colors.items():
            img = tk.PhotoImage(master=master, width=size, height=size)
            img.put(color, to=(2, 2, size-2, size-2))
            images[key] = img
    except Exception:
        images["🔴"] = None
        images["🟢"] = None
        images["🟡"] = None
    return images


def format_currency(value: float | int | None) -> str:
    if value is None:
        return "-"
    try:
        amount = float(value)
    except Exception:
        return "-"
    sign = "-" if amount < 0 else ""
    amount = abs(amount)
    formatted = f"{amount:,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")
    return f"{sign}€ {formatted}"


def parse_number(value: str | None) -> float | None:
    if value is None:
        return None
    raw = str(value).strip()
    if not raw:
        return None
    raw = raw.replace("EUR", "").replace("euro", "").replace("€", "")
    raw = raw.replace(" ", "")
    if "," in raw and "." in raw:
        raw = raw.replace(".", "").replace(",", ".")
    elif raw.count(",") == 1 and raw.count(".") == 0:
        raw = raw.replace(",", ".")
    else:
        raw = raw.replace(",", "")
    try:
        return float(Decimal(raw))
    except (InvalidOperation, ValueError):
        return None


def safe_ratio(num: float | None, den: float | None) -> float | None:
    if num is None or den in (None, 0):
        return None
    try:
        return num / den
    except Exception:
        return None


def text_from_supported_file(path: str) -> str:
    ext = Path(path).suffix.lower()
    if ext == ".pdf":
        return read_pdf_text(path)
    if ext in {".txt", ".csv", ".md", ".log"}:
        return Path(path).read_text(encoding="utf-8", errors="ignore")
    return ""


def extract_first_amount(patterns: list[str], text: str) -> float | None:
    for pattern in patterns:
        match = re.search(pattern, text, re.IGNORECASE)
        if match:
            value = parse_number(match.group(1))
            if value is not None:
                return value
    return None


def extract_all_year_amounts(keyword_patterns: list[str], text: str) -> dict[int, float]:
    results: dict[int, float] = {}
    flat_text = text.replace("\n", " ").replace("\r", " ")
    for year in (2022, 2023, 2024):
        for keyword in keyword_patterns:
            pattern = rf"{keyword}.{{0,60}}?([0-9\.\,]+)"
            match = re.search(pattern, flat_text, re.IGNORECASE)
            if match:
                value = parse_number(match.group(1))
                if value is not None:
                    results[year] = value
                    break
    return results


def analyze_credit_documents(client: sqlite3.Row | None, selected_docs: dict[str, sqlite3.Row | None]) -> dict:
    client_name = client["denominazione"] if client else "Cliente"
    extracted_docs = []
    combined_text_parts: list[str] = []
    doc_texts: dict[str, str] = {}
    for slot_name, row in selected_docs.items():
        if not row:
            continue
        path = row["stored_path"] or ""
        text = ""
        try:
            text = text_from_supported_file(path) if path else ""
        except Exception:
            text = ""
        doc_texts[slot_name] = text
        combined_text_parts.append(text)
        extracted_docs.append({
            "slot": slot_name,
            "title": row["title"] or row["original_filename"] or slot_name,
            "category": row["category"] or "",
            "path": path,
            "loaded": bool(text.strip()),
        })

    text = "\n".join(combined_text_parts)
    bilancio_text = doc_texts.get("bilancio", "") + "\n" + doc_texts.get("bozza_bilancio", "") + "\n" + doc_texts.get("report", "")
    cr_text = doc_texts.get("cr", "") + "\n" + doc_texts.get("report", "")

    indicators = {
        "ricavi": extract_first_amount([r"ricavi[^0-9-]{0,30}([0-9\.\,]+)", r"fatturato[^0-9-]{0,30}([0-9\.\,]+)"], bilancio_text),
        "ebitda": extract_first_amount([r"ebitda[^0-9-]{0,30}([0-9\.\,]+)", r"margine operativo lordo[^0-9-]{0,30}([0-9\.\,]+)", r"mol[^0-9-]{0,30}([0-9\.\,]+)"], bilancio_text),
        "utile": extract_first_amount([r"utile[^0-9-]{0,30}([0-9\.\,]+)", r"risultato d['’]?esercizio[^0-9-]{0,30}([0-9\.\,]+)"], bilancio_text),
        "patrimonio_netto": extract_first_amount([r"patrimonio netto[^0-9-]{0,30}([0-9\.\,]+)"], bilancio_text),
        "debiti_banche": extract_first_amount([r"debiti verso banche[^0-9-]{0,30}([0-9\.\,]+)", r"debiti bancari[^0-9-]{0,30}([0-9\.\,]+)"], bilancio_text + "\n" + cr_text),
        "accordato_cr": extract_first_amount([r"accordato[^0-9-]{0,30}([0-9\.\,]+)", r"totale accordato[^0-9-]{0,30}([0-9\.\,]+)"], cr_text),
        "utilizzato_cr": extract_first_amount([r"utilizzato[^0-9-]{0,30}([0-9\.\,]+)", r"totale utilizzato[^0-9-]{0,30}([0-9\.\,]+)"], cr_text),
        "sconfinamenti": extract_first_amount([r"sconfinament[oi][^0-9-]{0,30}([0-9\.\,]+)"], cr_text),
        "sofferenze": extract_first_amount([r"sofferenz[ea][^0-9-]{0,30}([0-9\.\,]+)"], cr_text),
    }

    trend = {
        "ricavi": extract_all_year_amounts([r"ricavi", r"fatturato"], bilancio_text),
        "ebitda": extract_all_year_amounts([r"ebitda", r"mol", r"margine operativo lordo"], bilancio_text),
        "utile": extract_all_year_amounts([r"utile", r"risultato d['’]?esercizio"], bilancio_text),
    }

    ratios = {
        "margine_ebitda": safe_ratio(indicators["ebitda"], indicators["ricavi"]),
        "margine_utile": safe_ratio(indicators["utile"], indicators["ricavi"]),
        "copertura_debiti": safe_ratio(indicators["patrimonio_netto"], indicators["debiti_banche"]),
        "utilizzo_cr": safe_ratio(indicators["utilizzato_cr"], indicators["accordato_cr"]),
        "roe": safe_ratio(indicators["utile"], indicators["patrimonio_netto"]),
    }

    score = 50
    notes: list[str] = []
    positives: list[str] = []
    negatives: list[str] = []

    if indicators["ricavi"]:
        if indicators["ricavi"] >= 3000000:
            score += 10
            positives.append("Ricavi coerenti con una fascia dimensionalmente solida.")
        elif indicators["ricavi"] >= 800000:
            score += 5
        else:
            score -= 4
            negatives.append("Volume ricavi contenuto: maggiore attenzione alla sostenibilita del debito.")
    else:
        notes.append("Ricavi non letti automaticamente: verificare il bilancio o inserire un PDF testo piu chiaro.")

    if ratios["margine_ebitda"] is not None:
        if ratios["margine_ebitda"] >= 0.12:
            score += 12
            positives.append("Margine EBITDA/MOL buono rispetto ai ricavi.")
        elif ratios["margine_ebitda"] >= 0.06:
            score += 5
        else:
            score -= 10
            negatives.append("Marginalita operativa bassa.")
    else:
        notes.append("EBITDA/MOL non identificato in modo certo.")

    if indicators["utile"] is not None:
        if indicators["utile"] > 0:
            score += 8
            positives.append("Utile positivo.")
        else:
            score -= 12
            negatives.append("Utile nullo o negativo.")

    if indicators["patrimonio_netto"] is not None:
        if indicators["patrimonio_netto"] > 0:
            score += 8
        else:
            score -= 18
            negatives.append("Patrimonio netto negativo o assente.")

    if ratios["utilizzo_cr"] is not None:
        if ratios["utilizzo_cr"] <= 0.7:
            score += 8
            positives.append("Utilizzo della CR sotto controllo.")
        elif ratios["utilizzo_cr"] <= 0.9:
            score += 2
        else:
            score -= 8
            negatives.append("Utilizzo molto elevato degli affidamenti in CR.")

    if indicators["sconfinamenti"]:
        score -= 10
        negatives.append("Presenza di sconfinamenti segnalati.")
    if indicators["sofferenze"]:
        score -= 18
        negatives.append("Presenza di sofferenze o posizioni critiche.")

    score = max(1, min(100, score))
    if score >= 75:
        rating = "Affidabilita buona"
        risk = "Verde"
    elif score >= 55:
        rating = "Affidabilita media"
        risk = "Giallo"
    else:
        rating = "Affidabilita da approfondire"
        risk = "Rosso"

    ebitda = indicators["ebitda"] or 0
    patrimonio = indicators["patrimonio_netto"] or 0
    debiti = indicators["debiti_banche"] or 0
    base_amount = max(0.0, ebitda * 0.35 + patrimonio * 0.12 - debiti * 0.10)
    score_multiplier = 0.8 + (score / 100.0) * 0.8
    estimated_amount = max(0.0, min(base_amount * score_multiplier, max(ebitda * 0.8, patrimonio * 0.35, 50000 if score >= 70 else 0)))

    suggestions = []
    if indicators["patrimonio_netto"] is not None and indicators["patrimonio_netto"] < 150000:
        suggestions.append(("Rafforzamento patrimonio netto", 150000 - indicators["patrimonio_netto"], "Valutare versamenti soci o destinazione utili a riserva."))
    if ratios["margine_ebitda"] is not None and ratios["margine_ebitda"] < 0.08 and indicators["ricavi"]:
        target = indicators["ricavi"] * 0.08
        suggestions.append(("Incremento EBITDA/MOL", max(0, target - (indicators["ebitda"] or 0)), "Lavorare su pricing, costi diretti e assorbimento spese generali."))
    if ratios["utilizzo_cr"] is not None and ratios["utilizzo_cr"] > 0.85 and indicators["accordato_cr"] and indicators["utilizzato_cr"]:
        reduce_amt = indicators["utilizzato_cr"] - indicators["accordato_cr"] * 0.75
        suggestions.append(("Riduzione utilizzo linee CR", max(0, reduce_amt), "Ridurre tensione di cassa e concentrazione sul breve termine."))
    if indicators["utile"] is not None and indicators["utile"] < 50000:
        suggestions.append(("Miglioramento utile netto", max(0, 50000 - indicators["utile"]), "Agire su marginalita e costi non ricorrenti per presentare un utile piu robusto."))
    if not suggestions:
        suggestions.append(("Mantenimento equilibrio", 0, "La posizione appare ordinata; monitorare comunque patrimonio, marginalita e utilizzo affidamenti."))

    summary_lines = []
    if positives:
        summary_lines.append("Punti di forza: " + " ".join(positives[:3]))
    if negatives:
        summary_lines.append("Aree critiche: " + " ".join(negatives[:3]))
    if notes:
        summary_lines.append("Note lettura automatica: " + " ".join(notes[:2]))
    summary_text = "\n".join(summary_lines) if summary_lines else "Analisi preliminare completata con dati parziali."

    return {
        "client_name": client_name,
        "documents": extracted_docs,
        "indicators": indicators,
        "ratios": ratios,
        "score": score,
        "rating": rating,
        "risk": risk,
        "estimated_amount": estimated_amount,
        "suggestions": suggestions,
        "summary_text": summary_text,
        "trend": trend,
        "notes": notes,
        "positives": positives,
        "negatives": negatives,
        "raw_text_available": bool(text.strip()),
    }


def compute_financing_simulation(amount: float, years: int = 5, tan: float = 0.082, fees_rate: float = 0.015) -> dict:
    months = max(12, years * 12)
    monthly_rate = tan / 12
    if amount <= 0:
        return {"amount": 0.0, "years": years, "tan": tan, "taeg": tan + fees_rate, "monthly_payment": 0.0, "total_interest": 0.0, "fees": 0.0}
    if monthly_rate == 0:
        payment = amount / months
    else:
        payment = amount * (monthly_rate / (1 - (1 + monthly_rate) ** (-months)))
    total_paid = payment * months
    fees = amount * fees_rate
    taeg = tan + fees_rate
    return {
        "amount": amount,
        "years": years,
        "tan": tan,
        "taeg": taeg,
        "monthly_payment": payment,
        "total_interest": total_paid - amount,
        "fees": fees,
    }


