class DocumentFormDialog(BaseWindow):
    def __init__(self, master, db: Database, client_id: int, on_saved=None):
        super().__init__(master, "Nuovo Documento", "860x560")
        self.db = db
        self.client_id = client_id
        self.on_saved = on_saved
        self.selected_file: str | None = None
        self.selected_files: list[str] = []
        self.assigned_collaborator_id: int | None = None
        self.assigned_collaborator_var = tk.StringVar(value="")

        container = ttk.Frame(self.content_frame, padding=18)
        container.pack(fill="both", expand=True)

        ttk.Label(
            container,
            text="Carica uno o più documenti: il programma li cataloga automaticamente leggendo nome file, titolo e contenuto disponibile (PDF, Word, Excel, CSV/TXT). Non devi più inserire una categoria manuale.",
            wraplength=720,
            justify="left",
        ).grid(row=0, column=0, columnspan=2, sticky="w", pady=(0, 12))

        ttk.Label(container, text="Titolo documento:").grid(row=1, column=0, sticky="w", pady=8, padx=(0, 10))
        self.title_entry = ttk.Entry(container, width=52)
        self.title_entry.grid(row=1, column=1, sticky="ew", pady=8)

        ttk.Label(container, text="Collaboratore:").grid(row=2, column=0, sticky="w", pady=8, padx=(0, 10))
        ttk.Entry(container, width=52, textvariable=self.assigned_collaborator_var, state="readonly").grid(row=2, column=1, sticky="ew", pady=8)

        ttk.Label(container, text="File:").grid(row=3, column=0, sticky="w", pady=8, padx=(0, 10))
        file_row = ttk.Frame(container)
        file_row.grid(row=3, column=1, sticky="ew", pady=8)
        file_row.columnconfigure(0, weight=1)
        self.file_var = tk.StringVar()
        ttk.Entry(file_row, textvariable=self.file_var, state="readonly").grid(row=0, column=0, sticky="ew")
        ttk.Button(file_row, text="Sfoglia", command=self.choose_file).grid(row=0, column=1, padx=(8, 0))

        self.multi_hint_var = tk.StringVar(value="")
        ttk.Label(container, textvariable=self.multi_hint_var, wraplength=640, justify="left", foreground=MUTED_TEXT).grid(row=4, column=1, sticky="w", pady=(0, 6))

        ttk.Label(container, text="Note:").grid(row=5, column=0, sticky="nw", pady=8, padx=(0, 10))
        self.notes_text = ScrolledText(container, width=48, height=10, wrap="word")
        self.notes_text.grid(row=5, column=1, sticky="nsew", pady=8)

        container.columnconfigure(1, weight=1)
        container.rowconfigure(5, weight=1)

        buttons = ttk.Frame(container)
        buttons.grid(row=6, column=0, columnspan=2, sticky="e", pady=(18, 0))
        ttk.Button(buttons, text="Salva", command=self.save).pack(side="right", padx=(8, 0))
        ttk.Button(buttons, text="Chiudi", command=self.destroy).pack(side="right")

        self.load_assigned_collaborator()
        self._update_file_hint()

    def load_assigned_collaborator(self):
        client_row = self.db.get_client(self.client_id)
        if client_row and client_row["responsible_collaborator_id"]:
            self.assigned_collaborator_id = client_row["responsible_collaborator_id"]
            collab = self.db.get_collaborator(self.assigned_collaborator_id)
            if collab:
                self.assigned_collaborator_var.set(f"{collab['nome']} {collab['cognome']}")
                return
        self.assigned_collaborator_id = None
        self.assigned_collaborator_var.set("")

    def _update_file_hint(self):
        self.multi_hint_var.set("Catalogazione automatica attiva: puoi selezionare uno o più file e ogni documento verrà riconosciuto da nome file, titolo e contenuto leggibile.")

    def choose_file(self):
        paths = list(filedialog.askopenfilenames(
            title="Seleziona uno o più documenti",
            filetypes=[
                ("Documenti supportati", "*.pdf *.xlsx *.xls *.xlsm *.csv *.docx *.txt *.rtf *.png *.jpg *.jpeg"),
                ("PDF", "*.pdf"),
                ("Excel", "*.xlsx *.xls *.xlsm *.csv"),
                ("Word", "*.docx"),
                ("Testo", "*.txt *.rtf *.md *.csv"),
                ("Immagini", "*.png *.jpg *.jpeg"),
                ("Tutti i file", "*.*"),
            ],
        ))
        if not paths:
            return
        self.selected_files = paths
        self.selected_file = paths[0]
        first = Path(paths[0])
        detected_category, reason = infer_document_category(paths[0], fallback="Altro", title=first.stem)
        if len(paths) == 1:
            self.file_var.set(paths[0])
            if not self.title_entry.get().strip():
                self.title_entry.insert(0, first.stem)
            self.multi_hint_var.set(f"Catalogazione automatica: {detected_category} ({reason}).")
        else:
            self.file_var.set(f"{len(paths)} file selezionati")
            if not self.title_entry.get().strip():
                self.title_entry.insert(0, "Documenti vari")
            self.multi_hint_var.set(f"{len(paths)} file selezionati: ogni documento sarà catalogato automaticamente in base a nome file, titolo e contenuto.")

    def save(self):
        title_base = self.title_entry.get().strip()
        if not self.selected_files:
            messagebox.showwarning("Attenzione", "Seleziona almeno un file da archiviare.")
            return

        client_folder = get_client_documents_folder(self.client_id)
        collaborator_id = self.assigned_collaborator_id
        notes = self.notes_text.get("1.0", tk.END).strip()
        saved_count = 0

        try:
            for index, selected_path in enumerate(self.selected_files, start=1):
                original = Path(selected_path)
                timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
                target = client_folder / f"{timestamp}_{index}_{original.name}"
                shutil.copy2(original, target)

                if len(self.selected_files) == 1:
                    title = title_base or original.stem
                else:
                    if title_base and title_base != "Documenti vari":
                        title = f"{title_base} - {original.stem}"
                    else:
                        title = original.stem

                detected_category, detection_reason = infer_document_category(str(target), fallback="Altro", title=title)

                final_notes = notes
                if detection_reason:
                    final_notes = (final_notes + "\n" if final_notes else "") + f"Catalogazione automatica da nome file, titolo e contenuto: {detected_category} ({detection_reason})."

                data = {
                    "client_id": self.client_id,
                    "collaborator_id": collaborator_id,
                    "category": detected_category,
                    "title": title,
                    "original_filename": original.name,
                    "stored_path": str(target),
                    "notes": final_notes,
                }
                self.db.add_document(data)
                mirror_document_to_scoring_plus(self.db, self.client_id, detected_category, original.name, str(target), final_notes)
                saved_count += 1

            if saved_count == 1:
                messagebox.showinfo("Salvataggio completato", "Documento archiviato correttamente.")
            else:
                messagebox.showinfo("Salvataggio completato", f"Documenti archiviati correttamente: {saved_count}")
            if self.on_saved:
                self.on_saved()
            self.destroy()
        except Exception as exc:
            messagebox.showerror("Errore", f"Impossibile archiviare il documento.\n\n{exc}")


class DocumentManagementWindow(BaseWindow):
    def __init__(self, master, db: Database, preselected_client_id: int | None = None, on_saved=None):
        super().__init__(master, "Gestione Documenti", "1080x700")
