class ClientDetailWindow(BaseWindow):
    def __init__(self, master, db: Database, client_id: int, on_changed=None):
        super().__init__(master, "Scheda Cliente", "1100x760")
        self.db = db
        self.client_id = client_id
        self.on_changed = on_changed

        self.title_label.configure(font=("Segoe UI", 16, "bold"), wraplength=430, justify="left")
        self.title_label.pack_configure(padx=(18, 8))
        self.home_button.pack_forget()
        try:
            self.header_logo.pack_forget()
        except Exception:
            pass

        self.detail_logo = pack_logo_label(self.header, size=(110, 42), watermark=False, bg=CARD_BG, side="right", padx=(0, 10), pady=10)
        action_bar = ttk.Frame(self.header)
        action_bar.pack(side="right", padx=12, pady=10)
        ttk.Button(action_bar, text="Modifica anagrafica", command=self.edit_client).pack(side="left", padx=(0, 8))
        ttk.Button(action_bar, text="Modifica informazioni", command=self.edit_info).pack(side="left", padx=(0, 8))
        ttk.Button(action_bar, text="Richieste Doc / Prat", command=self.manage_requests).pack(side="left", padx=(0, 8))
        ttk.Button(action_bar, text="Home", command=self.go_home).pack(side="left")

        self.notebook = ttk.Notebook(self.content_frame)
        self.notebook.pack(fill="both", expand=True, padx=12, pady=12)

        self.tab_anagrafica = ttk.Frame(self.notebook, padding=16)
        self.tab_anagrafica_completa = ttk.Frame(self.notebook, padding=16)
        self.tab_info = ttk.Frame(self.notebook, padding=16)
        self.tab_requests = ttk.Frame(self.notebook, padding=16)
        self.tab_documents = ttk.Frame(self.notebook, padding=16)
        self.tab_collabs = ttk.Frame(self.notebook, padding=16)
        self.tab_note = ttk.Frame(self.notebook, padding=16)
        self.tab_note2 = ttk.Frame(self.notebook, padding=16)

        self.notebook.add(self.tab_anagrafica, text="Anagrafica")
        self.notebook.add(self.tab_anagrafica_completa, text="Anagrafica completa")
        self.notebook.add(self.tab_info, text="Informazioni")
        self.notebook.add(self.tab_requests, text="Richieste Doc / Pratiche")
        self.notebook.add(self.tab_documents, text="Documenti")
        self.notebook.add(self.tab_collabs, text="Collaboratori collegati")
        self.notebook.add(self.tab_note, text="Note")
        self.notebook.add(self.tab_note2, text="Note2")

        self.load_data()

    def _fill_key_values(self, parent, pairs):
        for widget in parent.winfo_children():
            widget.destroy()
        tree, _holder = create_treeview_with_scrollbars(parent, ("campo", "valore"), show="headings")
        tree.heading("campo", text="Campo")
        tree.heading("valore", text="Valore")
        tree.column("campo", width=260, anchor="w", stretch=False)
        tree.column("valore", width=760, anchor="w")
        for label, value in pairs:
            shown = value if value not in (None, "") else "-"
            tree.insert("", "end", values=(label, shown))

    def load_data(self):
        client = self.db.get_client(self.client_id)
        if not client:
            messagebox.showerror("Errore", "Cliente non trovato.")
            self.destroy()
            return
        short_name = (client['denominazione'] or '').strip()
        if len(short_name) > 48:
            short_name = short_name[:45].rstrip() + '...'
        self.title_label.configure(text=f"Scheda Cliente - {short_name}")
        self.title(f"Scheda Cliente - {client['denominazione']} - {APP_TITLE}")

        responsible_name = ""
        if client["responsible_collaborator_id"]:
            collab = self.db.get_collaborator(client["responsible_collaborator_id"])
            if collab:
                responsible_name = f"{collab['nome']} {collab['cognome']}"
        self._fill_key_values(
            self.tab_anagrafica,
            [(label, client[field]) for field, label in CLIENT_FIELDS] + [("Collaboratore", responsible_name)],
        )

        self._populate_anagrafica_completa_tab(client)

        info = self.db.get_client_info(self.client_id)
        info_pairs = []
        for field, label in INFO_FIELDS:
            if field in INFO_BOOLEAN_FIELDS:
                choice = info[f"{field}_choice"] if info else ""
                note = info[f"{field}_note"] if info else ""
                value = f"{choice} | {note}" if choice or note else ""
            else:
                value = info[field] if info else ""
            info_pairs.append((label, value))
        self._fill_key_values(self.tab_info, info_pairs)

        self._populate_requests_tab()
        self._populate_documents_tab()
        self._populate_collabs_tab()
        self._populate_note_tab(info, client)
        self._populate_note2_tab(client)
        if self.on_changed:
            self.on_changed()


    def _populate_anagrafica_completa_tab(self, client):
        for widget in self.tab_anagrafica_completa.winfo_children():
            widget.destroy()
        raw = (client["anagrafica_completa"] or "").strip()
        if not raw:
            ttk.Label(self.tab_anagrafica_completa, text="Nessuna anagrafica completa disponibile dal report caricato.").pack(anchor="w")
            return
        tree, _holder = create_treeview_with_scrollbars(self.tab_anagrafica_completa, ("campo", "valore"), show="headings")
        tree.heading("campo", text="Campo")
        tree.heading("valore", text="Valore")
        tree.column("campo", width=260, anchor="w")
        tree.column("valore", width=760, anchor="w")
        for line in [ln.strip() for ln in raw.splitlines() if ln.strip()]:
            if ":" in line:
                campo, valore = line.split(":", 1)
                tree.insert("", "end", values=(campo.strip(), valore.strip()))
            else:
                tree.insert("", "end", values=(line, ""))

    def _populate_requests_tab(self):
        for widget in self.tab_requests.winfo_children():
            widget.destroy()
        rows = self.db.list_requests(self.client_id)
        tree, _holder = create_treeview_with_scrollbars(self.tab_requests, ("data", "contatto", "oggetto", "stato", "resp"), show="tree headings")
        tree._traffic_dot_images = create_traffic_dot_images(self)
        tree.heading("#0", text="Semaforo")
        tree.heading("data", text="Data")
        tree.heading("contatto", text="Mail / Cell")
        tree.heading("oggetto", text="Oggetto richiesta")
        tree.heading("stato", text="Stato richiesta")
        tree.heading("resp", text="Responsabile")
        tree.column("#0", width=90, anchor="center", stretch=False)
        tree.column("data", width=100, anchor="center")
        tree.column("contatto", width=100, anchor="center")
        tree.column("oggetto", width=260)
        tree.column("stato", width=320)
        tree.column("resp", width=180)
        for row in rows:
            light = normalize_traffic_light(row["traffic_light"] or "")
            tree.insert(
                "",
                "end",
                iid=str(row["id"]),
                text="",
                image=tree._traffic_dot_images.get(light),
                values=(
                    row["request_date"] or "",
                    row["contact_method"] or "",
                    (row["request_subject"] or row["notes"] or "")[:100],
                    (row["status_detail"] or row["request_status"] or "")[:120],
                    row["responsible_name"] or "",
                ),
            )

    def _populate_documents_tab(self):
        for widget in self.tab_documents.winfo_children():
            widget.destroy()
        rows = self.db.list_documents_linked(self.client_id)
        tree, _holder = create_treeview_with_scrollbars(self.tab_documents, ("titolo", "resp", "file", "data"), show="headings")
        tree.heading("titolo", text="Titolo")
        tree.heading("resp", text="Responsabile")
        tree.heading("file", text="File")
        tree.heading("data", text="Data")
        tree.column("titolo", width=280)
        tree.column("resp", width=190)
        tree.column("file", width=250)
        tree.column("data", width=130, anchor="center")
        for row in rows:
            tree.insert(
                "",
                "end",
                iid=str(row["id"]),
                values=(row["title"] or "", row["collaborator_name"] or "", row["original_filename"] or "", (row["uploaded_at"] or "")[:10]),
            )
        tree.bind("<Double-1>", lambda _e: self._open_document_from_tree(tree))

    def _open_document_from_tree(self, tree):
        selection = tree.selection()
        if not selection:
            return
        row = self.db.get_document(int(selection[0]))
        if row and row["stored_path"]:
            open_path(row["stored_path"])

    def _populate_collabs_tab(self):
        for widget in self.tab_collabs.winfo_children():
            widget.destroy()
        rows = self.db.get_related_collaborators_for_client(self.client_id)
        tree, _holder = create_treeview_with_scrollbars(self.tab_collabs, ("nome", "cellulare", "mail"), show="headings")
        tree.heading("nome", text="Collaboratore")
        tree.heading("cellulare", text="Cellulare")
        tree.heading("mail", text="Mail")
        tree.column("nome", width=260)
        tree.column("cellulare", width=180)
        tree.column("mail", width=300)
        for row in rows:
            tree.insert(
                "",
                "end",
                iid=str(row["id"]),
                values=(f"{row['nome']} {row['cognome']}", row["cellulare"] or "", row["mail"] or ""),
            )
        tree.bind("<Double-1>", lambda _e: self._open_collaborator_from_tree(tree))

    def _open_collaborator_from_tree(self, tree):
        selection = tree.selection()
        if not selection:
            return
        CollaboratorDetailWindow(self, self.db, int(selection[0]))

    def _populate_note_tab(self, info, client):
        for widget in self.tab_note.winfo_children():
            widget.destroy()
        container = ttk.Frame(self.tab_note)
        container.pack(fill="both", expand=True)
        container.rowconfigure(1, weight=1)
        container.columnconfigure(0, weight=1)

        ttk.Label(container, text="Note cliente", font=("Segoe UI", 11, "bold")).grid(row=0, column=0, sticky="w", pady=(0, 10))

        holder = ttk.Frame(container)
        holder.grid(row=1, column=0, sticky="nsew")
        holder.rowconfigure(0, weight=1)
        holder.columnconfigure(0, weight=1)
        note_text = tk.Text(holder, wrap="word", font=("Segoe UI", 10), height=18, undo=True)
        vbar = ttk.Scrollbar(holder, orient="vertical", command=note_text.yview)
        hbar = ttk.Scrollbar(holder, orient="horizontal", command=note_text.xview)
        note_text.configure(yscrollcommand=vbar.set, xscrollcommand=hbar.set)
        note_text.grid(row=0, column=0, sticky="nsew")
        vbar.grid(row=0, column=1, sticky="ns")
        hbar.grid(row=1, column=0, sticky="ew")

        chunks = []
        if info and (info["informazioni_aggiuntive"] or "").strip():
            chunks.append("Informazioni aggiuntive azienda:\n" + (info["informazioni_aggiuntive"] or "").strip())
        if client and (client["report_dati"] or "").strip():
            chunks.append("Dati aggiuntivi da report:\n" + (client["report_dati"] or "").strip())
        content = "\n\n".join(chunks).strip() if chunks else "Nessuna nota disponibile per questo cliente."
        note_text.insert("1.0", content)
        note_text.configure(state="disabled")

    def _populate_note2_tab(self, client):
        for widget in self.tab_note2.winfo_children():
            widget.destroy()
        container = ttk.Frame(self.tab_note2)
        container.pack(fill="both", expand=True)
        container.rowconfigure(1, weight=1)
        container.columnconfigure(0, weight=1)

        top = ttk.Frame(container)
        top.grid(row=0, column=0, sticky="ew", pady=(0, 10))
        ttk.Label(top, text="Note2 cliente", font=("Segoe UI", 11, "bold")).pack(side="left")
        ttk.Button(top, text="Salva Note2", command=self.save_note2).pack(side="right")

        holder = ttk.Frame(container)
        holder.grid(row=1, column=0, sticky="nsew")
        holder.rowconfigure(0, weight=1)
        holder.columnconfigure(0, weight=1)
        self.note2_text = tk.Text(holder, wrap="word", font=("Segoe UI", 10), height=18, undo=True)
        vbar = ttk.Scrollbar(holder, orient="vertical", command=self.note2_text.yview)
        hbar = ttk.Scrollbar(holder, orient="horizontal", command=self.note2_text.xview)
        self.note2_text.configure(yscrollcommand=vbar.set, xscrollcommand=hbar.set)
        self.note2_text.grid(row=0, column=0, sticky="nsew")
        vbar.grid(row=0, column=1, sticky="ns")
        hbar.grid(row=1, column=0, sticky="ew")
        self.note2_text.delete("1.0", tk.END)
        self.note2_text.insert("1.0", (client["note2"] or "").strip())

    def save_note2(self):
        content = self.note2_text.get("1.0", tk.END).strip() if hasattr(self, "note2_text") else ""
        try:
            self.db.update_client_note2(self.client_id, content)
            messagebox.showinfo("Note2 salvate", "Le Note2 del cliente sono state salvate correttamente.")
            self.load_data()
        except Exception as exc:
            messagebox.showerror("Errore", f"Impossibile salvare le Note2.\n\n{exc}")

    def edit_client(self):
        ClientFormWindow(self, self.db, self.client_id, on_saved=self.load_data)

    def edit_info(self):
        ClientInfoWindow(self, self.db, preselected_client_id=self.client_id, on_saved=self.load_data)

    def manage_requests(self):
        RequestManagementWindow(self, self.db, preselected_client_id=self.client_id, on_saved=self.load_data)

    def manage_documents(self):
        DocumentManagementWindow(self, self.db, preselected_client_id=self.client_id, on_saved=self.load_data)

    def open_pdf_sheet(self):
        client = self.db.get_client(self.client_id)
        safe_client = sanitize_client_storage_name(client["denominazione"] if client else None, f"cliente_{self.client_id}")
        output = get_app_data_dir() / f"scheda_cliente_{safe_client}.pdf"
        try:
            export_client_sheet_pdf(self.db, self.client_id, str(output))
            open_path(str(output))
        except Exception as exc:
            messagebox.showerror("Errore", f"Impossibile generare il PDF scheda.\n\n{exc}")


class CollaboratorDetailWindow(BaseWindow):
    def __init__(self, master, db: Database, collaborator_id: int, on_changed=None):
        super().__init__(master, "Scheda Collaboratore", "1040x720")
        self.db = db
        self.collaborator_id = collaborator_id
        self.on_changed = on_changed

        action_bar = ttk.Frame(self.header)
        action_bar.pack(side="right", padx=12)
        ttk.Button(action_bar, text="Modifica", command=self.edit_collaborator).pack(side="left", pady=12)

        self.notebook = ttk.Notebook(self.content_frame)
        self.notebook.pack(fill="both", expand=True, padx=12, pady=12)

        self.tab_card = ttk.Frame(self.notebook, padding=16)
        self.tab_clients = ttk.Frame(self.notebook, padding=16)
        self.tab_requests = ttk.Frame(self.notebook, padding=16)
        self.tab_documents = ttk.Frame(self.notebook, padding=16)

        self.notebook.add(self.tab_card, text="Scheda")
        self.notebook.add(self.tab_clients, text="Clienti collegati")
        self.notebook.add(self.tab_requests, text="Richieste assegnate")
        self.notebook.add(self.tab_documents, text="Documenti assegnati")

        self.load_data()

    def _fill_key_values(self, parent, pairs):
        for widget in parent.winfo_children():
            widget.destroy()
        tree, _holder = create_treeview_with_scrollbars(parent, ("campo", "valore"), show="headings")
        tree.heading("campo", text="Campo")
        tree.heading("valore", text="Valore")
        tree.column("campo", width=240, anchor="w", stretch=False)
        tree.column("valore", width=720, anchor="w")
        for label, value in pairs:
            tree.insert("", "end", values=(label, value if value else "-"))

    def load_data(self):
        collab = self.db.get_collaborator(self.collaborator_id)
        if not collab:
            messagebox.showerror("Errore", "Collaboratore non trovato.")
            self.destroy()
            return
        self.title_label.configure(text=f"Scheda Collaboratore - {collab['nome']} {collab['cognome']}")
        self._fill_key_values(self.tab_card, [(label, collab[field]) for field, label in COLLABORATOR_FIELDS])
        self._populate_clients_tab()
        self._populate_requests_tab()
        self._populate_documents_tab()
        if self.on_changed:
            self.on_changed()

    def _populate_clients_tab(self):
        for widget in self.tab_clients.winfo_children():
            widget.destroy()
        rows = self.db.get_related_clients_for_collaborator(self.collaborator_id)
        tree, _holder = create_treeview_with_scrollbars(self.tab_clients, ("den", "ruolo", "amm", "settore"), show="headings")
        tree.heading("den", text="Cliente")
        tree.heading("ruolo", text="Collegamento")
        tree.heading("amm", text="Amministratore")
        tree.heading("settore", text="Settore")
        tree.column("den", width=250)
        tree.column("ruolo", width=160)
        tree.column("amm", width=220)
        tree.column("settore", width=220)
        for row in rows:
            role = "Cliente assegnato" if row["responsible_collaborator_id"] == self.collaborator_id else "Collegato"
            tree.insert("", "end", iid=str(row["id"]), values=(row["denominazione"], role, row["amministratore"] or "", row["settore_attivita"] or ""))
        tree.bind("<Double-1>", lambda _e: self._open_client_from_tree(tree))


    def _populate_anagrafica_completa_tab(self, client):
        for widget in self.tab_anagrafica_completa.winfo_children():
            widget.destroy()
        raw = (client["anagrafica_completa"] or "").strip()
        if not raw:
            ttk.Label(self.tab_anagrafica_completa, text="Nessuna anagrafica completa disponibile dal report caricato.").pack(anchor="w")
            return
        tree = ttk.Treeview(self.tab_anagrafica_completa, columns=("campo", "valore"), show="headings")
        tree.heading("campo", text="Campo")
        tree.heading("valore", text="Valore")
        tree.column("campo", width=260, anchor="w")
        tree.column("valore", width=760, anchor="w")
        for line in [ln.strip() for ln in raw.splitlines() if ln.strip()]:
            if ":" in line:
                campo, valore = line.split(":", 1)
                tree.insert("", "end", values=(campo.strip(), valore.strip()))
            else:
                tree.insert("", "end", values=(line, ""))

    def _populate_requests_tab(self):
        for widget in self.tab_requests.winfo_children():
            widget.destroy()
        rows = self.db.list_requests_by_collaborator(self.collaborator_id)
        tree, _holder = create_treeview_with_scrollbars(self.tab_requests, ("cliente", "data", "stato", "note"), show="headings")
        tree.heading("cliente", text="Cliente")
        tree.heading("data", text="Data")
        tree.heading("stato", text="Stato")
        tree.heading("note", text="Note")
        tree.column("cliente", width=280)
        tree.column("data", width=120, anchor="center")
        tree.column("stato", width=180, anchor="center")
        tree.column("note", width=360)
        for row in rows:
            tree.insert("", "end", iid=str(row["id"]), values=(row["denominazione"], row["request_date"], row["request_status"] or "", (row["notes"] or "")[:120]))

    def _populate_documents_tab(self):
        for widget in self.tab_documents.winfo_children():
            widget.destroy()
        rows = self.db.list_documents_by_collaborator(self.collaborator_id)
        tree, _holder = create_treeview_with_scrollbars(self.tab_documents, ("cliente", "titolo", "file"), show="headings")
        tree.heading("cliente", text="Cliente")
        tree.heading("titolo", text="Titolo")
        tree.heading("file", text="File")
        tree.column("cliente", width=280)
        tree.column("titolo", width=280)
        tree.column("file", width=250)
        for row in rows:
            tree.insert("", "end", iid=str(row["id"]), values=(row["denominazione"], row["title"] or "", row["original_filename"] or ""))
        tree.bind("<Double-1>", lambda _e: self._open_document_from_tree(tree))

    def _open_client_from_tree(self, tree):
        selection = tree.selection()
        if not selection:
            return
        ClientDetailWindow(self, self.db, int(selection[0]))

    def _open_document_from_tree(self, tree):
        selection = tree.selection()
        if not selection:
            return
        row = self.db.get_document(int(selection[0]))
        if row and row["stored_path"]:
            open_path(row["stored_path"])

    def edit_collaborator(self):
        CollaboratorFormWindow(self, self.db, self.collaborator_id, on_saved=self.load_data)


class ValutazioneWindow(BaseWindow):
    SLOT_LABELS = {
        "bilancio": "Inserisci bilancio",
        "cr": "Inserisci CR",
        "bozza_bilancio": "Inserisci bozza di bilancio",
        "report": "Inserisci report",
    }
    SLOT_KEYWORDS = {
        "bilancio": ["bilancio"],
        "cr": ["cr 36 mesi", "cr", "centrale rischi"],
        "bozza_bilancio": ["bozza"],
        "report": ["report"],
    }
    def __init__(self, master, db: Database):
        super().__init__(master, "Valutazione", "1220x820")
        self.db = db
        self.client_ids_by_name: dict[str, int] = {}
        self.document_rows_by_title: dict[str, sqlite3.Row] = {}
        self.doc_combos: dict[str, ttk.Combobox] = {}
        self.current_result: dict | None = None
        self.current_simulation: dict | None = None
        top = ttk.Frame(self.content_frame, padding=16)
        top.pack(fill="x")
        ttk.Label(top, text="Cliente:").pack(side="left")
        self.client_combo = ttk.Combobox(top, width=46, state="readonly")
        self.client_combo.pack(side="left", padx=(8, 0))
        self.client_combo.bind("<<ComboboxSelected>>", lambda _e: self.refresh_documents())
        ttk.Button(top, text="Esegui analisi", command=self.run_analysis).pack(side="right")
        ttk.Button(top, text="Salva analisi", command=self.save_analysis).pack(side="right", padx=(0, 8))
        ttk.Button(top, text="Esporta PDF valutazione", command=self.export_pdf).pack(side="right", padx=(0, 8))
        ttk.Button(top, text="Apri documento", command=self.open_selected_document).pack(side="right", padx=(0, 8))
        body = ttk.Frame(self.content_frame, padding=(16, 0, 16, 16))
        body.pack(fill="both", expand=True)
        body.columnconfigure(0, weight=3)
        body.columnconfigure(1, weight=2)
        body.rowconfigure(1, weight=1)
        docs_card = ttk.LabelFrame(body, text="Documenti collegati da Gestione Documenti", padding=14)
        docs_card.grid(row=0, column=0, sticky="nsew", padx=(0, 10), pady=(0, 10))
        docs_card.columnconfigure(1, weight=1)
        for i, (slot, label) in enumerate(self.SLOT_LABELS.items()):
            ttk.Label(docs_card, text=label + ":").grid(row=i, column=0, sticky="w", pady=6, padx=(0, 10))
            combo = ttk.Combobox(docs_card, state="readonly")
            combo.grid(row=i, column=1, sticky="ew", pady=6)
            self.doc_combos[slot] = combo
        sim_card = ttk.LabelFrame(body, text="Simulazione finanziamento", padding=14)
        sim_card.grid(row=0, column=1, sticky="nsew", pady=(0, 10))
        ttk.Label(sim_card, text="Durata (anni):").grid(row=0, column=0, sticky="w", pady=6, padx=(0, 8))
        self.years_combo = ttk.Combobox(sim_card, width=10, state="readonly", values=["3", "4", "5", "6", "7"])
        self.years_combo.grid(row=0, column=1, sticky="w", pady=6)
        self.years_combo.set("5")
        ttk.Label(sim_card, text="TAN %:").grid(row=1, column=0, sticky="w", pady=6, padx=(0, 8))
        self.tan_entry = ttk.Entry(sim_card, width=12)
        self.tan_entry.grid(row=1, column=1, sticky="w", pady=6)
        self.tan_entry.insert(0, "8.20")
        ttk.Label(sim_card, text="TAEG stimato: verra calcolato automaticamente", wraplength=240).grid(row=2, column=0, columnspan=2, sticky="w", pady=(10, 0))
        left_bottom = ttk.Frame(body)
        left_bottom.grid(row=1, column=0, sticky="nsew", padx=(0, 10))
        left_bottom.rowconfigure(1, weight=1)
        left_bottom.columnconfigure(0, weight=1)
        summary_card = ttk.LabelFrame(left_bottom, text="Esito sintetico", padding=14)
        summary_card.grid(row=0, column=0, sticky="ew", pady=(0, 10))
        summary_card.columnconfigure(1, weight=1)
        self.score_var = tk.StringVar(value="-")
        self.rating_var = tk.StringVar(value="-")
        self.risk_var = tk.StringVar(value="-")
        self.amount_var = tk.StringVar(value="-")
        self.sim_var = tk.StringVar(value="-")
        fields = [("Score interno", self.score_var), ("Rating", self.rating_var), ("Semaforo rischio", self.risk_var), ("Importo chirografario stimato", self.amount_var), ("Rata indicativa", self.sim_var)]
        for r, (label, var) in enumerate(fields):
            ttk.Label(summary_card, text=label + ":").grid(row=r, column=0, sticky="nw", padx=(0, 10), pady=4)
            ttk.Label(summary_card, textvariable=var, wraplength=400, justify="left").grid(row=r, column=1, sticky="w", pady=4)
        details_card = ttk.LabelFrame(left_bottom, text="Report valutazione", padding=10)
        details_card.grid(row=1, column=0, sticky="nsew")
        details_card.rowconfigure(0, weight=1)
        details_card.columnconfigure(0, weight=1)
        self.report_text = ScrolledText(details_card, wrap="word", font=("Segoe UI", 10), height=18)
        self.report_text.grid(row=0, column=0, sticky="nsew")
        right_bottom = ttk.Frame(body)
        right_bottom.grid(row=1, column=1, sticky="nsew")
        right_bottom.rowconfigure(1, weight=1)
        right_bottom.columnconfigure(0, weight=1)
        chart_card = ttk.LabelFrame(right_bottom, text="Dashboard grafica", padding=12)
        chart_card.grid(row=0, column=0, sticky="ew", pady=(0, 10))
        self.chart_canvas = tk.Canvas(chart_card, width=340, height=210, bg="white", highlightthickness=1, highlightbackground="#d7deeb")
        self.chart_canvas.pack(fill="both", expand=True)
        sugg_card = ttk.LabelFrame(right_bottom, text="Miglioramenti consigliati", padding=10)
        sugg_card.grid(row=1, column=0, sticky="nsew")
        sugg_card.rowconfigure(0, weight=1)
        sugg_card.columnconfigure(0, weight=1)
        self.suggestions_text = ScrolledText(sugg_card, wrap="word", font=("Segoe UI", 10), height=16)
        self.suggestions_text.grid(row=0, column=0, sticky="nsew")
        self.refresh_clients()
    def refresh_clients(self):
        clients = self.db.list_clients()
        self.client_ids_by_name = {f"{row['denominazione']} (ID {row['id']})": row['id'] for row in clients}
        self.client_combo["values"] = list(self.client_ids_by_name.keys())
        if clients:
            self.client_combo.set(next(iter(self.client_ids_by_name.keys())))
            self.refresh_documents()
    def selected_client_id(self) -> int | None:
        return self.client_ids_by_name.get(self.client_combo.get())
    def refresh_documents(self):
        client_id = self.selected_client_id()
        rows = self.db.list_documents_linked(client_id) if client_id else []
        self.document_rows_by_title = {}
        titles = []
        for row in rows:
            title = f"{row['title'] or row['original_filename']}"
            self.document_rows_by_title[title] = row
            titles.append(title)
        for slot, combo in self.doc_combos.items():
            combo["values"] = [""] + titles
            combo.set("")
            keywords = self.SLOT_KEYWORDS.get(slot, [])
            for title in titles:
                row = self.document_rows_by_title[title]
                cat = normalize_category(row['category'] or '')
                full = normalize_category((row['title'] or '') + ' ' + (row['original_filename'] or ''))
                if any(k in cat or k in full for k in keywords):
                    combo.set(title)
                    break
    def selected_documents(self) -> dict[str, sqlite3.Row | None]:
        output = {}
        for slot, combo in self.doc_combos.items():
            output[slot] = self.document_rows_by_title.get(combo.get())
        return output
    def open_selected_document(self):
        for combo in self.doc_combos.values():
            row = self.document_rows_by_title.get(combo.get())
            if row and row['stored_path']:
                open_path(row['stored_path'])
                return
        messagebox.showwarning("Attenzione", "Seleziona almeno un documento collegato.")
    def run_analysis(self):
        client_id = self.selected_client_id()
        if not client_id:
            messagebox.showwarning("Attenzione", "Seleziona un cliente.")
            return
        client = self.db.get_client(client_id)
        result = analyze_credit_documents(client, self.selected_documents())
        try:
            tan = float((self.tan_entry.get() or '8.20').replace(',', '.')) / 100.0
        except ValueError:
            tan = 0.082
        years = int(self.years_combo.get() or '5')
        simulation = compute_financing_simulation(result['estimated_amount'], years=years, tan=tan)
        self.current_result = result
        self.current_simulation = simulation
        self.score_var.set(f"{result['score']}/100")
        self.rating_var.set(result['rating'])
        self.risk_var.set(result['risk'])
        self.amount_var.set(format_currency(result['estimated_amount']))
        self.sim_var.set(f"{format_currency(simulation['monthly_payment'])} al mese per {years} anni")
        report_lines = [
            f"Cliente: {result['client_name']}",
            f"Giudizio sintetico: {result['rating']}",
            f"Score interno preliminare: {result['score']}/100",
            f"Semaforo rischio: {result['risk']}",
            f"Importo chirografario indicativo: {format_currency(result['estimated_amount'])}",
            "",
            "Indicatori estratti automaticamente:",
        ]
        for key, label in [("ricavi", "Ricavi"), ("ebitda", "EBITDA / MOL"), ("utile", "Utile"), ("patrimonio_netto", "Patrimonio netto"), ("debiti_banche", "Debiti verso banche"), ("accordato_cr", "Accordato CR"), ("utilizzato_cr", "Utilizzato CR"), ("sconfinamenti", "Sconfinamenti"), ("sofferenze", "Sofferenze")]:
            report_lines.append(f"- {label}: {format_currency(result['indicators'][key])}")
        report_lines.extend(["", "Valutazione sintetica:", result['summary_text'], "", "Simulazione finanziamento:", f"- TAN: {simulation['tan']*100:.2f}%", f"- TAEG stimato: {simulation['taeg']*100:.2f}%", f"- Rata indicativa: {format_currency(simulation['monthly_payment'])}", f"- Interessi complessivi: {format_currency(simulation['total_interest'])}"])
        self.report_text.delete("1.0", tk.END)
        self.report_text.insert("1.0", "\n".join(report_lines))
        sugg_lines = []
        for idx, (title, amount, note) in enumerate(result['suggestions'], start=1):
            sugg_lines.append(f"{idx}. {title}")
            sugg_lines.append(f"   Importo indicativo: {format_currency(amount)}")
            sugg_lines.append(f"   Azione consigliata: {note}")
            sugg_lines.append("")
        self.suggestions_text.delete("1.0", tk.END)
        self.suggestions_text.insert("1.0", "\n".join(sugg_lines).strip())
        self.draw_dashboard(result)

    def save_analysis(self):
        client_id = self.selected_client_id()
        if not client_id:
            messagebox.showwarning("Attenzione", "Seleziona un cliente.")
            return
        if not self.current_result or not self.current_simulation:
            messagebox.showwarning("Attenzione", "Esegui prima l'analisi.")
            return

        client = self.db.get_client(client_id)
        if not client:
            messagebox.showerror("Errore", "Cliente non trovato.")
            return

        client_folder = get_client_documents_folder(client_id)

        safe_name = sanitize_client_storage_name(client["denominazione"], f"cliente_{client_id}")
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        filename = f"{timestamp}_analisi_valutazione_{safe_name}.txt"
        file_path = client_folder / filename

        selected_docs = self.selected_documents()
        selected_lines = []
        for slot, row in selected_docs.items():
            label = self.SLOT_LABELS.get(slot, slot)
            if row:
                selected_lines.append(f"- {label}: {row['title'] or row['original_filename'] or 'Documento'} ({row['category'] or 'Senza categoria'})")
            else:
                selected_lines.append(f"- {label}: non selezionato")

        report_body = self.report_text.get("1.0", tk.END).strip()
        suggestions_body = self.suggestions_text.get("1.0", tk.END).strip()

        content = "\n".join([
            f"Analisi Valutazione Cliente - {client['denominazione']}",
            f"Data salvataggio: {datetime.now().strftime('%d/%m/%Y %H:%M:%S')}",
            "",
            "Documenti collegati:",
            *selected_lines,
            "",
            "Report analisi:",
            report_body,
            "",
            "Miglioramenti consigliati:",
            suggestions_body or "-",
            "",
            "Simulazione:",
            f"- Durata: {self.years_combo.get() or '5'} anni",
            f"- TAN: {(self.current_simulation.get('tan', 0) * 100):.2f}%",
            f"- TAEG: {(self.current_simulation.get('taeg', 0) * 100):.2f}%",
            f"- Rata indicativa: {format_currency(self.current_simulation.get('monthly_payment'))}",
            f"- Interessi totali: {format_currency(self.current_simulation.get('total_interest'))}",
            "",
            "Generato da Gestione Clienti Offline - Valutazione",
        ])

        try:
            file_path.write_text(content, encoding="utf-8")
            collaborator_id = client["responsible_collaborator_id"] if "responsible_collaborator_id" in client.keys() else None
            doc_id = self.db.add_document({
                "client_id": client_id,
                "collaborator_id": collaborator_id,
                "category": "Report",
                "title": f"Analisi valutazione {client['denominazione']}",
                "original_filename": filename,
                "stored_path": str(file_path),
                "notes": "Analisi salvata dalla finestra Valutazione",
            })
            messagebox.showinfo("Analisi salvata", f"Analisi salvata correttamente tra i documenti del cliente.\n\nID documento: {doc_id}")
        except Exception as exc:
            messagebox.showerror("Errore", f"Impossibile salvare l'analisi.\n\n{exc}")

    def draw_dashboard(self, result: dict):
        canvas = self.chart_canvas
        canvas.delete("all")
        width = int(canvas.winfo_width() or 340)
        height = int(canvas.winfo_height() or 210)
        canvas.create_text(16, 14, anchor='nw', text='Score cliente', font=('Segoe UI', 11, 'bold'), fill='#223046')
        risk_color = '#2e9f5b' if result['risk'] == 'Verde' else '#c59a00' if result['risk'] == 'Giallo' else '#c23b22'
        canvas.create_rectangle(16, 34, width - 16, 58, fill='#ebeff7', outline='#d0d7e7')
        filled = 16 + (width - 32) * (result['score'] / 100.0)
        canvas.create_rectangle(16, 34, filled, 58, fill=risk_color, outline=risk_color)
        canvas.create_text(width - 20, 46, anchor='e', text=f"{result['score']}/100", font=('Segoe UI', 10, 'bold'), fill='#223046')
        canvas.create_text(16, 72, anchor='nw', text=f"Semaforo rischio: {result['risk']}", font=('Segoe UI', 10, 'bold'), fill=risk_color)
        bars = [('EBITDA', result['indicators']['ebitda'] or 0), ('Debiti', result['indicators']['debiti_banche'] or 0), ('Patrimonio', result['indicators']['patrimonio_netto'] or 0)]
        max_val = max([v for _, v in bars] + [1])
        x0 = 26
        base_y = height - 26
        bar_w = 48
        gap = 34
        canvas.create_line(18, base_y, width - 18, base_y, fill='#aab6cc')
        for i, (label, val) in enumerate(bars):
            x = x0 + i * (bar_w + gap)
            h = 0 if max_val <= 0 else (val / max_val) * 90
            canvas.create_rectangle(x, base_y - h, x + bar_w, base_y, fill='#4d7bdc', outline='#4d7bdc')
            canvas.create_text(x + bar_w / 2, base_y + 12, text=label, font=('Segoe UI', 8), fill='#223046')
            canvas.create_text(x + bar_w / 2, base_y - h - 8, text=(format_currency(val).replace(' EUR', '') if val else '0'), font=('Segoe UI', 8), fill='#223046')
    def export_pdf(self):
        if not self.current_result or not self.current_simulation:
            messagebox.showwarning("Attenzione", "Esegui prima l'analisi della valutazione.")
            return
        if not REPORTLAB_AVAILABLE:
            messagebox.showerror("Errore", "Libreria PDF non disponibile nell'ambiente del programma.")
            return
        client_id = self.selected_client_id()
        client = self.db.get_client(client_id) if client_id else None
        if not client:
            messagebox.showerror("Errore", "Cliente non trovato.")
            return
        default_name = f"valutazione_{client['denominazione'].replace(' ', '_')}.pdf"
        path = filedialog.asksaveasfilename(title="Salva PDF valutazione", defaultextension=".pdf", initialfile=default_name, filetypes=[('PDF', '*.pdf')])
        if not path:
            return
        try:
            export_valuation_pdf(path, client, self.current_result, self.current_simulation)
            messagebox.showinfo("PDF creato", "Report PDF valutazione generato correttamente.")
            open_path(path)
        except Exception as exc:
            messagebox.showerror("Errore", f"Impossibile generare il PDF.\n\n{exc}")



def summarize_document_title(row):
    if not row:
        return ""
    return f"{row['title'] or row['original_filename'] or 'Documento'}"


def category_matches(row, accepted_categories: list[str]) -> bool:
    """Verifica categoria documento anche se caricato come Altro.
    Se la categoria non combacia, prova a riconoscerla da nome file/titolo/PDF e aggiorna il filtro.
    """
    accepted = {normalize_category(item) for item in accepted_categories}
    cat = normalize_category(row["category"] or "")
    if cat in accepted:
        return True
    try:
        title = normalize_category((row["title"] or "") + " " + (row["original_filename"] or ""))
        guessed, _reason = infer_document_category(row["stored_path"] or row["original_filename"] or title, fallback=row["category"] or "Altro")
        guessed_norm = normalize_category(guessed)
        if guessed_norm in accepted:
            return True
        # Sinonimi operativi usati nei report
        if guessed_norm == "situazione aggiornata" and normalize_category("Bilancio") in accepted:
            return True
        if guessed_norm == "bilancio" and normalize_category("Bozza Bilancio") in accepted:
            return True
    except Exception:
        pass
    return False


def pick_documents_for_categories(db, client_id: int, accepted_categories: list[str]):
    rows = db.list_documents_linked(client_id)
    return [row for row in rows if category_matches(row, accepted_categories)]


def pick_first_document_for_categories(db, client_id: int, accepted_categories: list[str]):
    rows = pick_documents_for_categories(db, client_id, accepted_categories)
    return rows[0] if rows else None


def build_professional_bilancio_report(client_row, indicators: dict, score: int, rating: str, estimated_amount: float) -> dict:
    ricavi = indicators.get("ricavi")
    ebitda = indicators.get("ebitda")
    utile = indicators.get("utile")
    patrimonio = indicators.get("patrimonio_netto")
    debiti = indicators.get("debiti_banche")
    current_score = score
    improved_score = min(100, current_score + 9)
    delta_equity = max(50000, round((debiti or 0) * 0.04 / 1000) * 1000) if debiti else 50000
    delta_debt = max(30000, round((debiti or 0) * 0.06 / 1000) * 1000) if debiti else 30000
    delta_ebitda = max(25000, round((abs(ebitda or 0) * 0.18) / 1000) * 1000) if ebitda is not None else 25000
    proforma = {
        "ricavi": ricavi,
        "ebitda": (ebitda or 0) + delta_ebitda,
        "utile": (utile or 0) + int(delta_ebitda * 0.7),
        "patrimonio_netto": (patrimonio or 0) + delta_equity,
        "debiti_banche": max(0, (debiti or 0) - delta_debt),
        "score": improved_score,
        "rating": "Migliorato" if improved_score > current_score else rating,
    }
    intro = (
        f"Il bilancio disponibile di {client_row['denominazione']} mostra un profilo economico-finanziario "
        f"con ricavi pari a {format_currency(ricavi)}, EBITDA/MOL pari a {format_currency(ebitda)}, utile netto pari a {format_currency(utile)} "
        f"e patrimonio netto pari a {format_currency(patrimonio)}. La valutazione documentale attribuisce attualmente uno score interno preliminare di {current_score}/100 con giudizio {rating}."
    )
    chapter1 = [
        "1. Analisi del bilancio e valutazione creditizia",
        intro,
        f"I debiti verso banche / debiti finanziari letti dal documento risultano pari a {format_currency(debiti)}. "
        "L'analisi evidenzia che il merito creditizio dipende soprattutto dal livello di patrimonializzazione, dalla qualità della marginalità operativa e dal grado di tensione sull'indebitamento.",
    ]
    chapter2 = [
        "2. Suggerimenti e bilancio pro-forma con nuovo rating",
        f"Si suggerisce un rafforzamento del patrimonio netto per almeno {format_currency(delta_equity)}, una riduzione dell'esposizione finanziaria per almeno {format_currency(delta_debt)} "
        f"e una normalizzazione / miglioramento del MOL per circa {format_currency(delta_ebitda)}.",
        f"Nello scenario pro-forma, il patrimonio netto salirebbe a {format_currency(proforma['patrimonio_netto'])}, i debiti si ridurrebbero a {format_currency(proforma['debiti_banche'])}, "
        f"l'EBITDA/MOL salirebbe a {format_currency(proforma['ebitda'])} e l'utile netto a {format_currency(proforma['utile'])}. Lo score interno stimato migliorerebbe a {proforma['score']}/100.",
    ]
    chapter3 = [
        "3. Analisi comparativa tra bilancio originario e bilancio pro-forma",
        f"Il confronto fra bilancio originario e pro-forma evidenzia un miglioramento della leva, una maggiore robustezza patrimoniale e una migliore sostenibilità prospettica del debito.",
        f"Originario: patrimonio netto {format_currency(patrimonio)}, debiti {format_currency(debiti)}, MOL {format_currency(ebitda)}, utile {format_currency(utile)}.",
        f"Pro-forma: patrimonio netto {format_currency(proforma['patrimonio_netto'])}, debiti {format_currency(proforma['debiti_banche'])}, MOL {format_currency(proforma['ebitda'])}, utile {format_currency(proforma['utile'])}.",
    ]
    chapter4 = [
        "4. Stima indicativa dell'importo potenzialmente accessibile come chirografario",
        f"Sulla base dei soli dati documentali, l'importo potenzialmente accessibile come chirografario è stimabile in circa {format_currency(estimated_amount)}. "
        "Tale importo resta indicativo e va confermato con verifica andamentale, Centrale Rischi, eventuali eventi pregiudizievoli e fascicolo completo cliente.",
    ]
    return {
        "title": "Report Analisi bilancio da depositare",
        "sections": [chapter1, chapter2, chapter3, chapter4],
        "proforma": proforma,
    }


def build_cr_report(client_row, indicators: dict) -> dict:
    accordato = indicators.get("accordato_cr")
    utilizzato = indicators.get("utilizzato_cr")
    sconfinamenti = indicators.get("sconfinamenti")
    sofferenze = indicators.get("sofferenze")
    utilizzo = safe_ratio(utilizzato, accordato)
    giudizio = "ordinata" if utilizzo is not None and utilizzo <= 0.75 and not sconfinamenti and not sofferenze else "da presidiare"
    sections = [
        [
            "1. Analisi CR",
            f"Per il cliente {client_row['denominazione']} la Centrale Rischi documentale evidenzia un accordato pari a {format_currency(accordato)} e un utilizzato pari a {format_currency(utilizzato)}.",
            f"L'indice di utilizzo stimato è {'-' if utilizzo is None else f'{utilizzo*100:.1f}%'} e il giudizio complessivo è {giudizio}."
        ],
        [
            "2. Valutazione descrittiva",
            f"Sconfinamenti rilevati: {format_currency(sconfinamenti)}. Sofferenze / posizioni critiche rilevate: {format_currency(sofferenze)}.",
            "Un utilizzo sostenibile, con assenza di sconfinamenti e assenza di sofferenze, rafforza la bancabilità percepita e la coerenza del profilo andamentale."
        ],
        [
            "3. Indicazioni operative",
            "Ridurre eventuali picchi di utilizzo, presidiare gli affidamenti a breve e consolidare la qualità dell'andamentale bancario prima della presentazione in istruttoria.",
            "In caso di tensioni ricorrenti, valutare conversione del breve in medio termine, maggiore patrimonializzazione o miglioramento del ciclo incassi/pagamenti."
        ],
    ]
    return {"title": "Report Analisi CR", "sections": sections}


def build_complete_report(client_row, valuation_result: dict, cr_report: dict, simulation: dict) -> dict:
    sections = [
        [
            "1. Sintesi valutazione creditizia / finanziaria",
            valuation_result.get("summary_text", ""),
            f"Score interno preliminare: {valuation_result.get('score', '-')}/100. Rating: {valuation_result.get('rating', '-')}. Importo chirografario stimato: {format_currency(valuation_result.get('estimated_amount'))}."
        ],
        cr_report["sections"][0],
        [
            "3. Simulazione finanziamento rate + interessi",
            f"Importo simulato: {format_currency(simulation['amount'])}. Durata: {simulation['years']} anni. TAN: {simulation['tan']*100:.2f}%. TAEG stimato: {simulation['taeg']*100:.2f}%.",
            f"Rata indicativa: {format_currency(simulation['monthly_payment'])}. Interessi complessivi: {format_currency(simulation['total_interest'])}. Spese stimate: {format_currency(simulation['fees'])}."
        ],
        [
            "4. Fascicolo completo cliente e raccomandazioni",
            "Il report completo unisce documenti economico-finanziari, report CR e valutazione creditizia preliminare in un fascicolo unico di presentazione, in stile bancario.",
            "Si raccomanda di allegare bilancio, bozza bilancio, CR, report, documentazione societaria, commento gestionale e simulazione finanziamento."
        ],
    ]
    return {"title": "Report Completo", "sections": sections}


def export_simple_sections_pdf(output_path: str, title: str, client_row, sections: list[list[str]]) -> None:
    if not REPORTLAB_AVAILABLE:
        raise RuntimeError("ReportLab non disponibile: impossibile generare il PDF.")
    styles = getSampleStyleSheet()
    title_style = ParagraphStyle("RepTitle", parent=styles["Heading1"], fontName="Helvetica-Bold", fontSize=18, leading=22, textColor=colors.HexColor("#1f4ea8"), spaceAfter=10)
    h2 = ParagraphStyle("RepH2", parent=styles["Heading2"], fontName="Helvetica-Bold", fontSize=12, leading=15, textColor=colors.HexColor("#1f4ea8"), spaceBefore=8, spaceAfter=4)
    body = ParagraphStyle("RepBody", parent=styles["BodyText"], fontName="Helvetica", fontSize=9.5, leading=13, spaceAfter=6)
    doc = SimpleDocTemplate(output_path, pagesize=A4, leftMargin=1.6*cm, rightMargin=1.6*cm, topMargin=2.8*cm, bottomMargin=1.4*cm)
    story = [Paragraph(title, title_style)]
    if client_row:
        story.append(Paragraph(f"Cliente: <b>{client_row['denominazione']}</b>", body))
    for section in sections:
        if not section:
            continue
        story.append(Paragraph(section[0], h2))
        for paragraph in section[1:]:
            story.append(Paragraph(str(paragraph).replace("\n", "<br/>"), body))
        story.append(Spacer(1, 6))
    def add_page(canvas, _doc):
        draw_pdf_branding(canvas, title)
        canvas.saveState()
        canvas.setFont('Helvetica', 8)
        canvas.setFillColor(colors.HexColor('#6b778c'))
        canvas.drawRightString(A4[0] - 1.6*cm, 1.0*cm, f"Pagina {canvas.getPageNumber()}")
        canvas.restoreState()
    doc.build(story, onFirstPage=add_page, onLaterPages=add_page)




# === Motore creditizio integrato ===
@dataclass
class IntegratedCompanyData:
    denominazione: str = ""
    codice_fiscale: str = ""
    partita_iva: str = ""
    cod_cciaa: str = ""
    sede_legale: str = ""
    forma_giuridica: str = ""
    stato_attivita: str = ""
    data_costituzione: str = ""
    attivita: str = ""
    pec: str = ""
    amministratore: str = ""
    principali_soci: str = ""
    gruppo: str = ""
    numero_dipendenti: float | None = None
    fatturato: float | None = None
    trend_fatturato_pct: float | None = None
    mol: float | None = None
    utile: float | None = None
    cash_flow: float | None = None
    indice_indebitamento: float | None = None
    fido_consigliato: float | None = None
    current_ratio_pct: float | None = None
    roe_pct: float | None = None


@dataclass
class IntegratedCreditOutcome:
    score: int
    classe: str
    semaforo: str
    ebitda_margin_pct: float | None
    dscr: float | None
    importo_teorico: float | None
    importo_prudenziale_min: float | None
    importo_prudenziale_max: float | None
    giudizio: str
    punti_forza: list[str]
    criticita: list[str]
    raccomandazioni: list[str]


def extract_company_data_from_integrated_report(pdf_path: str | Path) -> IntegratedCompanyData:
    text = read_pdf_text(str(pdf_path))
    data = IntegratedCompanyData()
    data.denominazione = _clean_spaces(_first_match([
        r'Denominazione:\s*(.+?)\nCod\. fiscale',
        r'Data evasione:\s*\d{2}/\d{2}/\d{4}\s+(.+?)\s+C\.F\.',
    ], text, flags=re.IGNORECASE | re.DOTALL))
    data.codice_fiscale = _clean_spaces(_first_match([r'Cod\. fiscale:\s*([A-Z0-9]+)', r'C\.F\.\s*([A-Z0-9]+)'], text))
    data.partita_iva = _clean_spaces(_first_match([r'Partita IVA:\s*([A-Z0-9]+)', r'P\.Iva\s*([A-Z0-9]+)'], text))
    data.cod_cciaa = _clean_spaces(_first_match([r'Cod\. CCIAA\s*([A-Z0-9/]+)', r'Cod\.CCIAA\s*([A-Z0-9/]+)'], text))
    data.sede_legale = _clean_spaces(_first_match([
        r'Sede:\s*([^\n]+(?:\n[^\n]+)?)',
        r'Sede Legale\s+([^\n]+(?:\n[^\n]+)?)',
    ], text, flags=re.IGNORECASE))
    data.sede_legale = data.sede_legale.replace('\n', ' ')
    data.forma_giuridica = _clean_spaces(_first_match([r'Forma giuridica:\s*(.+?)\nStato attività'], text))
    data.stato_attivita = _clean_spaces(_first_match([r'Stato attività:\s*(.+?)\nData costituzione', r'STATO ATTIVITÀ\s+([A-Z]+)'], text))
    data.data_costituzione = _clean_spaces(_first_match([r'Data costituzione:\s*([0-9/]+)', r'DATA COSTITUZIONE\s*([0-9/]+)'], text))
    data.attivita = _clean_spaces(_first_match([
        r"Attività svolta normalizzata:\s*(.+?)\nQuesta informazione",
        r"CODICE ATECO\s+(.+?)\s+STATO ATTIVITÀ",
    ], text, flags=re.IGNORECASE | re.DOTALL))
    data.pec = _clean_spaces(_first_match([r'PEC:\s*([^\s\n]+)'], text))
    data.amministratore = _clean_spaces(_first_match([
        r'([A-ZÀ-ÖØ-Ý\' ]+)\s+[A-Z0-9]{16}\s+AMMINISTRATORE\s+UNICO',
        r'Esponenti Cariche\s+([A-ZÀ-ÖØ-Ý\' ]+)\s+Cod\. Fiscale',
    ], text, flags=re.IGNORECASE | re.DOTALL))
    data.principali_soci = _clean_spaces(_first_match([r'Principali soci\s+(.+?)\n', r'Principali soci a capo del gruppo\s+(.+?)\n'], text))
    data.gruppo = _clean_spaces(_first_match([r'Gruppo\s+(.+?)\n'], text))
    data.numero_dipendenti = extract_first_amount([r'Numero di dipendenti:\s*([0-9.,]+)', r'DIPENDENTI\s*([0-9.,]+)'], text)
    data.fatturato = extract_first_amount([r'FATTURATO\s*([0-9\.,]+)\s*€', r'Ricavi\s*([0-9\.,]+)\s*\+'], text)
    data.trend_fatturato_pct = extract_first_amount([r'TREND FATTURATO\s*\+\s*([0-9\.,]+)\s*%', r'Ricavi\s*[0-9\.,]+\s*\+([0-9\.,]+)'], text)
    data.mol = extract_first_amount([r'MOL\s*([0-9\.,]+)\s*€', r'=Margine operativo lordo\s*([0-9\.,]+)'], text)
    data.utile = extract_first_amount([r'UTILE/PERDITA\s*([0-9\.,]+)\s*€', r'=Utile/perdita d\'esercizio\s*([0-9\.,]+)'], text)
    data.cash_flow = extract_first_amount([r'CASH FLOW\s*([0-9\.,]+)\s*€', r'Cash-flow\s*([0-9\.,]+)'], text)
    data.indice_indebitamento = extract_first_amount([r'INDICE INDEBITAMENTO\s*([0-9\.,]+)', r'Indice indebitamento\s*([0-9\.,]+)'], text)
    data.fido_consigliato = extract_first_amount([r'Valore Fido Medio Accordabile\s*€\s*([0-9\.,]+)'], text)
    data.current_ratio_pct = extract_first_amount([r'Current ratio \(%\)\s*([0-9\.,]+)'], text)
    data.roe_pct = extract_first_amount([r'R\.O\.E\. \(%\)\s*([0-9\.,]+)', r'ROE\s.*?2024\s*([0-9\.,]+)%'], text)
    return data


def compute_integrated_credit_outcome(data: IntegratedCompanyData, requested_amount: float | None = None, years: int = 5, tan_pct: float = 8.5) -> IntegratedCreditOutcome:
    points = 0
    strengths: list[str] = []
    risks: list[str] = []
    recommendations: list[str] = []
    ebitda_margin_pct = (data.mol / data.fatturato * 100) if data.fatturato and data.mol else None
    if data.mol and data.mol > 0:
        points += 2
        strengths.append('MOL positivo.')
    else:
        risks.append('MOL assente o negativo.')
    if data.utile and data.utile > 0:
        points += 2
        strengths.append('Utile positivo.')
    else:
        risks.append('Utile assente o negativo.')
    if ebitda_margin_pct is not None:
        if ebitda_margin_pct >= 8:
            points += 2
            strengths.append(f'Marginalità EBITDA buona ({ebitda_margin_pct:.1f}%).')
        elif ebitda_margin_pct >= 5:
            points += 1
        else:
            risks.append(f'Marginalità EBITDA bassa ({ebitda_margin_pct:.1f}%).')
    if data.indice_indebitamento is not None:
        if data.indice_indebitamento < 1:
            points += 2
            strengths.append('Indebitamento sotto controllo.')
        elif data.indice_indebitamento < 2:
            points += 1
        else:
            risks.append('Indebitamento elevato.')
    if data.cash_flow and data.cash_flow > 0:
        points += 1
        strengths.append('Cash flow positivo.')
    else:
        risks.append('Cash flow debole o assente.')
    if data.current_ratio_pct is not None:
        if data.current_ratio_pct >= 120:
            points += 1
            strengths.append('Liquidità corrente soddisfacente.')
        else:
            risks.append('Liquidità corrente da presidiare.')
    if points >= 8:
        classe = 'A'
        semaforo = '🟢'
        giudizio = 'Profilo creditizio buono su base documentale.'
    elif points >= 5:
        classe = 'B'
        semaforo = '🟡'
        giudizio = 'Profilo creditizio medio con elementi da approfondire.'
    else:
        classe = 'C'
        semaforo = '🔴'
        giudizio = 'Profilo creditizio debole o incompleto su base documentale.'
    importo_teorico = None
    if data.cash_flow and data.cash_flow > 0:
        importo_teorico = data.cash_flow * 4
    if requested_amount and requested_amount > 0:
        importo_teorico = max(importo_teorico or 0, requested_amount)
    prud_min = importo_teorico * 0.35 if importo_teorico else None
    prud_max = importo_teorico * 0.55 if importo_teorico else None
    dscr = None
    if data.cash_flow and requested_amount and requested_amount > 0:
        monthly_rate = (tan_pct / 100.0) / 12.0
        months = max(12, years * 12)
        if monthly_rate > 0:
            rata = requested_amount * (monthly_rate / (1 - (1 + monthly_rate) ** (-months)))
        else:
            rata = requested_amount / months
        annual_debt_service = rata * 12
        if annual_debt_service > 0:
            dscr = data.cash_flow / annual_debt_service
    if data.indice_indebitamento is not None and data.indice_indebitamento > 1:
        recommendations.append('Ridurre la leva finanziaria e consolidare il passivo a breve.')
    if ebitda_margin_pct is not None and ebitda_margin_pct < 8:
        recommendations.append('Incrementare marginalità e qualità del MOL.')
    if data.cash_flow and data.cash_flow < 100000:
        recommendations.append('Rafforzare la generazione di cassa a supporto del debito.')
    if not recommendations:
        recommendations.append('Mantenere l equilibrio economico-finanziario e presidiare il modulo andamentale.')
    return IntegratedCreditOutcome(points, classe, semaforo, ebitda_margin_pct, dscr, importo_teorico, prud_min, prud_max, giudizio, strengths, risks, recommendations)


class ReportBaseWindow(BaseWindow):
    def __init__(self, master, db: Database, title: str, accepted_categories: list[str], preselected_client_id: int | None = None):
        super().__init__(master, title, "1220x820")
        self.db = db
        self.accepted_categories = accepted_categories
        self.preselected_client_id = preselected_client_id
        self.client_ids_by_name: dict[str, int] = {}
        self.document_rows_by_title: dict[str, sqlite3.Row] = {}
        self.current_sections: list[list[str]] = []
        self.current_pdf_title = title

        top = ttk.Frame(self.content_frame, padding=16)
        top.pack(fill="x")
        ttk.Label(top, text="Cliente:").pack(side="left")
        self.client_combo = ttk.Combobox(top, width=38, state="readonly")
        self.client_combo.pack(side="left", padx=(8, 12))
        self.client_combo.bind("<<ComboboxSelected>>", lambda _e: self.refresh_documents())
        ttk.Label(top, text="Documento:").pack(side="left")
        self.doc_combo = ttk.Combobox(top, width=54, state="readonly")
        self.doc_combo.pack(side="left", padx=(8, 0), fill="x", expand=True)

        buttons = ttk.Frame(self.content_frame, padding=(16, 0, 16, 8))
        buttons.pack(fill="x")
        ttk.Button(buttons, text="Esporta PDF valutazione", command=self.export_pdf).pack(side="right")
        ttk.Button(buttons, text="Salva analisi", command=self.save_analysis).pack(side="right", padx=(0, 8))
        ttk.Button(buttons, text="Apri documento", command=self.open_selected_document).pack(side="right", padx=(0, 8))
        ttk.Button(buttons, text="Esegui analisi", command=self.run_analysis).pack(side="right", padx=(0, 8))
        ttk.Button(buttons, text="Inserisci documento", command=self.add_document).pack(side="right", padx=(0, 8))

        info = ttk.Label(self.content_frame, text="I documenti vengono recuperati automaticamente da Gestione Documenti per il cliente selezionato, anche se caricati da altre finestre collegate.", foreground=MUTED_TEXT, wraplength=980, justify="left")
        info.pack(fill="x", padx=16, pady=(0, 8))

        body = ttk.Frame(self.content_frame, padding=(16, 0, 16, 16))
        body.pack(fill="both", expand=True)
        body.columnconfigure(0, weight=3)
        body.columnconfigure(1, weight=2)
        body.rowconfigure(0, weight=1)

        left_shell = ttk.Frame(body)
        left_shell.grid(row=0, column=0, sticky="nsew", padx=(0, 10))
        left_shell.columnconfigure(0, weight=1)
        left_shell.rowconfigure(0, weight=3)
        left_shell.rowconfigure(1, weight=2)

        left = ttk.LabelFrame(left_shell, text="Report", padding=10)
        left.grid(row=0, column=0, sticky="nsew", pady=(0, 10))
        left.rowconfigure(0, weight=1)
        left.columnconfigure(0, weight=1)
        self.report_text = ScrolledText(left, wrap="word", font=("Segoe UI", 10))
        self.report_text.grid(row=0, column=0, sticky="nsew")

        docs_box = ttk.LabelFrame(left_shell, text="Documenti caricati", padding=10)
        docs_box.grid(row=1, column=0, sticky="nsew")
        docs_box.rowconfigure(0, weight=1)
        docs_box.columnconfigure(0, weight=1)
        self.docs_tree, self.docs_tree_holder = create_treeview_with_scrollbars(docs_box, ("titolo", "file", "data"), show="headings", height=7)
        self.docs_tree.heading("titolo", text="Titolo")
        self.docs_tree.heading("file", text="File")
        self.docs_tree.heading("data", text="Data")
        self.docs_tree.column("titolo", width=260)
        self.docs_tree.column("file", width=220)
        self.docs_tree.column("data", width=110, anchor="center")
        self.docs_tree.grid(row=0, column=0, sticky="nsew")
        docs_scroll = ttk.Scrollbar(docs_box, orient="vertical", command=self.docs_tree.yview, style="Visible.Vertical.TScrollbar")
        docs_scroll.grid(row=0, column=1, sticky="ns")
        self.docs_tree.configure(yscrollcommand=docs_scroll.set)
        self.docs_tree.bind("<<TreeviewSelect>>", self._on_docs_tree_select)
        self.docs_tree.bind("<Double-1>", lambda _e: self.open_selected_document())

        right = ttk.LabelFrame(body, text="Dashboard grafica", padding=10)
        right.grid(row=0, column=1, sticky="nsew")
        self.chart_canvas = tk.Canvas(right, width=360, height=260, bg="white", highlightthickness=1, highlightbackground="#d7deeb")
        self.chart_canvas.pack(fill="both", expand=True)

        self.refresh_clients()

    def refresh_clients(self):
        clients = self.db.list_clients()
        self.client_ids_by_name = {f"{row['denominazione']} (ID {row['id']})": row['id'] for row in clients}
        self.client_combo["values"] = list(self.client_ids_by_name.keys())
        if self.preselected_client_id is not None:
            for name, cid in self.client_ids_by_name.items():
                if cid == self.preselected_client_id:
                    self.client_combo.set(name)
                    break
        elif clients:
            self.client_combo.set(next(iter(self.client_ids_by_name.keys())))
        self.refresh_documents()

    def selected_client_id(self) -> int | None:
        return self.client_ids_by_name.get(self.client_combo.get())

    def refresh_documents(self):
        client_id = self.selected_client_id()
        rows = pick_documents_for_categories(self.db, client_id, self.accepted_categories) if client_id else []
        self.document_rows_by_title = {summarize_document_title(row): row for row in rows}
        self.doc_combo["values"] = [""] + list(self.document_rows_by_title.keys())
        if rows:
            self.doc_combo.set(summarize_document_title(rows[0]))
        else:
            self.doc_combo.set("")

        for item in self.docs_tree.get_children():
            self.docs_tree.delete(item)
        all_rows = self.db.list_documents_linked(client_id) if client_id else []
        for row in all_rows:
            self.docs_tree.insert(
                "",
                "end",
                iid=str(row["id"]),
                values=(
                    row["title"] or "",
                    row["original_filename"] or "",
                    (row["uploaded_at"] or "")[:10],
                ),
            )

    def _on_docs_tree_select(self, _event=None):
        selection = self.docs_tree.selection()
        if not selection:
            return
        row = self.db.get_document(int(selection[0]))
        if not row:
            return
        title = summarize_document_title(row)
        if title in self.document_rows_by_title:
            self.doc_combo.set(title)

    def selected_document(self):
        row = self.document_rows_by_title.get(self.doc_combo.get())
        if row:
            return row
        selection = self.docs_tree.selection()
        if selection:
            return self.db.get_document(int(selection[0]))
        return None

    def add_document(self):
        client_id = self.selected_client_id()
        if not client_id:
            messagebox.showwarning("Attenzione", "Seleziona un cliente.")
            return
        DocumentFormDialog(self, self.db, client_id, on_saved=self.refresh_documents)

    def open_selected_document(self):
        row = self.selected_document()
        if not row or not row["stored_path"]:
            messagebox.showwarning("Attenzione", "Seleziona un documento.")
            return
        open_path(row["stored_path"])

    def set_report(self, sections: list[list[str]], pdf_title: str):
        self.current_sections = sections
        self.current_pdf_title = pdf_title
        flat = []
        for section in sections:
            flat.append(section[0])
            flat.extend(section[1:])
            flat.append("")
        self.report_text.delete("1.0", tk.END)
        self.report_text.insert("1.0", "\n".join(flat).strip())

    def export_pdf(self):
        if not self.current_sections:
            messagebox.showwarning("Attenzione", "Esegui prima l'analisi.")
            return
        client_id = self.selected_client_id()
        client = self.db.get_client(client_id) if client_id else None
        default_name = f"{normalize_category(self.current_pdf_title).replace(' ', '_')}.pdf"
        path = filedialog.asksaveasfilename(title="Salva report PDF", defaultextension=".pdf", initialfile=default_name, filetypes=[('PDF', '*.pdf')])
        if not path:
            return
        try:
            export_simple_sections_pdf(path, self.current_pdf_title, client, self.current_sections)
            open_path(path)
        except Exception as exc:
            messagebox.showerror("Errore", f"Impossibile esportare il PDF.\n\n{exc}")

    def _save_analysis_category(self) -> str:
        title_norm = normalize_category(self.current_pdf_title)
        if 'bplan' in title_norm or 'business plan' in title_norm:
            return 'BPlan'
        return 'Report'

    def save_analysis(self):
        client_id = self.selected_client_id()
        if not client_id:
            messagebox.showwarning("Attenzione", "Seleziona un cliente.")
            return
        if not self.current_sections:
            messagebox.showwarning("Attenzione", "Esegui prima l'analisi.")
            return

        client = self.db.get_client(client_id)
        if not client:
            messagebox.showerror("Errore", "Cliente non trovato.")
            return

        client_folder = get_client_documents_folder(client_id)

        safe_client = sanitize_client_storage_name(client['denominazione'], f'cliente_{client_id}')
        safe_title = re.sub(r'[^A-Za-z0-9_-]+', '_', (self.current_pdf_title or 'analisi')).strip('_') or 'analisi'
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        filename = f'{timestamp}_{safe_title}_{safe_client}.txt'
        file_path = client_folder / filename

        selected_row = self.selected_document()
        selected_doc_line = '- Nessun documento selezionato'
        if selected_row:
            selected_doc_line = f"- {selected_row['title'] or selected_row['original_filename'] or 'Documento'}"

        linked_docs = []
        for item in self.docs_tree.get_children():
            vals = self.docs_tree.item(item, 'values')
            if vals:
                linked_docs.append(f"- {vals[0] or vals[1] or 'Documento'} | {vals[2] or ''}")

        body = self.report_text.get('1.0', tk.END).strip()
        sections_dump = []
        for section in self.current_sections:
            if not section:
                continue
            sections_dump.append(section[0])
            sections_dump.extend(str(x) for x in section[1:])
            sections_dump.append('')

        content = '\n'.join([
            f"Analisi salvata - {self.current_pdf_title}",
            f"Cliente: {client['denominazione']}",
            f"Data salvataggio: {datetime.now().strftime('%d/%m/%Y %H:%M:%S')}",
            '',
            'Documento principale selezionato:',
            selected_doc_line,
            '',
            'Documenti collegati visibili nella finestra:',
            *(linked_docs or ['- Nessun documento collegato']),
            '',
            'Testo analisi:',
            body or '\n'.join(sections_dump).strip() or '-',
            '',
            'Sezioni strutturate:',
            '\n'.join(sections_dump).strip() or '-',
            '',
            'Generato da Gestione Clienti Offline - Finestra Report',
        ])

        try:
            file_path.write_text(content, encoding='utf-8')
            collaborator_id = client['responsible_collaborator_id'] if 'responsible_collaborator_id' in client.keys() else None
            doc_id = self.db.add_document({
                'client_id': client_id,
                'collaborator_id': collaborator_id,
                'category': self._save_analysis_category(),
                'title': f"{self.current_pdf_title} - {client['denominazione']}",
                'original_filename': filename,
                'stored_path': str(file_path),
                'notes': f"Analisi salvata dalla finestra {self.current_pdf_title}",
            })
            messagebox.showinfo('Analisi salvata', f"Analisi salvata correttamente tra i documenti del cliente.\n\nID documento: {doc_id}")
            self.refresh_documents()
        except Exception as exc:
            messagebox.showerror('Errore', f"Impossibile salvare l'analisi.\n\n{exc}")

    def run_analysis(self):
        raise NotImplementedError


class MotoreCreditizioWindow(ReportBaseWindow):
    def __init__(self, master, db: Database, preselected_client_id: int | None = None):
        super().__init__(master, db, 'Merito Creditizio', ['Report', 'Bilancio', 'Bozza Bilancio', 'Centrale Rischi'], preselected_client_id)
        self.requested_amount_var = tk.StringVar(value='150000')
        self.years_var = tk.StringVar(value='5')
        self.tan_var = tk.StringVar(value='8.50')
        controls = ttk.LabelFrame(self.content_frame, text='Parametri di simulazione', padding=10)
        body = self.content_frame.winfo_children()[2]
        controls.pack(fill='x', padx=16, pady=(0, 10), before=body)
        ttk.Label(controls, text='Importo richiesto:').pack(side='left')
        ttk.Entry(controls, textvariable=self.requested_amount_var, width=12).pack(side='left', padx=(8, 18))
        ttk.Label(controls, text='Durata anni:').pack(side='left')
        ttk.Combobox(controls, textvariable=self.years_var, values=['3', '4', '5', '6', '7'], state='readonly', width=8).pack(side='left', padx=(8, 18))
        ttk.Label(controls, text='TAN %:').pack(side='left')
        ttk.Entry(controls, textvariable=self.tan_var, width=8).pack(side='left', padx=(8, 0))

    def _float_from_var(self, var: tk.StringVar, default: float) -> float:
        try:
            return float((var.get() or '').replace('.', '').replace(',', '.') if ',' in (var.get() or '') and '.' in (var.get() or '') else (var.get() or '').replace(',', '.'))
        except Exception:
            return default

    def run_analysis(self):
        client_id = self.selected_client_id()
        row = self.selected_document()
        if not client_id or not row:
            messagebox.showwarning('Attenzione', 'Seleziona cliente e documento.')
            return
        path = row['stored_path'] or ''
        if not path:
            messagebox.showwarning('Attenzione', 'Il documento selezionato non ha un file collegato.')
            return
        client = self.db.get_client(client_id)
        requested_amount = self._float_from_var(self.requested_amount_var, 150000.0)
        years = int(self.years_var.get() or '5')
        tan = self._float_from_var(self.tan_var, 8.5)
        data = extract_company_data_from_integrated_report(path)
        if not data.denominazione:
            data.denominazione = client['denominazione'] if client else ''
        outcome = compute_integrated_credit_outcome(data, requested_amount=requested_amount, years=years, tan_pct=tan)
        sections = [
            ['1. Anagrafica e dati principali',
             f"Denominazione: {data.denominazione or '-'}",
             f"CF / P.IVA: {data.codice_fiscale or '-'} / {data.partita_iva or '-'}",
             f"Sede legale: {data.sede_legale or '-'}",
             f"Forma giuridica: {data.forma_giuridica or '-'}",
             f"Attività: {data.attivita or '-'}"],
            ['2. Indicatori economico-finanziari',
             f"Fatturato: {format_currency(data.fatturato)}",
             f"MOL / EBITDA: {format_currency(data.mol)}",
             f"Utile: {format_currency(data.utile)}",
             f"Cash flow: {format_currency(data.cash_flow)}",
             f"Indice indebitamento: {data.indice_indebitamento if data.indice_indebitamento is not None else '-'}",
             f"Current ratio %: {data.current_ratio_pct if data.current_ratio_pct is not None else '-'}",
             f"ROE %: {data.roe_pct if data.roe_pct is not None else '-'}"],
            ['3. Esito merito creditizio',
             f"Score interno: {outcome.score}/10",
             f"Classe: {outcome.classe}",
             f"Semaforo: {outcome.semaforo}",
             f"EBITDA margin: {format_pct(outcome.ebitda_margin_pct)}",
             f"DSCR simulato: {'-' if outcome.dscr is None else f'{outcome.dscr:.2f}x'}",
             outcome.giudizio],
            ['4. Capacità di accesso al credito',
             f"Importo teorico: {format_currency(outcome.importo_teorico)}",
             f"Range prudenziale: {format_currency(outcome.importo_prudenziale_min)} - {format_currency(outcome.importo_prudenziale_max)}",
             f"Fido commerciale dal report: {format_currency(data.fido_consigliato)}"],
            ['5. Punti di forza, criticità e raccomandazioni',
             'Punti di forza: ' + ('; '.join(outcome.punti_forza) if outcome.punti_forza else '-'),
             'Criticità: ' + ('; '.join(outcome.criticita) if outcome.criticita else '-'),
             'Raccomandazioni: ' + ('; '.join(outcome.raccomandazioni) if outcome.raccomandazioni else '-')],
        ]
        self.set_report(sections, f"Merito Creditizio - {data.denominazione or (client['denominazione'] if client else 'Cliente')}")
        self._draw_credit_chart(data, outcome)

    def _draw_credit_chart(self, data: IntegratedCompanyData, outcome: IntegratedCreditOutcome):
        c = self.chart_canvas
        c.delete('all')
        width = int(c.winfo_width() or 360)
        height = int(c.winfo_height() or 260)
        c.create_text(16, 16, anchor='nw', text='Motore creditizio', font=('Segoe UI', 11, 'bold'), fill='#223046')
        c.create_text(16, 36, anchor='nw', text=f'Score: {outcome.score}/10 {outcome.semaforo}', font=('Segoe UI', 10, 'bold'), fill='#223046')
        vals = [('Ricavi', data.fatturato or 0), ('MOL', data.mol or 0), ('Utile', data.utile or 0), ('Cash', data.cash_flow or 0)]
        max_val = max([abs(v) for _, v in vals] + [1])
        base_y = height - 32
        x = 22
        for label, value in vals:
            bar_h = (abs(value) / max_val) * 120
            c.create_rectangle(x, base_y - bar_h, x + 42, base_y, fill='#4d7bdc', outline='#4d7bdc')
            c.create_text(x + 21, base_y + 12, text=label, font=('Segoe UI', 8), fill='#223046')
            c.create_text(x + 21, base_y - bar_h - 8, text=(format_currency(value).replace(' EUR', '') if value else '0'), font=('Segoe UI', 8), fill='#223046')
            x += 78
        risk_color = '#2e9f5b' if outcome.semaforo == '🟢' else '#c59a00' if outcome.semaforo == '🟡' else '#c23b22'
        c.create_rectangle(width - 130, 28, width - 24, 56, fill='#ebeff7', outline='#d0d7e7')
        c.create_rectangle(width - 130, 28, width - 130 + (106 * min(1.0, outcome.score / 10.0)), 56, fill=risk_color, outline=risk_color)
        c.create_text(width - 77, 42, text=outcome.classe, font=('Segoe UI', 11, 'bold'), fill='#223046')

class ReportBilancioWindow(ReportBaseWindow):
    def __init__(self, master, db: Database, preselected_client_id: int | None = None):
        super().__init__(master, db, "Analisi bilancio da depositare", ["Bilancio", "Bozza Bilancio"], preselected_client_id)

    def run_analysis(self):
        client_id = self.selected_client_id()
        row = self.selected_document()
        if not client_id or not row:
            messagebox.showwarning("Attenzione", "Seleziona cliente e documento di bilancio.")
            return
        client = self.db.get_client(client_id)
        text = text_from_supported_file(row["stored_path"] or "")
        indicators = {
            "ricavi": extract_first_amount([r"ricavi[^0-9-]{0,30}([0-9\.,-]+)", r"fatturato[^0-9-]{0,30}([0-9\.,-]+)"], text),
            "ebitda": extract_first_amount([r"ebitda[^0-9-]{0,30}([0-9\.,-]+)", r"mol[^0-9-]{0,30}([0-9\.,-]+)", r"margine operativo lordo[^0-9-]{0,30}([0-9\.,-]+)"], text),
            "utile": extract_first_amount([r"utile[^0-9-]{0,30}([0-9\.,-]+)", r"risultato d['’]?esercizio[^0-9-]{0,30}([0-9\.,-]+)"], text),
            "patrimonio_netto": extract_first_amount([r"patrimonio netto[^0-9-]{0,30}([0-9\.,-]+)"], text),
            "debiti_banche": extract_first_amount([r"debiti verso banche[^0-9-]{0,30}([0-9\.,-]+)", r"totale debiti[^0-9-]{0,30}([0-9\.,-]+)"], text),
        }
        score = 65
        if indicators["patrimonio_netto"] and indicators["patrimonio_netto"] > 0:
            score += 8
        if indicators["utile"] and indicators["utile"] > 0:
            score += 8
        if indicators["debiti_banche"] and indicators["patrimonio_netto"] and indicators["debiti_banche"] > indicators["patrimonio_netto"] * 4:
            score -= 6
        score = max(1, min(100, score))
        rating = "buono" if score >= 70 else "medio"
        est = max(50000.0, ((indicators["ebitda"] or indicators["utile"] or 0) * 0.8))
        report = build_professional_bilancio_report(client, indicators, score, rating, est)
        self.set_report(report["sections"], report["title"])
        self.draw_chart(indicators, report["proforma"])

    def draw_chart(self, indicators: dict, proforma: dict):
        c = self.chart_canvas
        c.delete("all")
        width = int(c.winfo_width() or 360)
        height = int(c.winfo_height() or 260)
        c.create_text(16, 16, anchor="nw", text="Orig. vs Pro-forma", font=("Segoe UI", 11, "bold"), fill="#223046")
        items = [
            ("PN", indicators.get("patrimonio_netto") or 0, proforma.get("patrimonio_netto") or 0),
            ("Debiti", indicators.get("debiti_banche") or 0, proforma.get("debiti_banche") or 0),
            ("MOL", indicators.get("ebitda") or 0, proforma.get("ebitda") or 0),
            ("Utile", indicators.get("utile") or 0, proforma.get("utile") or 0),
        ]
        max_val = max([abs(v1) for _, v1, _ in items] + [abs(v2) for _, _, v2 in items] + [1])
        base_y = height - 30
        x = 26
        for label, v1, v2 in items:
            h1 = (abs(v1) / max_val) * 140
            h2 = (abs(v2) / max_val) * 140
            c.create_rectangle(x, base_y - h1, x + 24, base_y, fill="#4d7bdc", outline="#4d7bdc")
            c.create_rectangle(x + 30, base_y - h2, x + 54, base_y, fill="#1f8f5f", outline="#1f8f5f")
            c.create_text(x + 27, base_y + 12, text=label, font=("Segoe UI", 8))
            x += 78


class ReportCRWindow(ReportBaseWindow):
    def __init__(self, master, db: Database, preselected_client_id: int | None = None):
        super().__init__(master, db, "Analisi CR", ["Centrale Rischi"], preselected_client_id)

    def run_analysis(self):
        client_id = self.selected_client_id()
        row = self.selected_document()
        if not client_id or not row:
            messagebox.showwarning("Attenzione", "Seleziona cliente e documento CR.")
            return
        client = self.db.get_client(client_id)
        text = text_from_supported_file(row["stored_path"] or "")
        indicators = {
            "accordato_cr": extract_first_amount([r"accordato[^0-9-]{0,30}([0-9\.,-]+)", r"totale accordato[^0-9-]{0,30}([0-9\.,-]+)"], text),
            "utilizzato_cr": extract_first_amount([r"utilizzato[^0-9-]{0,30}([0-9\.,-]+)", r"totale utilizzato[^0-9-]{0,30}([0-9\.,-]+)"], text),
            "sconfinamenti": extract_first_amount([r"sconfinament[oi][^0-9-]{0,30}([0-9\.,-]+)"], text),
            "sofferenze": extract_first_amount([r"sofferenz[ea][^0-9-]{0,30}([0-9\.,-]+)"], text),
        }
        report = build_cr_report(client, indicators)
        self.set_report(report["sections"], report["title"])
        self.draw_chart(indicators)

    def draw_chart(self, indicators: dict):
        c = self.chart_canvas
        c.delete("all")
        c.create_text(16, 16, anchor="nw", text="CR - indicatori principali", font=("Segoe UI", 11, "bold"), fill="#223046")
        items = [
            ("Acc.", indicators.get("accordato_cr") or 0),
            ("Util.", indicators.get("utilizzato_cr") or 0),
            ("Sconf.", indicators.get("sconfinamenti") or 0),
            ("Soff.", indicators.get("sofferenze") or 0),
        ]
        max_val = max([v for _, v in items] + [1])
        base_y = 220
        x = 26
