# ============================================================
# MODULO NEUTRO - CALCOLO RATA MENSILE DA CENTRALE RISCHI
# - nessun dato cliente hardcoded
# - legge PDF/Documenti CR collegati al cliente
# - genera report PDF e lo salva in Gestione Documenti
# ============================================================

TILE_ICONS.setdefault("CALCOLO RATA CR", "CR")
_CRM_NUM_RE = r"[-+]?\d{1,3}(?:\.\d{3})+(?:,\d+)?|[-+]?\d+(?:,\d+)?"
_CRM_MONTHS_IT = globals().get("_CR36_MONTHS_IT", {
    "gennaio": 1, "febbraio": 2, "marzo": 3, "aprile": 4,
    "maggio": 5, "giugno": 6, "luglio": 7, "agosto": 8,
    "settembre": 9, "ottobre": 10, "novembre": 11, "dicembre": 12,
    "genn": 1, "feb": 2, "mar": 3, "apr": 4, "mag": 5,
    "giu": 6, "lug": 7, "ago": 8, "set": 9, "ott": 10,
    "nov": 11, "dic": 12,
})


def _crm_read_text(path: str, max_chars: int = 250000) -> str:
    """Lettura neutra del documento CR. Riusa i reader gia presenti nell'app."""
    reader = globals().get("_cr36_read_text")
    if callable(reader):
        try:
            return str(reader(path, max_chars=max_chars) or "")[:max_chars]
        except TypeError:
            try:
                return str(reader(path) or "")[:max_chars]
            except Exception:
                pass
        except Exception:
            pass
    for reader_name in ("_sp_read_any_document_text", "safe_read_document_text", "text_from_supported_file"):
        reader = globals().get(reader_name)
        if callable(reader):
            try:
                txt = reader(path)
                if txt and str(txt).strip():
                    return str(txt)[:max_chars]
            except Exception:
                pass
    try:
        return Path(path).read_text(encoding="utf-8", errors="ignore")[:max_chars]
    except Exception:
        return ""


def _crm_clean_text(text: str) -> str:
    cleaner = globals().get("_cr36_clean_text")
    if callable(cleaner):
        try:
            return cleaner(text)
        except Exception:
            pass
    text = (text or "").replace("\xa0", " ")
    text = re.sub(r"[ \t]+", " ", text)
    text = re.sub(r"\n{3,}", "\n\n", text)
    return text.strip()


def _crm_parse_num(value) -> float:
    parser = globals().get("_cr36_parse_num")
    if callable(parser):
        try:
            return float(parser(value))
        except Exception:
            pass
    s = str(value or "").strip().replace("EUR", "").replace("euro", "").replace(" ", "")
    s = re.sub(r"[^0-9,\.\-]", "", s)
    if not s or s in {"-", ".", ","}:
        return 0.0
    try:
        if "," in s and "." in s:
            if s.rfind(",") > s.rfind("."):
                s = s.replace(".", "").replace(",", ".")
            else:
                s = s.replace(",", "")
        elif "," in s:
            s = s.replace(".", "").replace(",", ".")
        elif "." in s:
            parts = s.split(".")
            if len(parts) > 1 and all(len(x) == 3 for x in parts[1:]):
                s = "".join(parts)
        return float(s)
    except Exception:
        return float(parse_number(str(value)) or 0.0)


def _crm_money(value, decimals: int = 2) -> str:
    try:
        value = float(value or 0)
    except Exception:
        value = 0.0
    return format_currency(value)


def _crm_pmt(principal: float, months: int, annual_rate: float) -> float:
    principal = max(0.0, float(principal or 0))
    months = max(1, int(months or 1))
    r = max(0.0, float(annual_rate or 0)) / 12.0
    if principal <= 0:
        return 0.0
    if r <= 0:
        return principal / months
    return principal * (r / (1 - (1 + r) ** (-months)))


def _crm_month_end(year: int, month: int) -> datetime:
    import calendar
    month = max(1, min(12, int(month or 1)))
    day = calendar.monthrange(int(year), month)[1]
    return datetime(int(year), month, day)


def _crm_add_months(dt: datetime, months: int) -> datetime:
    import calendar
    months = max(0, int(months or 0))
    month_index = (dt.month - 1) + months
    year = dt.year + month_index // 12
    month = month_index % 12 + 1
    day = min(dt.day, calendar.monthrange(year, month)[1])
    return datetime(year, month, day)


def _crm_find_reference_date(text: str) -> dict:
    clean = _crm_clean_text(text)
    ref_label = "Non rilevata"
    ref_year = None
    ref_month = None
    m = re.search(r"DATA DI RIFERIMENTO\s*:\s*([^\n]+)", clean, flags=re.IGNORECASE)
    if m:
        ref_label = m.group(1).strip()[:80]
        norm = normalize_category(ref_label)
        for name, num in _CRM_MONTHS_IT.items():
            if re.search(r"\b" + re.escape(name) + r"\b", norm):
                ref_month = num
                break
        y = re.search(r"(20\d{2})", ref_label)
        if y:
            ref_year = int(y.group(1))
    if not ref_year or not ref_month:
        # fallback su mesi presenti nel testo, prendendo il piu recente
        candidates = []
        month_names = "|".join(sorted(_CRM_MONTHS_IT.keys(), key=len, reverse=True))
        for m2 in re.finditer(r"\b(" + month_names + r")\s+(20\d{2})\b", clean, flags=re.IGNORECASE):
            mm = _CRM_MONTHS_IT.get(normalize_category(m2.group(1)))
            yy = int(m2.group(2))
            if mm:
                candidates.append((yy, mm, m2.group(0)))
        if candidates:
            yy, mm, label = sorted(candidates)[-1]
            ref_year, ref_month, ref_label = yy, mm, label
    start_dt = datetime.now()
    if ref_year and ref_month:
        # Prima scadenza gestionale: fine mese successivo alla rilevazione CR.
        ref_end = _crm_month_end(ref_year, ref_month)
        next_ref = _crm_add_months(ref_end, 1)
        start_dt = _crm_month_end(next_ref.year, next_ref.month)
    return {"label": ref_label, "year": ref_year, "month": ref_month, "start_dt": start_dt}


def _crm_find_client_name(text: str, fallback: str = "Cliente") -> str:
    clean = _crm_clean_text(text)
    candidates = []
    for m in re.finditer(r"(?:^|\n)Intestatario\s*:\s*([^\n]+)", clean, flags=re.IGNORECASE):
        val = (m.group(1) or "").strip()
        if val and not re.fullmatch(r"[0-9\s\.]+", val):
            candidates.append(val[:90])
    # Scarta intestazioni vuote o etichette catturate da layout PDF.
    candidates = [c for c in candidates if c and "sede legale" not in normalize_category(c) and "cciaa" not in normalize_category(c) and normalize_category(c) != "intestatario"]
    if candidates:
        candidates.sort(key=lambda x: (len(re.findall(r"[A-Za-z]", x)), len(x)), reverse=True)
        return candidates[0]
    # Fallback per prospetti in cui la denominazione e stampata su una riga dopo il codice intestatario.
    m = re.search(r"Intestatario\s*:\s*\n(?:[^\n]*\n){0,4}([A-Z0-9][A-Z0-9 \.&'/-]{2,120})", clean, flags=re.IGNORECASE)
    if m and not re.fullmatch(r"[0-9\s\.]+", m.group(1).strip()):
        return m.group(1).strip()[:90]
    return fallback or "Cliente"


def _crm_amounts_from_window(window: str) -> list[float]:
    vals = []
    for token in re.findall(_CRM_NUM_RE, window or ""):
        val = _crm_parse_num(token)
        # Esclude anni, durate, codici piccoli e pagine; mantiene importi monetari plausibili.
        if val >= 1000 and val < 1000000000 and not (1900 <= abs(val) <= 2099):
            vals.append(val)
    return vals


def _crm_row_numeric_values(window: str) -> list[float]:
    # Taglia intestazioni/piedipagina che talvolta finiscono dentro la riga estratta.
    body = re.split(r"Data di elaborazione|FILIALE DI|Intestatario\s*:|Le informazioni sono disponibili", window or "", flags=re.IGNORECASE)[0]
    vals = []
    for token in re.findall(_CRM_NUM_RE, body):
        val = _crm_parse_num(token)
        if val < 0 or val >= 1000000000 or (1900 <= abs(val) <= 2099):
            continue
        vals.append(val)
    return vals


def _crm_main_amount(window: str) -> float:
    vals = _crm_row_numeric_values(window)
    # Nelle righe CR i 4 valori finali sono normalmente accordato / accordato operativo / utilizzato / garantito
    # o comunque includono l'utilizzato come penultimo valore.
    if len(vals) >= 4:
        return max(0.0, vals[-2])
    vals_big = [v for v in vals if v >= 1000]
    if vals_big:
        return max(vals_big)
    return 0.0


def _crm_duration_info(window: str) -> dict:
    norm = re.sub(r"\s+", " ", normalize_category(window or "")).strip()
    if "oltre cinque anni" in norm or "oltre 5 anni" in norm:
        origin = "Oltre 5 anni"
    elif "da oltre un anno fino a cinque anni" in norm or "da oltre 1 anno fino a cinque anni" in norm:
        origin = "Da oltre 1 a 5 anni"
    elif "fino a un anno" in norm or "fino a 1 anno" in norm:
        origin = "Fino a 1 anno"
    else:
        origin = "Non rilevata"

    # La durata residua e ricavata con criterio prudenziale; la CR non espone la scadenza puntuale.
    if "fino a 1 anno" in norm or "fino a un anno" in norm:
        residual = "Fino a 1 anno"
    elif "oltre 1 anno" in norm or "oltre un anno" in norm:
        residual = "Oltre 1 anno"
    else:
        residual = "Non rilevata"
    return {"origin": origin, "residual": residual}


def _crm_months_for_item(item: dict, scenario: str = "base") -> int:
    origin = normalize_category(item.get("durata_originaria", ""))
    residual = normalize_category(item.get("durata_residua", ""))
    if "fino a 1 anno" in residual or "fino a un anno" in residual:
        return 12
    if "oltre 5" in origin or "oltre cinque" in origin:
        return {"breve": 60, "base": 72, "lungo": 120}.get(scenario, 72)
    if "da oltre" in origin and ("5" in origin or "cinque" in origin):
        return {"breve": 24, "base": 36, "lungo": 60}.get(scenario, 36)
    if "fino a 1" in origin or "fino a un" in origin:
        return 12
    return {"breve": 24, "base": 48, "lungo": 72}.get(scenario, 48)


def _crm_row_windows(block: str) -> list[tuple[str, str]]:
    markers = []
    pattern = r"RISCHI\s+A\s+SCADENZA|RISCHI\s+AUTOLIQUIDANTI|RISCHI\s+A\s+REVOCA|GARANZIE\s+CONNESSE\s+CON\s+OPERAZIONI\s+DI\s+NATURA\s+FINANZIARIA"
    for m in re.finditer(pattern, block or "", flags=re.IGNORECASE):
        label = re.sub(r"\s+", " ", m.group(0).upper()).strip()
        markers.append((m.start(), label))
    windows = []
    stop_re = re.compile(r"INFORMAZIONI SUI GARANTI|INFORMAZIONI SUI DEBITORI|Sezione informativa|RICHIESTE DI INFORMAZIONE|LISTA DEI SERVICER", re.IGNORECASE)
    for idx, (pos, label) in enumerate(markers):
        next_pos = markers[idx + 1][0] if idx + 1 < len(markers) else len(block)
        stop = stop_re.search(block, pos, next_pos)
        end = min(next_pos, stop.start() if stop else next_pos)
        window = block[pos:end]
        if window.strip():
            windows.append((label, window))
    return windows


def _crm_split_intermediary_blocks(text: str) -> list[tuple[str, str]]:
    clean = _crm_clean_text(text)
    # Alcuni estrattori PDF invertono la testata e restituiscono
    # "NOME BANCAIntermediario:" anziche "Intermediario: NOME BANCA".
    clean = re.sub(
        r"(^|\n)([^\n]{4,220}?)\s*Intermediario\s*:\s*",
        lambda m: f"\nIntermediario: {m.group(2).strip()}\n",
        clean,
        flags=re.IGNORECASE,
    )
    chunks = re.split(r"(?:^|\n)Intermediario\s*:\s*", clean, flags=re.IGNORECASE)
    blocks = []
    for chunk in chunks[1:]:
        lines = [x.strip() for x in chunk.splitlines() if x.strip()]
        if not lines:
            continue
        name = lines[0]
        # Se la forma era "Intermediario:\nNOME", prova la riga successiva.
        if normalize_category(name) in {"crediti per cassa", "situazione corrente", "crediti di firma"} and len(lines) > 1:
            name = lines[1]
        name = re.sub(r"\s+", " ", name)[:140]
        blocks.append((name, chunk))
    return blocks


def _crm_extract_credit_data(text: str, fallback_client: str = "Cliente") -> dict:
    clean = _crm_clean_text(text)
    ref = _crm_find_reference_date(clean)
    client_name = _crm_find_client_name(clean, fallback=fallback_client)
    term_items = []
    auto_items = []
    firma_items = []
    revoca_items = []
    critical_items = []

    for intermediary, block in _crm_split_intermediary_blocks(clean):
        for label, window in _crm_row_windows(block):
            amount = _crm_main_amount(window)
            if amount <= 0:
                continue
            norm_window = normalize_category(window)
            dur = _crm_duration_info(window)
            if "RISCHI A SCADENZA" in label:
                tipo = "Leasing" if "leasing" in norm_window else "Rischi a scadenza"
                item = {
                    "intermediario": intermediary,
                    "tipo": tipo,
                    "importo": amount,
                    "durata_originaria": dur["origin"],
                    "durata_residua": dur["residual"],
                    "stato": "Scaduto/sconfinante" if "scaduti o sconfinanti" in norm_window else "Regolare/non contestato",
                    "fonte": "CR - blocco intermediario",
                }
                term_items.append(item)
            elif "RISCHI AUTOLIQUIDANTI" in label:
                # Le righe della sezione informativa "crediti scaduti" sono riportate tra le criticita,
                # non sommate alle linee autoliquidanti ordinarie.
                if "crediti scaduti" in norm_window:
                    continue
                state = "Regolare/non contestato" if "diversi da scaduti" in norm_window else ("Scaduto/sconfinante" if ("scaduti" in norm_window or "sconfinanti" in norm_window or "impagati" in norm_window) else "Regolare/non contestato")
                auto_items.append({"intermediario": intermediary, "tipo": "Rischi autoliquidanti/factoring", "importo": amount, "stato": state})
            elif "RISCHI A REVOCA" in label:
                revoca_items.append({"intermediario": intermediary, "tipo": "Rischi a revoca", "importo": amount, "stato": "Saldo medio/utilizzo rilevato"})
            elif "GARANZIE CONNESSE" in label:
                firma_items.append({"intermediario": intermediary, "tipo": "Crediti di firma", "importo": amount, "stato": "Garanzia finanziaria"})

        # Sezione informativa: crediti scaduti/impagati.
        for m in re.finditer(r"RISCHI\s+AUTOLIQUIDANTI\s*-\s*CREDITI\s+SCADUTI[^\n]*", block, flags=re.IGNORECASE):
            window = m.group(0)
            vals = _crm_amounts_from_window(window)
            if vals:
                state = "Impagati" if re.search(r"IMPAGATI", window, flags=re.IGNORECASE) else "Pagati/Informativo"
                critical_items.append({"intermediario": intermediary, "voce": "Crediti autoliquidanti scaduti", "importo": max(vals), "stato": state})

    # Deduplica righe uguali generate da impaginazione o testo ripetuto.
    def dedupe(items, key_fields):
        out = []
        seen = set()
        for item in items:
            key = tuple(str(item.get(k, "")).lower().strip() for k in key_fields) + (round(float(item.get("importo") or 0), 2),)
            if key in seen:
                continue
            seen.add(key)
            out.append(item)
        return out

    term_items = dedupe(term_items, ["intermediario", "tipo", "durata_originaria", "durata_residua"])
    auto_items = dedupe(auto_items, ["intermediario", "tipo"])
    firma_items = dedupe(firma_items, ["intermediario", "tipo"])
    revoca_items = dedupe(revoca_items, ["intermediario", "tipo"])
    critical_items = dedupe(critical_items, ["intermediario", "voce", "stato"])

    # Richieste di informazione: conteggio euristico negli ultimi sei mesi, se presenti nel prospetto.
    request_section = ""
    req_m = re.search(r"RICHIESTE DI INFORMAZIONE(.+?)(?:LISTA DEI SERVICER|LEGENDA|$)", clean, flags=re.IGNORECASE | re.DOTALL)
    if req_m:
        request_section = req_m.group(1)
    request_count = len(re.findall(r"PRIMA INFORMAZIONE", request_section, flags=re.IGNORECASE))
    request_fido_count = len(re.findall(r"RICHIESTA PER CONCESSIONE DI FIDO", request_section, flags=re.IGNORECASE))

    return {
        "cliente": client_name,
        "data_riferimento": ref,
        "term_items": term_items,
        "auto_items": auto_items,
        "firma_items": firma_items,
        "revoca_items": revoca_items,
        "critical_items": critical_items,
        "request_count": request_count,
        "request_fido_count": request_fido_count,
    }


def _crm_build_report(client_row, docs: list, extracted: dict, annual_rate_pct: float = 6.0) -> dict:
    annual_rate = max(0.0, float(annual_rate_pct or 0.0)) / 100.0
    term_items = [dict(x) for x in extracted.get("term_items") or []]
    start_dt = extracted.get("data_riferimento", {}).get("start_dt") or datetime.now()

    for item in term_items:
        base_months = _crm_months_for_item(item, "base")
        item["mesi_base"] = base_months
        item["inizio"] = start_dt.strftime("%d/%m/%Y")
        item["fine"] = _crm_add_months(start_dt, base_months - 1).strftime("%d/%m/%Y")
        item["rata_capitale"] = float(item.get("importo") or 0) / max(1, base_months)
        item["rata_interessi"] = _crm_pmt(item.get("importo") or 0, base_months, annual_rate)

    totals = {}
    for scenario in ("breve", "base", "lungo"):
        months_list = [_crm_months_for_item(item, scenario) for item in term_items]
        totals[scenario] = {
            "rata_capitale": sum((item.get("importo") or 0) / max(1, m) for item, m in zip(term_items, months_list)),
            "rata_interessi": sum(_crm_pmt(item.get("importo") or 0, m, annual_rate) for item, m in zip(term_items, months_list)),
            "fine": _crm_add_months(start_dt, max(months_list or [1]) - 1).strftime("%d/%m/%Y"),
            "mesi_max": max(months_list or [0]),
        }

    total_term = sum(float(x.get("importo") or 0) for x in term_items)
    total_auto = sum(float(x.get("importo") or 0) for x in extracted.get("auto_items") or [])
    total_firma = sum(float(x.get("importo") or 0) for x in extracted.get("firma_items") or [])
    total_revoca = sum(float(x.get("importo") or 0) for x in extracted.get("revoca_items") or [])
    total_critical = sum(float(x.get("importo") or 0) for x in extracted.get("critical_items") or [])
    client_name = (client_row["denominazione"] if client_row and "denominazione" in client_row.keys() else extracted.get("cliente")) or extracted.get("cliente") or "Cliente"
    doc_names = ", ".join([d["original_filename"] or d["title"] or "Documento CR" for d in docs]) if docs else "Documenti CR collegati"
    title = "Report neutro rata mensile Centrale Rischi"

    sections = [
        [
            "1. Sintesi del calcolo rata mensile",
            f"Cliente: {client_name}",
            f"Data riferimento CR: {extracted.get('data_riferimento', {}).get('label', 'Non rilevata')}",
            f"Documenti analizzati: {doc_names}",
            f"Totale rapporti rateali/a scadenza rilevati: {_crm_money(total_term)}",
            f"Rata mensile stimata scenario base: {_crm_money(totals['base']['rata_interessi'])}",
            f"Inizio piano stimato: {start_dt.strftime('%d/%m/%Y')}; fine aggregata stimata: {totals['base']['fine']}",
        ],
        [
            "2. Metodo neutro utilizzato",
            "Il calcolo considera solo rapporti riconducibili a rischi a scadenza e leasing. Autoliquidanti, factoring, revoche e crediti di firma sono analizzati come esposizione e rischio, ma non trasformati automaticamente in rata ordinaria.",
            f"Tasso annuo indicativo inserito dall'utente: {annual_rate_pct:.2f}%.",
            "La CR non contiene piano di ammortamento, TAN/TAEG contrattuale, maxicanoni, preammortamenti o scadenza puntuale. Le date di fine sono quindi stime gestionali basate sulle classi di durata rilevate.",
        ],
        [
            "3. Quadro esposizioni collegate",
            f"Rischi a scadenza/leasing: {_crm_money(total_term)}",
            f"Rischi autoliquidanti/factoring: {_crm_money(total_auto)}",
            f"Rischi a revoca: {_crm_money(total_revoca)}",
            f"Crediti di firma/garanzie finanziarie: {_crm_money(total_firma)}",
            f"Eventi critici/informativi rilevati: {_crm_money(total_critical)}",
        ],
        [
            "4. Valutazione operativa",
            "La rata stimata va confrontata con EBITDA mensile, cash flow operativo e marginalita disponibile. In presenza di scaduti, sconfinamenti o crediti impagati, la priorita non e solo la rata, ma anche la regolarizzazione andamentale.",
            f"Richieste di prima informazione rilevate: {extracted.get('request_count', 0)}; richieste per concessione fido: {extracted.get('request_fido_count', 0)}.",
            "Per validare il dato occorre allegare piani di ammortamento ufficiali, contratti, scadenziario finanziamenti e situazione aggiornata degli incassi.",
        ],
    ]

    return {
        "title": title,
        "client_name": client_name,
        "sections": sections,
        "items": term_items,
        "auto_items": extracted.get("auto_items") or [],
        "firma_items": extracted.get("firma_items") or [],
        "revoca_items": extracted.get("revoca_items") or [],
        "critical_items": extracted.get("critical_items") or [],
        "totals": totals,
        "amounts": {
            "term": total_term,
            "auto": total_auto,
            "firma": total_firma,
            "revoca": total_revoca,
            "critical": total_critical,
        },
        "annual_rate_pct": annual_rate_pct,
        "start_date": start_dt.strftime("%d/%m/%Y"),
        "reference_label": extracted.get("data_riferimento", {}).get("label", "Non rilevata"),
        "documents": doc_names,
    }


def _crm_pdf_para(text: str, style):
    return Paragraph(str(text).replace("\n", "<br/>"), style)


def _crm_make_table(rows, col_widths=None, font_size: int = 7, right_cols: list[int] | None = None):
    right_cols = right_cols or []
    table = Table(rows, repeatRows=1, colWidths=col_widths)
    style = [
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#e8efff")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.HexColor("#223046")),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTNAME", (0, 1), (-1, -1), "Helvetica"),
        ("FONTSIZE", (0, 0), (-1, -1), font_size),
        ("LEADING", (0, 0), (-1, -1), font_size + 2),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#c7d1df")),
        ("LEFTPADDING", (0, 0), (-1, -1), 4),
        ("RIGHTPADDING", (0, 0), (-1, -1), 4),
        ("TOPPADDING", (0, 0), (-1, -1), 3),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 3),
    ]
    for col in right_cols:
        style.append(("ALIGN", (col, 1), (col, -1), "RIGHT"))
    table.setStyle(TableStyle(style))
    return table


def _crm_export_pdf(path: str, client_row, report: dict) -> None:
    if not REPORTLAB_AVAILABLE:
        raise RuntimeError("ReportLab non disponibile: impossibile generare PDF.")
    from reportlab.lib.enums import TA_CENTER
    from reportlab.platypus import KeepTogether

    styles = getSampleStyleSheet()
    styles.add(ParagraphStyle(name="CRMTitle", parent=styles["Title"], fontSize=18, leading=22, alignment=TA_CENTER, textColor=colors.HexColor("#1f3a5f")))
    styles.add(ParagraphStyle(name="CRMH1", parent=styles["Heading1"], fontSize=13, leading=16, textColor=colors.HexColor("#1f3a5f"), spaceBefore=8, spaceAfter=6))
    styles.add(ParagraphStyle(name="CRMBody", parent=styles["BodyText"], fontSize=8.2, leading=11, spaceAfter=4))
    styles.add(ParagraphStyle(name="CRMSmall", parent=styles["BodyText"], fontSize=7, leading=9, textColor=colors.HexColor("#4d5a69")))
    styles.add(ParagraphStyle(name="CRMBold", parent=styles["BodyText"], fontName="Helvetica-Bold", fontSize=7.3, leading=9.5, textColor=colors.HexColor("#223046")))
    styles.add(ParagraphStyle(name="CRMMetric", parent=styles["BodyText"], fontName="Helvetica-Bold", fontSize=12, leading=14, alignment=TA_CENTER, textColor=colors.HexColor("#1f3a5f")))

    story = []
    title = report.get("title") or "Report rata mensile Centrale Rischi"
    client_name = report.get("client_name") or (client_row["denominazione"] if client_row else "Cliente")
    story.append(_crm_pdf_para(title, styles["CRMTitle"]))
    story.append(_crm_pdf_para(f"Cliente: <b>{client_name}</b>", styles["CRMBody"]))
    story.append(_crm_pdf_para(f"Data riferimento CR: {report.get('reference_label', '-')}; documenti: {report.get('documents', '-')}", styles["CRMSmall"]))
    story.append(Spacer(1, 0.25 * cm))

    totals = report.get("totals", {})
    amounts = report.get("amounts", {})
    kpi_rows = [[
        _crm_pdf_para("Rata base", styles["CRMBold"]),
        _crm_pdf_para("Inizio stimato", styles["CRMBold"]),
        _crm_pdf_para("Fine base", styles["CRMBold"]),
        _crm_pdf_para("Debito rateale", styles["CRMBold"]),
    ], [
        _crm_pdf_para(_crm_money(totals.get("base", {}).get("rata_interessi")), styles["CRMMetric"]),
        _crm_pdf_para(report.get("start_date", "-"), styles["CRMMetric"]),
        _crm_pdf_para(totals.get("base", {}).get("fine", "-"), styles["CRMMetric"]),
        _crm_pdf_para(_crm_money(amounts.get("term")), styles["CRMMetric"]),
    ]]
    story.append(_crm_make_table(kpi_rows, col_widths=[4.2*cm, 4.0*cm, 4.0*cm, 4.2*cm], font_size=8))
    story.append(Spacer(1, 0.25 * cm))

    for section in report.get("sections", []):
        if not section:
            continue
        story.append(_crm_pdf_para(section[0], styles["CRMH1"]))
        for line in section[1:]:
            story.append(_crm_pdf_para(line, styles["CRMBody"]))

    story.append(_crm_pdf_para("5. Scenari rata mensile", styles["CRMH1"]))
    scenario_rows = [["Scenario", "Mesi max", "Rata solo capitale", f"Rata con TAN {report.get('annual_rate_pct', 0):.2f}%", "Fine stimata"]]
    for key, label in [("breve", "Breve/prudenziale"), ("base", "Base"), ("lungo", "Lungo")]:
        t = totals.get(key, {})
        scenario_rows.append([label, str(t.get("mesi_max", "-")), _crm_money(t.get("rata_capitale")), _crm_money(t.get("rata_interessi")), t.get("fine", "-")])
    story.append(_crm_make_table([[ _crm_pdf_para(c, styles["CRMBold"] if r == 0 else styles["CRMSmall"]) for c in row] for r, row in enumerate(scenario_rows)], col_widths=[4.0*cm, 2.0*cm, 3.4*cm, 3.8*cm, 3.0*cm], right_cols=[1,2,3]))
    story.append(Spacer(1, 0.25 * cm))

    story.append(_crm_pdf_para("6. Dettaglio rapporti rateali/a scadenza", styles["CRMH1"]))
    item_rows = [["Intermediario", "Tipo", "Importo", "Durata orig.", "Durata resid.", "Mesi", "Rata base", "Inizio", "Fine"]]
    for item in report.get("items") or []:
        item_rows.append([
            item.get("intermediario", "-"), item.get("tipo", "-"), _crm_money(item.get("importo")), item.get("durata_originaria", "-"), item.get("durata_residua", "-"), str(item.get("mesi_base", "-")), _crm_money(item.get("rata_interessi")), item.get("inizio", "-"), item.get("fine", "-"),
        ])
    if len(item_rows) == 1:
        item_rows.append(["Nessun rapporto rateale rilevato", "", "", "", "", "", "", "", ""])
    story.append(_crm_make_table([[ _crm_pdf_para(c, styles["CRMBold"] if r == 0 else styles["CRMSmall"]) for c in row] for r, row in enumerate(item_rows)], col_widths=[3.5*cm, 2.3*cm, 2.2*cm, 2.1*cm, 2.0*cm, 1.1*cm, 2.1*cm, 1.8*cm, 1.8*cm], font_size=6.2, right_cols=[2,5,6]))
    story.append(PageBreak())

    story.append(_crm_pdf_para("7. Esposizioni non trasformate in rata", styles["CRMH1"]))
    exp_rows = [["Aggregato", "Importo", "Nota"]]
    exp_rows.append(["Rischi autoliquidanti/factoring", _crm_money(amounts.get("auto")), "Linee collegate al circolante; non sono rate standard."])
    exp_rows.append(["Rischi a revoca", _crm_money(amounts.get("revoca")), "Aperture/revoche: da monitorare come utilizzo e saldo medio."])
    exp_rows.append(["Crediti di firma", _crm_money(amounts.get("firma")), "Garanzie finanziarie: impegno potenziale, non rata diretta."])
    story.append(_crm_make_table([[ _crm_pdf_para(c, styles["CRMBold"] if r == 0 else styles["CRMSmall"]) for c in row] for r, row in enumerate(exp_rows)], col_widths=[5.0*cm, 3.0*cm, 8.0*cm], right_cols=[1]))
    story.append(Spacer(1, 0.25 * cm))

    if report.get("critical_items"):
        story.append(_crm_pdf_para("8. Criticita/informazioni scadute rilevate", styles["CRMH1"]))
        crit_rows = [["Intermediario", "Voce", "Importo", "Stato"]]
        for item in report.get("critical_items") or []:
            crit_rows.append([item.get("intermediario", "-"), item.get("voce", "-"), _crm_money(item.get("importo")), item.get("stato", "-")])
        story.append(_crm_make_table([[ _crm_pdf_para(c, styles["CRMBold"] if r == 0 else styles["CRMSmall"]) for c in row] for r, row in enumerate(crit_rows)], col_widths=[5.0*cm, 5.0*cm, 3.0*cm, 3.0*cm], right_cols=[2]))
        story.append(Spacer(1, 0.25 * cm))

    story.append(_crm_pdf_para("9. Conclusioni e limiti", styles["CRMH1"]))
    story.append(_crm_pdf_para("Il report e neutro e parametrico: usa esclusivamente dati presenti nei documenti collegati al cliente e i parametri inseriti nella finestra. Non contiene valori hardcoded di un singolo cliente.", styles["CRMBody"]))
    story.append(_crm_pdf_para("La rata corretta deve essere confermata con i piani di ammortamento ufficiali. Il calcolo qui prodotto serve per una stima gestionale preliminare e per l'organizzazione del fascicolo cliente.", styles["CRMBody"]))

    def on_page(canv, _doc):
        try:
            draw_pdf_branding(canv, title)
        except Exception:
            pass
        canv.saveState()
        canv.setFont("Helvetica", 8)
        canv.setFillColor(colors.HexColor("#6b778c"))
        canv.drawRightString(A4[0] - 1.2*cm, 0.8*cm, f"Pagina {canv.getPageNumber()}")
        canv.restoreState()

    doc = SimpleDocTemplate(path, pagesize=A4, rightMargin=1.2*cm, leftMargin=1.2*cm, topMargin=1.35*cm, bottomMargin=1.2*cm, title=title)
    doc.build(story, onFirstPage=on_page, onLaterPages=on_page)


class CRMMonthlyInstallmentWindow(ReportBaseWindow):
    def __init__(self, master, db: Database, preselected_client_id: int | None = None):
        super().__init__(master, db, "Calcolo rata mensile CR", ["Centrale Rischi", "Esposizioni Mensili"], preselected_client_id)
        self.current_crm_report = None
        self.current_crm_pdf_path = None
        self.tan_var = tk.StringVar(value="6.00")
        try:
            body = self.content_frame.winfo_children()[3]
        except Exception:
            body = None
        controls = ttk.LabelFrame(self.content_frame, text="Parametri calcolo rata CR", padding=10)
        if body is not None:
            controls.pack(fill="x", padx=16, pady=(0, 10), before=body)
        else:
            controls.pack(fill="x", padx=16, pady=(0, 10))
        ttk.Button(controls, text="Carica Centrale Rischi", command=self.upload_cr_documents).pack(side="left")
        ttk.Label(controls, text="TAN stimato %:").pack(side="left", padx=(14, 4))
        ttk.Entry(controls, textvariable=self.tan_var, width=8).pack(side="left")
        ttk.Button(controls, text="Calcola e crea PDF", command=self.run_analysis).pack(side="left", padx=(10, 0))
        ttk.Button(controls, text="Esporta PDF", command=self.export_pdf).pack(side="left", padx=(8, 0))
        ttk.Label(controls, text="Modulo neutro: prende i documenti CR dal cliente selezionato e salva il report nei documenti.", foreground=MUTED_TEXT).pack(side="left", padx=12)

    def _float_from_var(self, var: tk.StringVar, default: float) -> float:
        raw = (var.get() or "").strip()
        try:
            if "," in raw and "." in raw:
                raw = raw.replace(".", "").replace(",", ".")
            else:
                raw = raw.replace(",", ".")
            return float(raw)
        except Exception:
            return default

    def upload_cr_documents(self):
        client_id = self.selected_client_id()
        if not client_id:
            messagebox.showwarning("Attenzione", "Seleziona prima un cliente.")
            return
        paths = filedialog.askopenfilenames(
            title="Seleziona Centrale Rischi o documenti esposizioni",
            filetypes=[("Documenti supportati", "*.pdf *.xlsx *.xls *.csv *.txt *.docx"), ("PDF", "*.pdf"), ("Tutti i file", "*.*")],
        )
        if not paths:
            return
        client = self.db.get_client(client_id)
        collaborator_id = None
        try:
            collaborator_id = client["responsible_collaborator_id"]
        except Exception:
            pass
        added = 0
        for p in paths:
            try:
                stored_path = archive_document_file(client_id, p, prefix="centrale_rischi")
                title = f"Centrale Rischi - {Path(p).stem}"
                notes = "Documento caricato dal modulo neutro Calcolo rata mensile CR. Collegato al cliente e disponibile in Gestione Documenti."
                self.db.add_document({
                    "client_id": client_id,
                    "collaborator_id": collaborator_id,
                    "category": "Centrale Rischi",
                    "title": title,
                    "original_filename": Path(p).name,
                    "stored_path": stored_path,
                    "notes": notes,
                })
                try:
                    mirror_document_to_scoring_plus(self.db, client_id, "Centrale Rischi", Path(p).name, stored_path, notes)
                except Exception:
                    pass
                added += 1
            except Exception as exc:
                messagebox.showerror("Errore caricamento", f"Impossibile caricare {p}\n\n{exc}")
        self.refresh_documents()
        messagebox.showinfo("Caricamento completato", f"Documenti collegati al cliente: {added}")

    def _documents_to_analyze(self) -> list:
        row = self.selected_document()
        if row and (row["stored_path"] or ""):
            return [row]
        client_id = self.selected_client_id()
        if not client_id:
            return []
        rows = pick_documents_for_categories(self.db, client_id, ["Centrale Rischi", "Esposizioni Mensili"])
        return list(rows or [])

    def run_analysis(self):
        client_id = self.selected_client_id()
        if not client_id:
            messagebox.showwarning("Attenzione", "Seleziona un cliente.")
            return
        docs = self._documents_to_analyze()
        if not docs:
            if messagebox.askyesno("Nessun documento CR", "Non trovo documenti CR collegati al cliente. Vuoi caricarli ora?"):
                self.upload_cr_documents()
                docs = self._documents_to_analyze()
            if not docs:
                return
        client = self.db.get_client(client_id)
        text_parts = []
        for row in docs:
            txt = _crm_read_text(row["stored_path"] or "")
            if txt and txt.strip():
                text_parts.append(f"\n--- {row['original_filename'] or row['title'] or 'Documento'} ---\n{txt}")
        full_text = _crm_clean_text("\n".join(text_parts))
        if not full_text:
            messagebox.showwarning("Testo non leggibile", "Il documento non contiene testo estraibile. Se e' una scansione, serve un PDF OCR/testuale.")
            return
        tan = self._float_from_var(self.tan_var, 6.0)
        extracted = _crm_extract_credit_data(full_text, fallback_client=client["denominazione"] if client else "Cliente")
        report = _crm_build_report(client, docs, extracted, annual_rate_pct=tan)
        self.current_crm_report = report
        self.current_pdf_title = report["title"]
        self.set_report(report["sections"], report["title"])
        self.draw_chart(report)
        if not report.get("items"):
            messagebox.showwarning("Nessuna rata rilevata", "Non ho trovato rapporti a scadenza/leasing nel testo estratto. Il report resta disponibile a video con esposizioni e limiti.")
            return
        try:
            folder = get_client_documents_folder(client_id)
            safe_client = sanitize_client_storage_name(client["denominazione"] if client else "cliente", f"cliente_{client_id}")
            stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            pdf_path = folder / f"{stamp}_Report_rata_mensile_CR_{safe_client}.pdf"
            _crm_export_pdf(str(pdf_path), client, report)
            self.current_crm_pdf_path = str(pdf_path)
            doc_id = self.db.add_document({
                "client_id": client_id,
                "collaborator_id": client["responsible_collaborator_id"] if client and "responsible_collaborator_id" in client.keys() else None,
                "category": "Report",
                "title": f"Report rata mensile CR - {client['denominazione'] if client else client_id}",
                "original_filename": pdf_path.name,
                "stored_path": str(pdf_path),
                "notes": "Report PDF generato dal modulo neutro Calcolo rata mensile CR e collegato ai documenti del cliente.",
            })
            self.refresh_documents()
            msg = f"Report creato e salvato nei documenti del cliente.\nID documento: {doc_id}\n\n{pdf_path}\n\nVuoi aprirlo ora?"
            if messagebox.askyesno("Report creato", msg):
                open_path(str(pdf_path))
        except Exception as exc:
            messagebox.showerror("Errore PDF", f"Impossibile creare il report PDF.\n\n{exc}")

    def export_pdf(self):
        if not self.current_crm_report:
            messagebox.showwarning("Attenzione", "Esegui prima il calcolo.")
            return
        client_id = self.selected_client_id()
        client = self.db.get_client(client_id) if client_id else None
        path = filedialog.asksaveasfilename(
            title="Salva report rata mensile CR",
            defaultextension=".pdf",
            initialfile="Report_rata_mensile_CR.pdf",
            filetypes=[("PDF", "*.pdf")],
        )
        if not path:
            return
        try:
            _crm_export_pdf(path, client, self.current_crm_report)
            open_path(path)
        except Exception as exc:
            messagebox.showerror("Errore PDF", f"Impossibile esportare il PDF.\n\n{exc}")

    def draw_chart(self, report: dict):
        c = self.chart_canvas
        c.delete("all")
        c.create_text(16, 16, anchor="nw", text="Rata mensile CR - riepilogo", font=("Segoe UI", 11, "bold"), fill=TEXT_COLOR)
        totals = report.get("totals", {})
        vals = [
            ("Breve", totals.get("breve", {}).get("rata_interessi") or 0),
            ("Base", totals.get("base", {}).get("rata_interessi") or 0),
            ("Lungo", totals.get("lungo", {}).get("rata_interessi") or 0),
        ]
        max_val = max([v for _, v in vals] + [1])
        width = int(c.winfo_width() or 360) - 60
        base_y = int(c.winfo_height() or 260) - 45
        x = 35
        bar_w = max(40, min(80, width // 5))
        for label, value in vals:
            h = min(140, (value / max_val) * 140)
            c.create_rectangle(x, base_y - h, x + bar_w, base_y, fill=PRIMARY_COLOR, outline=PRIMARY_COLOR)
            c.create_text(x + bar_w/2, base_y + 12, text=label, font=("Segoe UI", 8), anchor="n")
            c.create_text(x + bar_w/2, base_y - h - 8, text=_crm_money(value), font=("Segoe UI", 7), anchor="s")
            x += bar_w + 28
        c.create_text(16, 48, anchor="nw", text=f"Debito rateale: {_crm_money(report.get('amounts', {}).get('term'))}", font=("Segoe UI", 9))
        c.create_text(16, 68, anchor="nw", text=f"Inizio: {report.get('start_date', '-')} | Fine base: {totals.get('base', {}).get('fine', '-')}", font=("Segoe UI", 9, "bold"))



class ReportHubWindow(BaseWindow):
    def __init__(self, master, db: Database):
        super().__init__(master, "REPORT", "980x640")
        self.db = db
        self.client_ids_by_name: dict[str, int] = {}
        shell = ttk.Frame(self.content_frame, padding=18)
        shell.pack(fill="both", expand=True)
        top = ttk.LabelFrame(shell, text="Collegamento a Gestione Documenti", padding=14)
        top.pack(fill="x", pady=(0, 16))
        ttk.Label(top, text="Cliente:").grid(row=0, column=0, sticky="w")
        self.client_combo = ttk.Combobox(top, width=46, state="readonly")
        self.client_combo.grid(row=0, column=1, sticky="ew", padx=(8, 0))
        ttk.Label(top, text="Selezionando il cliente verranno recuperati automaticamente tutti i documenti già salvati in Gestione Documenti e usati per elaborare i report.", wraplength=760, justify="left").grid(row=1, column=0, columnspan=2, sticky="w", pady=(10, 0))
        top.columnconfigure(1, weight=1)
        grid = ttk.Frame(shell)
        grid.pack(fill="both", expand=True)
        grid.columnconfigure((0,1), weight=1)
        grid.rowconfigure((0,1,2,3), weight=1)
        buttons = [
            ("Analisi bilancio da depositare", lambda: ReportBilancioWindow(self, self.db, self.selected_client_id())),
            ("Analisi CR", lambda: ReportCRWindow(self, self.db, self.selected_client_id())),
            ("Calcolo rata mensile CR", lambda: CRMMonthlyInstallmentWindow(self, self.db, self.selected_client_id())),
            ("Analisi CR 36 mesi", lambda: CR36AnalysisWindow(self, self.db, self.selected_client_id())),
            ("Analisi Valutazione Creditizia/Finanziaria", lambda: ReportValutazioneFinanziariaWindow(self, self.db, self.selected_client_id())),
            ("Merito Creditizio", lambda: MotoreCreditizioWindow(self, self.db, self.selected_client_id())),
            ("Report Completo", lambda: ReportCompletoWindow(self, self.db, self.selected_client_id())),
        ]
        for idx, (label, command) in enumerate(buttons):
            r, c = divmod(idx, 2)
            btn = tk.Button(grid, text=label, command=command, bg=PRIMARY_COLOR, fg="white", activebackground=PRIMARY_HOVER, activeforeground="white", relief="flat", bd=0, padx=12, pady=18, font=("Segoe UI", 12, "bold"), cursor="hand2", wraplength=280)
            btn.grid(row=r, column=c, sticky="nsew", padx=10, pady=10)
        self.refresh_clients()

    def refresh_clients(self):
        clients = self.db.list_clients()
        self.client_ids_by_name = {f"{row['denominazione']} (ID {row['id']})": row['id'] for row in clients}
        self.client_combo["values"] = list(self.client_ids_by_name.keys())
        if clients:
            self.client_combo.set(next(iter(self.client_ids_by_name.keys())))

    def selected_client_id(self) -> int | None:
        return self.client_ids_by_name.get(self.client_combo.get())

class ModelFormWindow(BaseWindow):
    MODEL_CATEGORIES = ["PDF", "Word / Testo", "Excel / Tabelle", "Immagine", "Presentazione", "Testo", "Altro"]

    def __init__(self, master, db: Database, model_id: int | None = None, on_saved=None):
        super().__init__(master, "Inserire Modello" if model_id is None else "Modifica Modello", "980x720")
        self.db = db
        self.model_id = model_id
        self.on_saved = on_saved
        self.selected_file: str | None = None
        self.stored_path: str = ""

        container = ttk.Frame(self.content_frame, padding=18)
        container.pack(fill="both", expand=True)
        container.columnconfigure(1, weight=1)

        ttk.Label(container, text="Nome modello:").grid(row=0, column=0, sticky="w", pady=8, padx=(0, 12))
        self.title_entry = ttk.Entry(container, width=60)
        self.title_entry.grid(row=0, column=1, sticky="ew", pady=8)

        ttk.Label(container, text="Categoria:").grid(row=1, column=0, sticky="w", pady=8, padx=(0, 12))
        self.category_combo = ttk.Combobox(container, width=18, state="readonly", values=self.MODEL_CATEGORIES)
        self.category_combo.grid(row=1, column=1, sticky="w", pady=8)
        self.category_combo.set("Altro")

        ttk.Label(container, text="File modello:").grid(row=2, column=0, sticky="w", pady=8, padx=(0, 12))
        file_row = ttk.Frame(container)
        file_row.grid(row=2, column=1, sticky="ew", pady=8)
        file_row.columnconfigure(0, weight=1)
        self.file_var = tk.StringVar()
        ttk.Entry(file_row, textvariable=self.file_var, state="readonly").grid(row=0, column=0, sticky="ew")
        ttk.Button(file_row, text="Sfoglia", command=self.choose_file).grid(row=0, column=1, padx=(8, 0))

        preview_card = ttk.LabelFrame(container, text="Anteprima testo / dettagli file", padding=10)
        preview_card.grid(row=3, column=0, columnspan=2, sticky="nsew", pady=(10, 0))
        preview_card.rowconfigure(0, weight=1)
        preview_card.columnconfigure(0, weight=1)
        self.content_text = ScrolledText(preview_card, wrap="word", height=18, font=("Segoe UI", 10))
        self.content_text.grid(row=0, column=0, sticky="nsew")

        buttons = ttk.Frame(container)
        buttons.grid(row=4, column=0, columnspan=2, sticky="e", pady=(18, 0))
        ttk.Button(buttons, text="Salva", command=self.save).pack(side="right", padx=(8, 0))
        ttk.Button(buttons, text="Chiudi", command=self.destroy).pack(side="right")

        if self.model_id is not None:
            self.load_data()

    def choose_file(self):
        path = filedialog.askopenfilename(title="Seleziona file modello", filetypes=[("Tutti i file", "*.*"), ("Documenti", "*.pdf *.doc *.docx *.rtf *.odt *.txt *.md"), ("Fogli di calcolo", "*.xls *.xlsx *.csv *.ods"), ("Presentazioni", "*.ppt *.pptx *.odp"), ("Immagini", "*.png *.jpg *.jpeg *.webp *.bmp *.tif *.tiff"), ("PDF", "*.pdf")])
        if not path:
            return
        self.selected_file = path
        self.stored_path = ""
        self.file_var.set(path)
        detected_category = model_file_category(path)
        self.category_combo.set(detected_category if detected_category in self.MODEL_CATEGORIES else "Altro")
        if not self.title_entry.get().strip():
            self.title_entry.insert(0, Path(path).stem)
        extracted = extract_model_file_content(path)
        self.content_text.delete("1.0", tk.END)
        self.content_text.insert("1.0", extracted)

    def load_data(self):
        row = self.db.get_model(self.model_id)
        if not row:
            messagebox.showerror("Errore", "Modello non trovato.")
            self.destroy()
            return
        self.title_entry.delete(0, tk.END)
        self.title_entry.insert(0, row["title"] or "")
        self.category_combo.set(row["category"] or "Altro")
        self.file_var.set(row["original_filename"] or row["stored_path"] or "")
        self.stored_path = row["stored_path"] or ""
        self.content_text.delete("1.0", tk.END)
        self.content_text.insert("1.0", row["content"] or "")

    def save(self):
        title = self.title_entry.get().strip()
        content = self.content_text.get("1.0", tk.END).strip()
        if not title:
            messagebox.showwarning("Attenzione", "Inserisci il nome del modello.")
            return
        if not (self.selected_file or self.stored_path):
            messagebox.showwarning("Attenzione", "Seleziona un file modello.")
            return
        if not content:
            content = content or extract_model_file_content(self.selected_file or self.stored_path)
        try:
            stored_path = self.stored_path
            original_filename = Path(stored_path).name if stored_path else ""
            if self.selected_file:
                stored_path = archive_model_file(self.selected_file)
                original_filename = Path(self.selected_file).name
            category = self.category_combo.get() or model_file_category(self.selected_file or self.stored_path)
            if category == "Altro" and (self.selected_file or self.stored_path):
                category = model_file_category(self.selected_file or self.stored_path)
            data = {
                "title": title,
                "category": category,
                "content": content,
                "original_filename": original_filename,
                "stored_path": stored_path,
            }
            self.db.save_model(data, self.model_id)
            messagebox.showinfo("Salvataggio completato", "Modello salvato correttamente.")
            if self.on_saved:
                self.on_saved()
            self.destroy()
        except Exception as exc:
            messagebox.showerror("Errore", f"Impossibile salvare il modello.\n\n{exc}")


class ModelListWindow(BaseWindow):
    def __init__(self, master, db: Database):
        super().__init__(master, "Elenco Modelli", "1120x760")
        self.db = db

        top = ttk.Frame(self.content_frame, padding=16)
        top.pack(fill="x")
        ttk.Label(top, text="Cerca:").pack(side="left")
        self.search_var = tk.StringVar()
        search_entry = ttk.Entry(top, textvariable=self.search_var, width=34)
        search_entry.pack(side="left", padx=(8, 8))
        search_entry.bind("<KeyRelease>", lambda _e: self.refresh_table())
        ttk.Button(top, text="Inserire modello", command=self.new_model).pack(side="right")
        ttk.Button(top, text="Elimina", command=self.delete_selected).pack(side="right", padx=(0, 8))

        actions = ttk.Frame(self.content_frame, padding=(16, 0, 16, 8))
        actions.pack(fill="x")
        ttk.Button(actions, text="Copia", command=self.copy_selected).pack(side="right")
        ttk.Button(actions, text="Condividi WhatsApp", command=self.share_whatsapp).pack(side="right", padx=(0, 8))
        ttk.Button(actions, text="Condividi Email", command=self.share_email).pack(side="right", padx=(0, 8))
        ttk.Button(actions, text="Apri file", command=self.open_selected_pdf).pack(side="right", padx=(0, 8))

        columns = ("nome", "file", "categoria", "data")
        self.tree, self.tree_holder = create_treeview_with_scrollbars(self.content_frame, columns, show="headings")
        self.tree.heading("nome", text="Nome modello")
        self.tree.heading("file", text="File")
        self.tree.heading("categoria", text="Categoria")
        self.tree.heading("data", text="Ultimo aggiornamento")
        self.tree.column("nome", width=320)
        self.tree.column("file", width=320)
        self.tree.column("categoria", width=120, anchor="center")
        self.tree.column("data", width=180, anchor="center")
        self.tree_holder.pack_configure(padx=16, pady=(0, 10))
        self.tree.bind("<Double-1>", lambda _e: self.open_selected_pdf())

        preview_card = ttk.LabelFrame(self.content_frame, text="Anteprima testo estratto", padding=10)
        preview_card.pack(fill="both", expand=True, padx=16, pady=(0, 16))
        preview_card.rowconfigure(0, weight=1)
        preview_card.columnconfigure(0, weight=1)
        self.preview_text = ScrolledText(preview_card, wrap="word", height=12, font=("Segoe UI", 10))
        self.preview_text.grid(row=0, column=0, sticky="nsew")
        self.preview_text.configure(state="disabled")
        self.tree.bind("<<TreeviewSelect>>", lambda _e: self.update_preview())

        self.refresh_table()

    def refresh_table(self):
        for item in self.tree.get_children():
            self.tree.delete(item)
        rows = self.db.list_models(self.search_var.get())
        for row in rows:
            self.tree.insert(
                "",
                "end",
                iid=str(row["id"]),
                values=(
                    row["title"] or "",
                    row["original_filename"] or "",
                    row["category"] or "",
                    (row["updated_at"] or "")[:19].replace("T", " "),
                ),
            )
        self.update_preview()

    def selected_model_id(self) -> int | None:
        selection = self.tree.selection()
        if not selection:
            return None
        return int(selection[0])

    def selected_model(self):
        model_id = self.selected_model_id()
        return self.db.get_model(model_id) if model_id is not None else None

    def update_preview(self):
        row = self.selected_model()
        self.preview_text.configure(state="normal")
        self.preview_text.delete("1.0", tk.END)
        if row:
            self.preview_text.insert("1.0", row["content"] or "")
        self.preview_text.configure(state="disabled")

    def new_model(self):
        ModelFormWindow(self, self.db, on_saved=self.refresh_table)

    def delete_selected(self):
        model_id = self.selected_model_id()
        if model_id is None:
            messagebox.showwarning("Attenzione", "Seleziona un modello.")
            return
        if not messagebox.askyesno("Conferma", "Vuoi eliminare il modello selezionato?"):
            return
        self.db.delete_model(model_id)
        self.refresh_table()

    def open_selected_pdf(self):
        row = self.selected_model()
        if not row or not row["stored_path"]:
            messagebox.showwarning("Attenzione", "Seleziona un modello con file allegato.")
            return
        open_path(row["stored_path"])

    def copy_selected(self):
        row = self.selected_model()
        if not row:
            messagebox.showwarning("Attenzione", "Seleziona un modello.")
            return
        self.clipboard_clear()
        self.clipboard_append(row["content"] or "")
        messagebox.showinfo("Copiato", "Testo del modello copiato negli appunti.")

    def share_email(self):
        row = self.selected_model()
        if not row:
            messagebox.showwarning("Attenzione", "Seleziona un modello.")
            return
        subject = row["title"] or "Modello"
        body = row["content"] or ""
        attachments = [row["stored_path"]] if row.get("stored_path") else []
        compose_branded_email(subject, body, attachments=attachments)

    def share_whatsapp(self):
        row = self.selected_model()
        if not row:
            messagebox.showwarning("Attenzione", "Seleziona un modello.")
            return
        text = urllib.parse.quote(row["content"] or "")
        open_path(f"https://wa.me/?text={text}")


