def decode_mime_words(value: str | None) -> str:
    if not value:
        return ""
    parts = decode_header(value)
    out = []
    for text_part, enc in parts:
        if isinstance(text_part, bytes):
            out.append(text_part.decode(enc or "utf-8", errors="ignore"))
        else:
            out.append(text_part)
    return "".join(out).strip()


def sanitize_filename(name: str, max_length: int = 90) -> str:
    name = decode_mime_words(name)
    name = (name or "").replace('\r', ' ').replace('\n', ' ')
    name = re.sub(r'[\x00-\x1f]+', ' ', name)
    name = re.sub(r'[\/:*?"<>|]+', '_', name)
    name = re.sub(r'\s+', ' ', name).strip(' ._')
    if not name:
        return f"allegato_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
    p = Path(name)
    suffix = re.sub(r'[^A-Za-z0-9.]', '', p.suffix or '')[:12]
    stem = re.sub(r'[^A-Za-z0-9 _.-]+', '_', p.stem or name)
    stem = re.sub(r'\s+', ' ', stem).strip(' ._') or 'allegato'
    room = max(12, max_length - len(suffix))
    stem = stem[:room].rstrip(' ._') or 'allegato'
    return f"{stem}{suffix}"


def build_safe_attachment_storage_name(uid: str, filename: str) -> str:
    ts = datetime.now().strftime('%Y%m%d_%H%M%S')
    short_uid = re.sub(r'[^A-Za-z0-9]+', '', uid or '')[-12:] or 'msg'
    safe_filename = sanitize_filename(filename, max_length=70)
    return f"{ts}_{short_uid}_{safe_filename}"


def normalize_text(value: str) -> str:
    value = (value or "").lower()
    repl = {
        "à": "a", "è": "e", "é": "e", "ì": "i", "ò": "o", "ù": "u", "'": "", '"': "",
    }
    for src, dst in repl.items():
        value = value.replace(src, dst)
    value = re.sub(r"[^a-z0-9 ]+", " ", value)
    value = re.sub(r"\s+", " ", value).strip()
    return value


class TempMailDocumentsStore:
    def __init__(self, db_path: str | Path):
        self.db_path = str(db_path)
        self.conn = sqlite3.connect(self.db_path)
        self.conn.row_factory = sqlite3.Row
        self.conn.execute("PRAGMA foreign_keys = ON")
        self.init_db()

    def init_db(self):
        self.conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS settings (
                key TEXT PRIMARY KEY,
                value TEXT
            );

            CREATE TABLE IF NOT EXISTS temp_mail_documents (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                email_uid TEXT,
                mail_date TEXT,
                sender TEXT,
                subject TEXT,
                filename TEXT,
                stored_path TEXT,
                message_id TEXT,
                matched_client_id INTEGER,
                matched_client_name TEXT,
                imported_to_documents INTEGER NOT NULL DEFAULT 0,
                saved_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(email_uid, filename)
            );
            """
        )
        self.conn.commit()

    def save_settings(self, config: TempMailConfig):
        self.conn.execute(
            "INSERT OR REPLACE INTO settings(key, value) VALUES(?, ?)",
            ("mail_config", json.dumps(config.__dict__)),
        )
        self.conn.commit()

    def load_settings(self) -> TempMailConfig:
        row = self.conn.execute("SELECT value FROM settings WHERE key = ?", ("mail_config",)).fetchone()
        if not row:
            return TempMailConfig()
        try:
            data = json.loads(row["value"])
            return TempMailConfig(**data)
        except Exception:
            return TempMailConfig()

    def add_document(
        self,
        email_uid: str,
        mail_date: str,
        sender: str,
        subject: str,
        filename: str,
        stored_path: str,
        message_id: str = "",
        matched_client_id=None,
        matched_client_name: str = "",
    ) -> bool:
        cursor = self.conn.execute(
            """
            INSERT OR IGNORE INTO temp_mail_documents
            (email_uid, mail_date, sender, subject, filename, stored_path, message_id, matched_client_id, matched_client_name)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (email_uid, mail_date, sender, subject, filename, stored_path, message_id, matched_client_id, matched_client_name),
        )
        self.conn.commit()
        return cursor.rowcount > 0

    def list_documents(self):
        return self.conn.execute(
            """
            SELECT * FROM temp_mail_documents
            ORDER BY datetime(saved_at) DESC, id DESC
            """
        ).fetchall()

    def get_document(self, row_id: int):
        return self.conn.execute("SELECT * FROM temp_mail_documents WHERE id = ?", (row_id,)).fetchone()

    def delete_document(self, row_id: int):
        row = self.get_document(row_id)
        if row and row["stored_path"] and Path(row["stored_path"]).exists():
            try:
                Path(row["stored_path"]).unlink()
            except OSError:
                pass
        self.conn.execute("DELETE FROM temp_mail_documents WHERE id = ?", (row_id,))
        self.conn.commit()

    def mark_imported(self, row_id: int):
        self.conn.execute("UPDATE temp_mail_documents SET imported_to_documents = 1 WHERE id = ?", (row_id,))
        self.conn.commit()


class TempMailBridge:
    def __init__(self, db: Database):
        self.db = db

    def list_clients(self):
        try:
            return self.db.fetch_all(
                "SELECT id, denominazione, partita_iva, codice_fiscale, mail_azienda FROM clients ORDER BY denominazione COLLATE NOCASE"
            )
        except Exception:
            return []

    def match_client(self, sender: str, subject: str):
        clients = self.list_clients()
        base = normalize_text(sender + " " + subject)
        for row in clients:
            den = normalize_text(row["denominazione"] or "")
            piva = normalize_text(row["partita_iva"] or "")
            cf = normalize_text(row["codice_fiscale"] or "")
            mail = normalize_text(row["mail_azienda"] or "")
            keys = [den, piva, cf]
            if mail:
                keys.append(mail.split("@")[0])
                keys.append(mail)
            for key in keys:
                if key and key in base:
                    return row["id"], row["denominazione"]
        return None, ""

    def import_into_documents(self, temp_row, client_id: int, category: str, title: str):
        client = self.db.get_client(client_id)
        collaborator_id = client["responsible_collaborator_id"] if client and "responsible_collaborator_id" in client.keys() else None
        self.db.archive_external_document(
            client_id,
            temp_row["stored_path"],
            category,
            title,
            notes=f"Importato da Allegati Mail IMAP | Mittente: {temp_row['sender']} | Oggetto: {temp_row['subject']}",
            collaborator_id=collaborator_id,
        )


class TempMailAttachmentFetcher:
    def __init__(self, config: TempMailConfig, target_folder: str | Path, bridge: TempMailBridge | None = None):
        self.config = config
        self.target_folder = Path(target_folder)
        self.target_folder.mkdir(parents=True, exist_ok=True)
        self.bridge = bridge

    def _build_search_criterion(self) -> str:
        scope = (self.config.mail_scope or "tutte").strip().lower()
        if scope == "non lette":
            return "UNSEEN"
        if scope == "lette":
            return "SEEN"
        return "ALL"

    def _collect_uids(self, mail) -> list[bytes]:
        criterion = self._build_search_criterion()
        status, data = mail.uid("search", None, criterion)
        if status == "OK" and data:
            return data[0].split()
        status, data = mail.search(None, criterion)
        if status == "OK" and data:
            return data[0].split()
        raise RuntimeError(f"Ricerca IMAP non riuscita per il criterio: {criterion}")

    def _is_attachment_part(self, part) -> bool:
        if part.is_multipart():
            return False
        filename = part.get_filename()
        disposition = str(part.get("Content-Disposition") or "").lower()
        if filename:
            return True
        return "attachment" in disposition or "inline" in disposition

    def fetch_attachments(self, store: TempMailDocumentsStore) -> dict:
        if self.config.use_ssl:
            mail = imaplib.IMAP4_SSL(self.config.imap_host, self.config.imap_port, ssl_context=build_ssl_context(bool(getattr(self.config, 'ignore_ssl_verify', False))))
        else:
            mail = imaplib.IMAP4(self.config.imap_host, self.config.imap_port)

        stats = {
            "messages": 0,
            "attachments_found": 0,
            "saved": 0,
            "duplicates": 0,
            "skipped_extension": 0,
        }

        try:
            login_status, login_data = mail.login(self.config.email_address, self.config.password)
            if login_status != "OK":
                raise RuntimeError(f"Login IMAP non riuscito: {login_data}")

            mailbox_name = (self.config.mailbox or "INBOX").strip() or "INBOX"
            select_status, _select_data = mail.select(mailbox_name, readonly=True)
            if select_status != "OK":
                raise RuntimeError(f"Mailbox non accessibile: {mailbox_name}")

            uid_list = self._collect_uids(mail)
            for uid_bytes in uid_list:
                uid = uid_bytes.decode(errors="ignore")
                fetch_status, msg_data = mail.uid("fetch", uid, "(RFC822)")
                if fetch_status != "OK" or not msg_data:
                    continue

                raw = None
                for item in msg_data:
                    if isinstance(item, tuple) and len(item) >= 2:
                        raw = item[1]
                        break
                if not raw:
                    continue

                stats["messages"] += 1
                msg = email.message_from_bytes(raw)

                subject = decode_mime_words(msg.get("Subject"))
                sender = decode_mime_words(msg.get("From"))
                message_id = (msg.get("Message-ID") or "").strip()

                mail_date = ""
                try:
                    if msg.get("Date"):
                        mail_date = parsedate_to_datetime(msg.get("Date")).strftime("%Y-%m-%d %H:%M:%S")
                except Exception:
                    mail_date = ""

                matched_client_id, matched_client_name = (None, "")
                if self.bridge:
                    matched_client_id, matched_client_name = self.bridge.match_client(sender, subject)

                for part in msg.walk():
                    if not self._is_attachment_part(part):
                        continue

                    raw_filename = part.get_filename() or ""
                    filename = sanitize_filename(raw_filename) if raw_filename else ""
                    if not filename:
                        ext_guess = mimetypes.guess_extension(part.get_content_type() or "") or ""
                        filename = f"allegato_{uid}{ext_guess}"

                    suffix = Path(filename).suffix.lower()
                    if self.config.only_pdf:
                        if suffix != ".pdf":
                            stats["skipped_extension"] += 1
                            continue
                    elif suffix and suffix not in ATTACHMENT_EXTENSIONS:
                        stats["skipped_extension"] += 1
                        continue

                    payload = part.get_payload(decode=True)
                    if not payload:
                        continue

                    stats["attachments_found"] += 1
                    safe_name = build_safe_attachment_storage_name(uid, filename)
                    file_path = self.target_folder / safe_name
                    file_path.write_bytes(payload)

                    inserted = store.add_document(
                        email_uid=uid,
                        mail_date=mail_date,
                        sender=sender,
                        subject=subject,
                        filename=filename,
                        stored_path=str(file_path),
                        message_id=message_id,
                        matched_client_id=matched_client_id,
                        matched_client_name=matched_client_name,
                    )
                    if inserted:
                        stats["saved"] += 1
                    else:
                        stats["duplicates"] += 1
                        try:
                            file_path.unlink()
                        except OSError:
                            pass

            return stats
        finally:
            try:
                mail.logout()
            except Exception:
                pass


class TempMailDocumentsWindow(BaseWindow):
    def __init__(self, master, db: Database):
        super().__init__(master, "Allegati Mail IMAP", "1380x820")
        self.main_db = db
        self.bridge = TempMailBridge(self.main_db)
        self.base_dir = get_app_data_dir() / "mail_imap"
        self.base_dir.mkdir(parents=True, exist_ok=True)
        self.attachments_dir = self.base_dir / "allegati"
        self.attachments_dir.mkdir(parents=True, exist_ok=True)
        self.store = TempMailDocumentsStore(self.base_dir / "temporanea_documenti_mail.db")
        self.config_data = self.store.load_settings()

        self._build_ui()
        self._load_settings_into_ui()
        self.refresh_table()

    def _build_ui(self):
        outer = ttk.Frame(self.content_frame, padding=14)
        outer.pack(fill="both", expand=True)

        cfg = ttk.LabelFrame(outer, text="Configurazione mail IMAP / Aruba SMTP", padding=12)
        cfg.pack(fill="x", pady=(0, 10))
        for i in range(8):
            cfg.columnconfigure(i, weight=1)

        self.host_var = tk.StringVar(value="imaps.aruba.it")
        self.port_var = tk.StringVar(value="993")
        self.email_var = tk.StringVar(value="pratice@financeplus.tech")
        self.password_var = tk.StringVar(value="123Dd456@7")
        self.mailbox_var = tk.StringVar(value="INBOX")
        self.ignore_ssl_verify_var = tk.BooleanVar(value=False)
        self.only_pdf_var = tk.BooleanVar(value=False)
        self.mail_scope_var = tk.StringVar(value="tutte")
        self.smtp_enabled_var = tk.BooleanVar(value=True)
        self.smtp_host_var = tk.StringVar(value="smtps.aruba.it")
        self.smtp_port_var = tk.StringVar(value="465")
        self.smtp_from_name_var = tk.StringVar(value=BRAND_NAME)
        self.smtp_default_sender_var = tk.StringVar(value="principale")
        self.alt_email_var = tk.StringVar(value="d.dangelo@financeplus.tech")
        self.alt_password_var = tk.StringVar(value="123Dd456@7")
        self.imap_sender_var = tk.StringVar(value="principale")
        self.alt_smtp_enabled_var = tk.BooleanVar(value=True)
        self.alt_smtp_host_var = tk.StringVar(value="smtps.aruba.it")
        self.alt_smtp_port_var = tk.StringVar(value="465")
        self.alt_smtp_from_name_var = tk.StringVar(value=BRAND_NAME)

        fields = [
            ("Host IMAP", self.host_var, 0, 0),
            ("Porta", self.port_var, 0, 2),
            ("Email Aruba principale", self.email_var, 1, 0),
            ("Password / App Password", self.password_var, 1, 2),
            ("Mailbox", self.mailbox_var, 2, 0),
            ("Host SMTP Aruba", self.smtp_host_var, 3, 0),
            ("Porta SMTP", self.smtp_port_var, 3, 2),
            ("Nome mittente", self.smtp_from_name_var, 4, 0),
        ]
        for label, var, r, c in fields:
            ttk.Label(cfg, text=label + ":").grid(row=r, column=c, sticky="w", padx=(0, 8), pady=6)
            entry = ttk.Entry(cfg, textvariable=var)
            entry.grid(row=r, column=c + 1, sticky="ew", padx=(0, 12), pady=6)

        ttk.Label(cfg, text="Casella da leggere:").grid(row=1, column=4, sticky="e", padx=(0, 8), pady=6)
        ttk.Combobox(cfg, textvariable=self.imap_sender_var, values=["principale", "secondaria"], state="readonly", width=14).grid(row=1, column=5, sticky="w", pady=6)
        ttk.Checkbutton(cfg, text="Scarica solo PDF", variable=self.only_pdf_var).grid(row=2, column=2, sticky="w", pady=6)
        ttk.Checkbutton(cfg, text="Ignora verifica certificato SSL", variable=self.ignore_ssl_verify_var).grid(row=3, column=3, columnspan=2, sticky="w", pady=6)
        ttk.Label(cfg, text="Messaggi:").grid(row=2, column=3, sticky="e", padx=(0, 8), pady=6)
