    def _bind_tree_scrolling(self):
        widgets = [self.tree]
        for widget in widgets:
            widget.bind("<MouseWheel>", self._on_tree_mousewheel, add="+")
            widget.bind("<Shift-MouseWheel>", self._on_tree_shift_mousewheel, add="+")
            widget.bind("<Button-4>", self._on_tree_linux_up, add="+")
            widget.bind("<Button-5>", self._on_tree_linux_down, add="+")
            widget.bind("<Shift-Button-4>", self._on_tree_linux_shift_up, add="+")
            widget.bind("<Shift-Button-5>", self._on_tree_linux_shift_down, add="+")

    def _on_tree_mousewheel(self, event):
        delta = event.delta
        if delta == 0:
            return "break"
        self.tree.yview_scroll(int(-delta / 120), "units")
        return "break"

    def _on_tree_shift_mousewheel(self, event):
        delta = event.delta
        if delta == 0:
            return "break"
        self.tree.xview_scroll(int(-delta / 120), "units")
        return "break"

    def _on_tree_linux_up(self, _event):
        self.tree.yview_scroll(-1, "units")
        return "break"

    def _on_tree_linux_down(self, _event):
        self.tree.yview_scroll(1, "units")
        return "break"

    def _on_tree_linux_shift_up(self, _event):
        self.tree.xview_scroll(-1, "units")
        return "break"

    def _on_tree_linux_shift_down(self, _event):
        self.tree.xview_scroll(1, "units")
        return "break"

    def _load_settings_into_ui(self):
        cfg = self.config_data
        self.host_var.set('imaps.aruba.it')
        self.port_var.set(str(getattr(cfg, 'imap_port', 993) or 993))
        self.email_var.set('pratice@financeplus.tech')
        self.password_var.set(getattr(cfg, 'password', '') or '123Dd456@7')
        imap_sender = (getattr(cfg, 'imap_sender', 'principale') or 'principale').strip().lower()
        if imap_sender not in {'principale', 'secondaria'}:
            imap_sender = 'principale'
        self.imap_sender_var.set(imap_sender)
        self.mailbox_var.set((getattr(cfg, 'mailbox', 'INBOX') or 'INBOX').strip() or 'INBOX')
        self.ignore_ssl_verify_var.set(bool(getattr(cfg, 'ignore_ssl_verify', False)))
        self.only_pdf_var.set(bool(getattr(cfg, 'only_pdf', False)))
        scope = (getattr(cfg, 'mail_scope', 'tutte') or 'tutte').strip().lower()
        if scope not in {"tutte", "non lette", "lette"}:
            scope = "tutte"
        self.mail_scope_var.set(scope)
        self.smtp_enabled_var.set(True)
        self.smtp_host_var.set('smtps.aruba.it')
        self.smtp_port_var.set(str(getattr(cfg, 'smtp_port', 465) or 465))
        self.smtp_from_name_var.set((getattr(cfg, 'smtp_from_name', BRAND_NAME) or BRAND_NAME).strip())
        default_sender = (getattr(cfg, 'smtp_default_sender', 'principale') or 'principale').strip().lower()
        if default_sender not in {'principale', 'secondario'}:
            default_sender = 'principale'
        self.smtp_default_sender_var.set(default_sender)
        self.alt_email_var.set('d.dangelo@financeplus.tech')
        self.alt_password_var.set(getattr(cfg, 'alt_password', '') or '123Dd456@7')
        self.alt_smtp_enabled_var.set(True)
        self.alt_smtp_host_var.set('smtps.aruba.it')
        self.alt_smtp_port_var.set(str(getattr(cfg, 'alt_smtp_port', 465) or 465))
        self.alt_smtp_from_name_var.set((getattr(cfg, 'alt_smtp_from_name', BRAND_NAME) or BRAND_NAME).strip())

    def build_config(self) -> TempMailConfig:
        try:
            port = int(self.port_var.get().strip() or "993")
        except ValueError:
            port = 993
        try:
            smtp_port = int(self.smtp_port_var.get().strip() or "465")
        except ValueError:
            smtp_port = 465
        try:
            alt_smtp_port = int(self.alt_smtp_port_var.get().strip() or "465")
        except ValueError:
            alt_smtp_port = 465
        email_address = self.email_var.get().strip()
        alt_email_address = self.alt_email_var.get().strip()
        smtp_host = self.smtp_host_var.get().strip() or guess_aruba_smtp_host(email_address)
        alt_smtp_host = self.alt_smtp_host_var.get().strip() or guess_aruba_smtp_host(alt_email_address)
        return TempMailConfig(
            imap_host=self.host_var.get().strip(),
            imap_port=port,
            email_address=email_address,
            password=self.password_var.get().strip(),
            mailbox=self.mailbox_var.get().strip() or "INBOX",
            use_ssl=True,
            ignore_ssl_verify=self.ignore_ssl_verify_var.get(),
            only_pdf=self.only_pdf_var.get(),
            mail_scope=(self.mail_scope_var.get().strip().lower() or "tutte"),
            smtp_enabled=self.smtp_enabled_var.get(),
            smtp_host=smtp_host,
            smtp_port=smtp_port,
            smtp_use_ssl=True,
            smtp_from_name=self.smtp_from_name_var.get().strip() or BRAND_NAME,
            smtp_default_sender=(self.smtp_default_sender_var.get().strip().lower() or 'principale'),
            alt_email_address=alt_email_address,
            alt_password=self.alt_password_var.get().strip(),
            alt_smtp_enabled=self.alt_smtp_enabled_var.get(),
            alt_smtp_host=alt_smtp_host if alt_email_address else '',
            alt_smtp_port=alt_smtp_port,
            alt_smtp_use_ssl=True,
            alt_smtp_from_name=self.alt_smtp_from_name_var.get().strip() or BRAND_NAME,
        )

    def save_settings(self):
        cfg = self.build_config()
        self.store.save_settings(cfg)
        messagebox.showinfo("Configurazione", "Configurazione salvata correttamente.")

    def _build_effective_imap_config(self, sender_key='principale'):
        cfg = self.build_config()
        chosen = (sender_key or cfg.imap_sender or 'principale').strip().lower()
        effective_cfg = TempMailConfig(**cfg.__dict__)
        if chosen == 'secondaria':
            effective_cfg.email_address = (cfg.alt_email_address or '').strip()
            effective_cfg.password = (cfg.alt_password or '').strip()
        else:
            effective_cfg.email_address = (cfg.email_address or '').strip()
            effective_cfg.password = (cfg.password or '').strip()
        return cfg, effective_cfg, chosen

    def _explain_mail_error(self, exc: Exception, email_address: str) -> str:
        raw = str(exc) or exc.__class__.__name__
        lower = raw.lower()
        tips = []
        if 'authenticationfailed' in lower or 'invalid credentials' in lower or 'login failed' in lower:
            tips.append(f"Il server Aruba ha rifiutato user/password per {email_address}.")
            tips.append("Controlla che la casella esista davvero e che la password sia quella della singola mailbox.")
            tips.append("Prova anche l'accesso dalla Webmail Aruba con le stesse credenziali.")
        elif 'mailbox non riuscita' in lower or 'select' in lower:
            tips.append("Login riuscito ma apertura cartella non riuscita. Controlla il nome mailbox, di solito INBOX.")
        elif 'timed out' in lower or 'timeout' in lower:
            tips.append("Il server non risponde in tempo: controlla connessione, firewall o antivirus.")
        elif 'certificate_verify_failed' in lower or 'ssl: certificate_verify_failed' in lower or 'self signed certificate' in lower or 'unable to get local issuer certificate' in lower:
            tips.append("Problema di certificato SSL/TLS sul PC o nell'ambiente Python.")
            tips.append("Attiva la casella 'Ignora verifica certificato SSL' e riprova.")
            tips.append("Per Aruba usa IMAP 993 SSL e SMTP 465 SSL.")
        elif 'ssl' in lower or 'tls' in lower:
            tips.append("Possibile problema SSL/TLS. Per Aruba usa IMAP 993 SSL e SMTP 465 SSL.")
            tips.append("Se il problema continua, attiva 'Ignora verifica certificato SSL'.")
        if not tips:
            tips.append("Errore tecnico restituito dal server o dalla connessione.")
        return raw + "\n\n" + "\n".join(tips)

    def test_imap_login(self, sender_key='principale'):
        cfg, effective_cfg, chosen = self._build_effective_imap_config(sender_key)
        if not effective_cfg.imap_host or not effective_cfg.email_address or not effective_cfg.password:
            messagebox.showwarning("Attenzione", f"Compila host IMAP, email e password per la casella {chosen}.")
            return
        self.store.save_settings(cfg)
        mail = None
        try:
            if effective_cfg.use_ssl:
                mail = imaplib.IMAP4_SSL(effective_cfg.imap_host, effective_cfg.imap_port, ssl_context=build_ssl_context(bool(getattr(effective_cfg, 'ignore_ssl_verify', False))))
            else:
                mail = imaplib.IMAP4(effective_cfg.imap_host, effective_cfg.imap_port)
            login_status, login_data = mail.login(effective_cfg.email_address, effective_cfg.password)
            if login_status != 'OK':
                raise RuntimeError(f"Login IMAP non riuscito: {login_data}")
            mailbox_name = (effective_cfg.mailbox or 'INBOX').strip() or 'INBOX'
            select_status, _ = mail.select(mailbox_name, readonly=True)
            if select_status != 'OK':
                raise RuntimeError(f"Apertura mailbox non riuscita: {mailbox_name}")
            try:
                status, data = mail.search(None, 'ALL')
                total = len(data[0].split()) if status == 'OK' and data and data[0] else 0
            except Exception:
                total = None
            extra = f"\nMessaggi trovati nella cartella {mailbox_name}: {total}" if total is not None else ""
            messagebox.showinfo("Test IMAP Aruba", f"Connessione IMAP riuscita per {effective_cfg.email_address}.{extra}")
        except Exception as exc:
            messagebox.showerror("Test IMAP Aruba", self._explain_mail_error(exc, effective_cfg.email_address))
        finally:
            if mail is not None:
                try:
                    mail.logout()
                except Exception:
                    pass

    def run_full_mail_diagnostics(self):
        cfg = self.build_config()
        self.store.save_settings(cfg)
        results = []
        for sender_key in ('principale', 'secondaria'):
            _cfg, effective_cfg, _chosen = self._build_effective_imap_config(sender_key)
            label = 'Principale' if sender_key == 'principale' else 'Secondaria'
            if effective_cfg.email_address and effective_cfg.password:
                mail = None
                try:
                    if effective_cfg.use_ssl:
                        mail = imaplib.IMAP4_SSL(effective_cfg.imap_host, effective_cfg.imap_port, ssl_context=build_ssl_context(bool(getattr(effective_cfg, 'ignore_ssl_verify', False))))
                    else:
                        mail = imaplib.IMAP4(effective_cfg.imap_host, effective_cfg.imap_port)
                    login_status, login_data = mail.login(effective_cfg.email_address, effective_cfg.password)
                    if login_status != 'OK':
                        raise RuntimeError(f"Login IMAP non riuscito: {login_data}")
                    mailbox_name = (effective_cfg.mailbox or 'INBOX').strip() or 'INBOX'
                    select_status, _ = mail.select(mailbox_name, readonly=True)
                    if select_status != 'OK':
                        raise RuntimeError(f"Apertura mailbox non riuscita: {mailbox_name}")
                    results.append(f"{label} IMAP: OK ({effective_cfg.email_address})")
                except Exception as exc:
                    results.append(f"{label} IMAP: KO ({effective_cfg.email_address})")
                    results.append(self._explain_mail_error(exc, effective_cfg.email_address))
                finally:
                    if mail is not None:
                        try:
                            mail.logout()
                        except Exception:
                            pass
            else:
                results.append(f"{label} IMAP: campi email/password mancanti")
            profile = resolve_smtp_profile(cfg.__dict__, sender_key='secondario' if sender_key == 'secondaria' else 'principale')
            if profile.get('email_address') and profile.get('password') and profile.get('smtp_enabled'):
                try:
                    if profile.get('smtp_use_ssl', True):
                        with smtplib.SMTP_SSL(profile.get('smtp_host'), int(profile.get('smtp_port') or 465), context=build_ssl_context(ignore_ssl_verify), timeout=20) as server:
                            server.login(profile.get('email_address'), profile.get('password'))
                    else:
                        with smtplib.SMTP(profile.get('smtp_host'), int(profile.get('smtp_port') or 465), timeout=20) as server:
                            server.starttls(context=build_ssl_context(ignore_ssl_verify))
                            server.login(profile.get('email_address'), profile.get('password'))
                    results.append(f"{label} SMTP: OK ({profile.get('email_address')})")
                except Exception as exc:
                    results.append(f"{label} SMTP: KO ({profile.get('email_address')})")
                    results.append(self._explain_mail_error(exc, profile.get('email_address')))
            else:
                results.append(f"{label} SMTP: campi mancanti o invio non attivo")
            results.append('')
        messagebox.showinfo("Diagnostica completa mail", "\n".join(results).strip())

    def test_smtp_send(self, sender_key='principale'):
        cfg = self.build_config()
        profile = resolve_smtp_profile(cfg.__dict__, sender_key=sender_key)
        if not profile.get('email_address') or not profile.get('password'):
            messagebox.showwarning("Attenzione", f"Compila email e password/app password Aruba per il mittente {sender_key}.")
            return
        recipient = simple_input_dialog(self, "Test Aruba SMTP", "Inserisci l'indirizzo email destinatario per il test:", initial=profile.get('email_address') or '')
        if not recipient:
            return
        self.store.save_settings(cfg)
        ok, info = send_email_via_smtp(
            subject="Test collegamento Aruba SMTP",
            plain_body="Questa e una email di test inviata dal gestionale tramite Aruba SMTP.",
            attachments=[],
            to=recipient,
            config=cfg.__dict__,
            sender_key=sender_key,
        )
        if ok:
            messagebox.showinfo("Aruba SMTP", f"Email di test inviata correttamente.\n\n{info}")
        else:
            messagebox.showerror("Aruba SMTP", f"Invio non riuscito.\n\n{info}")

    def sync_mail(self):
        cfg = self.build_config()
        chosen = (cfg.imap_sender or 'principale').strip().lower()
        effective_cfg = TempMailConfig(**cfg.__dict__)
        if chosen == 'secondaria':
            effective_cfg.email_address = (cfg.alt_email_address or '').strip()
            effective_cfg.password = (cfg.alt_password or '').strip()
        if not effective_cfg.imap_host or not effective_cfg.email_address or not effective_cfg.password:
            messagebox.showwarning("Attenzione", f"Compila host IMAP, email e password/app password per la casella {chosen}.")
            return
        self.store.save_settings(cfg)
        try:
            fetcher = TempMailAttachmentFetcher(effective_cfg, self.attachments_dir, self.bridge)
            stats = fetcher.fetch_attachments(self.store)
            self.refresh_table()
            messagebox.showinfo(
                "Completato",
                (
                    f"Casella letta: {effective_cfg.email_address}\n"
                    f"Messaggi letti: {stats['messages']}\n"
                    f"Allegati trovati: {stats['attachments_found']}\n"
                    f"Nuovi allegati salvati: {stats['saved']}\n"
                    f"Duplicati gia presenti: {stats['duplicates']}\n"
                    f"Saltati per estensione/filtro: {stats['skipped_extension']}"
                ),
            )
        except Exception as exc:
            messagebox.showerror("Errore", f"Impossibile scaricare gli allegati.\n\n{exc}")


    def refresh_table(self):
        for item in self.tree.get_children():
            self.tree.delete(item)
        for row in self.store.list_documents():
            self.tree.insert(
                "",
                "end",
                iid=str(row["id"]),
                values=(
                    row["mail_date"] or "",
                    row["sender"] or "",
                    row["subject"] or "",
                    row["filename"] or "",
                    row["matched_client_name"] or "",
                    "Si" if row["imported_to_documents"] else "No",
                    row["stored_path"] or "",
                ),
            )

    def selected_row(self):
        selection = self.tree.selection()
        if not selection:
            return None
        return self.store.get_document(int(selection[0]))

    def open_selected(self):
        row = self.selected_row()
        if not row:
            messagebox.showwarning("Attenzione", "Seleziona un allegato.")
            return
        open_path(row["stored_path"])

    def delete_selected(self):
        row = self.selected_row()
        if not row:
            messagebox.showwarning("Attenzione", "Seleziona un allegato.")
            return
        if not messagebox.askyesno("Conferma", "Vuoi eliminare l'allegato selezionato?"):
            return
        self.store.delete_document(row["id"])
        self.refresh_table()

    def import_selected(self):
        row = self.selected_row()
        if not row:
            messagebox.showwarning("Attenzione", "Seleziona un allegato.")
            return
        if row["imported_to_documents"]:
            if not messagebox.askyesno("Documento già importato", "Questo allegato risulta già importato. Vuoi importarlo di nuovo?"):
                return

        clients = self.bridge.list_clients()
        choice_map = {f"{r['denominazione']} (ID {r['id']})": r["id"] for r in clients}
        if not choice_map:
            messagebox.showwarning("Attenzione", "Non ci sono clienti disponibili nel gestionale.")
            return

        dialog = tk.Toplevel(self)
        dialog.title("Importa in Gestione Documenti")
        dialog.transient(self)
        dialog.grab_set()
        dialog.geometry("660x260")

        ttk.Label(dialog, text="Cliente:").pack(anchor="w", padx=14, pady=(14, 4))
        combo = ttk.Combobox(dialog, values=list(choice_map.keys()), state="readonly", width=68)
        combo.pack(fill="x", padx=14)
        if row["matched_client_name"]:
            for name in choice_map:
                if row["matched_client_name"] in name:
                    combo.set(name)
                    break
        if not combo.get() and choice_map:
            combo.set(next(iter(choice_map.keys())))

        initial_title = Path(row["filename"]).stem
        detected_cat, detected_reason = infer_document_category(row["stored_path"], fallback="Altro", title=initial_title)
        ttk.Label(dialog, text=f"Catalogazione automatica da nome file e contenuto: {detected_cat} ({detected_reason})", foreground=MUTED_TEXT, wraplength=620).pack(anchor="w", padx=14, pady=(12, 0))

        ttk.Label(dialog, text="Titolo documento:").pack(anchor="w", padx=14, pady=(12, 4))
        title_var = tk.StringVar(value=initial_title)
        ttk.Entry(dialog, textvariable=title_var).pack(fill="x", padx=14)

        def do_import():
            cid = choice_map.get(combo.get())
            if not cid:
                messagebox.showwarning("Attenzione", "Seleziona un cliente.", parent=dialog)
                return
            self.bridge.import_into_documents(
                row,
                cid,
                detected_cat,
                title_var.get().strip() or Path(row["filename"]).stem,
            )
            self.store.mark_imported(row["id"])
            self.refresh_table()
            dialog.destroy()
            messagebox.showinfo("Importazione", "Documento importato in Gestione Documenti.")

        bar = ttk.Frame(dialog)
        bar.pack(fill="x", padx=14, pady=14)
        ttk.Button(bar, text="Importa", command=do_import).pack(side="right")
        ttk.Button(bar, text="Annulla", command=dialog.destroy).pack(side="right", padx=(0, 8))


