    def _build_ce_sheet(self, nb):
        tab = ttk.Frame(nb, padding=10)
        nb.add(tab, text="Conto economico")
        ttk.Label(tab, text="Conto economico: ricavi, margini e oneri", font=("Segoe UI", 11, "bold")).pack(anchor="w", pady=(0, 8))
        table = ttk.Frame(tab)
        table.pack(anchor="nw")
        ttk.Label(table, text="Voce", width=26).grid(row=0, column=0, padx=4, pady=4)
        for c, y in enumerate(self.YEARS, start=1):
            ttk.Label(table, text=y, width=16).grid(row=0, column=c, padx=4, pady=4)
        for r, field in enumerate(self.CE_FIELDS, start=1):
            ttk.Label(table, text=field, width=26).grid(row=r, column=0, sticky="w", padx=4, pady=3)
            for c, y in enumerate(self.YEARS, start=1):
                self._make_entry(table, f"ce|{field}|{y}").grid(row=r, column=c, padx=4, pady=3)
        ttk.Button(tab, text="Calcola KPI Conto Economico", command=self._refresh_kpi_preview).pack(anchor="w", pady=12)

    def _build_scroll_table(self, parent):
        canvas = tk.Canvas(parent, bg=BG_COLOR, highlightthickness=0)
        ybar = ttk.Scrollbar(parent, orient="vertical", command=canvas.yview)
        frame = ttk.Frame(canvas)
        frame.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
        canvas.create_window((0, 0), window=frame, anchor="nw")
        canvas.configure(yscrollcommand=ybar.set)
        bind_mousewheel_to_canvas(canvas, parent)
        canvas.pack(side="left", fill="both", expand=True)
        ybar.pack(side="right", fill="y")
        return frame

    def _build_cr_sheet(self, nb):
        tab = ttk.Frame(nb, padding=10)
        nb.add(tab, text="Centrale Rischi 36 mesi")
        ttk.Label(tab, text="Inserisci accordato, utilizzato, sconfinamenti e ritardi per 36 mesi", font=("Segoe UI", 11, "bold")).pack(anchor="w", pady=(0, 8))
        body = ttk.Frame(tab)
        body.pack(fill="both", expand=True)
