def prew_parse_amount(value) -> float:
    try:
        parsed = parse_number(str(value or ""))
        return float(parsed or 0)
    except Exception:
        return 0.0


def prew_read_document(row, max_chars: int = 70000) -> str:
    path = row["stored_path"] if row and "stored_path" in row.keys() else ""
    try:
        reader = globals().get("_sp_read_any_document_text")
        if callable(reader):
            text = reader(path, max_chars=max_chars)
            if text:
                return text[:max_chars]
    except Exception:
        pass
    try:
        ext = Path(path).suffix.lower()
        if ext == ".pdf":
            return safe_read_pdf_text(path, max_pages=30, max_chars=max_chars)
        if ext in {".txt", ".csv", ".md", ".log"}:
            return Path(path).read_text(encoding="utf-8", errors="ignore")[:max_chars]
    except Exception:
        return ""
    return ""


def prew_find_value(text: str, labels: list[str]) -> float:
    finder = globals().get("_sp_find_value")
    if callable(finder):
        try:
            return float(finder(text, labels) or 0)
        except Exception:
            pass
    clean = normalize_category(text or "")
    for label in labels:
        idx = clean.find(normalize_category(label))
        if idx >= 0:
            window = text[idx:idx + 320]
            nums = re.findall(r"[-+]?\d{1,3}(?:[\.\s]\d{3})*(?:,\d+)?|[-+]?\d+(?:,\d+|\.\d+)?", window)
            vals = [prew_parse_amount(x) for x in nums]
            vals = [v for v in vals if abs(v) > 0 and not (1900 <= abs(v) <= 2100)]
            if vals:
                return vals[0]
    return 0.0


def prew_pct(value) -> str:
    return "-" if value is None else f"{value*100:.1f}%"


def prew_ratio(value) -> str:
    if value is None:
        return "-"
    if abs(value) > 90:
        return "> 90x"
    return f"{value:.2f}x"


def prew_payment(amount: float, months: int, annual_rate: float) -> tuple[float, float]:
    amount = max(0.0, amount or 0)
    months = max(1, int(months or 60))
    monthly_rate = max(0.0, annual_rate or 0) / 12
    if amount <= 0:
        return 0.0, 0.0
    if monthly_rate == 0:
        monthly = amount / months
    else:
        monthly = amount * (monthly_rate / (1 - (1 + monthly_rate) ** (-months)))
    return monthly, monthly * 12


def prew_safe_div(a, b):
    try:
        if b in (0, None):
            return None
        return a / b
    except Exception:
        return None


def prew_match_checklist(doc_infos: list[dict]) -> tuple[list[dict], dict]:
    rows = []
    complete = 0
    required_missing = 0
    for area, doc, required, keys in PREW_DOC_CHECKLIST:
        match = ""
        for info in doc_infos:
            hay = normalize_category(" ".join([info.get("category", ""), info.get("detected", ""), info.get("title", ""), info.get("filename", ""), info.get("text", "")[:1500]]))
            if any(normalize_category(k) in hay for k in keys):
                match = info.get("title") or info.get("filename") or ""
                break
        if match:
            complete += 1
        elif required:
            required_missing += 1
        rows.append({
            "area": area,
            "documento": doc,
            "obbligatorio": "Sì" if required else "No",
            "stato": "Completo" if match else "Da raccogliere",
            "trovato": match or "-",
        })
    summary = {
        "totale": len(PREW_DOC_CHECKLIST),
        "completi": complete,
        "avanzamento": complete / len(PREW_DOC_CHECKLIST) if PREW_DOC_CHECKLIST else 0,
        "obbligatori_mancanti": required_missing,
    }
    return rows, summary


def prew_analyze(client, document_rows, amount: float, months: int, rate: float) -> dict:
    doc_infos = []
    all_text_parts = []
    for row in document_rows:
        detected, reason = infer_document_category(row["stored_path"] or row["original_filename"] or row["title"], fallback=row["category"] or "Altro")
        text = prew_read_document(row)
        info = {
            "id": row["id"],
            "title": row["title"] or row["original_filename"] or f"Documento {row['id']}",
            "filename": row["original_filename"] or "",
            "category": row["category"] or "",
            "detected": detected,
            "reason": reason,
            "path": row["stored_path"] or "",
            "read": "OK" if text.strip() else "Solo metadati",
            "text": text,
        }
        doc_infos.append(info)
        if text:
            all_text_parts.append(text)
    all_text = "\n".join(all_text_parts)

    ricavi = prew_find_value(all_text, ["ricavi annui", "ricavi", "fatturato", "valore della produzione"])
    ebitda = prew_find_value(all_text, ["ebitda", "margine operativo lordo", "mol"])
    ebit = prew_find_value(all_text, ["ebit", "risultato operativo"])
    utile = prew_find_value(all_text, ["utile netto", "risultato d esercizio", "utile dell esercizio"])
    patrimonio = prew_find_value(all_text, ["patrimonio netto", "totale patrimonio netto"])
    debiti_fin = prew_find_value(all_text, ["debiti finanziari lordi", "debiti verso banche", "debiti bancari", "banche passive", "debito residuo"])
    liquidita = prew_find_value(all_text, ["liquidita", "disponibilita liquide", "cassa", "banche attive", "saldo disponibile"])
    crediti = prew_find_value(all_text, ["crediti commerciali", "crediti verso clienti", "crediti clienti"])
    attivo_corrente = prew_find_value(all_text, ["attivo corrente", "attivo circolante"])
    passivo_corrente = prew_find_value(all_text, ["passivo corrente", "passivita correnti", "debiti a breve"])
    debiti_fornitori = prew_find_value(all_text, ["debiti verso fornitori", "debiti fornitori"])
    acquisti = prew_find_value(all_text, ["acquisti", "costi fornitori", "costo del venduto"])
    oneri = prew_find_value(all_text, ["oneri finanziari", "interessi passivi"])
    cash_flow = prew_find_value(all_text, ["flusso di cassa operativo", "cash flow operativo", "cash-flow", "cash flow"])
    capex = prew_find_value(all_text, ["capex", "investimenti minimi", "investimenti ricorrenti"])
    imposte = prew_find_value(all_text, ["imposte", "assorbimenti ricorrenti"])
    rate_esistenti = prew_find_value(all_text, ["rate annue debiti esistenti", "rate finanziamenti", "rate annue"])
    accordato = prew_find_value(all_text, ["accordato", "accordato operativo", "totale accordato"])
    utilizzato = prew_find_value(all_text, ["utilizzato", "utilizzato operativo", "totale utilizzato"])
    sconfini = prew_find_value(all_text, ["sconfinamenti", "sconfino", "extra fido", "past due"])
    ritardi = prew_find_value(all_text, ["ritardi", "rate scadute", "insoluti"])
    pfn = prew_find_value(all_text, ["posizione finanziaria netta", "pfn"])

    if not pfn and (debiti_fin or liquidita):
        pfn = debiti_fin - liquidita
    if not attivo_corrente and (liquidita or crediti):
        attivo_corrente = liquidita + crediti
    if not passivo_corrente and (debiti_fornitori or debiti_fin):
        passivo_corrente = debiti_fornitori + debiti_fin * 0.35
    estimated_notes = []
    if not cash_flow and ebitda:
        cash_flow = ebitda * 0.65
        estimated_notes.append("Cash flow stimato prudenzialmente al 65% dell'EBITDA perché non letto nei documenti.")

    monthly_new, annual_new = prew_payment(amount, months, rate)
    flusso_disponibile = cash_flow - capex - imposte
    rate_totali = rate_esistenti + annual_new

    ebitda_margin = prew_safe_div(ebitda, ricavi)
    debt_equity = prew_safe_div(debiti_fin, patrimonio)
    current_ratio = prew_safe_div(attivo_corrente, passivo_corrente)
    quick_ratio = prew_safe_div(liquidita + crediti, passivo_corrente)
    ccn = attivo_corrente - passivo_corrente
    pfn_ebitda = prew_safe_div(pfn, ebitda)
    dscr = prew_safe_div(flusso_disponibile, rate_totali)
    interest_coverage = prew_safe_div(ebitda, oneri)
    rata_ebitda = prew_safe_div(annual_new, ebitda)
    utilizzo_cr = prew_safe_div(utilizzato, accordato)
    giorni_incasso = prew_safe_div(crediti * 365, ricavi)
    giorni_pagamento = prew_safe_div(debiti_fornitori * 365, acquisti)

    checklist, doc_summary = prew_match_checklist(doc_infos)

    redd = 0
    redd += 6 if ebitda_margin is not None and ebitda_margin > 0.10 else 3 if ebitda_margin is not None and ebitda_margin >= 0.05 else 0
    redd += 5 if (ebit and ebit > 0) or (utile and utile > 0) else 0
    redd += 5 if patrimonio > 0 else 0
    redd += 4 if debt_equity is not None and debt_equity < 2 else 2 if debt_equity is not None and debt_equity < 4 else 0
    redd += 3 if ricavi > 0 else 0
    redd += 2 if utile > 0 else 0
    redd = min(redd, 25)

    liq = 0
    liq += 4 if current_ratio is not None and current_ratio > 1.30 else 2 if current_ratio is not None and current_ratio >= 1 else 0
    liq += 3 if quick_ratio is not None and quick_ratio > 1 else 1.5 if quick_ratio is not None and quick_ratio >= 0.70 else 0
    liq += 3 if ccn > 0 else 0
    liq += 2 if giorni_incasso is not None and giorni_incasso < 90 else 1 if giorni_incasso is not None and giorni_incasso <= 150 else 0
    liq += 2 if giorni_pagamento is not None and giorni_pagamento < 120 else 1 if giorni_pagamento is not None and giorni_pagamento <= 180 else 0
    liq += 1 if liquidita > 0 else 0
    liq = min(liq, 15)

    sosten = 0
    sosten += 7 if pfn_ebitda is not None and pfn_ebitda < 2.5 else 4 if pfn_ebitda is not None and pfn_ebitda <= 4 else 0
    sosten += 7 if dscr is not None and dscr > 1.30 else 4 if dscr is not None and dscr >= 1 else 0
    sosten += 4 if interest_coverage is not None and interest_coverage > 4 else 2 if interest_coverage is not None and interest_coverage >= 2 else 0
    sosten += 3 if rata_ebitda is not None and rata_ebitda < 0.20 else 1.5 if rata_ebitda is not None and rata_ebitda <= 0.35 else 0
    sosten += 3 if flusso_disponibile > 0 else 0
    sosten += 1 if 36 <= months <= 84 else 0
    sosten = min(sosten, 25)

    has_cr = any("risch" in normalize_category(d["detected"] + " " + d["title"]) or "cr" in normalize_category(d["title"]) for d in doc_infos)
    has_bank = any(any(k in normalize_category(d["detected"] + " " + d["title"]) for k in ["estratti", "affidamenti", "ammortamento", "finanziamenti"]) for d in doc_infos)
    cr = 0
    cr += 5 if utilizzo_cr is not None and utilizzo_cr < 0.70 else 3 if utilizzo_cr is not None and utilizzo_cr <= 0.90 else 0
    cr += 5 if not sconfini else 2 if sconfini < 1000 else 0
    cr += 4 if not ritardi else 1
    cr += 3 if has_cr else 0
    cr += 3 if has_bank else 0
    cr = min(cr, 20)

    has_rating = any(any(k in normalize_category(d["detected"] + " " + d["title"]) for k in ["mcc", "more", "scoring", "rating"]) for d in doc_infos)
    has_neg = any(k in normalize_category(all_text[:10000]) for k in ["protesto", "pregiudizievole", "fallimento", "liquidazione giudiziale"])
    rating = 0
    rating += 7 if has_rating else 0
    rating += 3 if not has_neg else 0
    rating += 3 if amount > 0 else 0
    rating += 2 if doc_summary["avanzamento"] >= 0.90 else 1 if doc_summary["avanzamento"] >= 0.60 else 0
    rating = min(rating, 15)

    areas = [
        {"area": "Redditività e solidità", "peso": 25, "punti": round(redd, 1)},
        {"area": "Liquidità e circolante", "peso": 15, "punti": round(liq, 1)},
        {"area": "Sostenibilità debito", "peso": 25, "punti": round(sosten, 1)},
        {"area": "Centrale Rischi e banche", "peso": 20, "punti": round(cr, 1)},
        {"area": "Rating, eventi e richiesta", "peso": 15, "punti": round(rating, 1)},
    ]
    for a in areas:
        a["copertura"] = a["punti"] / a["peso"] if a["peso"] else 0
        a["semaforo"] = "Verde" if a["copertura"] >= 0.72 else "Giallo" if a["copertura"] >= 0.45 else "Rosso"
    score = round(sum(a["punti"] for a in areas), 1)
    esito = "VERDE" if score >= 70 else "GIALLO" if score >= 50 else "ROSSO"
    lettura = "Pratica impostata bene: completare verifiche formali e coerenza istruttoria." if esito == "VERDE" else "Pratica lavorabile, ma serve rafforzare dati, documenti o sostenibilità." if esito == "GIALLO" else "Rischio elevato o documentazione insufficiente: completare e ricalibrare importo/durata."
    actions = []
    if dscr is None or dscr < 1.30:
        actions.append("Portare il DSCR prospettico sopra 1,30: ridurre importo, allungare durata o rafforzare cash flow.")
    if pfn_ebitda is None or pfn_ebitda > 4:
        actions.append("Ridurre PFN/EBITDA o preparare spiegazioni su debito, investimenti e rientro.")
    if doc_summary["obbligatori_mancanti"] > 0:
        actions.append(f"Completare {doc_summary['obbligatori_mancanti']} documenti obbligatori prima dell'invio.")
    if utilizzo_cr is not None and utilizzo_cr > 0.90:
        actions.append("Spiegare utilizzo CR elevato e predisporre evidenze di rientro/saldi aggiornati.")
    if not actions:
        actions.append("Mantenere coerenza tra finalità, importo, durata e documentazione a supporto.")

    kpis = {
        "ricavi": ricavi, "ebitda": ebitda, "utile": utile, "patrimonio_netto": patrimonio,
        "debiti_fin": debiti_fin, "pfn": pfn, "liquidita": liquidita, "crediti": crediti,
        "attivo_corrente": attivo_corrente, "passivo_corrente": passivo_corrente, "debiti_fornitori": debiti_fornitori,
        "cash_flow": cash_flow, "flusso_disponibile": flusso_disponibile, "nuova_rata_mensile": monthly_new,
        "nuova_rata_annua": annual_new, "rate_totali": rate_totali, "accordato_cr": accordato, "utilizzato_cr": utilizzato,
        "sconfinamenti": sconfini, "ritardi": ritardi, "ebitda_margin": ebitda_margin, "debt_equity": debt_equity,
        "current_ratio": current_ratio, "quick_ratio": quick_ratio, "ccn": ccn, "pfn_ebitda": pfn_ebitda,
        "dscr": dscr, "interest_coverage": interest_coverage, "rata_ebitda": rata_ebitda, "utilizzo_cr": utilizzo_cr,
    }
    return {"client_name": client["denominazione"] if client else "Cliente", "score": score, "esito": esito, "lettura": lettura, "areas": areas, "kpis": kpis, "doc_infos": doc_infos, "checklist": checklist, "doc_summary": doc_summary, "actions": actions, "estimated_notes": estimated_notes, "amount": amount, "months": months, "rate": rate, "created_at": datetime.now().strftime("%d/%m/%Y %H:%M")}



