# Financial Pre-Evaluation: collegamento tool HTML a cliente/documenti
# -----------------------------
CREDIT_SCORING_TOOL_WEB_HTML = '<!doctype html>\n<html lang="it">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1">\n<title>Credit Scoring Aziendale - Tool automatico</title>\n<style>\n:root{--bg:#f6f8fb;--card:#fff;--ink:#1f2937;--muted:#64748b;--accent:#1f4e79;--line:#d9e2ec;--soft:#eaf2f8;--warn:#fff2cc}\nbody{margin:0;font-family:Arial,Helvetica,sans-serif;background:var(--bg);color:var(--ink)}\nheader{padding:28px 36px;background:var(--soft);border-bottom:1px solid var(--line)}\nh1{margin:0;font-size:28px;color:var(--accent)}\np{color:var(--muted)}\nmain{padding:24px 36px;max-width:1200px;margin:auto}\n.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:16px}\n.card{background:var(--card);border:1px solid var(--line);border-radius:14px;padding:18px;box-shadow:0 1px 3px rgba(15,23,42,.05)}\n.card h2{font-size:18px;margin:0 0 12px;color:var(--accent)}\nlabel{display:block;font-size:13px;margin-top:10px;color:#334155}\ninput,select{width:100%;box-sizing:border-box;padding:10px;border:1px solid var(--line);border-radius:10px;background:#fff;font-size:14px}\n.input{background:var(--warn)}\nbutton{background:var(--accent);color:#fff;border:0;border-radius:10px;padding:12px 18px;font-size:15px;cursor:pointer;margin-top:18px}\n.kpis{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:14px;margin-top:18px}\n.kpi{background:#fff;border:1px solid var(--line);border-radius:14px;padding:18px}\n.kpi small{color:var(--muted);display:block}\n.kpi strong{font-size:26px;color:var(--accent)}\ntable{width:100%;border-collapse:collapse;margin-top:12px}\nth,td{border-bottom:1px solid var(--line);padding:9px;text-align:left;font-size:14px}\nth{background:#eef5fb;color:#334155}\n.note{font-size:13px;color:var(--muted);line-height:1.45}\n.badge{display:inline-block;border-radius:999px;padding:6px 10px;background:#eef5fb;color:var(--accent);font-weight:bold}\n</style>\n</head>\n<body>\n<header>\n<h1>Credit Scoring Aziendale</h1>\n<p>Tool locale per pre-valutare rating, probabilità di approvazione, rischio default e importo massimo sostenibile.</p>\n</header>\n<main>\n<div class="grid">\n<section class="card">\n<h2>Dati azienda e assunzioni</h2>\n<label>Nome azienda <input id="azienda" class="input" value="Inserire nome"></label>\n<label>Settore <input id="settore" class="input" value="Multi-settore"></label>\n<label>DSCR target banca <input id="dscrTarget" class="input" type="number" step="0.05" value="1.30"></label>\n<label>Tasso annuo stimato nuovo debito <input id="tasso" class="input" type="number" step="0.005" value="0.085"></label>\n<label>Durata finanziamento (anni) <input id="anni" class="input" type="number" step="1" value="5"></label>\n</section>\n\n<section class="card">\n<h2>Bilancio / situazione aggiornata</h2>\n<label>Ricavi <input id="ricavi" class="input" type="number" value="0"></label>\n<label>EBITDA <input id="ebitda" class="input" type="number" value="0"></label>\n<label>EBIT <input id="ebit" class="input" type="number" value="0"></label>\n<label>Oneri finanziari <input id="oneri" class="input" type="number" value="0"></label>\n<label>Debiti finanziari totali <input id="debiti" class="input" type="number" value="0"></label>\n<label>Liquidità <input id="liquidita" class="input" type="number" value="0"></label>\n<label>Patrimonio netto <input id="pn" class="input" type="number" value="0"></label>\n<label>Capex + imposte annue <input id="capexImposte" class="input" type="number" value="0"></label>\n</section>\n\n<section class="card">\n<h2>Centrale Rischi 36 mesi</h2>\n<label>Accordato totale / medio <input id="accordato" class="input" type="number" value="0"></label>\n<label>Utilizzato totale / medio <input id="utilizzato" class="input" type="number" value="0"></label>\n<label>Mesi con sconfinamento <input id="mesiSconf" class="input" type="number" value="0"></label>\n<label>Ritardo massimo giorni <input id="ritardoMax" class="input" type="number" value="0"></label>\n<label>Trend utilizzo ultimi 6 vs precedenti 6 <input id="trend" class="input" type="number" step="0.01" value="0"></label>\n</section>\n\n<section class="card">\n<h2>Andamentale conto ed esposizioni</h2>\n<label>Cash flow medio mensile <input id="cfMensile" class="input" type="number" value="0"></label>\n<label>Saldo medio <input id="saldoMedio" class="input" type="number" value="0"></label>\n<label>Giorni in rosso annui <input id="giorniRosso" class="input" type="number" value="0"></label>\n<label>Volatilità cash flow <input id="volatilita" class="input" type="number" step="0.1" value="0"></label>\n<label>Impegni mensili medi <input id="impegniMensili" class="input" type="number" value="0"></label>\n<button onclick="calcola()">Calcola scoring</button>\n</section>\n</div>\n\n<section class="kpis">\n<div class="kpi"><small>Score totale</small><strong id="score">0.0</strong></div>\n<div class="kpi"><small>Rating</small><strong id="rating">B / CCC</strong></div>\n<div class="kpi"><small>Probabilità approvazione</small><strong id="approvazione">0.0%</strong></div>\n<div class="kpi"><small>Rischio default</small><strong id="pd">0.0%</strong></div>\n<div class="kpi"><small>Importo massimo sostenibile</small><strong id="importo">€0</strong></div>\n<div class="kpi"><small>Fascia rischio</small><strong id="fascia">-</strong></div>\n</section>\n\n<section class="card" style="margin-top:18px">\n<h2>Dettaglio aree</h2>\n<table>\n<thead><tr><th>Area</th><th>Score medio</th><th>Peso</th><th>Contributo</th></tr></thead>\n<tbody id="dettaglio"></tbody>\n</table>\n<p class="note">Il modello è euristico e serve per pre-screening interno. Non sostituisce istruttoria bancaria, CRIF/business information, garanzie, analisi settoriale e policy creditizie dell’intermediario.</p>\n<p><span class="badge" id="messaggio">Inserire dati e calcolare.</span></p>\n</section>\n</main>\n<script>\nconst val=id=>Number(document.getElementById(id).value||0);\nconst euro=n=>new Intl.NumberFormat(\'it-IT\',{style:\'currency\',currency:\'EUR\',minimumFractionDigits:2,maximumFractionDigits:2}).format(Math.max(0,n||0));\nconst pct=n=>(100*Math.max(0,Math.min(1,n||0))).toFixed(1)+\'%\';\nconst clamp=n=>Math.max(0,Math.min(100,n||0));\nfunction rating(score){return score>=90?\'AAA\':score>=85?\'AA\':score>=78?\'A\':score>=70?\'BBB\':score>=60?\'BB\':\'B / CCC\'}\nfunction calcola(){\nlet ricavi=val(\'ricavi\'), ebitda=val(\'ebitda\'), ebit=val(\'ebit\'), oneri=val(\'oneri\'), debiti=val(\'debiti\'), liquidita=val(\'liquidita\'), pn=val(\'pn\');\nlet pfn=debiti-liquidita, ebitdaMargin=ricavi?ebitda/ricavi:0, interest=oneri?ebit/oneri:0, pfnEbitda=ebitda?pfn/ebitda:10, debtEquity=pn?debiti/pn:10;\nlet hasBil=ricavi+ebitda+ebit+debiti+pn!==0;\nlet sBil=[\nhasBil?clamp(50+300*ebitdaMargin):0,\nhasBil?clamp(25*interest):0,\nhasBil?clamp(100-20*pfnEbitda):0,\nhasBil?clamp(100-25*debtEquity):0\n];\nlet accordato=val(\'accordato\'), utilizzato=val(\'utilizzato\'), mesiSconf=val(\'mesiSconf\'), ritardoMax=val(\'ritardoMax\'), trend=val(\'trend\');\nlet utilizzo=accordato?utilizzato/accordato:0, hasCr=accordato+utilizzato!==0;\nlet sCr=[\nhasCr?clamp(100-80*utilizzo):0,\nhasCr?clamp(100-7*mesiSconf):0,\nhasCr?clamp(100-2*ritardoMax):0,\nhasCr?clamp(100-100*Math.max(0,trend)):0\n];\nlet cf=val(\'cfMensile\'), giorni=val(\'giorniRosso\'), vol=val(\'volatilita\'), saldo=val(\'saldoMedio\');\nlet hasEc=cf+giorni+vol+saldo!==0;\nlet sEc=[\nhasEc?clamp(50+0.002*cf):0,\nhasEc?clamp(100-2*giorni):0,\nhasEc?clamp(100-25*vol):0\n];\nlet impegni=val(\'impegniMensili\'), dscr=impegni?ebitda/(impegni*12):0, dscrTarget=val(\'dscrTarget\'), capex=val(\'capexImposte\');\nlet rataSostenibile=Math.max(0,(ebitda-capex)/dscrTarget/12);\nlet hasExp=impegni!==0;\nlet sExp=[\nhasExp?clamp(75*dscr/dscrTarget):0,\nhasExp?clamp(50+0.001*rataSostenibile):0\n];\nlet avg=a=>a.reduce((x,y)=>x+y,0)/a.length;\nlet bil=avg(sBil), cr=avg(sCr), ec=avg(sEc), exp=avg(sExp);\nlet score=bil*0.40+cr*0.30+ec*0.20+exp*0.10;\nlet z=2.2-0.04*score+0.8*pfnEbitda+0.35*mesiSconf+0.02*giorni-0.6*dscr;\nlet pd=1/(1+Math.exp(-z));\nlet approvazione=clamp(20+0.8*score-45*pd)/100;\nlet tasso=val(\'tasso\'), anni=val(\'anni\');\nlet importo=rataSostenibile*12*(1-Math.pow(1+tasso,-anni))/tasso;\nlet fascia=pd<0.05?\'Basso\':pd<0.15?\'Medio\':pd<0.30?\'Alto\':\'Molto alto\';\ndocument.getElementById(\'score\').textContent=score.toFixed(1);\ndocument.getElementById(\'rating\').textContent=rating(score);\ndocument.getElementById(\'approvazione\').textContent=pct(approvazione);\ndocument.getElementById(\'pd\').textContent=pct(pd);\ndocument.getElementById(\'importo\').textContent=euro(importo);\ndocument.getElementById(\'fascia\').textContent=fascia;\ndocument.getElementById(\'messaggio\').textContent=score>=70?\'Pratica potenzialmente approvabile: verificare garanzie, settore e documenti.\':\'Pratica fragile: migliorare DSCR, ridurre sconfinamenti o ridimensionare importo.\';\nlet rows=[[\'Bilancio\',bil,\'40%\',bil*0.40],[\'Centrale Rischi\',cr,\'30%\',cr*0.30],[\'Andamentale conto\',ec,\'20%\',ec*0.20],[\'Esposizioni\',exp,\'10%\',exp*0.10]];\ndocument.getElementById(\'dettaglio\').innerHTML=rows.map(r=>`<tr><td>${r[0]}</td><td>${r[1].toFixed(1)}</td><td>${r[2]}</td><td>${r[3].toFixed(1)}</td></tr>`).join(\'\');\n}\ncalcola();\n</script>\n</body>\n</html>'
CREDIT_SCORING_TOOL_ISTITUTI_HTML = '<!doctype html>\n<html lang="it">\n<head>\n<meta charset="utf-8"/>\n<meta name="viewport" content="width=device-width,initial-scale=1"/>\n<title>Credit Scoring Multi-Istituto - Tool locale</title>\n<style>\n:root{--bg:#f7f9fc;--card:#fff;--ink:#172033;--muted:#667085;--line:#e5e7eb;--blue:#2563eb;--green:#16a34a;--amber:#d97706;--red:#dc2626}\nbody{font-family:Inter,Arial,sans-serif;background:var(--bg);color:var(--ink);margin:0;padding:24px}\nh1{font-size:26px;margin:0 0 8px} h2{font-size:18px;margin:0 0 12px}\np{color:var(--muted);line-height:1.5}.grid{display:grid;grid-template-columns:repeat(12,1fr);gap:16px;max-width:1280px;margin:auto}\n.card{background:var(--card);border:1px solid var(--line);border-radius:18px;padding:18px;box-shadow:0 6px 18px rgba(15,23,42,.05)}\n.col-12{grid-column:span 12}.col-6{grid-column:span 6}.col-4{grid-column:span 4}.col-3{grid-column:span 3}\nlabel{display:block;font-size:12px;color:var(--muted);margin:10px 0 4px}input,select{width:100%;box-sizing:border-box;border:1px solid var(--line);border-radius:10px;padding:10px;background:white}\nbutton{background:var(--blue);color:white;border:0;border-radius:12px;padding:12px 16px;font-weight:700;cursor:pointer}\ntable{width:100%;border-collapse:collapse;font-size:13px}th,td{border-bottom:1px solid var(--line);padding:9px;text-align:left}th{background:#eff6ff}\n.kpi{font-size:28px;font-weight:800}.pill{display:inline-block;border-radius:999px;padding:4px 10px;font-size:12px;font-weight:700}\n.good{background:#dcfce7;color:#166534}.warn{background:#fef3c7;color:#92400e}.bad{background:#fee2e2;color:#991b1b}\nsmall{color:var(--muted)}@media(max-width:800px){.col-6,.col-4,.col-3{grid-column:span 12}}\n</style>\n</head>\n<body>\n<div class="grid">\n<div class="card col-12">\n<h1>Credit Scoring Multi-Istituto</h1>\n<p>Tool locale dimostrativo: stima fattibilità, rischio default e importo richiedibile con modelli proxy ispirati a TeamSystem/MORE, AideXa, MCC/Fondo di Garanzia, Mediocredito e Banca Ifis. Non replica algoritmi proprietari.</p>\n</div>\n\n<div class="card col-6"><h2>Input economico-finanziari</h2>\n<label>Ricavi ultimi (€)</label><input id="ricavi" type="number" value="1150000">\n<label>EBITDA (€)</label><input id="ebitda" type="number" value="230000">\n<label>EBIT (€)</label><input id="ebit" type="number" value="175000">\n<label>Oneri finanziari annui (€)</label><input id="oneri" type="number" value="30000">\n<label>PFN (€)</label><input id="pfn" type="number" value="275000">\n<label>Debiti bancari totali (€)</label><input id="debiti" type="number" value="345000">\n<label>Patrimonio netto (€)</label><input id="pn" type="number" value="231000">\n<label>Attività correnti (€)</label><input id="attcorr" type="number" value="433000">\n<label>Passività correnti (€)</label><input id="passcorr" type="number" value="552000">\n</div>\n\n<div class="card col-6"><h2>Input andamentali e richiesta</h2>\n<label>Cash flow operativo annuo (€)</label><input id="cfo" type="number" value="159400">\n<label>Rate/impegni annui esistenti (€)</label><input id="rate" type="number" value="90000">\n<label>Utilizzo medio Centrale Rischi (%)</label><input id="crutil" type="number" value="76.9">\n<label>Mesi sconfinamento CR</label><input id="sconf" type="number" value="3">\n<label>Mesi past due/ritardi CR</label><input id="ritardi" type="number" value="2">\n<label>Trend utilizzo CR ultimi mesi (%)</label><input id="trend" type="number" value="34.7">\n<label>Cash flow bancario medio mensile (€)</label><input id="cfbanca" type="number" value="10200">\n<label>Giorni saldo negativo annui</label><input id="negativi" type="number" value="12">\n<label>Pregiudizievoli/protesti</label><select id="preg"><option>No</option><option>Sì</option></select>\n<label>Anni attività</label><input id="anni" type="number" value="4">\n<label>Importo richiesto (€)</label><input id="richiesto" type="number" value="150000">\n<label>Tasso annuo stimato (%)</label><input id="tasso" type="number" value="8.5">\n<label>Durata anni</label><input id="durata" type="number" value="5">\n<button onclick="calc()">Calcola scoring</button>\n</div>\n\n<div class="card col-3"><small>Score medio</small><div id="scoreMedio" class="kpi">-</div></div>\n<div class="card col-3"><small>Prob. approvazione media</small><div id="probMedia" class="kpi">-</div></div>\n<div class="card col-3"><small>PD media stimata</small><div id="pdMedia" class="kpi">-</div></div>\n<div class="card col-3"><small>Importo max consigliato</small><div id="impMax" class="kpi">-</div></div>\n\n<div class="card col-12">\n<h2>Confronto istituti</h2>\n<table id="tab"><thead><tr><th>Istituto</th><th>Score</th><th>Rating</th><th>PD</th><th>Prob. approvazione</th><th>Importo richiedibile</th><th>Esito</th><th>Classe</th></tr></thead><tbody></tbody></table>\n</div>\n\n<div class="card col-12">\n<h2>Assunzioni</h2>\n<p>Le logiche sono proxy trasparenti: bilancio, andamentale Centrale Rischi/conti, pregiudizievoli, soglie DSCR, cap su ricavi e EBITDA. Le soglie vanno calibrate su settore, forma tecnica, garanzie, anzianità aziendale e policy effettiva dell’intermediario.</p>\n</div>\n</div>\n\n<script>\nconst fmtEur = n => new Intl.NumberFormat(\'it-IT\',{style:\'currency\',currency:\'EUR\',minimumFractionDigits:2,maximumFractionDigits:2}).format(n||0);\nconst pct = n => ((n||0)*100).toFixed(1)+\'%\';\nfunction val(id){return parseFloat(document.getElementById(id).value)||0}\nfunction scoreClamp(x){return Math.max(0,Math.min(100,x))}\nfunction rating(s){return s>=85?\'AAA\':s>=75?\'A\':s>=65?\'BBB\':s>=50?\'BB\':\'B/CCC\'}\nfunction classe(p){return p>=.80?\'Alta\':p>=.60?\'Medio-alta\':p>=.40?\'Media\':p>=.25?\'Bassa\':\'Critica\'}\nfunction calc(){\n const ricavi=val(\'ricavi\'), ebitda=val(\'ebitda\'), ebit=val(\'ebit\'), oneri=val(\'oneri\'), pfn=val(\'pfn\'), debiti=val(\'debiti\'), pn=val(\'pn\'), att=val(\'attcorr\'), pass=val(\'passcorr\');\n const cfo=val(\'cfo\'), rate=val(\'rate\'), crutil=val(\'crutil\')/100, sconf=val(\'sconf\'), ritardi=val(\'ritardi\'), trend=val(\'trend\')/100, cfb=val(\'cfbanca\'), neg=val(\'negativi\');\n const preg=document.getElementById(\'preg\').value===\'No\'?100:0, anni=val(\'anni\'), richiesto=val(\'richiesto\'), tasso=val(\'tasso\')/100, durata=val(\'durata\');\n const ebMargin=ricavi?ebitda/ricavi:0, de=pn?debiti/pn:99, pfnE=ebitda?pfn/ebitda:99, curr=pass?att/pass:0, ic=oneri?ebit/oneri:0, dscr=rate?cfo/rate:0;\n const comp=[\n  scoreClamp(ebMargin/.15*100), scoreClamp((3-de)/3*100), scoreClamp((5-pfnE)/5*100), scoreClamp(curr/1.5*100), scoreClamp(ic/5*100), scoreClamp(dscr/2*100)\n ];\n const bilancio=comp.reduce((a,b)=>a+b,0)/comp.length;\n const andamento=[\n  scoreClamp((1-crutil)*125), scoreClamp(100-sconf*20), scoreClamp(100-ritardi*35), scoreClamp((.30-trend)/.30*100), scoreClamp(50+cfb/5000*50), scoreClamp(100-neg*2)\n ].reduce((a,b)=>a+b,0)/6;\n const models=[\n  [\'TeamSystem / MORE\',.55,.35,.10,1.30,.25,3.0,50000,2],\n  [\'AideXa\',.35,.50,.15,1.25,.20,2.5,50000,2],\n  [\'MCC / FdG\',.50,.40,.10,1.30,.30,3.5,50000,2],\n  [\'Mediocredito\',.60,.30,.10,1.40,.35,3.0,100000,2],\n  [\'Banca Ifis\',.40,.45,.15,1.25,.22,2.7,50000,2]\n ];\n const tbody=document.querySelector(\'#tab tbody\'); tbody.innerHTML=\'\';\n let sumS=0,sumP=0,sumPd=0,maxImp=0;\n models.forEach(m=>{\n  const [nome,wb,wa,wq,dscrT,capR,capE,minR,minA]=m;\n  const score=wb*bilancio+wa*andamento+wq*preg;\n  const pd=Math.max(.01,Math.min(.60,1/(1+Math.exp((score-55)/8))));\n  const gate=(ricavi>=minR && anni>=minA && preg>0);\n  const rata=Math.max(0,cfo/dscrT-rate);\n  const annuity=tasso? rata*(1-Math.pow(1+tasso,-durata))/tasso : rata*durata;\n  const impBase=Math.min(annuity, ricavi*capR, Math.max(0, ebitda*capE-pfn));\n  const prob=Math.max(0,Math.min(.98,1-pd))*(gate?1:.15);\n  const imp=gate?impBase*prob:Math.min(impBase*prob,50000);\n  const ok=richiesto<=imp?\'Richiesta sostenibile\':\'Ridurre richiesta\';\n  sumS+=score; sumP+=prob; sumPd+=pd; maxImp=Math.max(maxImp,imp);\n  const tr=document.createElement(\'tr\');\n  tr.innerHTML=`<td>${nome}</td><td>${score.toFixed(1)}</td><td>${rating(score)}</td><td>${pct(pd)}</td><td>${pct(prob)}</td><td>${fmtEur(imp)}</td><td>${ok}</td><td><span class="pill ${prob>=.6?\'good\':prob>=.35?\'warn\':\'bad\'}">${classe(prob)}</span></td>`;\n  tbody.appendChild(tr);\n });\n document.getElementById(\'scoreMedio\').textContent=(sumS/models.length).toFixed(1);\n document.getElementById(\'probMedia\').textContent=pct(sumP/models.length);\n document.getElementById(\'pdMedia\').textContent=pct(sumPd/models.length);\n document.getElementById(\'impMax\').textContent=fmtEur(maxImp);\n}\ncalc();\n</script>\n</body></html>'


def prew_num(value, default: float = 0.0) -> float:
    try:
        if value is None:
            return default
        if isinstance(value, float) and (math.isnan(value) or math.isinf(value)):
            return default
        return float(value)
    except Exception:
        return default


def prew_num_str(value, default: float = 0.0, decimals: int = 2) -> str:
    n = prew_num(value, default)
    if abs(n - round(n)) < 0.005:
        return str(int(round(n)))
    return f"{n:.{decimals}f}"


def prew_client_years_active(client) -> int:
    try:
        year = int(str(client["anno_costituzione"] or "").strip()[:4])
        if 1800 <= year <= datetime.now().year:
            return max(0, datetime.now().year - year)
    except Exception:
        pass
    return 3


def prew_client_sector(client) -> str:
    for key in ("settore_attivita", "attivita", "oggetto_sociale"):
        try:
            val = client[key]
            if val:
                return str(val)
        except Exception:
            continue
    return "Multi-settore"


def prew_detect_negative_events(result: dict) -> bool:
    hay = normalize_category(" ".join((info.get("text", "")[:5000] + " " + info.get("title", "")) for info in result.get("doc_infos", [])))
    return any(k in hay for k in ["protesto", "protesti", "pregiudizievole", "pregiudizievoli", "fallimento", "liquidazione giudiziale", "pignoramento"])


def prew_days_or_months_from_value(value: float, *, max_default: int = 0) -> int:
    n = prew_num(value, 0)
    if n <= 0:
        return 0
    if n <= 36:
        return int(round(n))
    return max_default or 1


def prew_build_html_tool_payloads(client, result: dict) -> tuple[dict, dict, list[tuple[str, str]]]:
    k = result.get("kpis", {})
    months = max(1, int(prew_num(result.get("months"), 60)))
    years = max(1, round(months / 12))
    amount = prew_num(result.get("amount"), 0)
    rate = prew_num(result.get("rate"), 0.065)
    anni_attivita = prew_client_years_active(client)
    ricavi = prew_num(k.get("ricavi"), 0)
    ebitda = prew_num(k.get("ebitda"), 0)
    ebit = prew_num(k.get("ebit"), 0) if "ebit" in k else prew_num(k.get("ebitda"), 0) * 0.75
    oneri = prew_num(k.get("oneri_finanziari"), 0) if "oneri_finanziari" in k else 0
    debiti = prew_num(k.get("debiti_fin"), 0)
    liquidita = prew_num(k.get("liquidita"), 0)
    pfn = prew_num(k.get("pfn"), debiti - liquidita)
    pn = prew_num(k.get("patrimonio_netto"), 0)
    attcorr = prew_num(k.get("attivo_corrente"), 0)
    passcorr = prew_num(k.get("passivo_corrente"), 0)
    cash_flow = prew_num(k.get("cash_flow"), 0)
    accordato = prew_num(k.get("accordato_cr"), 0)
    utilizzato = prew_num(k.get("utilizzato_cr"), 0)
    utilizzo = prew_num(k.get("utilizzo_cr"), 0)
    sconfini_raw = prew_num(k.get("sconfinamenti"), 0)
    ritardi_raw = prew_num(k.get("ritardi"), 0)
    impegni_annui_esistenti = max(0, prew_num(k.get("rate_totali"), 0) - prew_num(k.get("nuova_rata_annua"), 0))
    impegni_mensili = impegni_annui_esistenti / 12 if impegni_annui_esistenti else 0
    negative = prew_detect_negative_events(result)
    sector = prew_client_sector(client)
    client_name = result.get("client_name") or (client["denominazione"] if client else "Cliente")

    web_payload = {
        "azienda": client_name,
        "settore": sector,
        "dscrTarget": "1.30",
        "tasso": prew_num_str(rate, 0.065, 4),
        "anni": str(years),
        "ricavi": prew_num_str(ricavi),
        "ebitda": prew_num_str(ebitda),
        "ebit": prew_num_str(ebit),
        "oneri": prew_num_str(oneri),
        "debiti": prew_num_str(debiti),
        "liquidita": prew_num_str(liquidita),
        "pn": prew_num_str(pn),
        "capexImposte": "0",
        "accordato": prew_num_str(accordato),
        "utilizzato": prew_num_str(utilizzato),
        "mesiSconf": str(prew_days_or_months_from_value(sconfini_raw, max_default=1)),
        "ritardoMax": str(prew_days_or_months_from_value(ritardi_raw, max_default=15)),
        "trend": "0",
        "cfMensile": prew_num_str(cash_flow / 12 if cash_flow else 0),
        "saldoMedio": prew_num_str(liquidita),
        "giorniRosso": str(12 if sconfini_raw > 0 else 0),
        "volatilita": "0",
        "impegniMensili": prew_num_str(impegni_mensili),
    }

    istituti_payload = {
        "ricavi": prew_num_str(ricavi),
        "ebitda": prew_num_str(ebitda),
        "ebit": prew_num_str(ebit),
        "oneri": prew_num_str(oneri),
        "pfn": prew_num_str(pfn),
        "debiti": prew_num_str(debiti),
        "pn": prew_num_str(pn),
        "attcorr": prew_num_str(attcorr),
        "passcorr": prew_num_str(passcorr),
        "cfo": prew_num_str(cash_flow),
        "rate": prew_num_str(impegni_annui_esistenti),
        "crutil": prew_num_str(utilizzo * 100 if utilizzo <= 1 else utilizzo, 0, 1),
        "sconf": str(prew_days_or_months_from_value(sconfini_raw, max_default=1)),
        "ritardi": str(prew_days_or_months_from_value(ritardi_raw, max_default=1)),
        "trend": "0",
        "cfbanca": prew_num_str(cash_flow / 12 if cash_flow else 0),
        "negativi": str(12 if sconfini_raw > 0 else 0),
        "preg": "Sì" if negative else "No",
        "anni": str(anni_attivita),
        "richiesto": prew_num_str(amount),
        "tasso": prew_num_str(rate * 100 if rate <= 1 else rate, 8.5, 2),
        "durata": str(years),
    }

    summary_rows = [
        ("Azienda", str(client_name)),
        ("Settore", str(sector)),
        ("Ricavi", format_currency(ricavi)),
        ("EBITDA", format_currency(ebitda)),
        ("Debiti finanziari", format_currency(debiti)),
        ("Liquidità", format_currency(liquidita)),
        ("PFN", format_currency(pfn)),
        ("Patrimonio netto", format_currency(pn)),
        ("Accordato CR", format_currency(accordato)),
        ("Utilizzato CR", format_currency(utilizzato)),
        ("Cash flow operativo", format_currency(cash_flow)),
        ("Impegni annui esistenti", format_currency(impegni_annui_esistenti)),
        ("Importo richiesto", format_currency(amount)),
        ("Durata richiesta", f"{months} mesi"),
    ]
    return web_payload, istituti_payload, summary_rows


def prew_inject_payload_in_html(template: str, payload: dict, *, client_name: str, title: str) -> str:
    safe_payload = json.dumps(payload, ensure_ascii=False)
    safe_client = html.escape(client_name or "Cliente")
    banner = f"""
<div style="max-width:1280px;margin:0 auto 16px;background:#eff6ff;border:1px solid #bfdbfe;border-radius:14px;padding:14px 18px;color:#172033">
  <strong>Dati collegati al cliente:</strong> {safe_client}<br>
  <small>Valori precompilati automaticamente dalla tab Financial Pre-Evaluation e dai documenti collegati al cliente. Puoi modificarli prima del calcolo.</small>
</div>
"""
    script = f"""
<script>
(function() {{
  const payload = {safe_payload};
  function applyPayload() {{
    Object.keys(payload).forEach(function(id) {{
      const el = document.getElementById(id);
      if (!el) return;
      el.value = payload[id];
      el.dispatchEvent(new Event('input', {{bubbles:true}}));
      el.dispatchEvent(new Event('change', {{bubbles:true}}));
    }});
    if (typeof calcola === 'function') calcola();
    if (typeof calc === 'function') calc();
  }}
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', applyPayload);
  else applyPayload();
}})();
</script>
"""
    out = template
    if '<div class="grid">' in out:
        out = out.replace('<div class="grid">', banner + '\\n<div class="grid">', 1)
    elif '<main>' in out:
        out = out.replace('<main>', '<main>\\n' + banner, 1)
    else:
        out = banner + out
    out = out.replace('</body>', script + '\\n</body>') if '</body>' in out else out + script
    return out


def prew_safe_file_part(value: str) -> str:
    value = normalize_category(value or "cliente")
    value = re.sub(r"[^a-z0-9]+", "_", value).strip("_")
    return value[:80] or "cliente"


def prew_generate_client_tool_html(client, result: dict, tool: str) -> Path:
    web_payload, istituti_payload, _rows = prew_build_html_tool_payloads(client, result)
    client_name = result.get("client_name") or (client["denominazione"] if client else "Cliente")
    base_dir = get_app_data_dir() / "financial_pre_evaluation_tools" / prew_safe_file_part(client_name)
    base_dir.mkdir(parents=True, exist_ok=True)
    stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    if tool == "istituti":
        html_text = prew_inject_payload_in_html(CREDIT_SCORING_TOOL_ISTITUTI_HTML, istituti_payload, client_name=client_name, title="Credit Scoring Multi-Istituto")
        out = base_dir / f"multi_istituto_{stamp}.html"
    else:
        html_text = prew_inject_payload_in_html(CREDIT_SCORING_TOOL_WEB_HTML, web_payload, client_name=client_name, title="Credit Scoring Aziendale")
        out = base_dir / f"credit_scoring_aziendale_{stamp}.html"
    out.write_text(html_text, encoding="utf-8")
    return out



def export_prew_pdf(output_path: str, client_row, result: dict) -> None:
    if not REPORTLAB_AVAILABLE:
        raise RuntimeError("ReportLab non disponibile: impossibile generare il PDF.")
    styles = getSampleStyleSheet()
    title = ParagraphStyle("PrewTitle", parent=styles["Heading1"], fontName="Helvetica-Bold", fontSize=18, leading=23, textColor=colors.HexColor("#1f4ea8"), spaceAfter=10)
    h2 = ParagraphStyle("PrewH2", parent=styles["Heading2"], fontName="Helvetica-Bold", fontSize=12, leading=15, textColor=colors.HexColor("#1f4ea8"), spaceBefore=10, spaceAfter=6)
    body = ParagraphStyle("PrewBody", parent=styles["BodyText"], fontName="Helvetica", fontSize=8.8, leading=12, spaceAfter=4)
    small = ParagraphStyle("PrewSmall", parent=styles["BodyText"], fontName="Helvetica", fontSize=7.2, leading=9)
    doc = SimpleDocTemplate(output_path, pagesize=A4, leftMargin=1.5*cm, rightMargin=1.5*cm, topMargin=2.8*cm, bottomMargin=1.4*cm)
    story = [
        Paragraph("FINANCIAL PRE-EVALUATION chirografario aziendale", title),
        Paragraph(f"Cliente: <b>{html.escape(client_row['denominazione'])}</b>", body),
        Paragraph(f"Data analisi: {result['created_at']}", body),
        Spacer(1, 6),
    ]
    meta = [
        ["Punteggio totale", f"{result['score']:.1f}/100", "Esito", result["esito"]],
        ["Importo richiesto", format_currency(result["amount"]), "Durata", f"{result['months']} mesi"],
        ["Nuova rata annua stimata", format_currency(result["kpis"]["nuova_rata_annua"]), "Tasso annuo", f"{result['rate']*100:.2f}%"],
        ["DSCR prospettico", prew_ratio(result["kpis"]["dscr"]), "PFN / EBITDA", prew_ratio(result["kpis"]["pfn_ebitda"])],
        ["Documenti completi", f"{result['doc_summary']['completi']}/{result['doc_summary']['totale']}", "Obbligatori mancanti", str(result["doc_summary"]["obbligatori_mancanti"])],
    ]
    table = Table(meta, colWidths=[4.2*cm, 3.8*cm, 4.2*cm, 4.0*cm])
    table.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,0),colors.HexColor("#eaf1ff")),("GRID",(0,0),(-1,-1),0.35,colors.HexColor("#b8c8e8")),("FONTNAME",(0,0),(0,-1),"Helvetica-Bold"),("FONTNAME",(2,0),(2,-1),"Helvetica-Bold"),("FONTSIZE",(0,0),(-1,-1),8.4),("VALIGN",(0,0),(-1,-1),"MIDDLE"),("TOPPADDING",(0,0),(-1,-1),5),("BOTTOMPADDING",(0,0),(-1,-1),5)]))
    story += [table, Spacer(1, 8), Paragraph(html.escape(result["lettura"]), body), Paragraph("Grafico score", h2)]
    total_w = 12.2*cm
    filled = max(0.1, total_w * result["score"] / 100)
    empty = max(0.1, total_w - filled)
    bar_color = colors.HexColor("#2e9f5b") if result["esito"] == "VERDE" else colors.HexColor("#d1a300") if result["esito"] == "GIALLO" else colors.HexColor("#c23b22")
    bar = Table([["", ""]], colWidths=[filled, empty], rowHeights=[0.45*cm])
    bar.setStyle(TableStyle([("BACKGROUND",(0,0),(0,0),bar_color),("BACKGROUND",(1,0),(1,0),colors.HexColor("#ebeff7")),("BOX",(0,0),(-1,-1),0.4,colors.HexColor("#c0cde5"))]))
    story += [bar, Spacer(1, 10), Paragraph("Scoring per area", h2)]
    area_rows = [["Area", "Peso", "Punti", "Copertura", "Semaforo"]]
    for a in result["areas"]:
        area_rows.append([a["area"], a["peso"], a["punti"], f"{a['copertura']*100:.0f}%", a["semaforo"]])
    area_table = Table(area_rows, colWidths=[6.3*cm, 2*cm, 2*cm, 2.4*cm, 2.6*cm])
    area_table.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,0),colors.HexColor("#dfe9fb")),("GRID",(0,0),(-1,-1),0.35,colors.HexColor("#b8c8e8")),("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),("FONTSIZE",(0,0),(-1,-1),8.2),("TOPPADDING",(0,0),(-1,-1),5),("BOTTOMPADDING",(0,0),(-1,-1),5)]))
    story += [area_table, PageBreak(), Paragraph("KPI economico-finanziari", h2)]
    k = result["kpis"]
    kpi_rows = [["KPI", "Valore", "Lettura pratica"]]
    for r in [
        ("Ricavi annui", format_currency(k["ricavi"]), "Base dimensionale"),
        ("EBITDA", format_currency(k["ebitda"]), "Marginalità operativa"),
        ("EBITDA margin", prew_pct(k["ebitda_margin"]), "Verde indicativo > 10%"),
        ("Patrimonio netto", format_currency(k["patrimonio_netto"]), "Solidità patrimoniale"),
        ("Debt / Equity", prew_ratio(k["debt_equity"]), "Verde indicativo < 2x"),
        ("Current ratio", prew_ratio(k["current_ratio"]), "Verde indicativo > 1,30x"),
        ("Quick ratio", prew_ratio(k["quick_ratio"]), "Verde indicativo > 1,00x"),
        ("Capitale circolante netto", format_currency(k["ccn"]), "Positivo preferibile"),
        ("PFN / EBITDA", prew_ratio(k["pfn_ebitda"]), "Target indicativo < 2,5x"),
        ("DSCR prospettico", prew_ratio(k["dscr"]), "Target prudenziale > 1,30x"),
        ("Interest coverage", prew_ratio(k["interest_coverage"]), "Target indicativo > 4x"),
        ("Utilizzo CR", prew_pct(k["utilizzo_cr"]), "Target indicativo < 70%"),
    ]:
        kpi_rows.append(list(r))
    kpi_table = Table(kpi_rows, colWidths=[5.2*cm, 4.1*cm, 7*cm])
    kpi_table.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,0),colors.HexColor("#dfe9fb")),("GRID",(0,0),(-1,-1),0.35,colors.HexColor("#b8c8e8")),("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),("FONTSIZE",(0,0),(-1,-1),8),("TOPPADDING",(0,0),(-1,-1),4),("BOTTOMPADDING",(0,0),(-1,-1),4)]))
    story += [kpi_table, Spacer(1, 8), Paragraph("Azioni consigliate", h2)]
    for action in result["actions"]:
        story.append(Paragraph("• " + html.escape(action), body))
    if result.get("estimated_notes"):
        story.append(Paragraph("Note stime automatiche", h2))
        for note in result["estimated_notes"]:
            story.append(Paragraph("• " + html.escape(note), body))
    story += [PageBreak(), Paragraph("Checklist documentale", h2)]
    doc_rows = [["Area", "Documento", "Obbl.", "Stato", "Documento trovato"]]
    for row in result["checklist"]:
        doc_rows.append([row["area"], row["documento"], row["obbligatorio"], row["stato"], row["trovato"]])
    doc_table = Table(doc_rows, colWidths=[3.2*cm, 6.3*cm, 1.1*cm, 2.1*cm, 4*cm], repeatRows=1)
    doc_table.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,0),colors.HexColor("#dfe9fb")),("GRID",(0,0),(-1,-1),0.25,colors.HexColor("#b8c8e8")),("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),("FONTSIZE",(0,0),(-1,-1),6.7),("VALIGN",(0,0),(-1,-1),"TOP"),("TOPPADDING",(0,0),(-1,-1),3),("BOTTOMPADDING",(0,0),(-1,-1),3)]))
    story += [doc_table, PageBreak(), Paragraph("Documenti analizzati", h2)]
    used = [["Categoria riconosciuta", "Documento", "Lettura", "Riconoscimento"]]
    for info in result["doc_infos"][:60]:
        used.append([info["detected"], info["title"], info["read"], info["reason"]])
    if len(used) == 1:
        used.append(["-", "Nessun documento collegato", "-", "-"])
    used_table = Table(used, colWidths=[3.6*cm, 5.8*cm, 2.2*cm, 5*cm], repeatRows=1)
    used_table.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,0),colors.HexColor("#dfe9fb")),("GRID",(0,0),(-1,-1),0.25,colors.HexColor("#b8c8e8")),("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),("FONTSIZE",(0,0),(-1,-1),6.8),("VALIGN",(0,0),(-1,-1),"TOP"),("TOPPADDING",(0,0),(-1,-1),3),("BOTTOMPADDING",(0,0),(-1,-1),3)]))
    story += [used_table, Spacer(1, 6), Paragraph("Nota: la Financial Pre-Evaluation è una simulazione interna indicativa basata su dati letti automaticamente da documenti testuali e metadati. Non sostituisce istruttoria, rating ufficiale o delibera bancaria/intermediario.", small)]
    def add_page(canvas, _doc):
        draw_pdf_branding(canvas, "FINANCIAL PRE-EVALUATION chirografario")
        canvas.saveState()
        canvas.setFont("Helvetica", 8)
        canvas.setFillColor(colors.HexColor("#6b778c"))
        canvas.drawRightString(A4[0] - 1.5*cm, 1.0*cm, f"Pagina {canvas.getPageNumber()}")
        canvas.drawString(1.5*cm, 1.0*cm, f"Gestione Clienti Offline - {client_row['denominazione']}")
        canvas.restoreState()
    doc.build(story, onFirstPage=add_page, onLaterPages=add_page)


class PrewValutazioneWindow(BaseWindow):
    def __init__(self, master, db: Database):
        super().__init__(master, "FINANCIAL PRE-EVALUATION", "1320x850")
        self.db = db
        self.client_ids_by_name: dict[str, int] = {}
        self.doc_rows_by_iid: dict[str, sqlite3.Row] = {}
        self.current_result: dict | None = None
        self._build_ui()
        self.refresh_clients()

    def _build_ui(self):
        top = ttk.LabelFrame(self.content_frame, text="Cliente e dati pratica", padding=12)
        top.pack(fill="x", padx=12, pady=(12, 8))
        ttk.Label(top, text="Cliente:").grid(row=0, column=0, sticky="w", padx=(0, 6), pady=4)
        # Combo cliente accorciata: resta nella zona sinistra e non spinge i comandi a destra.
        self.client_combo = ttk.Combobox(top, width=38, state="readonly")
        self.client_combo.grid(row=0, column=1, sticky="w", padx=(0, 12), pady=4)
        self.client_combo.bind("<<ComboboxSelected>>", lambda _e: self.on_client_selected())
        self.amount_var = tk.StringVar(value="€ 0,00")
        self.months_var = tk.StringVar(value="60")
        self.rate_var = tk.StringVar(value="6,50")
        fields = [
            ("Importo richiesto:", self.amount_var, 16),
            ("Durata mesi:", self.months_var, 10),
            ("Tasso annuo %:", self.rate_var, 10),
        ]
        self.amount_entry = None
        for col, (label, var, width) in enumerate(fields, start=2):
            ttk.Label(top, text=label).grid(row=0, column=col * 2 - 2, sticky="w", padx=(0, 6), pady=4)
            entry = ttk.Entry(top, textvariable=var, width=width, justify="right")
            entry.grid(row=0, column=col * 2 - 1, sticky="w", padx=(0, 12), pady=4)
            if var is self.amount_var:
                self.amount_entry = entry
                entry.bind("<FocusOut>", lambda _e: self._format_amount_field())
                entry.bind("<Return>", lambda _e: self._format_amount_field())

        actions = ttk.Frame(top)
        actions.grid(row=1, column=2, columnspan=9, sticky="w", pady=(4, 0))
        ttk.Button(actions, text="Riconosci e seleziona tutti", command=lambda: self.refresh_documents(auto_run=False)).pack(side="left", padx=(0, 8))
        ttk.Button(actions, text="Esegui analisi", command=self.run_analysis).pack(side="left", padx=(0, 8))
        ttk.Button(actions, text="Esporta PDF", command=self.export_pdf).pack(side="left", padx=(0, 8))
        ttk.Button(actions, text="Apri Scoring Aziendale", command=lambda: self.open_scoring_tool("web")).pack(side="left", padx=(0, 8))
        ttk.Button(actions, text="Apri Multi-Istituto", command=lambda: self.open_scoring_tool("istituti")).pack(side="left")

        top.columnconfigure(1, weight=0)
        self.status_var = tk.StringVar(value="Seleziona un cliente: i documenti collegati vengono riconosciuti e selezionati automaticamente.")
        ttk.Label(top, textvariable=self.status_var, style="SubHeader.TLabel").grid(row=2, column=0, columnspan=11, sticky="w", pady=(8, 0))

        body = ttk.Frame(self.content_frame, padding=(12, 0, 12, 12))
        body.pack(fill="both", expand=True)
        body.columnconfigure(0, weight=3)
        body.columnconfigure(1, weight=2)
        body.rowconfigure(0, weight=1)

        left = ttk.LabelFrame(body, text="Documenti allegati al cliente - selezione automatica", padding=10)
        left.grid(row=0, column=0, sticky="nsew", padx=(0, 8))
        left.rowconfigure(0, weight=1)
        left.columnconfigure(0, weight=1)
        self.docs_tree, _holder = create_treeview_with_scrollbars(left, ("usa", "categoria", "documento", "lettura", "motivo"), show="headings")
        for col, label, width in [("usa", "Usa", 55), ("categoria", "Categoria riconosciuta", 160), ("documento", "Documento", 280), ("lettura", "Lettura", 95), ("motivo", "Riconoscimento", 320)]:
            self.docs_tree.heading(col, text=label)
            self.docs_tree.column(col, width=width, anchor="w", stretch=(col in {"documento", "motivo"}))
        self.docs_tree.bind("<Double-1>", self.toggle_document_use)

        # Colonna destra con scrollbar verticale visibile per esito, grafici e report.
        right_holder = ttk.Frame(body)
        right_holder.grid(row=0, column=1, sticky="nsew")
        right_holder.rowconfigure(0, weight=1)
        right_holder.columnconfigure(0, weight=1)
        self.right_scroll_canvas = tk.Canvas(right_holder, highlightthickness=0, bg=BG_COLOR)
        right_vbar = ttk.Scrollbar(right_holder, orient="vertical", command=self.right_scroll_canvas.yview, style="Visible.Vertical.TScrollbar")
        self.right_scroll_canvas.configure(yscrollcommand=right_vbar.set)
        self.right_scroll_canvas.grid(row=0, column=0, sticky="nsew")
        right_vbar.grid(row=0, column=1, sticky="ns")
        right = ttk.Frame(self.right_scroll_canvas)
        right_window = self.right_scroll_canvas.create_window((0, 0), window=right, anchor="nw")
        def _sync_right_scroll(_event=None):
            self.right_scroll_canvas.configure(scrollregion=self.right_scroll_canvas.bbox("all"))
        def _sync_right_width(event):
            self.right_scroll_canvas.itemconfigure(right_window, width=event.width)
        right.bind("<Configure>", _sync_right_scroll)
        self.right_scroll_canvas.bind("<Configure>", _sync_right_width)
        bind_mousewheel_to_canvas(self.right_scroll_canvas, right_holder)
        right.rowconfigure(2, weight=1)
        right.columnconfigure(0, weight=1)

        summary = ttk.LabelFrame(right, text="Esito sintetico", padding=12)
        summary.grid(row=0, column=0, sticky="ew", pady=(0, 8))
        summary.columnconfigure(1, weight=1)
        self.score_label_var = tk.StringVar(value="-")
        self.esito_label_var = tk.StringVar(value="-")
        self.dscr_label_var = tk.StringVar(value="-")
        self.pfn_label_var = tk.StringVar(value="-")
        self.docs_label_var = tk.StringVar(value="-")
        for r, (label, var) in enumerate([("Punteggio", self.score_label_var), ("Esito", self.esito_label_var), ("DSCR prospettico", self.dscr_label_var), ("PFN / EBITDA", self.pfn_label_var), ("Documenti", self.docs_label_var)]):
            ttk.Label(summary, text=label + ":").grid(row=r, column=0, sticky="w", pady=3, padx=(0, 8))
            ttk.Label(summary, textvariable=var, wraplength=360).grid(row=r, column=1, sticky="w", pady=3)

        chart = ttk.LabelFrame(right, text="Grafici", padding=10)
        chart.grid(row=1, column=0, sticky="ew", pady=(0, 8))
        self.chart_canvas = tk.Canvas(chart, width=430, height=230, bg="white", highlightthickness=1, highlightbackground="#d7deeb")
        self.chart_canvas.pack(fill="both", expand=True)

        report = ttk.LabelFrame(right, text="Report e azioni consigliate", padding=10)
        report.grid(row=2, column=0, sticky="nsew")
        report.rowconfigure(0, weight=1)
        report.columnconfigure(0, weight=1)
        self.report_text, _report_holder = create_text_with_scrollbars(report, wrap="none", height=18, font=("Segoe UI", 9))

    def _format_amount_field(self):
        try:
            self.amount_var.set(format_currency_input(self.amount_var.get()))
        except Exception:
            pass

    def refresh_clients(self):
        clients = self.db.list_clients()
        self.client_ids_by_name = {f"{row['denominazione']} (ID {row['id']})": row['id'] for row in clients}
        self.client_combo["values"] = list(self.client_ids_by_name.keys())
        if clients:
            self.client_combo.set(next(iter(self.client_ids_by_name.keys())))
            self.on_client_selected()
        else:
            self.status_var.set("Nessun cliente presente.")

    def selected_client_id(self) -> int | None:
        return self.client_ids_by_name.get(self.client_combo.get())

    def on_client_selected(self):
        self._load_request_defaults()
        self.refresh_documents(auto_run=True)

    def _duration_to_months(self, raw) -> str:
        s = str(raw or "").lower().strip()
        nums = re.findall(r"\d+", s)
        if not nums:
            return "60"
        val = int(nums[0])
        if "ann" in s or val <= 10:
            val *= 12
        return str(val)

    def _load_request_defaults(self):
        client_id = self.selected_client_id()
        if not client_id:
            return
        amount = "0"
        months = "60"
        try:
            info = self.db.get_client_info(client_id)
            if info:
                amount = info["importo_richiesta"] or amount
                months = self._duration_to_months(info["durata"] or months)
            req = self.db.fetch_one("SELECT importo_richiesta, durata FROM requests WHERE client_id=? ORDER BY datetime(created_at) DESC, id DESC LIMIT 1", (client_id,))
            if req:
                amount = req["importo_richiesta"] or amount
                months = self._duration_to_months(req["durata"] or months)
        except Exception:
            pass
        self.amount_var.set(format_currency_input(str(amount or "0")))
        self.months_var.set(str(months or "60"))

    def refresh_documents(self, auto_run: bool = False):
        for item in self.docs_tree.get_children():
            self.docs_tree.delete(item)
        self.doc_rows_by_iid = {}
        client_id = self.selected_client_id()
        if not client_id:
            return
        rows = self.db.list_documents_linked(client_id)
        for row in rows:
            detected, reason = infer_document_category(row["stored_path"] or row["original_filename"] or row["title"], fallback=row["category"] or "Altro")
            text = prew_read_document(row, max_chars=2500)
            status = "OK" if text.strip() else "Solo metadati"
            iid = str(row["id"])
            self.doc_rows_by_iid[iid] = row
            title = row["title"] or row["original_filename"] or f"Documento {row['id']}"
            self.docs_tree.insert("", "end", iid=iid, values=("Sì", detected, title, status, reason))
        if rows:
            self.docs_tree.selection_set([str(row["id"]) for row in rows])
            self.status_var.set(f"Riconosciuti e selezionati automaticamente {len(rows)} documenti collegati al cliente.")
        else:
            self.status_var.set("Nessun documento collegato: la Financial Pre-Evaluation userà solo i dati pratica disponibili.")
        if auto_run:
            self.after(200, lambda: self.run_analysis(silent=True))

    def toggle_document_use(self, _event=None):
        selection = self.docs_tree.selection()
        if not selection:
            return
        iid = selection[0]
        vals = list(self.docs_tree.item(iid, "values"))
        vals[0] = "No" if vals and vals[0] == "Sì" else "Sì"
        self.docs_tree.item(iid, values=vals)

    def selected_rows(self):
        rows = []
        for iid in self.docs_tree.get_children():
            vals = self.docs_tree.item(iid, "values")
            if vals and vals[0] == "Sì" and iid in self.doc_rows_by_iid:
                rows.append(self.doc_rows_by_iid[iid])
        return rows

    def practice_inputs(self):
        amount = prew_parse_amount(self.amount_var.get())
        months = int(prew_parse_amount(self.months_var.get()) or 60)
        rate = prew_parse_amount(self.rate_var.get())
        if rate > 1:
            rate /= 100
        if rate <= 0:
            rate = 0.065
        return amount, months, rate

    def run_analysis(self, silent: bool = False):
        client_id = self.selected_client_id()
        if not client_id:
            if not silent:
                messagebox.showwarning("FINANCIAL PRE-EVALUATION", "Seleziona un cliente.")
            return
        client = self.db.get_client(client_id)
        amount, months, rate = self.practice_inputs()
        self._format_amount_field()
        result = prew_analyze(client, self.selected_rows(), amount, months, rate)
        self.current_result = result
        self.score_label_var.set(f"{result['score']:.1f}/100")
        self.esito_label_var.set(result["esito"] + " - " + result["lettura"])
        self.dscr_label_var.set(prew_ratio(result["kpis"]["dscr"]))
        self.pfn_label_var.set(prew_ratio(result["kpis"]["pfn_ebitda"]))
        self.docs_label_var.set(f"{result['doc_summary']['completi']}/{result['doc_summary']['totale']} completi, {result['doc_summary']['obbligatori_mancanti']} obbligatori mancanti")
        self.write_report(result)
        self.draw_charts(result)
        self.status_var.set("Financial Pre-Evaluation completata: puoi esportare il PDF con tabelle e grafici.")

    def write_report(self, result):
        k = result["kpis"]
        lines = [
            f"Cliente: {result['client_name']}",
            f"Punteggio totale: {result['score']:.1f}/100",
            f"Esito sintetico: {result['esito']}",
            f"Lettura: {result['lettura']}",
            "",
            "Indicatori principali:",
            f"- Importo richiesto: {format_currency(result['amount'])}",
            f"- Nuova rata annua stimata: {format_currency(k['nuova_rata_annua'])}",
            f"- Ricavi: {format_currency(k['ricavi'])}",
            f"- EBITDA: {format_currency(k['ebitda'])}",
            f"- EBITDA margin: {prew_pct(k['ebitda_margin'])}",
            f"- Patrimonio netto: {format_currency(k['patrimonio_netto'])}",
            f"- Debt / Equity: {prew_ratio(k['debt_equity'])}",
            f"- Current ratio: {prew_ratio(k['current_ratio'])}",
            f"- PFN / EBITDA: {prew_ratio(k['pfn_ebitda'])}",
            f"- DSCR prospettico: {prew_ratio(k['dscr'])}",
            f"- Utilizzo CR: {prew_pct(k['utilizzo_cr'])}",
            "",
            "Scoring per area:",
        ]
        for area in result["areas"]:
            lines.append(f"- {area['area']}: {area['punti']}/{area['peso']} ({area['copertura']*100:.0f}%) - {area['semaforo']}")
        try:
            client_for_tools = self.db.get_client(self.selected_client_id())
            _web_payload, _istituti_payload, tool_rows = prew_build_html_tool_payloads(client_for_tools, result)
            lines += ["", "Dati riconosciuti e passati ai tool collegati:"]
            for label, value in tool_rows:
                lines.append(f"- {label}: {value}")
        except Exception:
            pass
        lines += ["", "Documenti:", f"- Completi: {result['doc_summary']['completi']}/{result['doc_summary']['totale']}", f"- Obbligatori mancanti: {result['doc_summary']['obbligatori_mancanti']}", "", "Azioni consigliate:"]
        for i, action in enumerate(result["actions"], 1):
            lines.append(f"{i}. {action}")
        if result["estimated_notes"]:
            lines += ["", "Note stime automatiche:"]
            lines += [f"- {n}" for n in result["estimated_notes"]]
        lines += ["", "Documenti analizzati:"]
        for info in result["doc_infos"][:60]:
            lines.append(f"- {info['detected']}: {info['title']} [{info['read']}]")
        self.report_text.delete("1.0", tk.END)
        self.report_text.insert("1.0", "\n".join(lines))

    def draw_charts(self, result):
        c = self.chart_canvas
        c.delete("all")
        w = int(c.winfo_width() or 430)
        h = int(c.winfo_height() or 230)
        c.create_text(14, 12, anchor="nw", text="Score e copertura aree", font=("Segoe UI", 11, "bold"), fill=TEXT_COLOR)
        score = result["score"]
        color = "#2e9f5b" if result["esito"] == "VERDE" else "#d1a300" if result["esito"] == "GIALLO" else "#c23b22"
        c.create_rectangle(14, 38, w - 14, 60, fill="#ebeff7", outline="#d0d7e7")
        c.create_rectangle(14, 38, 14 + (w - 28) * score / 100, 60, fill=color, outline=color)
        c.create_text(w - 18, 49, anchor="e", text=f"{score:.1f}/100", font=("Segoe UI", 10, "bold"), fill=TEXT_COLOR)
        y = 84
        max_bar = w - 190
        for area in result["areas"]:
            c.create_text(14, y + 6, anchor="w", text=area["area"][:28], font=("Segoe UI", 8), fill=TEXT_COLOR)
            x0 = 190
            c.create_rectangle(x0, y, x0 + max_bar, y + 12, fill="#ebeff7", outline="#d0d7e7")
            fill = max_bar * min(1, max(0, area["copertura"]))
            bar_color = "#2e9f5b" if area["semaforo"] == "Verde" else "#d1a300" if area["semaforo"] == "Giallo" else "#c23b22"
            c.create_rectangle(x0, y, x0 + fill, y + 12, fill=bar_color, outline=bar_color)
            c.create_text(w - 18, y + 6, anchor="e", text=f"{area['punti']}/{area['peso']}", font=("Segoe UI", 8), fill=TEXT_COLOR)
            y += 24
        c.create_text(14, h - 20, anchor="w", text=f"Documenti completi: {result['doc_summary']['completi']}/{result['doc_summary']['totale']} | Obbligatori mancanti: {result['doc_summary']['obbligatori_mancanti']}", font=("Segoe UI", 8, "bold"), fill=TEXT_COLOR)

    def ensure_current_result_for_tools(self):
        client_id = self.selected_client_id()
        if not client_id:
            messagebox.showwarning("FINANCIAL PRE-EVALUATION", "Seleziona un cliente.")
            return None, None
        if not self.current_result:
            self.run_analysis(silent=True)
        if not self.current_result:
            messagebox.showwarning("FINANCIAL PRE-EVALUATION", "Esegui prima l'analisi del cliente.")
            return None, None
        return self.db.get_client(client_id), self.current_result

    def open_scoring_tool(self, tool: str):
        client, result = self.ensure_current_result_for_tools()
        if not client or not result:
            return
        try:
            html_path = prew_generate_client_tool_html(client, result, tool)
            open_path(str(html_path))
            label = "Multi-Istituto" if tool == "istituti" else "Credit Scoring Aziendale"
            self.status_var.set(f"{label} aperto con i dati del cliente selezionato e dei documenti collegati.")
        except Exception as exc:
            messagebox.showerror("FINANCIAL PRE-EVALUATION", f"Impossibile aprire il tool collegato.\n\n{exc}")

    def export_pdf(self):
        client_id = self.selected_client_id()
        if not client_id:
            messagebox.showwarning("FINANCIAL PRE-EVALUATION", "Seleziona un cliente.")
            return
        if not self.current_result:
            self.run_analysis(silent=True)
        if not self.current_result:
            return
        if not REPORTLAB_AVAILABLE:
            messagebox.showerror("FINANCIAL PRE-EVALUATION", "Libreria PDF non disponibile.")
            return
        client = self.db.get_client(client_id)
        safe = re.sub(r"[^A-Za-z0-9_-]+", "_", client["denominazione"]).strip("_") if client else f"cliente_{client_id}"
        default_name = f"FINANCIAL_PRE_EVALUATION_{safe}_{datetime.now().strftime('%Y%m%d')}.pdf"
        path = filedialog.asksaveasfilename(title="Salva PDF Financial Pre-Evaluation", defaultextension=".pdf", initialfile=default_name, filetypes=[("PDF", "*.pdf")])
        if not path:
            return
        try:
            export_prew_pdf(path, client, self.current_result)
            try:
                self.db.add_document({
                    "client_id": client_id,
                    "collaborator_id": client["responsible_collaborator_id"] if client and "responsible_collaborator_id" in client.keys() else None,
                    "category": "Report",
                    "title": f"FINANCIAL PRE-EVALUATION {client['denominazione']}",
                    "original_filename": Path(path).name,
                    "stored_path": path,
                    "notes": "Report automatico Financial Pre-Evaluation con tabelle e grafici.",
                })
            except Exception:
                pass
            messagebox.showinfo("PDF creato", "Financial Pre-Evaluation esportata correttamente in PDF.")
            open_path(path)
        except Exception as exc:
            messagebox.showerror("Errore", f"Impossibile generare il PDF.\n\n{exc}")


class HomeSectionHubWindow(BaseWindow):
    def __init__(self, master, title: str, subtitle: str, items):
        # Usa SOLO l'area scrollabile già creata da BaseWindow.
        # In questo modo non si crea una seconda cornice con scrollbar a metà pagina
        # e non resta lo spazio vuoto sopra i pulsanti.
        super().__init__(master, title, "1040x660")
        self.items = items

        container = ttk.Frame(self.content_frame, style="Card.TFrame", padding=(22, 20, 22, 22))
        container.pack(fill="both", expand=True, padx=16, pady=16)
        add_logo_badge(container, size=(760, 520), watermark=True, bg=CARD_BG, relx=0.52, rely=0.50, anchor="center")

        title_lbl = ttk.Label(container, text=title, style="Header.TLabel")
        title_lbl.pack(anchor="center", pady=(0, 4))
        tk.Label(
            container,
            text=subtitle,
            bg=CARD_BG,
            fg=MUTED_TEXT,
            font=("Segoe UI", 10),
            wraplength=850,
            justify="center",
        ).pack(anchor="center", pady=(0, 18))

        grid = tk.Frame(container, bg=CARD_BG)
        grid.pack(fill="both", expand=True, anchor="center")

        cols = 2
        for col in range(cols):
            grid.columnconfigure(col, weight=1, uniform="hub_cols")
        rows = (len(items) + cols - 1) // cols
        for row in range(rows):
            grid.rowconfigure(row, weight=1, uniform="hub_rows")

        for idx, (btn_title, btn_subtitle, command) in enumerate(items):
            row, col = divmod(idx, cols)
            TileButton(
                grid,
                btn_title,
                btn_subtitle,
                command,
                height=112,
                title_font_size=11,
                subtitle_font_size=9,
                icon_font_size=27,
                wraplength=300,
            ).grid(row=row, column=col, padx=10, pady=10, sticky="nsew")

        # Forza l'aggiornamento della regione scrollabile globale della finestra.
        self.after(80, lambda: self.page_body.canvas.configure(scrollregion=self.page_body.canvas.bbox("all")))


