# ============================================================
# PATCH FINALE: collegamento automatico documenti -> Scoring Plus
# - recupera tutti i documenti già caricati in Gestione Documenti
# - ricataloga automaticamente i documenti inseriti come "Altro"
# - li collega a Scoring Plus, analisi e report
# - prova a precompilare i 5 fogli input leggendo PDF/CSV/XLSX
# ============================================================

def _sp_parse_number(raw: str) -> float:
    s = str(raw or "").strip()
    s = s.replace("€", "").replace("eur", "").replace("EUR", "")
    s = re.sub(r"[^0-9,\.\-]", "", s)
    if not s or s in {"-", ".", ","}:
        return 0.0
    # formato italiano 1.234.567,89
    if "," in s and "." in s:
        if s.rfind(",") > s.rfind("."):
            s = s.replace(".", "").replace(",", ".")
        else:
            s = s.replace(",", "")
    elif "," in s:
        s = s.replace(".", "").replace(",", ".")
    try:
        return float(s)
    except Exception:
        return 0.0


def _sp_read_any_document_text(path: str, max_chars: int = 50000) -> str:
    p = Path(path or "")
    if not p.exists():
        return ""
    ext = p.suffix.lower()
    try:
        if ext == ".pdf":
            return safe_read_pdf_text(str(p), max_pages=15, max_chars=max_chars)
        if ext in {".txt", ".csv"}:
            return p.read_text(encoding="utf-8", errors="ignore")[:max_chars]
        if ext in {".xlsx", ".xls"}:
            try:
                from openpyxl import load_workbook
                wb = load_workbook(str(p), data_only=True, read_only=True)
                chunks = []
                for ws in wb.worksheets[:8]:
                    chunks.append(ws.title)
                    for row in ws.iter_rows(max_row=300, values_only=True):
                        vals = [str(v) for v in row if v is not None]
                        if vals:
                            chunks.append(" | ".join(vals))
                return "\n".join(chunks)[:max_chars]
            except Exception:
                return ""
    except Exception:
        return ""
    return ""


def _sp_find_value(text: str, labels: list[str]) -> float:
    if not text:
        return 0.0
    low = normalize_category(text)
    for label in labels:
        lab = normalize_category(label)
        idx = low.find(lab)
        if idx >= 0:
            window = text[idx:idx + 260]
            nums = re.findall(r"[-+]?\d{1,3}(?:[\.\s]\d{3})*(?:,\d+)?|[-+]?\d+(?:,\d+|\.\d+)?", window)
            nums = [_sp_parse_number(n) for n in nums]
            nums = [n for n in nums if abs(n) > 0]
            if nums:
                # Evita anni puri se presenti come primo valore
                nums2 = [n for n in nums if not (1900 <= abs(n) <= 2100)]
                return nums2[0] if nums2 else nums[0]
    return 0.0


def _sp_extract_values_from_documents(rows) -> dict:
    """Estrae valori indicativi dai documenti caricati. Non usa OCR: funziona con PDF testuali, CSV e XLSX."""
    data = {}
    texts_by_cat = {}
    for r in rows:
        try:
            cat = r["category"] or "Altro"
            path = r["stored_path"] or ""
        except Exception:
            continue
        txt = _sp_read_any_document_text(path)
        if txt:
            texts_by_cat.setdefault(normalize_category(cat), "")
            texts_by_cat[normalize_category(cat)] += "\n" + txt

    # Bilancio e situazione aggiornata: attuale prende situazione aggiornata se presente, altrimenti bilancio.
    bil_text = texts_by_cat.get("bilanci", "") + "\n" + texts_by_cat.get("bilancio", "")
    sit_text = texts_by_cat.get("situazione aggiornata", "")
    main_text = sit_text or bil_text
    if main_text:
        mappings = {
            "sp|Liquidità|Attuale": ["liquidita", "disponibilita liquide", "cassa", "banche attive"],
            "sp|Crediti|Attuale": ["crediti", "crediti verso clienti", "crediti commerciali"],
            "sp|Magazzino|Attuale": ["magazzino", "rimanenze", "scorte"],
            "sp|Immobilizzazioni|Attuale": ["immobilizzazioni", "totale immobilizzazioni"],
            "sp|Debiti bancari|Attuale": ["debiti bancari", "debiti verso banche", "banche passive"],
            "sp|Debiti fornitori|Attuale": ["debiti fornitori", "debiti verso fornitori"],
            "sp|Altri debiti|Attuale": ["altri debiti", "debiti tributari", "debiti previdenziali"],
            "sp|Patrimonio netto|Attuale": ["patrimonio netto", "totale patrimonio netto"],
            "ce|Ricavi|Attuale": ["ricavi", "valore della produzione", "fatturato"],
            "ce|EBITDA|Attuale": ["ebitda", "margine operativo lordo", "mol"],
            "ce|EBIT|Attuale": ["ebit", "risultato operativo"],
            "ce|Utile netto|Attuale": ["utile netto", "risultato d esercizio", "utile dell esercizio"],
            "ce|Oneri finanziari|Attuale": ["oneri finanziari", "interessi passivi"],
        }
        for key, labs in mappings.items():
            v = _sp_find_value(main_text, labs)
            if v:
                data[key] = v
    # Se disponibile anche bilancio storico, compila Anno -1/-2 in modo prudenziale copiando quando non si riesce a distinguere anni.
    if bil_text:
        for base in ["Liquidità", "Crediti", "Magazzino", "Immobilizzazioni", "Debiti bancari", "Debiti fornitori", "Altri debiti", "Patrimonio netto"]:
            cur = data.get(f"sp|{base}|Attuale") or _sp_find_value(bil_text, [base])
            if cur:
                data.setdefault(f"sp|{base}|Anno -1", cur)
                data.setdefault(f"sp|{base}|Anno -2", cur)
        for base in ["Ricavi", "EBITDA", "EBIT", "Utile netto", "Oneri finanziari"]:
            cur = data.get(f"ce|{base}|Attuale") or _sp_find_value(bil_text, [base])
            if cur:
                data.setdefault(f"ce|{base}|Anno -1", cur)
                data.setdefault(f"ce|{base}|Anno -2", cur)

    cr_text = texts_by_cat.get("centrale rischi 36 mesi", "") + "\n" + texts_by_cat.get("centrale rischi", "")
    if cr_text:
        accordato = _sp_find_value(cr_text, ["accordato", "accordato operativo", "totale accordato"])
        utilizzato = _sp_find_value(cr_text, ["utilizzato", "utilizzato operativo", "totale utilizzato"])
        sconfinamenti = _sp_find_value(cr_text, ["sconfinamenti", "sconfino", "past due"])
        ritardi = _sp_find_value(cr_text, ["ritardi", "rate scadute", "insoluti"])
        for m in ScoringPlusWindow.MONTHS_36:
            if accordato: data[f"cr|{m}|Accordato"] = accordato
            if utilizzato: data[f"cr|{m}|Utilizzato"] = utilizzato
            if sconfinamenti: data[f"cr|{m}|Sconfinamenti"] = sconfinamenti
            if ritardi: data[f"cr|{m}|Ritardi"] = ritardi

    bank_text = texts_by_cat.get("estratti conto 12 mesi", "") + "\n" + texts_by_cat.get("estratti conto", "")
    if bank_text:
        saldo = _sp_find_value(bank_text, ["saldo", "saldo finale", "saldo contabile", "saldo disponibile"])
        entrate = _sp_find_value(bank_text, ["entrate", "accrediti", "avere", "incassi"])
        uscite = _sp_find_value(bank_text, ["uscite", "addebiti", "dare", "pagamenti"])
        rosso = _sp_find_value(bank_text, ["giorni in rosso", "scoperto", "saldo negativo"])
        for m in ScoringPlusWindow.MONTHS_12:
            if saldo: data[f"bank|{m}|Saldo"] = saldo
            if entrate: data[f"bank|{m}|Entrate"] = entrate
            if uscite: data[f"bank|{m}|Uscite"] = uscite
            if rosso: data[f"bank|{m}|Giorni in rosso"] = rosso

    exp_text = texts_by_cat.get("esposizioni mensili", "")
    if exp_text:
        rate = _sp_find_value(exp_text, ["rate finanziamenti", "rata finanziamento", "rata", "rate"])
        leasing = _sp_find_value(exp_text, ["leasing", "canone leasing"])
        mutui = _sp_find_value(exp_text, ["mutui", "mutuo", "rata mutuo"])
        altri = _sp_find_value(exp_text, ["altri impegni", "altri finanziamenti", "altri debiti"])
        for m in ScoringPlusWindow.MONTHS_12:
            if rate: data[f"exp|{m}|Rate finanziamenti"] = rate
            if leasing: data[f"exp|{m}|Leasing"] = leasing
            if mutui: data[f"exp|{m}|Mutui"] = mutui
            if altri: data[f"exp|{m}|Altri impegni"] = altri
    return data


def _sp_document_exists(db, client_id: int, stored_path: str) -> bool:
    row = db.fetch_one(
        "SELECT id FROM scoring_plus_documents WHERE client_id=? AND stored_path=?",
        (client_id, stored_path),
    )
    return bool(row)


def _sp_auto_sync_documents(self, show_status: bool = True):
    if not getattr(self, "current_client_id", None):
        return []
    ensure_scoring_plus_tables(self.db)
    try:
        docs = self.db.list_documents_linked(self.current_client_id)
    except Exception:
        docs = self.db.list_documents(self.current_client_id)
    imported = 0
    updated = 0
    for d in docs:
        stored = d["stored_path"] or ""
        if not stored:
            continue
        original_cat = d["category"] or "Altro"
        detected_cat, reason = infer_document_category(stored, fallback=original_cat or "Altro")
        # Ricataloga anche i documenti caricati come Altro, così poi entrano nei report corretti.
        if normalize_category(original_cat) == normalize_category("Altro") and normalize_category(detected_cat) != normalize_category("Altro"):
            try:
                self.db.execute("UPDATE documents SET category=?, notes=COALESCE(notes,'') || ? WHERE id=?", (detected_cat, f"\nAuto-catalogato: {detected_cat} ({reason})", d["id"]))
                updated += 1
            except Exception:
                pass
        sp_cat = scoring_plus_category(detected_cat)
        if not _sp_document_exists(self.db, self.current_client_id, stored):
            self.db.execute(
                "INSERT INTO scoring_plus_documents (client_id, category, original_filename, stored_path, notes) VALUES (?, ?, ?, ?, ?)",
                (self.current_client_id, sp_cat, d["original_filename"] or d["title"] or Path(stored).name, stored, f"Collegato automaticamente da Gestione Documenti. Categoria: {detected_cat}. Motivo: {reason}"),
            )
            imported += 1
    rows = self.db.fetch_all("SELECT * FROM scoring_plus_documents WHERE client_id=? ORDER BY uploaded_at DESC, id DESC", (self.current_client_id,))
    if show_status and hasattr(self, "status_var"):
        self.status_var.set(f"Documenti sincronizzati: {len(rows)} collegati ({imported} nuovi, {updated} ricatalogati).")
    return rows


def _sp_auto_populate_inputs_from_documents(self, overwrite_empty_only: bool = True):
    rows = _sp_auto_sync_documents(self, show_status=False)
    extracted = _sp_extract_values_from_documents(rows)
    filled = 0
    for key, val in extracted.items():
        if key in self.inputs:
            cur = self.inputs[key].get()
            if (not overwrite_empty_only) or (not cur or cur in {"0", "0.0", "0,0"}):
                self.inputs[key].set(str(round(float(val), 2)))
                filled += 1
    return filled, rows


# Mantiene riferimento ai metodi originali
_SP_ORIG_ON_CLIENT_SELECTED = ScoringPlusWindow._on_client_selected
