def _sp_patched_on_client_selected(self):
    _SP_ORIG_ON_CLIENT_SELECTED(self)
    if getattr(self, "current_client_id", None):
        rows = _sp_auto_sync_documents(self, show_status=True)
        filled, rows = _sp_auto_populate_inputs_from_documents(self, overwrite_empty_only=True)
        # Salvataggio silenzioso degli input precompilati, senza popup.
        if filled:
            try:
                data_json = json.dumps(self._collect_data(), ensure_ascii=False)
                self.db.conn.execute(
                    """
                    INSERT INTO scoring_plus_inputs (client_id, data_json, updated_at)
                    VALUES (?, ?, CURRENT_TIMESTAMP)
                    ON CONFLICT(client_id) DO UPDATE SET data_json=excluded.data_json, updated_at=CURRENT_TIMESTAMP
                    """,
                    (self.current_client_id, data_json),
                )
                self.db.conn.commit()
            except Exception:
                pass
        self.refresh_documents()
        self._refresh_kpi_preview()
        if hasattr(self, "status_var"):
            self.status_var.set(f"Cliente selezionato. Documenti recuperati: {len(rows)}. Campi input precompilati: {filled}.")


def _sp_patched_refresh_documents(self):
    if getattr(self, "current_client_id", None):
        _sp_auto_sync_documents(self, show_status=False)
    return _SP_ORIG_REFRESH_DOCUMENTS(self)


def _sp_patched_run_analysis(self):
    if not getattr(self, "current_client_id", None):
        messagebox.showwarning("Scoring Plus", "Seleziona prima un cliente.")
        return
    filled, rows = _sp_auto_populate_inputs_from_documents(self, overwrite_empty_only=True)
    # Salva silenziosamente senza aprire il popup di 'Salva input'.
    try:
        data_json = json.dumps(self._collect_data(), ensure_ascii=False)
        self.db.conn.execute(
            """
            INSERT INTO scoring_plus_inputs (client_id, data_json, updated_at)
            VALUES (?, ?, CURRENT_TIMESTAMP)
            ON CONFLICT(client_id) DO UPDATE SET data_json=excluded.data_json, updated_at=CURRENT_TIMESTAMP
            """,
            (self.current_client_id, data_json),
        )
        self.db.conn.commit()
    except Exception:
        pass
    metrics = self._compute_metrics()
    self._refresh_kpi_preview()
    try:
        pdf_path = self._generate_pdf(metrics)
        self.db.execute(
            "INSERT INTO scoring_plus_reports (client_id, report_path, summary_json) VALUES (?, ?, ?)",
            (self.current_client_id, str(pdf_path), json.dumps(metrics, ensure_ascii=False)),
        )
        msg = (
            f"Analisi completata usando i documenti già caricati per il cliente.\n\n"
            f"Documenti collegati: {len(rows)}\n"
            f"Campi input precompilati dai documenti: {filled}\n\n"
            f"Report salvato:\n{pdf_path}\n\nVuoi aprirlo ora?"
        )
        if messagebox.askyesno("Report creato", msg):
            open_path(str(pdf_path))
    except Exception as exc:
        messagebox.showerror("Errore report", f"Impossibile creare il PDF: {exc}")


ScoringPlusWindow._on_client_selected = _sp_patched_on_client_selected
