# ============================================================
# PATCH DEFINITIVA: collegamento clienti/documenti nelle finestre report
# - popola sempre il menu Clienti anche nelle finestre/tab secondarie
# - recupera i documenti collegati da Gestione Documenti
# - se sono caricati come Altro li riconosce e li usa comunque
# - in Analisi bilancio usa automaticamente tutti i documenti utili del cliente
# ============================================================

def _fp_safe_list_clients(db):
    """Lista clienti robusta: usa il DB dell'app e fallback diretto SQLite."""
    rows = []
    try:
        rows = list(db.list_clients() or [])
    except Exception:
        rows = []
    if not rows:
        try:
            rows = list(db.basic_client_choices() or [])
        except Exception:
            rows = []
    if not rows:
        # fallback diretto sullo stesso file database
        paths = []
        try:
            paths.append(Path(db.db_path))
        except Exception:
            pass
        try:
            paths.append(get_app_data_dir() / 'gestione_clienti.db')
        except Exception:
            pass
        for p in paths:
            try:
                if p and Path(p).exists():
                    conn = sqlite3.connect(p)
                    conn.row_factory = sqlite3.Row
                    rows = conn.execute('SELECT id, denominazione FROM clients ORDER BY denominazione COLLATE NOCASE').fetchall()
                    conn.close()
                    if rows:
                        break
            except Exception:
                pass
    return rows or []


def _fp_safe_client_name(row):
    try:
        den = row['denominazione'] or f"Cliente {row['id']}"
        cid = row['id']
    except Exception:
        den = str(row[1]) if len(row) > 1 else 'Cliente'
        cid = row[0]
    return f"{den} (ID {cid})", int(cid)


def _fp_auto_catalogue_client_documents(db, client_id: int):
    """Recupera documenti collegati e ricataloga automaticamente quelli Altro."""
    if not client_id:
        return []
    try:
        rows = list(db.list_documents_linked(client_id) or [])
    except Exception:
        try:
            rows = list(db.list_documents(client_id) or [])
        except Exception:
            rows = []
    # Riclassifica Altro appena possibile, così tutte le tab/report li vedono correttamente.
    for r in rows:
        try:
            old_cat = r['category'] or 'Altro'
            stored = r['stored_path'] or ''
            if normalize_category(old_cat) == normalize_category('Altro') and stored:
                guessed, reason = infer_document_category(stored, fallback='Altro')
                if normalize_category(guessed) != normalize_category('Altro'):
                    db.execute(
                        "UPDATE documents SET category=?, notes=COALESCE(notes,'') || ? WHERE id=?",
                        (guessed, f"\nAuto-catalogato per analisi/report: {guessed} ({reason})", r['id'])
                    )
        except Exception:
            pass
    try:
        return list(db.list_documents_linked(client_id) or [])
    except Exception:
        try:
            return list(db.list_documents(client_id) or [])
        except Exception:
            return rows


_FP_ORIG_RBW_REFRESH_CLIENTS = ReportBaseWindow.refresh_clients
_FP_ORIG_RBW_REFRESH_DOCUMENTS = ReportBaseWindow.refresh_documents
_FP_ORIG_RBW_SELECTED_DOCUMENT = ReportBaseWindow.selected_document


def _fp_reportbase_refresh_clients(self):
    clients = _fp_safe_list_clients(self.db)
    self.client_ids_by_name = {}
    for row in clients:
        try:
            name, cid = _fp_safe_client_name(row)
            self.client_ids_by_name[name] = cid
        except Exception:
            continue
    try:
        self.client_combo['values'] = list(self.client_ids_by_name.keys())
    except Exception:
        pass
    # Preseleziona cliente passato dalla home; altrimenti il primo cliente disponibile.
    selected = None
    if getattr(self, 'preselected_client_id', None) is not None:
        for name, cid in self.client_ids_by_name.items():
            if cid == self.preselected_client_id:
                selected = name
                break
    if selected is None and self.client_ids_by_name:
        selected = next(iter(self.client_ids_by_name.keys()))
    if selected:
        try:
            self.client_combo.set(selected)
        except Exception:
            pass
    self.refresh_documents()


def _fp_reportbase_refresh_documents(self):
    client_id = self.selected_client_id()
    rows_all = _fp_auto_catalogue_client_documents(self.db, client_id) if client_id else []
    rows = [r for r in rows_all if category_matches(r, self.accepted_categories)]
    # Per evitare schermate vuote: se non ci sono categorie perfette, mostra comunque tutti i documenti del cliente.
    if not rows:
        rows = rows_all
    self.document_rows_by_title = {}
    for row in rows:
        try:
            self.document_rows_by_title[summarize_document_title(row)] = row
        except Exception:
            pass
    try:
        self.doc_combo['values'] = [''] + list(self.document_rows_by_title.keys())
        self.doc_combo.set(next(iter(self.document_rows_by_title.keys()), ''))
    except Exception:
        pass
    try:
        for item in self.docs_tree.get_children():
            self.docs_tree.delete(item)
        for row in rows_all:
            self.docs_tree.insert('', 'end', iid=str(row['id']), values=(
                row['title'] or '',
                row['original_filename'] or '',
                (row['uploaded_at'] or '')[:10],
            ))
    except Exception:
        pass


def _fp_reportbase_selected_document(self):
    row = None
    try:
        row = self.document_rows_by_title.get(self.doc_combo.get())
    except Exception:
        row = None
    if row:
        return row
    try:
        selection = self.docs_tree.selection()
        if selection:
            return self.db.get_document(int(selection[0]))
    except Exception:
        pass
    # Se non selezionato nulla, prende automaticamente il primo documento utile.
    try:
        client_id = self.selected_client_id()
        rows_all = _fp_auto_catalogue_client_documents(self.db, client_id) if client_id else []
        rows = [r for r in rows_all if category_matches(r, self.accepted_categories)]
        return (rows or rows_all or [None])[0]
    except Exception:
        return None


ReportBaseWindow.refresh_clients = _fp_reportbase_refresh_clients
ReportBaseWindow.refresh_documents = _fp_reportbase_refresh_documents
ReportBaseWindow.selected_document = _fp_reportbase_selected_document


def _fp_join_text_from_rows(rows, max_each=50000):
    chunks = []
    for r in rows:
        try:
            p = r['stored_path'] or ''
            txt = text_from_supported_file(p) or _sp_read_any_document_text(p)
            if txt:
                chunks.append(f"\n--- DOCUMENTO: {r['title'] or r['original_filename'] or p} | {r['category'] or ''} ---\n{txt[:max_each]}")
        except Exception:
            continue
    return '\n'.join(chunks)


def _fp_report_bilancio_run_analysis(self):
    client_id = self.selected_client_id()
    if not client_id:
        messagebox.showwarning('Attenzione', 'Seleziona un cliente. Se il menu è vuoto, apri prima Elenco Clienti e verifica che il cliente sia salvato.')
        return
    client = self.db.get_client(client_id)
    rows_all = _fp_auto_catalogue_client_documents(self.db, client_id)
    useful = [r for r in rows_all if category_matches(r, ['Bilancio', 'Bozza Bilancio', 'Situazione aggiornata', 'Report'])]
    if not useful:
        useful = rows_all
    if not useful:
        messagebox.showwarning('Attenzione', 'Non risultano documenti collegati a questo cliente. Caricali da Gestione Documenti oppure da Inserisci documento in questa finestra.')
        return
    text = _fp_join_text_from_rows(useful)
    indicators = {
        'ricavi': extract_first_amount([r"ricavi[^0-9-]{0,30}([0-9\.,-]+)", r"fatturato[^0-9-]{0,30}([0-9\.,-]+)", r"valore della produzione[^0-9-]{0,30}([0-9\.,-]+)"], text),
        'ebitda': extract_first_amount([r"ebitda[^0-9-]{0,30}([0-9\.,-]+)", r"mol[^0-9-]{0,30}([0-9\.,-]+)", r"margine operativo lordo[^0-9-]{0,30}([0-9\.,-]+)"], text),
        'utile': extract_first_amount([r"utile netto[^0-9-]{0,30}([0-9\.,-]+)", r"utile[^0-9-]{0,30}([0-9\.,-]+)", r"risultato d['’]?esercizio[^0-9-]{0,30}([0-9\.,-]+)"], text),
        'patrimonio_netto': extract_first_amount([r"patrimonio netto[^0-9-]{0,30}([0-9\.,-]+)", r"totale patrimonio netto[^0-9-]{0,30}([0-9\.,-]+)"], text),
        'debiti_banche': extract_first_amount([r"debiti verso banche[^0-9-]{0,30}([0-9\.,-]+)", r"debiti bancari[^0-9-]{0,30}([0-9\.,-]+)", r"totale debiti[^0-9-]{0,30}([0-9\.,-]+)"], text),
    }
    score = 65
    if indicators['patrimonio_netto'] and indicators['patrimonio_netto'] > 0:
        score += 8
    if indicators['utile'] and indicators['utile'] > 0:
        score += 8
    if indicators['ebitda'] and indicators['ebitda'] > 0:
        score += 6
    if indicators['debiti_banche'] and indicators['patrimonio_netto'] and indicators['debiti_banche'] > indicators['patrimonio_netto'] * 4:
        score -= 8
    score = max(1, min(100, score))
    rating = 'buono' if score >= 75 else 'medio' if score >= 55 else 'debole'
    est = max(0.0, ((indicators['ebitda'] or indicators['utile'] or 0) * 0.8))
    if est <= 0:
        est = 50000.0
    report = build_professional_bilancio_report(client, indicators, score, rating, est)
    # Aggiunge evidenza dei documenti realmente usati.
    doc_lines = [f"- {r['title'] or r['original_filename'] or 'Documento'} | {r['category'] or 'Senza categoria'}" for r in useful]
    report['sections'].insert(0, ['0. Documenti collegati al cliente usati automaticamente', *doc_lines])
    self.set_report(report['sections'], report['title'])
    try:
        self.draw_chart(indicators, report['proforma'])
    except Exception:
        pass


ReportBilancioWindow.run_analysis = _fp_report_bilancio_run_analysis

# Assicura che anche le finestre di valutazione/scoring vedano sempre i documenti collegati.
def _fp_pick_documents_for_categories(db, client_id: int, accepted_categories: list[str]):
    rows = _fp_auto_catalogue_client_documents(db, client_id) if client_id else []
    selected = [row for row in rows if category_matches(row, accepted_categories)]
    return selected or rows

def _fp_pick_first_document_for_categories(db, client_id: int, accepted_categories: list[str]):
    rows = _fp_pick_documents_for_categories(db, client_id, accepted_categories)
    return rows[0] if rows else None

pick_documents_for_categories = _fp_pick_documents_for_categories
