def _fp_selected_int_ids_from_tree(tree) -> list[int]:
    try:
        return [int(item) for item in tree.selection()]
    except Exception:
        return []


def _fp_find_descendant_treeview(widget):
    try:
        if isinstance(widget, ttk.Treeview):
            return widget
        for child in widget.winfo_children():
            found = _fp_find_descendant_treeview(child)
            if found is not None:
                return found
    except Exception:
        pass
    return None


def _fp_safe_delete_file(path_value: str | None) -> None:
    try:
        if path_value and Path(path_value).exists():
            Path(path_value).unlink()
    except Exception:
        pass


def _fp_db_delete_client_info(self, client_id: int) -> None:
    self.execute("DELETE FROM client_infos WHERE client_id = ?", (client_id,))


def _fp_db_clear_client_responsible(self, client_id: int) -> None:
    self.execute("UPDATE clients SET responsible_collaborator_id = NULL WHERE id = ?", (client_id,))


def _fp_db_delete_scoring_plus_input(self, client_id: int) -> None:
    try:
        self.execute("DELETE FROM scoring_plus_inputs WHERE client_id = ?", (client_id,))
    except Exception:
        # La tabella potrebbe non essere ancora stata creata su installazioni vecchie.
        pass


def _fp_db_delete_scoring_plus_document(self, document_id: int) -> None:
    row = None
    try:
        row = self.fetch_one("SELECT * FROM scoring_plus_documents WHERE id = ?", (document_id,))
    except Exception:
        row = None
    stored_path = row["stored_path"] if row and "stored_path" in row.keys() else ""
    if stored_path:
        try:
            linked = self.fetch_all("SELECT id FROM documents WHERE stored_path = ?", (stored_path,))
        except Exception:
            linked = []
        if linked:
            for linked_row in linked:
                try:
                    self.delete_document(int(linked_row["id"]))
                except Exception:
                    pass
        else:
            _fp_safe_delete_file(stored_path)
    try:
        self.execute("DELETE FROM scoring_plus_documents WHERE id = ?", (document_id,))
    except Exception:
        pass


def _fp_db_delete_scoring_plus_documents_for_client(self, client_id: int) -> None:
    try:
        rows = self.fetch_all("SELECT id FROM scoring_plus_documents WHERE client_id = ?", (client_id,))
    except Exception:
        rows = []
    for row in rows:
        try:
            self.delete_scoring_plus_document(int(row["id"]))
        except Exception:
            pass


