def _ci_open_selected_document(self):
    ids = self.selected_document_ids()
    if not ids:
        messagebox.showwarning("Attenzione", "Seleziona un documento da aprire.")
        return
    row = self.db.get_document(ids[0])
    if row and row["stored_path"]:
        open_path(row["stored_path"])
    else:
        messagebox.showerror("Errore", "Documento non trovato o file mancante.")


def _ci_delete_selected_documents(self):
    ids = self.selected_document_ids()
    if not ids:
        messagebox.showwarning("Attenzione", "Seleziona almeno un documento da eliminare.")
        return
    if not messagebox.askyesno("Conferma eliminazione", f"Vuoi eliminare definitivamente i documenti selezionati? ({len(ids)})"):
        return
    for document_id in ids:
        self.db.delete_document(document_id)
    self.refresh_documents()
    if self.on_saved:
        self.on_saved()
    messagebox.showinfo("Eliminazione completata", "Documento/i eliminato/i correttamente.")


def _ci_delete_client_information(self):
    client_id = self.selected_client_id()
    if not client_id:
        messagebox.showwarning("Attenzione", "Seleziona prima un cliente.")
        return
    if not messagebox.askyesno(
        "Conferma eliminazione",
        "Vuoi eliminare i dati/informazioni salvati per questo cliente?\n\nLe richieste e i documenti restano disponibili e possono essere eliminati dalle rispettive liste.",
    ):
        return
    self.db.delete_client_info(client_id)
    self.clear_form()
    if self.on_saved:
        self.on_saved()
    messagebox.showinfo("Eliminazione completata", "Dati/informazioni cliente eliminati correttamente.")


def _ci_remove_client_responsible(self):
    client_id = self.selected_client_id()
    if not client_id:
        messagebox.showwarning("Attenzione", "Seleziona prima un cliente.")
        return
    if not messagebox.askyesno("Conferma", "Vuoi rimuovere il responsabile assegnato a questo cliente?"):
        return
    self.db.clear_client_responsible(client_id)
    self.refresh_choices()
    if self.on_saved:
        self.on_saved()
    messagebox.showinfo("Responsabile rimosso", "Il responsabile cliente è stato rimosso.")


