def _collab_detail_remove_responsible_for_selected_client(self, tree):
    ids = _fp_selected_int_ids_from_tree(tree)
    if not ids:
        messagebox.showwarning("Attenzione", "Seleziona un cliente dalla lista.")
        return
    if not messagebox.askyesno("Conferma", "Vuoi rimuovere questo collaboratore come responsabile dai clienti selezionati?"):
        return
    for client_id in ids:
        self.db.execute(
            "UPDATE clients SET responsible_collaborator_id = NULL WHERE id = ? AND responsible_collaborator_id = ?",
            (client_id, self.collaborator_id),
        )
    self.load_data()
    messagebox.showinfo("Responsabile rimosso", "Collegamento responsabile rimosso dai clienti selezionati.")


