    ids = _fp_selected_int_ids_from_tree(self.docs_tree)
    if not ids:
        messagebox.showwarning("Attenzione", "Seleziona un documento da aprire.")
        return
    row = self.doc_rows_by_iid.get(str(ids[0])) or self.db.get_document(ids[0])
    if row and row["stored_path"]:
        open_path(row["stored_path"])
    else:
        messagebox.showerror("Errore", "Documento non trovato o file mancante.")


