# ---------- Scoring Plus: elimina input dati e documenti ----------

def _sp_delete_inputs(self):
    if not getattr(self, "current_client_id", None):
        messagebox.showwarning("Scoring Plus", "Seleziona prima un cliente.")
        return
    if not messagebox.askyesno("Conferma eliminazione", "Vuoi eliminare tutti gli input dati salvati per il cliente selezionato?"):
        return
    self.db.delete_scoring_plus_input(self.current_client_id)
    for var in getattr(self, "inputs", {}).values():
        try:
            var.set("0")
        except Exception:
            pass
    try:
        self._refresh_kpi_preview()
    except Exception:
        pass
    self.status_var.set("Input dati eliminati per il cliente selezionato.")
    messagebox.showinfo("Eliminazione completata", "Input dati eliminati correttamente.")


