def _bbp_cr36_client_rows(db):
    """Legge i clienti direttamente dal database dell'app, senza dipendere dal filtro delle altre finestre."""
    rows = []
    try:
        rows = list(db.conn.execute(
            """
            SELECT id, denominazione, partita_iva, codice_fiscale
            FROM clients
            ORDER BY denominazione COLLATE NOCASE, id
            """
        ).fetchall())
    except Exception:
        rows = []
    if not rows:
        try:
            rows = list(db.basic_client_choices() or [])
        except Exception:
            rows = []
    if not rows:
        try:
            rows = list(db.list_clients("") or [])
        except Exception:
            rows = []
    return rows or []


def _bbp_cr36_row_id_name(row):
    try:
        cid = int(row["id"])
    except Exception:
        cid = int(row[0])
    try:
        name = str(row["denominazione"] or "").strip()
    except Exception:
        name = str(row[1] or "").strip() if len(row) > 1 else ""
    if not name:
        name = f"Cliente {cid}"
    return cid, name


def _bbp_cr36_build_client_mapping(db):
    mapping = {}
    used_names = {}
    for row in _bbp_cr36_client_rows(db):
        try:
            cid, name = _bbp_cr36_row_id_name(row)
        except Exception:
            continue
        used_names[name] = used_names.get(name, 0) + 1
        label = name if used_names[name] == 1 else f"{name} (ID {cid})"
        mapping[label] = cid
        # chiavi di sicurezza non visualizzate: servono se il valore contiene gia' ID da vecchie versioni
        mapping[f"{name} (ID {cid})"] = cid
    # Mantiene solo la prima etichetta semplice tra i values visualizzati, ma lascia nel mapping anche gli alias.
    values = []
    seen_ids = set()
    for label, cid in mapping.items():
        if cid in seen_ids:
            continue
        seen_ids.add(cid)
        values.append(label)
    return mapping, values


def _bbp_cr36_force_clients(self, prefer_id=None, keep_current=True):
    """Popola sempre la tendina clienti della finestra CR36 e seleziona un cliente valido."""
    try:
        old_value = self.client_combo.get().strip()
    except Exception:
        old_value = ""
    mapping, values = _bbp_cr36_build_client_mapping(self.db)
    self.client_ids_by_name = mapping
    try:
        self.client_combo.configure(state="readonly", width=58)
        self.client_combo["values"] = values
    except Exception:
        pass

    selected = ""
    target_id = prefer_id or getattr(self, "preselected_client_id", None)
    if target_id is not None:
        try:
            target_id = int(target_id)
            for label in values:
                if int(mapping.get(label, -1)) == target_id:
                    selected = label
                    break
        except Exception:
            selected = ""
    if not selected and keep_current and old_value:
        if old_value in mapping:
            selected = old_value
        else:
            found = re.search(r"\(ID\s*(\d+)\)", old_value)
            if found:
                wanted = int(found.group(1))
                for label in values:
                    if int(mapping.get(label, -1)) == wanted:
                        selected = label
                        break
    if not selected and values:
        selected = values[0]
    try:
        self.client_combo.set(selected)
    except Exception:
        pass
    try:
        self.refresh_documents()
    except Exception:
        pass
    return mapping.get(selected) if selected else None


def _bbp_cr36_selected_client_id(self):
    try:
        raw = self.client_combo.get().strip()
        mapping = getattr(self, "client_ids_by_name", {}) or {}
        if raw in mapping:
            return int(mapping[raw])
        found = re.search(r"\(ID\s*(\d+)\)", raw)
        if found:
            return int(found.group(1))
        # Se la combo e' vuota ma ha valori, forza il caricamento e seleziona il primo cliente visibile.
        cid = _bbp_cr36_force_clients(self, keep_current=True)
        if cid:
            return int(cid)
    except Exception:
        pass
    return None


def _bbp_cr36_open_client_picker(self):
    mapping, values = _bbp_cr36_build_client_mapping(self.db)
    if not values:
        messagebox.showwarning(
            "Clienti non trovati",
            "Non risultano clienti salvati nel database. Inserisci prima il cliente dalla sezione Clienti e poi riapri Analisi CR 36 mesi.",
            parent=self,
        )
        return None

    dialog = tk.Toplevel(self)
    dialog.title("Seleziona cliente per Analisi CR 36 mesi")
    dialog.geometry("640x440")
    dialog.transient(self)
    dialog.grab_set()

    selected_id = {"value": None}
    frame = ttk.Frame(dialog, padding=14)
    frame.pack(fill="both", expand=True)
    ttk.Label(frame, text="Cerca cliente:").pack(anchor="w")
    search_var = tk.StringVar()
    search_entry = ttk.Entry(frame, textvariable=search_var)
    search_entry.pack(fill="x", pady=(4, 8))

    list_frame = ttk.Frame(frame)
    list_frame.pack(fill="both", expand=True)
    ybar = ttk.Scrollbar(list_frame, orient="vertical")
    lb = tk.Listbox(list_frame, activestyle="dotbox", yscrollcommand=ybar.set, font=("Segoe UI", 10))
    ybar.configure(command=lb.yview)
    lb.pack(side="left", fill="both", expand=True)
    ybar.pack(side="right", fill="y")

    def fill_list(*_args):
        q = normalize_text(search_var.get())
        lb.delete(0, tk.END)
        for label in values:
            if not q or q in normalize_text(label):
                lb.insert(tk.END, label)
        if lb.size() > 0:
            lb.selection_set(0)
            lb.activate(0)

    def apply_selection(_event=None):
        sel = lb.curselection()
        if not sel:
            messagebox.showwarning("Selezione cliente", "Seleziona un cliente dalla lista.", parent=dialog)
            return
        label = lb.get(sel[0])
        cid = mapping.get(label)
        if not cid:
            return
        selected_id["value"] = int(cid)
        try:
            self.client_combo.set(label)
            self.client_ids_by_name = mapping
        except Exception:
            pass
        try:
            self.refresh_documents()
        except Exception:
            pass
        dialog.destroy()

    search_var.trace_add("write", fill_list)
    lb.bind("<Double-1>", apply_selection)
    bar = ttk.Frame(frame)
    bar.pack(fill="x", pady=(12, 0))
    ttk.Button(bar, text="Seleziona", command=apply_selection).pack(side="right", padx=(8, 0))
    ttk.Button(bar, text="Annulla", command=dialog.destroy).pack(side="right")

    fill_list()
    try:
        search_entry.focus_set()
    except Exception:
        pass
    self.wait_window(dialog)
    return selected_id["value"]


try:
    _BBP_ORIG_CR36_INIT_SELECT_FIX = CR36AnalysisWindow.__init__
    _BBP_ORIG_CR36_UPLOAD_SELECT_FIX = CR36AnalysisWindow.upload_cr_documents

    def _bbp_cr36_init_select_fix(self, *args, **kwargs):
        _BBP_ORIG_CR36_INIT_SELECT_FIX(self, *args, **kwargs)
        try:
            _bbp_cr36_force_clients(self, keep_current=True)
            self.client_combo.configure(postcommand=lambda: _bbp_cr36_force_clients(self, keep_current=True))
            self.client_combo.bind("<<ComboboxSelected>>", lambda _e: self.refresh_documents(), add="+")
        except Exception:
            pass
        try:
            top = self.client_combo.master
            if not getattr(self, "_bbp_cr36_client_buttons_added", False):
                ttk.Button(top, text="Aggiorna clienti", command=lambda: _bbp_cr36_force_clients(self, keep_current=True)).pack(side="left", padx=(0, 8))
                ttk.Button(top, text="Scegli cliente", command=lambda: _bbp_cr36_open_client_picker(self)).pack(side="left", padx=(0, 8))
                self._bbp_cr36_client_buttons_added = True
        except Exception:
            pass
        try:
            self.after(150, lambda: _bbp_cr36_force_clients(self, keep_current=True))
        except Exception:
            pass

    def _bbp_cr36_upload_select_fix(self):
        client_id = self.selected_client_id()
        if not client_id:
            client_id = _bbp_cr36_force_clients(self, keep_current=True)
        if not client_id:
            client_id = _bbp_cr36_open_client_picker(self)
        if not client_id:
            return
        return _BBP_ORIG_CR36_UPLOAD_SELECT_FIX(self)

    CR36AnalysisWindow.__init__ = _bbp_cr36_init_select_fix
    CR36AnalysisWindow.selected_client_id = _bbp_cr36_selected_client_id
    CR36AnalysisWindow.scegli_cliente = _bbp_cr36_open_client_picker
    CR36AnalysisWindow.upload_cr_documents = _bbp_cr36_upload_select_fix
except Exception:
    pass


# ============================================================
# PATCH MIGLIORATIVO: Analisi CR 36 mesi piu' ricca, grafica e descrittiva
# ============================================================

def _cr36_std(values: list[float]) -> float:
    vals = [float(v) for v in values if v is not None]
    if not vals:
        return 0.0
    mean = sum(vals) / len(vals)
    return (sum((v - mean) ** 2 for v in vals) / len(vals)) ** 0.5


def _cr36_safe_pct(numerator, denominator):
    try:
        numerator = float(numerator or 0)
        denominator = float(denominator or 0)
    except Exception:
        return None
    if not denominator:
        return None
    return (numerator / denominator) * 100.0


def _cr36_short_month(label: str) -> str:
    label = str(label or '').strip()
    if re.match(r'^20\d{2}-\d{2}$', label):
        yy = label[2:4]
        mm = label[5:7]
        return f"{mm}/{yy}"
    return label[-5:] if len(label) > 5 else label


def _cr36_fmt_short_currency(value) -> str:
    try:
        amount = float(value or 0)
    except Exception:
        return '-'
    sign = '-' if amount < 0 else ''
    amount = abs(amount)
    if amount >= 1_000_000:
        return f"{sign}€ {amount/1_000_000:.2f}M".replace('.', ',')
    if amount >= 1_000:
        return f"{sign}€ {amount/1_000:.1f}K".replace('.', ',')
    return format_currency(sign and -amount or amount)


def _cr36_consecutive_true(rows: list[dict], predicate) -> int:
    best = 0
    current = 0
    for row in rows:
        if predicate(row):
            current += 1
            best = max(best, current)
        else:
            current = 0
    return best


def _cr36_trend_comment(delta_pct: float | None, label_positive: str, label_negative: str, stable_label: str) -> str:
    if delta_pct is None:
        return 'andamento non determinabile'
    if delta_pct >= 10:
        return f"{label_positive} ({delta_pct:+.1f}%)"
    if delta_pct <= -10:
        return f"{label_negative} ({delta_pct:+.1f}%)"
    return f"{stable_label} ({delta_pct:+.1f}%)"


def _cr36_build_summary(rows: list[dict]) -> dict:
    ratios = [r.get('utilizzo_pct') for r in rows if r.get('utilizzo_pct') is not None]
    used = [float(r.get('utilizzato') or 0) for r in rows]
    accorded = [float(r.get('accordato') or 0) for r in rows]
    sconf = [float(r.get('sconfinamenti') or 0) for r in rows]
    rate = [float(r.get('rate_mensili') or 0) for r in rows]
    scaduto = [float(r.get('scaduto') or 0) for r in rows]
    soff = [float(r.get('sofferenze') or 0) for r in rows]
    garanzie = [float(r.get('garanzie') or 0) for r in rows]
    seg = [int(r.get('segnalazioni') or 0) for r in rows]
    interr = [int(r.get('interrogazioni') or 0) for r in rows]

    critical_months = sum(1 for r in rows if (r.get('sconfinamenti') or 0) > 0 or (r.get('sofferenze') or 0) > 0 or (r.get('scaduto') or 0) > 0 or int(r.get('segnalazioni') or 0) > 0)
    high_use_months = sum(1 for r in rows if (r.get('utilizzo_pct') or 0) >= 90)
    watch_use_months = sum(1 for r in rows if 75 <= float(r.get('utilizzo_pct') or 0) < 90)
    max_ratio = max(ratios) if ratios else 0.0
    avg_ratio = _cr36_avg(ratios)
    avg_used = _cr36_avg(used)
    volatility_used_pct = _cr36_safe_pct(_cr36_std(used), avg_used) if avg_used else 0.0
    last_row = rows[-1] if rows else {}
    last_ratio = float(last_row.get('utilizzo_pct') or 0)

    recent_trend = 'N/D'
    delta_recent = None
    if len(used) >= 6:
        first = _cr36_avg(used[:3])
        last = _cr36_avg(used[-3:])
        if first:
            delta_recent = (last - first) / abs(first) * 100.0
            recent_trend = f"{delta_recent:+.1f}% ultimo trimestre vs primo trimestre"

    delta_last12 = None
    recent12 = rows[-12:] if len(rows) >= 12 else rows[:]
    prior12 = rows[-24:-12] if len(rows) >= 24 else []
    recent12_avg = _cr36_avg([r.get('utilizzo_pct') for r in recent12 if r.get('utilizzo_pct') is not None]) if recent12 else 0.0
    prior12_avg = _cr36_avg([r.get('utilizzo_pct') for r in prior12 if r.get('utilizzo_pct') is not None]) if prior12 else 0.0
    if prior12_avg:
        delta_last12 = (recent12_avg - prior12_avg) / abs(prior12_avg) * 100.0

    risk_points = 0
    if avg_ratio >= 90: risk_points += 3
    elif avg_ratio >= 80: risk_points += 2
    elif avg_ratio >= 70: risk_points += 1
    if max_ratio >= 100: risk_points += 2
    elif max_ratio >= 90: risk_points += 1
    if critical_months >= 8: risk_points += 3
    elif critical_months >= 4: risk_points += 2
    elif critical_months >= 1: risk_points += 1
    if sum(sconf) > 0: risk_points += 1
    if sum(seg) > 0: risk_points += 1
    if sum(soff) > 0: risk_points += 2
    if high_use_months >= 6: risk_points += 1
    if volatility_used_pct and volatility_used_pct >= 25: risk_points += 1

    if risk_points >= 8:
        giudizio = 'Critico'
        semaforo = 'Rosso'
    elif risk_points >= 5:
        giudizio = 'Da presidiare'
        semaforo = 'Arancione'
    else:
        giudizio = 'Regolare/monitorare'
        semaforo = 'Verde'

    return {
        'mesi_analizzati': len(rows),
        'accordato_medio': _cr36_avg(accorded),
        'accordato_max': max(accorded) if accorded else 0.0,
        'utilizzato_medio': avg_used,
        'utilizzato_max': max(used) if used else 0.0,
        'utilizzo_medio_pct': avg_ratio,
        'utilizzo_max_pct': max_ratio,
        'sconfinamenti_totali': sum(sconf),
        'mesi_con_sconfini': sum(1 for v in sconf if v > 0),
        'rate_medie': _cr36_avg(rate),
        'rate_max': max(rate) if rate else 0.0,
        'scaduto_totale': sum(scaduto),
        'scaduto_max': max(scaduto) if scaduto else 0.0,
        'sofferenze_totali': sum(soff),
        'sofferenze_max': max(soff) if soff else 0.0,
        'garanzie_medie': _cr36_avg(garanzie),
        'interrogazioni_totali': sum(interr),
        'segnalazioni_totali': sum(seg),
        'mesi_critici': critical_months,
        'mesi_alto_utilizzo': high_use_months,
        'mesi_utilizzo_watch': watch_use_months,
        'trend_utilizzato': recent_trend,
        'trend_delta_pct': delta_recent,
        'trend_ultimi_12_mesi_pct': delta_last12,
        'utilizzo_medio_ultimi_12_mesi_pct': recent12_avg,
        'utilizzo_medio_12_mesi_precedenti_pct': prior12_avg,
        'giudizio': giudizio,
        'semaforo': semaforo,
        'risk_points': risk_points,
        'last_month': last_row.get('mese', '-') if last_row else '-',
        'last_utilizzo_pct': last_ratio,
        'last_accordato': float(last_row.get('accordato') or 0),
        'last_utilizzato': float(last_row.get('utilizzato') or 0),
        'last_sconfinamenti': float(last_row.get('sconfinamenti') or 0),
        'last_scaduto': float(last_row.get('scaduto') or 0),
        'volatilita_utilizzato_pct': volatility_used_pct or 0.0,
        'max_consecutive_critical': _cr36_consecutive_true(rows, lambda r: (r.get('sconfinamenti') or 0) > 0 or (r.get('scaduto') or 0) > 0 or int(r.get('segnalazioni') or 0) > 0),
        'max_consecutive_high_use': _cr36_consecutive_true(rows, lambda r: (r.get('utilizzo_pct') or 0) >= 90),
    }


def _cr36_build_narrative(summary: dict, rows: list[dict], client_name: str, docs: list) -> dict:
    mesi = int(summary.get('mesi_analizzati') or 0)
    doc_names = ', '.join([(d['original_filename'] or d['title'] or 'Documento CR') for d in docs]) if docs else 'n.d.'
    avg_util = summary.get('utilizzo_medio_pct') or 0.0
    last_util = summary.get('last_utilizzo_pct') or 0.0
    volatility = summary.get('volatilita_utilizzato_pct') or 0.0
    delta_recent = summary.get('trend_delta_pct')
    delta_last12 = summary.get('trend_ultimi_12_mesi_pct')
    judgement = summary.get('giudizio', '-')

    if avg_util >= 90:
        use_profile = 'L\'azienda mostra una saturazione strutturalmente elevata delle linee accordate, con un utilizzo medio molto vicino alla piena capienza degli affidamenti.'
    elif avg_util >= 75:
        use_profile = 'L\'andamento evidenzia un utilizzo intenso ma non costantemente saturo, compatibile con una struttura finanziaria che richiede monitoraggio ravvicinato.'
    elif avg_util >= 55:
        use_profile = 'Il profilo di utilizzo degli affidamenti risulta intermedio: la posizione appare attiva ma con spazi di manovra ancora presenti.'
    else:
        use_profile = 'Il grado medio di utilizzo delle linee appare contenuto, segnale di margine disponibile e minore pressione finanziaria di breve periodo.'

    trend_txt = _cr36_trend_comment(delta_recent, 'crescita dell\'utilizzato', 'riduzione dell\'utilizzato', 'assetto sostanzialmente stabile')
    trend12_txt = _cr36_trend_comment(delta_last12, 'peggioramento negli ultimi 12 mesi rispetto ai 12 precedenti', 'miglioramento negli ultimi 12 mesi rispetto ai 12 precedenti', 'sostanziale allineamento ultimi 12 mesi / precedenti')

    alerts = []
    if summary.get('mesi_con_sconfini', 0):
        alerts.append(f"{summary['mesi_con_sconfini']} mesi con sconfinamenti")
    if summary.get('segnalazioni_totali', 0):
        alerts.append(f"{summary['segnalazioni_totali']} segnalazioni rilevate")
    if summary.get('interrogazioni_totali', 0):
        alerts.append(f"{summary['interrogazioni_totali']} interrogazioni")
    if summary.get('scaduto_totale', 0) > 0:
        alerts.append(f"scaduti/rate per {format_currency(summary['scaduto_totale'])}")
    if summary.get('sofferenze_totali', 0) > 0:
        alerts.append(f"sofferenze per {format_currency(summary['sofferenze_totali'])}")
    alerts_sentence = '; '.join(alerts) if alerts else 'non emergono dal testo estraibile anomalie ricorrenti di rilievo'

    strengths = []
    if avg_util < 75:
        strengths.append('utilizzo medio degli affidamenti sotto soglia di tensione')
    if not summary.get('mesi_con_sconfini', 0):
        strengths.append('assenza di mesi con sconfinamenti rilevati dal testo')
    if not summary.get('segnalazioni_totali', 0):
        strengths.append('assenza di segnalazioni qualitative/critiche estratte')
    if volatility < 20:
        strengths.append('profilo di utilizzo relativamente stabile e poco volatile')
    if not strengths:
        strengths.append('presenza di continuita operativa nelle linee accordate, da approfondire con verifica documentale puntuale')

    weaknesses = []
    if summary.get('mesi_alto_utilizzo', 0):
        weaknesses.append(f"{summary['mesi_alto_utilizzo']} mesi con utilizzo almeno al 90%")
    if summary.get('max_consecutive_high_use', 0) >= 3:
        weaknesses.append(f"picchi persistenti di utilizzo elevato per {summary['max_consecutive_high_use']} mesi consecutivi")
    if summary.get('mesi_con_sconfini', 0):
        weaknesses.append('presenza di sconfinamenti che meritano commento andamentale')
    if summary.get('max_consecutive_critical', 0) >= 2:
        weaknesses.append(f"sequenza di anomalie continuative per {summary['max_consecutive_critical']} mesi")
    if summary.get('interrogazioni_totali', 0) >= max(3, mesi // 6 if mesi else 3):
        weaknesses.append('frequenza di interrogazioni non trascurabile, possibile segnale di ricerca di credito')
    if summary.get('sofferenze_totali', 0) > 0:
        weaknesses.append('presenza di sofferenze/crediti deteriorati estratti dal documento')
    if not weaknesses:
        weaknesses.append('nessun fattore di criticita ricorrente particolarmente marcato sul testo analizzato')

    recommendations = []
    if judgement == 'Critico':
        recommendations += [
            'valutare con priorita un commento andamentale dettagliato, motivando gli eventi anomali e la dinamica degli utilizzi',
            'richiedere chiarimenti su sconfinamenti, scaduti e eventuali segnalazioni, con evidenza dei rientri gia avvenuti',
            'valutare il rafforzamento patrimoniale o il consolidamento di parte dell\'esposizione a breve',
        ]
    elif judgement == 'Da presidiare':
        recommendations += [
            'mantenere monitoraggio mensile dell\'utilizzo e presidiare i mesi in area oltre il 75%-90%',
            'verificare la sostenibilita delle rate mensili e l\'allineamento con i flussi di cassa',
            'accompagnare la pratica con nota qualitativa sull\'andamento CR e sugli eventuali eventi straordinari',
        ]
    else:
        recommendations += [
            'mantenere monitoraggio ordinario dell\'andamento, preservando l\'attuale equilibrio finanziario',
            'documentare la stabilita della posizione come elemento positivo nel fascicolo creditizio',
        ]
    recommendations.append('incrociare la presente analisi con bilanci, estratti conto ed esposizioni mensili per una lettura completa del merito creditizio')

    executive = (
        f"Su {mesi} mesi analizzati per il cliente {client_name}, il quadro CR restituisce un giudizio complessivo \"{judgement}\". "
        f"L'utilizzo medio delle linee accordate si attesta al {_cr36_format_pct(avg_util)}, con ultimo mese rilevato {summary.get('last_month', '-') } a {_cr36_format_pct(last_util)}. "
        f"Dal confronto temporale emerge {trend_txt}; nel confronto ultimi 12 mesi / 12 precedenti si osserva {trend12_txt}."
    )

    detail_1 = (
        f"Base documentale analizzata: {doc_names}. {use_profile} "
        f"L'accordato medio e' pari a {format_currency(summary.get('accordato_medio'))}, a fronte di un utilizzato medio di {format_currency(summary.get('utilizzato_medio'))}. "
        f"Il picco massimo di utilizzo tocca {_cr36_format_pct(summary.get('utilizzo_max_pct'))}; la volatilita dell'utilizzato e' pari a {_cr36_format_pct(summary.get('volatilita_utilizzato_pct'))}."
    )

    detail_2 = (
        f"Sotto il profilo qualitativo, {alerts_sentence}. "
        f"I mesi classificati come critici sono {summary.get('mesi_critici', 0)} su {mesi}; la sequenza piu' lunga di anomalie consecutive e' pari a {summary.get('max_consecutive_critical', 0)} mesi."
    )

    detail_3 = (
        f"Nell'ultimo mese rilevato ({summary.get('last_month', '-')}) risultano accordato {format_currency(summary.get('last_accordato'))}, "
        f"utilizzato {format_currency(summary.get('last_utilizzato'))}, sconfinamenti {format_currency(summary.get('last_sconfinamenti'))} e scaduto {format_currency(summary.get('last_scaduto'))}."
    )

    return {
        'executive_summary': executive,
        'detail_paragraphs': [detail_1, detail_2, detail_3],
        'strengths': strengths,
        'weaknesses': weaknesses,
        'recommendations': recommendations,
    }


def _cr36_build_report(client_row, docs: list, rows: list[dict]) -> dict:
    summary = _cr36_build_summary(rows)
    client_name = client_row['denominazione'] if client_row else 'Cliente'
    narrative = _cr36_build_narrative(summary, rows, client_name, docs)
    sections = [
        [
            '1. Executive summary',
            narrative['executive_summary'],
            *narrative['detail_paragraphs'],
        ],
        [
            '2. Indicatori chiave',
            f"Mesi analizzati: {summary['mesi_analizzati']}. Semaforo di rischio: {summary.get('semaforo', '-')}.",
            f"Accordato medio {format_currency(summary['accordato_medio'])} | Utilizzato medio {format_currency(summary['utilizzato_medio'])} | Utilizzo medio {_cr36_format_pct(summary['utilizzo_medio_pct'])}.",
            f"Picco utilizzo {_cr36_format_pct(summary['utilizzo_max_pct'])} | Mesi alto utilizzo {summary.get('mesi_alto_utilizzo', 0)} | Mesi in watchlist {summary.get('mesi_utilizzo_watch', 0)}.",
            f"Sconfinamenti totali {format_currency(summary['sconfinamenti_totali'])} | Rate medie {format_currency(summary['rate_medie'])} | Scaduto totale {format_currency(summary.get('scaduto_totale'))}.",
        ],
        ['3. Punti di forza', *[f"- {x}" for x in narrative['strengths']]],
        ['4. Aree di attenzione', *[f"- {x}" for x in narrative['weaknesses']]],
        ['5. Raccomandazioni operative', *[f"- {x}" for x in narrative['recommendations']]],
        [
            '6. Dettagli tabellari inclusi nel PDF',
            'Il PDF dettagliato include tabelle mese per mese con accordato, utilizzato, utilizzo %, sconfinamenti, rate/scaduti, interrogazioni, segnalazioni, sofferenze e garanzie.',
            'Sono inoltre presenti una tabella anomalie/alert, una vista grafica sintetica e una lettura qualitativa approfondita della dinamica CR.',
        ],
    ]
    report = {
        'title': 'Analisi CR 36 mesi',
        'sections': sections,
        'summary': summary,
        'rows': rows,
        'docs': docs,
        'narrative': narrative,
    }
    try:
        report['chart_path'] = _cr36_generate_visual(report)
    except Exception:
        report['chart_path'] = None
    return report


def _cr36_generate_visual(report: dict) -> str | None:
    if not PIL_AVAILABLE:
        return None
    try:
        from PIL import Image as PILImage, ImageDraw, ImageFont
        import tempfile, textwrap
    except Exception:
        return None

    rows = list(report.get('rows') or [])
    summary = dict(report.get('summary') or {})
    width, height = 1500, 920
    img = PILImage.new('RGB', (width, height), 'white')
    draw = ImageDraw.Draw(img)
    try:
        font_title = ImageFont.truetype('DejaVuSans-Bold.ttf', 32)
        font_sub = ImageFont.truetype('DejaVuSans.ttf', 18)
        font_small = ImageFont.truetype('DejaVuSans.ttf', 14)
        font_bold = ImageFont.truetype('DejaVuSans-Bold.ttf', 16)
    except Exception:
        font_title = ImageFont.load_default()
        font_sub = ImageFont.load_default()
        font_small = ImageFont.load_default()
        font_bold = ImageFont.load_default()

    # Header
    draw.rounded_rectangle((20, 20, width-20, 110), radius=22, fill='#f4f7ff', outline='#d8e2f4', width=2)
    draw.text((40, 38), report.get('title', 'Analisi CR 36 mesi'), fill='#1f4ea8', font=font_title)
    meta = f"Giudizio: {summary.get('giudizio', '-')}   |   Semaforo: {summary.get('semaforo', '-')}   |   Mesi analizzati: {summary.get('mesi_analizzati', 0)}"
    draw.text((42, 78), meta, fill='#526177', font=font_sub)

    # KPI cards
    cards = [
        ('Utilizzo medio', _cr36_format_pct(summary.get('utilizzo_medio_pct'))),
        ('Picco utilizzo', _cr36_format_pct(summary.get('utilizzo_max_pct'))),
        ('Mesi critici', str(summary.get('mesi_critici', 0))),
        ('Sconfini', str(summary.get('mesi_con_sconfini', 0))),
        ('Interrogazioni', str(summary.get('interrogazioni_totali', 0))),
        ('Segnalazioni', str(summary.get('segnalazioni_totali', 0))),
    ]
    card_y1, card_y2 = 132, 242
    gap = 16
    card_w = int((width - 40 - gap*5) / 6)
    for i, (label, value) in enumerate(cards):
        x1 = 20 + i * (card_w + gap)
        x2 = x1 + card_w
        fill = '#ffffff'
        outline = '#d9e2ef'
        draw.rounded_rectangle((x1, card_y1, x2, card_y2), radius=18, fill=fill, outline=outline, width=2)
        draw.text((x1+18, card_y1+18), label, fill='#6b778c', font=font_small)
        draw.text((x1+18, card_y1+58), str(value), fill='#223046', font=font_title)

    # Main chart area
    chart_x1, chart_y1, chart_x2, chart_y2 = 28, 280, 1028, 620
    draw.rounded_rectangle((chart_x1, chart_y1, chart_x2, chart_y2), radius=18, fill='#ffffff', outline='#d9e2ef', width=2)
    draw.text((chart_x1+18, chart_y1+16), 'Andamento accordato, utilizzato e utilizzo %', fill='#223046', font=font_bold)

    plot_left, plot_top, plot_right, plot_bottom = chart_x1 + 56, chart_y1 + 58, chart_x2 - 26, chart_y2 - 44
    draw.line((plot_left, plot_bottom, plot_right, plot_bottom), fill='#adb9ca', width=2)
    draw.line((plot_left, plot_top, plot_left, plot_bottom), fill='#adb9ca', width=2)
    # Thresholds
    for pct, color in [(75, '#dbeafe'), (90, '#fde68a'), (100, '#fecaca')]:
        y = plot_bottom - (pct / 120.0) * (plot_bottom - plot_top)
        draw.line((plot_left, y, plot_right, y), fill=color, width=2)
        draw.text((plot_left - 38, y - 8), f'{pct}%', fill='#6b778c', font=font_small)

    chart_rows = rows[-24:] if len(rows) > 24 else rows
    max_money = max([float(r.get('accordato') or 0) for r in chart_rows] + [float(r.get('utilizzato') or 0) for r in chart_rows] + [1.0])
    plot_h = plot_bottom - plot_top
    plot_w = plot_right - plot_left
    step = plot_w / max(len(chart_rows), 1)
    util_points = []
    for idx, row in enumerate(chart_rows):
        x = plot_left + step * idx + step/2
        accordato = float(row.get('accordato') or 0)
        utilizzato = float(row.get('utilizzato') or 0)
        ratio = float(row.get('utilizzo_pct') or 0)
        bar_half = min(12, max(5, int(step * 0.18)))
        h_acc = (accordato / max_money) * (plot_h * 0.88)
        h_use = (utilizzato / max_money) * (plot_h * 0.88)
        draw.rectangle((x - bar_half - 4, plot_bottom - h_acc, x - 4, plot_bottom), fill='#c7d7ff', outline='#c7d7ff')
        color_use = '#d97706' if ratio >= 90 else ('#4d7bdc' if ratio < 75 else '#7c92f5')
        draw.rectangle((x + 4, plot_bottom - h_use, x + bar_half + 4, plot_bottom), fill=color_use, outline=color_use)
        util_y = plot_bottom - (ratio / 120.0) * plot_h
        util_points.append((x, util_y))
        if idx % max(1, len(chart_rows) // 8) == 0 or idx == len(chart_rows)-1:
            draw.text((x - 18, plot_bottom + 10), _cr36_short_month(row.get('mese', '')), fill='#6b778c', font=font_small)
    if len(util_points) >= 2:
        draw.line(util_points, fill='#1f4ea8', width=4)
        for px, py in util_points:
            draw.ellipse((px-3, py-3, px+3, py+3), fill='#1f4ea8', outline='#1f4ea8')
    draw.text((plot_left, plot_top - 28), 'Barre: accordato/utilizzato  |  Linea: utilizzo %', fill='#6b778c', font=font_small)

    # Right panel narrative / alerts
    rx1, ry1, rx2, ry2 = 1050, 280, width - 28, 620
    draw.rounded_rectangle((rx1, ry1, rx2, ry2), radius=18, fill='#ffffff', outline='#d9e2ef', width=2)
    draw.text((rx1+18, ry1+16), 'Lettura qualitativa', fill='#223046', font=font_bold)
    narrative = report.get('narrative', {}) or {}
    bullets = [
        f"Giudizio complessivo: {summary.get('giudizio', '-')}",
        f"Trend utilizzato: {summary.get('trend_utilizzato', 'N/D')}",
        f"Volatilita utilizzato: {_cr36_format_pct(summary.get('volatilita_utilizzato_pct'))}",
        f"Ultimo mese: {summary.get('last_month', '-')} / utilizzo {_cr36_format_pct(summary.get('last_utilizzo_pct'))}",
    ]
    bullets += [f"• {x}" for x in (narrative.get('weaknesses') or [])[:4]]
    y = ry1 + 54
    for line in bullets:
        for part in textwrap.wrap(str(line), width=38):
            draw.text((rx1+22, y), part, fill='#445066', font=font_small)
            y += 21
        y += 6

    # Heatmap alerts
    hx1, hy1, hx2, hy2 = 28, 650, width - 28, 892
    draw.rounded_rectangle((hx1, hy1, hx2, hy2), radius=18, fill='#ffffff', outline='#d9e2ef', width=2)
    draw.text((hx1+18, hy1+16), 'Heatmap anomalie mese per mese', fill='#223046', font=font_bold)
    heat_rows = rows[-18:] if len(rows) > 18 else rows
    metrics = [
        ('Interrog.', lambda r: int(r.get('interrogazioni') or 0), '#dbeafe', '#2563eb'),
        ('Segnalaz.', lambda r: int(r.get('segnalazioni') or 0), '#fef3c7', '#d97706'),
        ('Sconfini', lambda r: 1 if float(r.get('sconfinamenti') or 0) > 0 else 0, '#fee2e2', '#dc2626'),
        ('Scaduti', lambda r: 1 if max(float(r.get('rate_mensili') or 0), float(r.get('scaduto') or 0)) > 0 else 0, '#fce7f3', '#db2777'),
    ]
    table_left = hx1 + 140
    table_top = hy1 + 58
    col_w = max(38, int((hx2 - table_left - 20) / max(len(heat_rows), 1)))
    row_h = 38
    for idx, row in enumerate(heat_rows):
        x = table_left + idx * col_w
        draw.text((x+2, table_top - 24), _cr36_short_month(row.get('mese', '')), fill='#6b778c', font=font_small)
    for ridx, (label, getter, bg, fg) in enumerate(metrics):
        y0 = table_top + ridx * row_h
        draw.text((hx1+24, y0 + 10), label, fill='#445066', font=font_bold)
        for cidx, row in enumerate(heat_rows):
            x0 = table_left + cidx * col_w
            val = getter(row)
            intensity = min(1.0, max(0.0, float(val) / 3.0)) if isinstance(val, (int, float)) else 0.0
            fill = bg if val else '#f8fafc'
            draw.rounded_rectangle((x0+2, y0+2, x0 + col_w - 4, y0 + row_h - 4), radius=8, fill=fill, outline='#e5ebf4')
            txt = str(val) if val else '-'
            draw.text((x0 + col_w/2 - 8, y0 + 10), txt, fill=fg if val else '#94a3b8', font=font_small)

    tmp = tempfile.NamedTemporaryFile(prefix='cr36_visual_', suffix='.png', delete=False)
    tmp.close()
    img.save(tmp.name)
    return tmp.name


def _cr36_export_pdf(output_path: str, client_row, report: dict) -> None:
    if not REPORTLAB_AVAILABLE:
        raise RuntimeError('ReportLab non disponibile: impossibile generare il PDF.')
    from reportlab.lib.pagesizes import landscape
    from reportlab.platypus import Image as RLImage

    styles = getSampleStyleSheet()
    title_style = ParagraphStyle('CR36Title2', parent=styles['Heading1'], fontName='Helvetica-Bold', fontSize=19, leading=23, textColor=colors.HexColor('#1f4ea8'), spaceAfter=10)
    h2 = ParagraphStyle('CR36H22', parent=styles['Heading2'], fontName='Helvetica-Bold', fontSize=12.5, leading=15.2, textColor=colors.HexColor('#1f4ea8'), spaceBefore=8, spaceAfter=5)
    h3 = ParagraphStyle('CR36H23', parent=styles['Heading3'], fontName='Helvetica-Bold', fontSize=10, leading=12, textColor=colors.HexColor('#223046'), spaceBefore=6, spaceAfter=3)
    body = ParagraphStyle('CR36Body2', parent=styles['BodyText'], fontName='Helvetica', fontSize=8.4, leading=10.8, textColor=colors.HexColor('#223046'), spaceAfter=4)
    small = ParagraphStyle('CR36Small2', parent=styles['BodyText'], fontName='Helvetica', fontSize=6.6, leading=8)
    bullet = ParagraphStyle('CR36Bullet2', parent=body, leftIndent=10, bulletIndent=0)

    doc = SimpleDocTemplate(output_path, pagesize=landscape(A4), leftMargin=1.0*cm, rightMargin=1.0*cm, topMargin=2.2*cm, bottomMargin=1.0*cm)
    story = []
    story.append(_cr36_para(report.get('title') or 'Analisi CR 36 mesi', title_style))
    if client_row:
        meta_text = f"Cliente: {client_row['denominazione']}"
        story.append(_cr36_para(meta_text, body))
    story.append(_cr36_para(f"Data report: {datetime.now().strftime('%d/%m/%Y %H:%M')}", body))
    story.append(Spacer(1, 0.10*cm))

    summary = report.get('summary', {}) or {}
    narrative = report.get('narrative', {}) or {}

    # Executive box
    exec_table = Table([
        [_cr36_para('Executive summary', h3)],
        [_cr36_para(narrative.get('executive_summary', ''), body)],
    ], colWidths=[26.5*cm])
    exec_table.setStyle(TableStyle([
        ('BACKGROUND', (0,0), (-1,0), colors.HexColor('#e8efff')),
        ('BACKGROUND', (0,1), (-1,1), colors.white),
        ('BOX', (0,0), (-1,-1), 0.6, colors.HexColor('#d7deeb')),
        ('INNERGRID', (0,0), (-1,-1), 0.2, colors.HexColor('#d7deeb')),
        ('LEFTPADDING', (0,0), (-1,-1), 8),
        ('RIGHTPADDING', (0,0), (-1,-1), 8),
        ('TOPPADDING', (0,0), (-1,-1), 6),
        ('BOTTOMPADDING', (0,0), (-1,-1), 6),
    ]))
    story.extend([exec_table, Spacer(1, 0.18*cm)])

    # KPI cards as tables (2 rows x 4 cols)
    kpis = [
        ('Semaforo', summary.get('semaforo', '-')),
        ('Giudizio', summary.get('giudizio', '-')),
        ('Utilizzo medio', _cr36_format_pct(summary.get('utilizzo_medio_pct'))),
        ('Picco utilizzo', _cr36_format_pct(summary.get('utilizzo_max_pct'))),
        ('Mesi critici', str(summary.get('mesi_critici', 0))),
        ('Mesi con sconfini', str(summary.get('mesi_con_sconfini', 0))),
        ('Interrogazioni', str(summary.get('interrogazioni_totali', 0))),
        ('Segnalazioni', str(summary.get('segnalazioni_totali', 0))),
    ]
    kpi_cells = []
    row = []
    for idx, (lab, val) in enumerate(kpis, start=1):
        cell = Table([
            [_cr36_para(lab, small)],
            [_cr36_para(f"<b>{html.escape(str(val))}</b>", body)],
        ], colWidths=[3.15*cm])
        cell.setStyle(TableStyle([
            ('BACKGROUND', (0,0), (-1,0), colors.HexColor('#f5f8ff')),
            ('BACKGROUND', (0,1), (-1,1), colors.white),
            ('BOX', (0,0), (-1,-1), 0.5, colors.HexColor('#d7deeb')),
            ('LEFTPADDING', (0,0), (-1,-1), 6),
            ('RIGHTPADDING', (0,0), (-1,-1), 6),
            ('TOPPADDING', (0,0), (-1,-1), 4),
            ('BOTTOMPADDING', (0,0), (-1,-1), 4),
        ]))
        row.append(cell)
        if idx % 4 == 0:
            kpi_cells.append(row)
            row = []
    if row:
        while len(row) < 4:
            row.append('')
        kpi_cells.append(row)
    kpi_table = Table(kpi_cells, colWidths=[6.45*cm, 6.45*cm, 6.45*cm, 6.45*cm], hAlign='LEFT')
    kpi_table.setStyle(TableStyle([('VALIGN', (0,0), (-1,-1), 'TOP')]))
    story.extend([_cr36_para('1. Cruscotto sintetico', h2), kpi_table, Spacer(1, 0.2*cm)])

    # Visual image
    chart_path = report.get('chart_path')
    if chart_path and Path(chart_path).exists():
        try:
            story.append(_cr36_para('2. Dashboard grafica', h2))
            story.append(RLImage(chart_path, width=25.8*cm, height=15.8*cm))
            story.append(Spacer(1, 0.18*cm))
        except Exception:
            pass

    # Narrative sections
    story.append(_cr36_para('3. Analisi descrittiva approfondita', h2))
    for par in narrative.get('detail_paragraphs', []):
        story.append(_cr36_para(par, body))
    story.append(Spacer(1, 0.08*cm))

    story.append(_cr36_para('4. Punti di forza e aree di attenzione', h2))
    story.append(_cr36_para('<b>Punti di forza</b>', h3))
    for item in narrative.get('strengths', []):
        story.append(Paragraph(f'• {html.escape(str(item))}', bullet))
    story.append(_cr36_para('<b>Aree di attenzione</b>', h3))
    for item in narrative.get('weaknesses', []):
        story.append(Paragraph(f'• {html.escape(str(item))}', bullet))
    story.append(_cr36_para('<b>Raccomandazioni operative</b>', h3))
    for item in narrative.get('recommendations', []):
        story.append(Paragraph(f'• {html.escape(str(item))}', bullet))
    story.append(Spacer(1, 0.15*cm))

    idx_rows = [['Indice', 'Valore'],
        ['Mesi analizzati', summary.get('mesi_analizzati', 0)],
        ['Accordato medio', format_currency(summary.get('accordato_medio'))],
        ['Accordato massimo', format_currency(summary.get('accordato_max'))],
        ['Utilizzato medio', format_currency(summary.get('utilizzato_medio'))],
        ['Utilizzato massimo', format_currency(summary.get('utilizzato_max'))],
        ['Utilizzo medio', _cr36_format_pct(summary.get('utilizzo_medio_pct'))],
        ['Picco utilizzo', _cr36_format_pct(summary.get('utilizzo_max_pct'))],
        ['Volatilita utilizzato', _cr36_format_pct(summary.get('volatilita_utilizzato_pct'))],
        ['Trend utilizzato', str(summary.get('trend_utilizzato', '-'))],
        ['Trend ultimi 12 mesi', _cr36_format_pct(summary.get('trend_ultimi_12_mesi_pct')) if summary.get('trend_ultimi_12_mesi_pct') is not None else '-'],
        ['Sconfinamenti totali', format_currency(summary.get('sconfinamenti_totali'))],
        ['Mesi con sconfini', summary.get('mesi_con_sconfini', 0)],
        ['Scaduto totale', format_currency(summary.get('scaduto_totale'))],
        ['Sofferenze totali', format_currency(summary.get('sofferenze_totali'))],
        ['Interrogazioni', summary.get('interrogazioni_totali', 0)],
        ['Segnalazioni', summary.get('segnalazioni_totali', 0)],
        ['Giudizio', summary.get('giudizio', '-')],
    ]
    idx_table = Table(idx_rows, colWidths=[7.0*cm, 7.0*cm])
    idx_table.setStyle(TableStyle([
        ('BACKGROUND', (0,0), (-1,0), colors.HexColor(ACCENT_COLOR)),
        ('GRID', (0,0), (-1,-1), 0.25, colors.grey),
        ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
        ('FONTSIZE', (0,0), (-1,-1), 8),
        ('VALIGN', (0,0), (-1,-1), 'TOP'),
        ('ROWBACKGROUNDS', (0,1), (-1,-1), [colors.white, colors.HexColor('#fafcff')]),
    ]))
    story += [_cr36_para('5. Tabella indici', h2), idx_table, Spacer(1, 0.25*cm)]

    rows = report.get('rows', [])
    table_rows = [['Mese', 'Accordato', 'Utilizzato', 'Util.%', 'Sconfini', 'Rate/Scaduti', 'Int.', 'Segn.', 'Soff.', 'Garanzie', 'Note']]
    row_colors = []
    for r in rows:
        rate_scad = max(float(r.get('rate_mensili') or 0), float(r.get('scaduto') or 0))
        note_text = str(r.get('note', '') or '')
        table_rows.append([
            r.get('mese', ''),
            format_currency(r.get('accordato')),
            format_currency(r.get('utilizzato')),
            _cr36_format_pct(r.get('utilizzo_pct')),
            format_currency(r.get('sconfinamenti')),
            format_currency(rate_scad),
            str(r.get('interrogazioni') or 0),
            str(r.get('segnalazioni') or 0),
            format_currency(r.get('sofferenze')),
            format_currency(r.get('garanzie')),
            _cr36_para(note_text, small),
        ])
        if (r.get('utilizzo_pct') or 0) >= 90 or (r.get('sconfinamenti') or 0) > 0 or int(r.get('segnalazioni') or 0) > 0 or rate_scad > 0:
            row_colors.append(colors.HexColor('#fff7ed'))
        else:
            row_colors.append(colors.white if len(row_colors) % 2 == 0 else colors.HexColor('#fafcff'))

    monthly_table = Table(table_rows, repeatRows=1, colWidths=[1.55*cm, 2.1*cm, 2.1*cm, 1.3*cm, 1.85*cm, 2.0*cm, 0.8*cm, 0.85*cm, 1.75*cm, 1.85*cm, 5.05*cm])
    month_style = [
        ('BACKGROUND', (0,0), (-1,0), colors.HexColor('#dfe9ff')),
        ('GRID', (0,0), (-1,-1), 0.20, colors.grey),
        ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
        ('FONTSIZE', (0,0), (-1,-1), 6.3),
        ('VALIGN', (0,0), (-1,-1), 'TOP'),
        ('ALIGN', (1,1), (9,-1), 'RIGHT'),
    ]
    for idx, bg in enumerate(row_colors, start=1):
        month_style.append(('BACKGROUND', (0, idx), (-1, idx), bg))
    monthly_table.setStyle(TableStyle(month_style))
    story += [_cr36_para('6. Dettaglio mese per mese - CR 36 mesi', h2), monthly_table, Spacer(1, 0.25*cm)]

    alerts = [['Mese', 'Interrogazioni', 'Segnalazioni', 'Sconfinamenti', 'Rate/Scaduti', 'Nota']]
    for r in rows:
        if int(r.get('interrogazioni') or 0) or int(r.get('segnalazioni') or 0) or (r.get('sconfinamenti') or 0) or (r.get('scaduto') or 0) or (r.get('rate_mensili') or 0):
            alerts.append([
                r.get('mese', ''), str(r.get('interrogazioni') or 0), str(r.get('segnalazioni') or 0),
                format_currency(r.get('sconfinamenti')), format_currency(max(float(r.get('rate_mensili') or 0), float(r.get('scaduto') or 0))),
                _cr36_para(r.get('note', ''), small),
            ])
    if len(alerts) == 1:
        alerts.append(['-', '0', '0', '-', '-', 'Nessuna anomalia rilevata dal testo estraibile.'])
    alert_table = Table(alerts, repeatRows=1, colWidths=[1.8*cm, 2.1*cm, 2.1*cm, 2.7*cm, 2.7*cm, 15.2*cm])
    alert_table.setStyle(TableStyle([
        ('BACKGROUND', (0,0), (-1,0), colors.HexColor('#fff2cc')),
        ('GRID', (0,0), (-1,-1), 0.20, colors.grey),
        ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
        ('FONTSIZE', (0,0), (-1,-1), 6.8),
        ('VALIGN', (0,0), (-1,-1), 'TOP'),
        ('ROWBACKGROUNDS', (0,1), (-1,-1), [colors.white, colors.HexColor('#fffdfa')]),
    ]))
    story += [_cr36_para('7. Tabella interrogazioni, segnalazioni, sconfinamenti e rate', h2), alert_table]
    story += [Spacer(1, 0.2*cm), _cr36_para('Nota metodologica: analisi automatica basata sul testo estraibile dalla documentazione caricata. In presenza di scansioni, layout complessi o tabelle non OCR, e\' consigliata una verifica manuale integrativa.', small)]

    def add_page(canv, _doc):
        draw_pdf_branding(canv, report.get('title') or 'Analisi CR 36 mesi')
        canv.saveState()
        canv.setFont('Helvetica', 8)
        canv.setFillColor(colors.HexColor('#6b778c'))
        canv.drawRightString(landscape(A4)[0] - 1.0*cm, 0.7*cm, f"Pagina {canv.getPageNumber()}")
        canv.restoreState()
    doc.build(story, onFirstPage=add_page, onLaterPages=add_page)


def _bbp_cr36_draw_chart_pretty(self, rows: list[dict], summary: dict):
    c = self.chart_canvas
    c.delete('all')
    try:
        width = max(360, int(c.winfo_width() or 360))
        height = max(260, int(c.winfo_height() or 260))
    except Exception:
        width, height = 360, 260
    c.create_rectangle(0, 0, width, height, fill='white', outline='')

    # top cards
    cards = [
        ('Giudizio', str(summary.get('giudizio', '-'))),
        ('Utilizzo medio', _cr36_format_pct(summary.get('utilizzo_medio_pct'))),
        ('Mesi critici', str(summary.get('mesi_critici', 0))),
        ('Sconfini', str(summary.get('mesi_con_sconfini', 0))),
    ]
    gap = 10
    margin = 12
    card_w = (width - margin*2 - gap*3) / 4
    for i, (label, value) in enumerate(cards):
        x1 = margin + i * (card_w + gap)
        x2 = x1 + card_w
        c.create_rectangle(x1, 10, x2, 72, fill='#f7f9fe', outline='#d7deeb')
        c.create_text(x1+10, 24, anchor='nw', text=label, font=('Segoe UI', 8), fill=MUTED_TEXT)
        c.create_text(x1+10, 48, anchor='nw', text=value, font=('Segoe UI', 10, 'bold'), fill=TEXT_COLOR)

    c.create_text(14, 88, anchor='nw', text='Andamento utilizzo % (ultimi mesi rilevati)', font=('Segoe UI', 10, 'bold'), fill=TEXT_COLOR)
    if not rows:
        c.create_text(14, 120, anchor='nw', text='Nessun mese rilevato dal documento')
        return
    plot_x1, plot_y1, plot_x2, plot_y2 = 24, 116, width - 16, height - 22
    c.create_rectangle(plot_x1, plot_y1, plot_x2, plot_y2, outline='#e0e6f2')
    for pct, color in [(75, '#e8efff'), (90, '#fff4cc'), (100, '#ffe3e3')]:
        y = plot_y2 - (pct / 120.0) * (plot_y2 - plot_y1)
        c.create_line(plot_x1, y, plot_x2, y, fill=color)
        c.create_text(plot_x1 - 3, y, text=str(pct), anchor='e', font=('Segoe UI', 7), fill=MUTED_TEXT)

    chart_rows = rows[-18:] if len(rows) > 18 else rows
    step = (plot_x2 - plot_x1) / max(len(chart_rows), 1)
    points = []
    for idx, r in enumerate(chart_rows):
        x = plot_x1 + idx * step + step/2
        ratio = float(r.get('utilizzo_pct') or 0)
        y = plot_y2 - (ratio / 120.0) * (plot_y2 - plot_y1)
        points.extend([x, y])
        color = WARNING_COLOR if ratio >= 90 or (r.get('sconfinamenti') or 0) > 0 else PRIMARY_COLOR
        c.create_oval(x-3, y-3, x+3, y+3, fill=color, outline=color)
        if (r.get('sconfinamenti') or 0) > 0 or int(r.get('segnalazioni') or 0) > 0:
            c.create_rectangle(x-4, plot_y2-14, x+4, plot_y2-6, fill='#d97706', outline='#d97706')
        if idx % max(1, len(chart_rows)//6) == 0 or idx == len(chart_rows)-1:
            c.create_text(x, plot_y2 + 10, text=_cr36_short_month(r.get('mese', '')), font=('Segoe UI', 7), fill=MUTED_TEXT)
    if len(points) >= 4:
        c.create_line(*points, fill=PRIMARY_DARK, width=2, smooth=True)
    c.create_text(14, height - 14, anchor='sw', text=f"Trend: {summary.get('trend_utilizzato', 'N/D')}  |  Volatilita: {_cr36_format_pct(summary.get('volatilita_utilizzato_pct'))}", font=('Segoe UI', 8), fill=MUTED_TEXT)

try:
    CR36AnalysisWindow.draw_chart = _bbp_cr36_draw_chart_pretty
except Exception:
    pass



# ============================================================
# PATCH CR36 Banca d'Italia - report gestionale approfondito
# ============================================================
# Questo blocco migliora l'analisi CR quando il PDF e' un prospetto
# Banca d'Italia: estrae i mesi da "DATA DI RIFERIMENTO", somma gli
# utilizzi per cassa per intermediario, separa le voci informative
# factoring/scaduti e produce note piu' vicine a un report consulenziale.

def _cr36_bdi_money_values(text: str) -> list[float]:
    vals = []
    for m in re.finditer(r"(?<![A-Za-z0-9])(?:\d{1,3}(?:\.\d{3})+|\d{4,}|\d{1,3})(?![A-Za-z0-9])", text or ""):
        v = _cr36_parse_num(m.group(0))
        # Esclude anni, codici censiti e importi troppo piccoli non significativi.
        if v >= 1000 and not (1900 <= v <= 2099) and v < 100000000:
            vals.append(v)
    return vals


def _cr36_bdi_extract_cash_rows(block: str) -> list[dict]:
    cash_rows = []
    text = _cr36_clean_text(block)
    parts = re.split(r"(?=Intermediario:\s*)", text)
    for part in parts:
        if "Intermediario:" not in part:
            continue
        im = re.search(r"Intermediario:\s*(.+?)(?:\s+Crediti per cassa|\s+Sezione informativa|\n|$)", part, re.I | re.S)
        interm = (im.group(1).strip() if im else "Intermediario n.d.")
        if "Crediti per cassa" not in part:
            continue
        # Segmenti che seguono la dicitura garanzia/privilegi: nel prospetto BDI
        # sono tipicamente: accordato, accordato operativo, utilizzato, importo garantito/ruolo.
        segment_values = []
        for m in re.finditer(r"(?:PRIVILEGI|GARANZIE\s+REALI\s+E/O\s+PRIVILEGI)\s+(.{0,180})", part, re.I | re.S):
            vals = _cr36_bdi_money_values(m.group(1))[:4]
            if len(vals) >= 2:
                segment_values.append(vals)
        if not segment_values:
            # fallback prudenziale: prende le ultime sequenze numeriche della sezione per cassa
            vals = _cr36_bdi_money_values(part)
            if len(vals) >= 2:
                segment_values.append(vals[-4:])
        for vals in segment_values:
            accordato = vals[0] if vals else 0.0
            accordato_operativo = vals[1] if len(vals) > 1 else accordato
            utilizzato = vals[2] if len(vals) > 2 else accordato_operativo
            cash_rows.append({
                "intermediario": interm,
                "accordato": accordato,
                "accordato_operativo": accordato_operativo,
                "utilizzato": utilizzato,
                "categoria": ("autoliquidanti" if re.search(r"RISCHI\s+AUTOLIQUIDANTI|FACTORING|ANTICIPI", part, re.I) else ("leasing" if re.search(r"LEASING", part, re.I) else "a scadenza")),
                "stato": "non contestato" if re.search(r"RAPPORTI\s+NON\s+CONTESTATI", part, re.I) else "da verificare",
                "raw": part[:900],
            })
    return cash_rows


def _cr36_bdi_extract_info(block: str) -> dict:
    text = _cr36_clean_text(block)
    info_scaduti = 0.0
    info_non_scaduti = 0.0
    info_impagati = 0.0
    debtors = sorted(set(re.findall(r"([A-Z0-9\. '&-]+S\.R\.L\.)\s*\(codice censito", text)))
    # Voci informative: IFITALIA e autoliquidanti pagati/impagati.
    for m in re.finditer(r"CREDITI\s+SCADUTI.{0,260}?((?:\d{1,3}\.)?\d{3,}(?:,\d+)?)", text, re.I | re.S):
        info_scaduti += _cr36_parse_num(m.group(1))
    for m in re.finditer(r"CREDITI\s+NON\s+SCADUTI.{0,260}?((?:\d{1,3}\.)?\d{3,}(?:,\d+)?)", text, re.I | re.S):
        info_non_scaduti += _cr36_parse_num(m.group(1))
    for m in re.finditer(r"CREDITI\s+IMPAGATI.{0,120}?((?:\d{1,3}\.)?\d{3,}(?:,\d+)?)", text, re.I | re.S):
        info_impagati += _cr36_parse_num(m.group(1))
    pagati = 0.0
    for m in re.finditer(r"CREDITI\s+PAGATI.{0,120}?((?:\d{1,3}\.)?\d{3,}(?:,\d+)?)", text, re.I | re.S):
        pagati += _cr36_parse_num(m.group(1))
    return {"info_scaduti": info_scaduti, "info_non_scaduti": info_non_scaduti, "info_impagati": info_impagati, "info_pagati": pagati, "debitori_ceduti": debtors[:8]}


def _cr36_parse_monthly_rows(text: str) -> list[dict]:
    clean = _cr36_clean_text(text)
    # Prospetto CR Banca d'Italia: usa marker ufficiali, evitando duplicazioni da intestazioni/pagine.
    if re.search(r"DATA\s+DI\s+RIFERIMENTO\s*:", clean, re.I):
        month_names = "|".join(sorted(_CR36_MONTHS_IT.keys(), key=len, reverse=True))
        markers = []
        for m in re.finditer(r"DATA\s+DI\s+RIFERIMENTO\s*:\s*(" + month_names + r")\s+(20\d{2})", clean, re.I):
            month = _CR36_MONTHS_IT.get(normalize_category(m.group(1)), 0)
            markers.append((m.start(), f"{m.group(2)}-{month:02d}"))
        rows_by_month = {}
        for idx, (pos, label) in enumerate(markers):
            end = markers[idx+1][0] if idx + 1 < len(markers) else len(clean)
            block = clean[pos:end]
            cash = _cr36_bdi_extract_cash_rows(block)
            info = _cr36_bdi_extract_info(block)
            accordato = sum(r["accordato_operativo"] or r["accordato"] for r in cash)
            utilizzato = sum(r["utilizzato"] for r in cash)
            garanzie = sum(_cr36_bdi_money_values(x)[:1][0] for x in re.findall(r"Importo Garantito\s+(.{0,80})", block, re.I | re.S) if _cr36_bdi_money_values(x)[:1])
            # Se lo stesso mese occupa piu' pagine, aggrega evitando di perdere intermediari.
            existing = rows_by_month.setdefault(label, {"mese": label, "accordato": 0.0, "utilizzato": 0.0, "cash_rows": [], "garanzie": 0.0,
                "info_scaduti": 0.0, "info_non_scaduti": 0.0, "info_impagati": 0.0, "info_pagati": 0.0, "debitori_ceduti": []})
            existing["accordato"] += accordato
            existing["utilizzato"] += utilizzato
            existing["cash_rows"].extend(cash)
            existing["garanzie"] += garanzie
            for k in ("info_scaduti", "info_non_scaduti", "info_impagati", "info_pagati"):
                existing[k] += info.get(k, 0.0)
            existing["debitori_ceduti"] = sorted(set(existing["debitori_ceduti"] + info.get("debitori_ceduti", [])))[:10]
        rows = []
        for label, r in rows_by_month.items():
            ratio = (r["utilizzato"] / r["accordato"] * 100.0) if r["accordato"] else None
            intermediari = sorted(set(x["intermediario"] for x in r["cash_rows"]))
            flags = []
            if ratio is not None and ratio >= 95: flags.append("utilizzo molto elevato")
            elif ratio is not None and ratio >= 80: flags.append("utilizzo elevato")
            if r["info_scaduti"] > 0: flags.append("crediti ceduti/scaduti in sezione informativa")
            if r["info_impagati"] > 0: flags.append("autoliquidanti impagati informativi")
            if not flags: flags.append("rapporti per cassa non contestati dal testo estraibile")
            rows.append({
                "mese": label,
                "accordato": r["accordato"],
                "utilizzato": r["utilizzato"],
                "utilizzo_pct": ratio,
                "sconfinamenti": max(0.0, r["utilizzato"] - r["accordato"]) if r["accordato"] else 0.0,
                "rate_mensili": 0.0,
                "scaduto": r["info_scaduti"] + r["info_impagati"],
                "interrogazioni": 0,
                "segnalazioni": 1 if (r["info_scaduti"] or r["info_impagati"]) else 0,
                "sofferenze": 0.0,
                "garanzie": r["garanzie"],
                "intermediari": intermediari,
                "cash_rows": r["cash_rows"],
                "info_scaduti": r["info_scaduti"],
                "info_non_scaduti": r["info_non_scaduti"],
                "info_impagati": r["info_impagati"],
                "info_pagati": r["info_pagati"],
                "debitori_ceduti": r["debitori_ceduti"],
                "note": "; ".join(flags) + (f"; intermediari: {', '.join(intermediari[:5])}" if intermediari else ""),
            })
        rows.sort(key=lambda r: _cr36_month_key(r.get("mese", "")))
        return rows[-36:]
    # fallback vecchio per report non Banca d'Italia
    blocks = _cr36_find_month_blocks(clean)
    rows_by_month = {}
    for label, block in blocks:
        row = _cr36_extract_row(label, block)
        rows_by_month[label] = row
    rows = list(rows_by_month.values())
    rows.sort(key=lambda r: _cr36_month_key(r.get("mese", "")))
    return rows[-36:]


def _cr36_build_narrative(summary: dict, rows: list[dict], client_name: str, docs: list) -> dict:
    last = rows[-1] if rows else {}
    first = rows[0] if rows else {}
    last_cash = last.get("cash_rows", []) if last else []
    last_info_scaduti = float(last.get("info_scaduti") or 0)
    last_debtors = ", ".join(last.get("debitori_ceduti", [])[:4]) or "n.d."
    trend = summary.get("trend_utilizzato", "N/D")
    delta_abs = (float(last.get("utilizzato") or 0) - float(first.get("utilizzato") or 0)) if rows else 0
    exec_txt = (
        f"Il prospetto CR di {client_name} mostra un quadro per cassa prevalentemente regolare: "
        f"non sono state estratte sofferenze e le posizioni principali risultano come rapporti non contestati. "
        f"L'utilizzato per cassa dell'ultimo mese e' {format_currency(last.get('utilizzato'))}, a fronte di accordato operativo stimato pari a {format_currency(last.get('accordato'))}. "
        f"Il giudizio automatico e' {summary.get('giudizio', '-')}, con semaforo {summary.get('semaforo', '-')}."
    )
    detail_1 = (
        f"Dinamica: nei {summary.get('mesi_analizzati', 0)} mesi riconosciuti l'utilizzato medio e' {format_currency(summary.get('utilizzato_medio'))}; "
        f"il trend calcolato e' {trend}. La variazione assoluta tra primo e ultimo mese analizzato e' {format_currency(delta_abs)}. "
        f"Questo consente di distinguere l'esposizione bancaria effettiva dalle voci informative di factoring."
    )
    detail_2 = (
        "Composizione ultimo mese: " + ("; ".join([f"{x.get('intermediario')}: {format_currency(x.get('utilizzato'))} ({x.get('categoria')})" for x in last_cash[:6]]) if last_cash else "non dettagliabile dal testo estraibile") + "."
    )
    detail_3 = (
        f"Voci informative: nell'ultimo mese risultano crediti ceduti/scaduti o impagati per {format_currency(float(last.get('scaduto') or 0))}. "
        f"Debitori ceduti ricorrenti rilevati: {last_debtors}. Queste voci non vanno automaticamente sommate al debito per cassa, ma incidono sulla lettura andamentale."
    )
    strengths = []
    weaknesses = []
    recommendations = []
    if summary.get("sofferenze_totali", 0) == 0:
        strengths.append("assenza di sofferenze estratte dal prospetto")
    if summary.get("mesi_con_sconfini", 0) == 0:
        strengths.append("assenza di sconfinamenti espliciti; eventuali eccedenze sono trattate come tecniche da riconciliare")
    if summary.get("trend_delta_pct") is not None and summary.get("trend_delta_pct") < 0:
        strengths.append("riduzione dell'utilizzato nel periodo recente")
    if summary.get("utilizzo_medio_pct", 0) >= 90:
        weaknesses.append("utilizzo medio delle linee molto elevato, con poco margine operativo")
    if summary.get("scaduto_totale", 0) > 0:
        weaknesses.append("presenza di crediti ceduti/scaduti o impagati in sezione informativa")
    if last_info_scaduti > 0:
        weaknesses.append(f"ultimo mese con crediti ceduti scaduti per {format_currency(last_info_scaduti)}")
    if last_cash and len(last_cash) <= 2:
        weaknesses.append("concentrazione delle fonti bancarie/autoliquidanti su pochi rapporti")
    recommendations.extend([
        "riconciliare con gli intermediari ogni mese in cui l'utilizzato supera l'accordato operativo o appare saturo",
        "ottenere evidenza di incasso/chiusura delle partite informative scadute e allegarla a eventuali pratiche bancarie",
        "preparare una nota gestionale su factoring, debitori ceduti e concentrazione clienti per anticipare le domande del deliberante",
        "monitorare mensilmente trend utilizzato, scaduti informativi e variazione garanzie personali/pubbliche",
    ])
    return {"executive_summary": exec_txt, "detail_paragraphs": [detail_1, detail_2, detail_3], "strengths": strengths or ["quadro leggibile e monitorabile"], "weaknesses": weaknesses or ["nessuna criticita' rilevante dal testo estraibile"], "recommendations": recommendations}



# ============================================================
# PATCH FINALE GRAFICA CR 36 MESI: tag <b> corretti, semafori
# visivi e dashboard PDF piu' pulita.
# ============================================================

def _cr36_para(text, style):
    """Paragraph ReportLab con escape sicuro e supporto tag base.

    Evita il problema dei tag stampati letteralmente (es. <b>Rosso</b>)
    mantenendo comunque sicuri i contenuti testuali provenienti dai PDF.
    Sono consentiti solo: b, i, u, br.
    """
    raw = str(text or "")
    tokens = re.split(r"(<br\s*/?>|</?b>|</?i>|</?u>)", raw, flags=re.I)
    out = []
    for tok in tokens:
        if not tok:
            continue
        low = tok.lower().replace(' ', '')
        if re.fullmatch(r"<br/?>", low):
            out.append("<br/>")
        elif low in ("<b>", "</b>", "<i>", "</i>", "<u>", "</u>"):
            out.append(low)
        else:
            out.append(html.escape(html.unescape(tok)).replace("\n", "<br/>"))
    return Paragraph("".join(out), style)


def _cr36_semaforo_style(value: str):
    v = normalize_category(str(value or ''))
    if 'ross' in v or 'critic' in v:
        return {'label': 'ROSSO', 'fill': '#fee2e2', 'stroke': '#dc2626', 'text': '#991b1b', 'dot': '#ef4444'}
    if 'aranc' in v or 'giall' in v or 'presid' in v:
        return {'label': 'GIALLO', 'fill': '#fff7d6', 'stroke': '#d97706', 'text': '#92400e', 'dot': '#f59e0b'}
    return {'label': 'VERDE', 'fill': '#dcfce7', 'stroke': '#16a34a', 'text': '#166534', 'dot': '#22c55e'}


def _cr36_generate_visual(report: dict) -> str | None:
    """Dashboard PNG evoluta per PDF: semaforo evidente, KPI leggibili, grafici puliti."""
    try:
        from PIL import Image as PILImage, ImageDraw, ImageFont
        import tempfile, textwrap, math
    except Exception:
        return None

    rows = list(report.get('rows') or [])
    summary = dict(report.get('summary') or {})
    narrative = report.get('narrative', {}) or {}
    width, height = 1600, 980
    img = PILImage.new('RGB', (width, height), 'white')
    draw = ImageDraw.Draw(img)
    try:
        font_title = ImageFont.truetype('DejaVuSans-Bold.ttf', 34)
        font_h = ImageFont.truetype('DejaVuSans-Bold.ttf', 19)
        font_bold = ImageFont.truetype('DejaVuSans-Bold.ttf', 16)
        font = ImageFont.truetype('DejaVuSans.ttf', 15)
        font_small = ImageFont.truetype('DejaVuSans.ttf', 13)
    except Exception:
        font_title = ImageFont.load_default(); font_h = font_title; font_bold = font_title; font = font_title; font_small = font_title

    def txt(x, y, s, fill='#223046', fnt=None):
        draw.text((x, y), str(s), fill=fill, font=fnt or font)

    sem = _cr36_semaforo_style(summary.get('semaforo', '-'))

    # Header con badge semaforo grande.
    draw.rounded_rectangle((28, 26, width-28, 138), radius=24, fill='#f4f7ff', outline='#d8e2f4', width=2)
    txt(54, 45, report.get('title', 'Analisi CR 36 mesi'), '#1f4ea8', font_title)
    meta = f"Giudizio: {summary.get('giudizio', '-')}  |  Mesi analizzati: {summary.get('mesi_analizzati', 0)}  |  Ultimo mese: {summary.get('last_month', '-')}"
    txt(56, 92, meta, '#526177', font)
    bx1, by1, bx2, by2 = width-330, 47, width-58, 118
    draw.rounded_rectangle((bx1, by1, bx2, by2), radius=22, fill=sem['fill'], outline=sem['stroke'], width=3)
    draw.ellipse((bx1+22, by1+20, bx1+54, by1+52), fill=sem['dot'], outline=sem['stroke'], width=2)
    txt(bx1+70, by1+15, 'SEMAFORO', sem['text'], font_small)
    txt(bx1+70, by1+34, sem['label'], sem['text'], font_h)

    # KPI cards.
    cards = [
        ('Utilizzo medio', _cr36_format_pct(summary.get('utilizzo_medio_pct')), '#eff6ff'),
        ('Picco utilizzo', _cr36_format_pct(summary.get('utilizzo_max_pct')), '#fff7ed'),
        ('Mesi critici', str(summary.get('mesi_critici', 0)), '#fef2f2' if summary.get('mesi_critici',0) else '#f8fafc'),
        ('Sconfini', str(summary.get('mesi_con_sconfini', 0)), '#fef2f2' if summary.get('mesi_con_sconfini',0) else '#f8fafc'),
        ('Scaduti info', _cr36_fmt_short_currency(summary.get('scaduto_totale')), '#fdf2f8' if summary.get('scaduto_totale',0) else '#f8fafc'),
        ('Segnalazioni', str(summary.get('segnalazioni_totali', 0)), '#fffbeb' if summary.get('segnalazioni_totali',0) else '#f8fafc'),
    ]
    y1, y2, gap = 164, 284, 18
    card_w = int((width - 56 - gap*5) / 6)
    for i, (label, value, fill) in enumerate(cards):
        x1 = 28 + i * (card_w + gap); x2 = x1 + card_w
        draw.rounded_rectangle((x1, y1, x2, y2), radius=18, fill=fill, outline='#d9e2ef', width=2)
        txt(x1+18, y1+18, label, '#6b778c', font_small)
        txt(x1+18, y1+54, value, '#223046', font_h)

    # Grafico principale.
    chart_x1, chart_y1, chart_x2, chart_y2 = 34, 318, 1070, 678
    draw.rounded_rectangle((chart_x1, chart_y1, chart_x2, chart_y2), radius=20, fill='#ffffff', outline='#d9e2ef', width=2)
    txt(chart_x1+20, chart_y1+16, 'Andamento accordato / utilizzato e soglie di utilizzo', '#223046', font_bold)
    plot_left, plot_top, plot_right, plot_bottom = chart_x1+70, chart_y1+70, chart_x2-34, chart_y2-54
    draw.line((plot_left, plot_bottom, plot_right, plot_bottom), fill='#adb9ca', width=2)
    draw.line((plot_left, plot_top, plot_left, plot_bottom), fill='#adb9ca', width=2)
    plot_h = plot_bottom - plot_top
    for pct, color, lab in [(75, '#dbeafe', '75%'), (90, '#fde68a', '90%'), (100, '#fecaca', '100%')]:
        y = plot_bottom - (pct/120.0)*plot_h
        draw.line((plot_left, y, plot_right, y), fill=color, width=2)
        txt(plot_left-48, y-8, lab, '#6b778c', font_small)

    chart_rows = rows[-24:] if len(rows) > 24 else rows
    max_money = max([float(r.get('accordato') or 0) for r in chart_rows] + [float(r.get('utilizzato') or 0) for r in chart_rows] + [1.0])
    step = (plot_right - plot_left) / max(len(chart_rows), 1)
    points = []
    for idx, r in enumerate(chart_rows):
        x = plot_left + step*idx + step/2
        acc = float(r.get('accordato') or 0); use = float(r.get('utilizzato') or 0); ratio = float(r.get('utilizzo_pct') or 0)
        barw = min(18, max(6, int(step*0.22)))
        h_acc = (acc/max_money)*(plot_h*0.86); h_use = (use/max_money)*(plot_h*0.86)
        draw.rounded_rectangle((x-barw-5, plot_bottom-h_acc, x-5, plot_bottom), radius=3, fill='#bdd0ff')
        use_color = '#dc2626' if ratio >= 100 else '#d97706' if ratio >= 90 else '#4d7bdc'
        draw.rounded_rectangle((x+5, plot_bottom-h_use, x+barw+5, plot_bottom), radius=3, fill=use_color)
        py = plot_bottom - (min(ratio, 120)/120.0)*plot_h
        points.append((x, py))
        if idx % max(1, len(chart_rows)//8) == 0 or idx == len(chart_rows)-1:
            txt(x-18, plot_bottom+13, _cr36_short_month(r.get('mese','')), '#6b778c', font_small)
    if len(points) > 1:
        draw.line(points, fill='#1f4ea8', width=4)
    for px, py in points:
        draw.ellipse((px-4, py-4, px+4, py+4), fill='#1f4ea8')
    txt(plot_left, plot_top-30, 'Barre azzurre: accordato | barre evidenziate: utilizzato | linea blu: utilizzo %', '#6b778c', font_small)

    # Panel qualitativo.
    rx1, ry1, rx2, ry2 = 1094, 318, width-34, 678
    draw.rounded_rectangle((rx1, ry1, rx2, ry2), radius=20, fill='#ffffff', outline='#d9e2ef', width=2)
    txt(rx1+22, ry1+18, 'Lettura qualitativa', '#223046', font_bold)
    bullets = [
        f"Giudizio complessivo: {summary.get('giudizio', '-')}",
        f"Semaforo: {summary.get('semaforo', '-')}",
        f"Trend utilizzato: {summary.get('trend_utilizzato', 'N/D')}",
        f"Volatilita: {_cr36_format_pct(summary.get('volatilita_utilizzato_pct'))}",
        f"Ultimo utilizzo: {_cr36_format_pct(summary.get('last_utilizzo_pct'))}",
    ] + [f"• {x}" for x in (narrative.get('weaknesses') or [])[:5]]
    y = ry1 + 58
    for line in bullets:
        for part in textwrap.wrap(str(line), width=42):
            txt(rx1+24, y, part, '#445066', font_small); y += 22
        y += 5

    # Heatmap anomalie.
    hx1, hy1, hx2, hy2 = 34, 710, width-34, 948
    draw.rounded_rectangle((hx1, hy1, hx2, hy2), radius=20, fill='#ffffff', outline='#d9e2ef', width=2)
    txt(hx1+20, hy1+17, 'Heatmap anomalie mese per mese', '#223046', font_bold)
    heat_rows = rows[-18:] if len(rows) > 18 else rows
    metrics = [
        ('Interrog.', lambda r: int(r.get('interrogazioni') or 0), '#dbeafe', '#2563eb'),
        ('Segnalaz.', lambda r: int(r.get('segnalazioni') or 0), '#fef3c7', '#d97706'),
        ('Sconfini', lambda r: 1 if float(r.get('sconfinamenti') or 0) > 0 else 0, '#fee2e2', '#dc2626'),
        ('Scaduti', lambda r: 1 if max(float(r.get('rate_mensili') or 0), float(r.get('scaduto') or 0)) > 0 else 0, '#fce7f3', '#db2777'),
    ]
    table_left, table_top = hx1+150, hy1+64
    col_w = max(52, int((hx2-table_left-24)/max(len(heat_rows),1)))
    row_h = 39
    for idx, r in enumerate(heat_rows):
        x = table_left + idx*col_w
        txt(x+4, table_top-26, _cr36_short_month(r.get('mese','')), '#6b778c', font_small)
    for ridx, (label, getter, bg, fg) in enumerate(metrics):
        y0 = table_top + ridx*row_h
        txt(hx1+26, y0+10, label, '#445066', font_bold)
        for cidx, r in enumerate(heat_rows):
            x0 = table_left + cidx*col_w; val = getter(r)
            fill = bg if val else '#f8fafc'
            draw.rounded_rectangle((x0+3, y0+3, x0+col_w-5, y0+row_h-5), radius=9, fill=fill, outline='#e5ebf4')
            t = str(val) if val else '-'
            txt(x0+col_w/2-5, y0+10, t, fg if val else '#94a3b8', font_small)

    tmp = tempfile.NamedTemporaryFile(prefix='cr36_visual_perfect_', suffix='.png', delete=False)
    tmp.close(); img.save(tmp.name, quality=95)
    return tmp.name


