_CREDIT_ANALYSIS_COMPLETE_B64 = """"""

def launch_integrated_credit_analysis(parent=None):
    """Avvia il modulo professionale integrato per Analisi CR avanzata + Analisi C/C.

    Il modulo permette di selezionare il cliente, caricare Centrale Rischi e
    estratti conto PDF, calcolare KPI/scoring/fattibilita finanziamento e
    generare un report PDF professionale.
    """
    import base64 as _base64
    import tempfile as _tempfile
    import subprocess as _subprocess
    import sys as _sys
    from pathlib import Path as _Path
    try:
        tmp_dir = _Path(_tempfile.gettempdir()) / "financeplus_credit_analysis_complete"
        tmp_dir.mkdir(parents=True, exist_ok=True)
        module_path = tmp_dir / "financeplus_credit_analysis_complete.py"
        module_code = _base64.b64decode(_CREDIT_ANALYSIS_COMPLETE_B64.encode('ascii')).decode('utf-8')
        launcher_code = module_code + "\n\nif __name__ == '__main__':\n    app = CreditAnalysisApp()\n    app.mainloop()\n"
        module_path.write_text(launcher_code, encoding='utf-8')
        _subprocess.Popen([_sys.executable, str(module_path)], cwd=str(tmp_dir))
        return True
    except Exception as exc:
        try:
            messagebox.showerror("Errore modulo Analisi Creditizia", str(exc))
        except Exception:
            print("Errore modulo Analisi Creditizia:", exc)
        return False



# === BANCA TOP 36M PER BANCA PATCH ===
# Analisi CR 36 mesi con dettaglio per banca, rata mensile stimata, KPI e merito creditizio.

import statistics as _bt_statistics

_BT_MONTHS = {
    "gennaio": 1, "febbraio": 2, "marzo": 3, "aprile": 4,
    "maggio": 5, "giugno": 6, "luglio": 7, "agosto": 8,
    "settembre": 9, "ottobre": 10, "novembre": 11, "dicembre": 12,
    "gen": 1, "feb": 2, "mar": 3, "apr": 4, "mag": 5, "giu": 6,
    "lug": 7, "ago": 8, "set": 9, "ott": 10, "nov": 11, "dic": 12,
}


def _bt_to_float(value):
    try:
        if value is None:
            return 0.0
        if isinstance(value, (int, float)):
            return float(value)
        s = str(value).strip().replace("EUR", "").replace("€", "").replace(" ", "")
        if not s:
            return 0.0
        if "," in s:
            s = s.replace(".", "").replace(",", ".")
        else:
            parts = s.split(".")
            if len(parts) > 2:
                s = "".join(parts)
        return float(s)
    except Exception:
        return 0.0


def _bt_money(value):
    try:
        return format_currency(float(value or 0))
    except Exception:
        return f"€ {float(value or 0):,.0f}".replace(",", ".")


def _bt_pct(value):
    try:
        return f"{float(value or 0) * 100:.1f}%".replace(".", ",")
    except Exception:
        return "n.d."


def _bt_ratio(value):
    try:
        return f"{float(value):.2f}x".replace(".", ",")
    except Exception:
        return "n.d."


def _bt_div(a, b):
    a = _bt_to_float(a)
    b = _bt_to_float(b)
    return None if b == 0 else a / b


def _bt_parse_amounts(text):
    values = []
    for raw in re.findall(r"(?<!\d)(?:\d{1,3}(?:\.\d{3})+|\d{4,})(?!\d)", text or ""):
        val = _bt_to_float(raw)
        if 1_000 <= val <= 50_000_000 and int(val) not in range(2020, 2035):
            values.append(val)
    return values


def _bt_clean_cr_text(text):
    try:
        return _cr36_clean_text(text)
    except Exception:
        return text or ""


def _bt_extract_month_blocks_36(text):
    """Estrae fino a 36 mesi dalla Centrale Rischi."""
    cleaned = _bt_clean_cr_text(text)
    pattern = re.compile(r"DATA\s+DI\s+RIFERIMENTO\s*:\s*([A-Za-zàèéìòù]+)\s+(\d{4})", re.IGNORECASE)
    matches = list(pattern.finditer(cleaned))
    by_period = {}
    for i, match in enumerate(matches):
        month_name = match.group(1).lower().strip()
        year = int(match.group(2))
        month_num = _BT_MONTHS.get(month_name, 0)
        if not month_num:
            continue
        start = match.start()
        end = matches[i + 1].start() if i + 1 < len(matches) else len(cleaned)
        period = f"{year}-{month_num:02d}"
        block = cleaned[start:end]
        if period not in by_period:
            by_period[period] = {
                "period": period,
                "label": f"{month_name} {year}",
                "month": month_num,
                "year": year,
                "text": block,
            }
        else:
            by_period[period]["text"] += chr(10) + block
    return sorted(by_period.values(), key=lambda x: (x["year"], x["month"]), reverse=True)[:36]


def _bt_amounts_for_bank_chunk(chunk):
    amounts = _bt_parse_amounts(chunk)
    econ = [round(v) for v in amounts if 1_000 <= v <= 20_000_000]
    freq = {}
    for v in econ:
        freq[v] = freq.get(v, 0) + 1
    repeated = [k for k, n in freq.items() if n >= 2]
    base = sorted(set(repeated if repeated else econ), reverse=True)
    if not base:
        return 0.0, 0.0, 0.0
    # Nei prospetti CR gli importi di rapporto spesso compaiono ripetuti come accordato/utilizzato/operativo.
    # Per prudenza sommiamo i primi importi principali del blocco banca.
    used = float(sum(base[:3]))
    return used, used, used


def _bt_extract_banks_from_block(block_text):
    """Estrae dettaglio mensile per banca/intermediario."""
    txt = block_text or ""
    chunks = re.split(r"(?=Intermediario:\s*)", txt, flags=re.IGNORECASE)
    banks = []
    for ch in chunks:
        if "Intermediario:" not in ch:
            continue
        m = re.search(r"Intermediario:\s*([^\n]+)", ch, flags=re.IGNORECASE)
        name = (m.group(1).strip() if m else "Intermediario n.d.")[:120]
        accordato, utilizzato, operativo = _bt_amounts_for_bank_chunk(ch)
        upper = ch.upper()
        vals = _bt_parse_amounts(ch)
        max_val = max(vals) if vals else 0.0
        banks.append({
            "intermediario": name,
            "accordato": accordato,
            "utilizzato": utilizzato,
            "accordato_operativo": operativo,
            "sconfinamenti": max_val if "SCONFIN" in upper else 0.0,
            "scaduti": max_val if "SCADUT" in upper else 0.0,
            "sofferenze": max_val if "SOFFEREN" in upper else 0.0,
        })
    return banks


def _bt_month_totals_from_banks(banks):
    banks = banks or []
    return {
        "accordato": sum(_bt_to_float(b.get("accordato")) for b in banks),
        "utilizzato": sum(_bt_to_float(b.get("utilizzato")) for b in banks),
        "accordato_operativo": sum(_bt_to_float(b.get("accordato_operativo")) for b in banks),
        "sconfinamenti": sum(_bt_to_float(b.get("sconfinamenti")) for b in banks),
        "scaduti": sum(_bt_to_float(b.get("scaduti")) for b in banks),
        "sofferenze": sum(_bt_to_float(b.get("sofferenze")) for b in banks),
        "intermediari": len(set(b.get("intermediario") for b in banks)),
        "rapporti": len(banks),
    }


def _cr36_parse_monthly_rows(text):
    """Override: parser CR massimo 36 mesi, con dettaglio per banca."""
    rows = []
    for block in _bt_extract_month_blocks_36(text):
        banks = _bt_extract_banks_from_block(block["text"])
        totals = _bt_month_totals_from_banks(banks)
        accordato = totals["accordato"]
        utilizzato = totals["utilizzato"]
        rows.append({
            "period": block["period"],
            "label": block["label"],
            "month": block["month"],
            "year": block["year"],
            "banks": banks,
            "accordato": accordato,
            "utilizzato": utilizzato,
            "accordato_operativo": totals["accordato_operativo"],
            "saldo_medio": utilizzato,
            "sconfinamenti": totals["sconfinamenti"],
            "sofferenze": totals["sofferenze"],
            "scaduti": totals["scaduti"],
            "intermediari": totals["intermediari"],
            "rapporti": totals["rapporti"],
            "utilizzo_pct": (_bt_div(utilizzato, accordato) or 0.0),
        })
    return rows[:36]


def _bt_last_n(rows, n):
    return list(rows or [])[:n]


def _bt_avg(rows, key):
    vals = [_bt_to_float(r.get(key)) for r in rows if _bt_to_float(r.get(key)) > 0]
    return sum(vals) / len(vals) if vals else 0.0


def _bt_max(rows, key):
    vals = [_bt_to_float(r.get(key)) for r in rows]
    return max(vals) if vals else 0.0


def _bt_min(rows, key):
    vals = [_bt_to_float(r.get(key)) for r in rows if _bt_to_float(r.get(key)) > 0]
    return min(vals) if vals else 0.0


def _bt_trend(rows, key):
    if len(rows) < 2:
        return 0.0
    recent = _bt_avg(_bt_last_n(rows, min(3, len(rows))), key)
    older = _bt_avg(rows[-min(3, len(rows)):], key)
    return 0.0 if older == 0 else (recent - older) / older


def _bt_build_bank_monthly_schedule(rows):
    """Tabella distinta per banca con rata mensile stimata.

    La rata stimata e' il calo dell'utilizzato rispetto al mese precedente per la stessa banca.
    Se l'utilizzato aumenta o resta invariato, la rata stimata e' zero.
    """
    chronological = sorted(list(rows or [])[:36], key=lambda r: str(r.get("period", "")))
    last_by_bank = {}
    out = []
    for row in chronological:
        for bank in row.get("banks", []) or []:
            name = bank.get("intermediario", "Intermediario n.d.")
            used = _bt_to_float(bank.get("utilizzato"))
            prev = last_by_bank.get(name)
            rata = max(0.0, prev - used) if prev is not None else 0.0
            last_by_bank[name] = used
            out.append({
                "period": row.get("period"),
                "label": row.get("label"),
                "intermediario": name,
                "accordato": _bt_to_float(bank.get("accordato")),
                "utilizzato": used,
                "rata_mensile_stimata": rata,
                "sconfinamenti": _bt_to_float(bank.get("sconfinamenti")),
                "scaduti": _bt_to_float(bank.get("scaduti")),
                "sofferenze": _bt_to_float(bank.get("sofferenze")),
            })
    return sorted(out, key=lambda x: (x["intermediario"], x["period"]))


def _bt_bank_schedule_lines(rows, max_lines=500):
    schedule = _bt_build_bank_monthly_schedule(rows)
    if not schedule:
        return "Nessun dettaglio banca/mese estratto. Verificare che il PDF CR sia testuale/OCR."
    lines = []
    current_bank = None
    count = 0
    for item in schedule:
        if item["intermediario"] != current_bank:
            current_bank = item["intermediario"]
            lines.append("")
            lines.append(current_bank)
            lines.append("Mese | Accordato | Utilizzato | Rata mensile stimata | Anomalie")
        anomalies = []
        if item["sconfinamenti"]:
            anomalies.append("sconfini " + _bt_money(item["sconfinamenti"]))
        if item["scaduti"]:
            anomalies.append("scaduti " + _bt_money(item["scaduti"]))
        if item["sofferenze"]:
            anomalies.append("sofferenze " + _bt_money(item["sofferenze"]))
        lines.append(
            f"{item['label']} | {_bt_money(item['accordato'])} | {_bt_money(item['utilizzato'])} | "
            f"{_bt_money(item['rata_mensile_stimata'])} | {', '.join(anomalies) if anomalies else 'regolare'}"
        )
        count += 1
        if count >= max_lines:
            lines.append("Tabella abbreviata per limite righe.")
            break
    return chr(10).join(lines).strip()


def _bt_bank_summary_lines(rows):
    schedule = _bt_build_bank_monthly_schedule(rows)
    if not schedule:
        return "Nessun dato banca disponibile."
    by_bank = {}
    for item in schedule:
        by_bank.setdefault(item["intermediario"], []).append(item)
    lines = ["Banca | Ultimo utilizzato | Media 36M | Totale rate stimate | Max anomalie"]
    for bank, items in sorted(by_bank.items()):
        ordered = sorted(items, key=lambda x: x["period"], reverse=True)
        latest = ordered[0]
        avg = sum(i["utilizzato"] for i in items) / len(items)
        total_rate = sum(i["rata_mensile_stimata"] for i in items)
        max_anom = max((i["sconfinamenti"] + i["scaduti"] + i["sofferenze"]) for i in items)
        lines.append(f"{bank} | {_bt_money(latest['utilizzato'])} | {_bt_money(avg)} | {_bt_money(total_rate)} | {_bt_money(max_anom)}")
    return chr(10).join(lines)


def _bt_build_cr36_kpi(rows):
    rows = list(rows or [])[:36]
    last3 = _bt_last_n(rows, 3)
    last6 = _bt_last_n(rows, 6)
    last12 = _bt_last_n(rows, 12)
    latest = rows[0] if rows else {}
    return {
        "months_count": len(rows),
        "latest_period": latest.get("label", "n.d."),
        "latest_accordato": _bt_to_float(latest.get("accordato")),
        "latest_utilizzato": _bt_to_float(latest.get("utilizzato")),
        "latest_utilizzo_pct": _bt_div(latest.get("utilizzato"), latest.get("accordato")) or 0.0,
        "avg_utilizzato_3m": _bt_avg(last3, "utilizzato"),
        "avg_utilizzato_6m": _bt_avg(last6, "utilizzato"),
        "avg_utilizzato_12m": _bt_avg(last12, "utilizzato"),
        "avg_utilizzato_36m": _bt_avg(rows, "utilizzato"),
        "max_utilizzato_36m": _bt_max(rows, "utilizzato"),
        "min_utilizzato_36m": _bt_min(rows, "utilizzato"),
        "trend_utilizzato_36m": _bt_trend(rows, "utilizzato"),
        "sconfinamenti_36m": sum(_bt_to_float(r.get("sconfinamenti")) for r in rows),
        "sofferenze_36m": sum(_bt_to_float(r.get("sofferenze")) for r in rows),
        "scaduti_36m": sum(_bt_to_float(r.get("scaduti")) for r in rows),
        "max_intermediari": _bt_max(rows, "intermediari"),
        "max_rapporti": _bt_max(rows, "rapporti"),
        "bank_schedule_rows": _bt_build_bank_monthly_schedule(rows),
    }


def _bt_credit_score_from_kpi(result, cr_kpi):
    indicators = (result or {}).get("indicators", {}) or {}
    ricavi = _bt_to_float(indicators.get("ricavi"))
    ebitda = _bt_to_float(indicators.get("ebitda"))
    utile = _bt_to_float(indicators.get("utile"))
    pn = _bt_to_float(indicators.get("patrimonio_netto"))
    debiti_banche = max(_bt_to_float(indicators.get("debiti_banche")), cr_kpi.get("latest_utilizzato", 0))

    ebitda_margin = _bt_div(ebitda, ricavi)
    debt_equity = _bt_div(debiti_banche, pn)
    debt_ebitda = _bt_div(debiti_banche, ebitda)
    utilization = cr_kpi.get("latest_utilizzo_pct", 0)

    score = 50
    if ebitda_margin is not None:
        score += 12 if ebitda_margin >= 0.12 else 7 if ebitda_margin >= 0.07 else 2 if ebitda_margin > 0 else -12
    if utile > 0:
        score += 8
    else:
        score -= 10
    if debt_equity is not None:
        score += 12 if debt_equity <= 1 else 6 if debt_equity <= 3 else -10
    if debt_ebitda is not None:
        score += 10 if debt_ebitda <= 3 else 4 if debt_ebitda <= 5 else -10
    if utilization:
        score += 6 if utilization <= 0.75 else 2 if utilization <= 0.90 else -6
    if cr_kpi.get("sconfinamenti_36m", 0) > 0:
        score -= 12
    if cr_kpi.get("scaduti_36m", 0) > 0:
        score -= 10
    if cr_kpi.get("sofferenze_36m", 0) > 0:
        score -= 30
    if cr_kpi.get("months_count", 0) >= 24:
        score += 4

    score = max(0, min(100, int(round(score))))
    if score >= 78:
        rating = "FORTE / BANCABILE"
        risk = "Verde"
        mcc = "2-3 indicativa"
        descr = "Merito creditizio positivo: andamento regolare, buona sostenibilita e profilo presentabile in banca."
    elif score >= 62:
        rating = "BUONO / ATTENZIONE"
        risk = "Giallo"
        mcc = "3-4 indicativa"
        descr = "Merito creditizio intermedio: finanziabile con prudenza, da migliorare su CR, margini o leva."
    else:
        rating = "DEBOLE / CRITICO"
        risk = "Rosso"
        mcc = "4-5 indicativa"
        descr = "Merito creditizio debole: prima della banca servono interventi su anomalie, debito o sostenibilita."

    return {
        "score": score,
        "rating": rating,
        "risk": risk,
        "mcc": mcc,
        "descrizione": descr,
        "ebitda_margin": ebitda_margin,
        "debt_equity": debt_equity,
        "debt_ebitda": debt_ebitda,
        "utilization": utilization,
        "ricavi": ricavi,
        "ebitda": ebitda,
        "utile": utile,
        "pn": pn,
        "debiti_banche": debiti_banche,
    }


def _bt_read_pdf_text_safe(path):
    try:
        return _cr36_read_text(path)
    except Exception:
        try:
            return extract_pdf_text(path)
        except Exception:
            return ""


class ReportBancaTop36MPerBancaWindow(ReportBaseWindow):
    def __init__(self, master, db: Database, preselected_client_id: int | None = None):
        super().__init__(
            master,
            db,
            "Banca Top 36M per Banca - KPI/MCC",
            ["Bilancio", "Situazione aggiornata", "Bozza Bilancio", "Centrale Rischi", "Estratti conto", "Report", "Visura camerale", "Visura"],
            preselected_client_id,
        )
        self.doc_combo.pack_forget()
        self.current_result = None

    def refresh_documents(self):
        pass

    def selected_document(self):
        client_id = self.selected_client_id()
        return {
            "bilancio": pick_first_document_for_categories(self.db, client_id, ["Bilancio", "Bilanci", "Situazione aggiornata"]),
            "bozza_bilancio": pick_first_document_for_categories(self.db, client_id, ["Bozza Bilancio", "Bozza bilancio"]),
            "cr": pick_first_document_for_categories(self.db, client_id, ["Centrale Rischi", "Centrale Rischi 36 mesi"]),
            "estratti_conto": pick_first_document_for_categories(self.db, client_id, ["Estratti conto", "Estratti conto 12 mesi"]),
            "report": pick_first_document_for_categories(self.db, client_id, ["Report"]),
            "visura": pick_first_document_for_categories(self.db, client_id, ["Visura camerale", "Visura"]),
        }

    def open_selected_document(self):
        docs = self.selected_document()
        for row in docs.values():
            if row and row["stored_path"]:
                open_path(row["stored_path"])
                return
        messagebox.showwarning("Attenzione", "Nessun documento utile trovato per il cliente selezionato.")

    def _read_cr_rows(self, docs):
        row = docs.get("cr") if isinstance(docs, dict) else None
        if not row or not row.get("stored_path"):
            return []
        text = _bt_read_pdf_text_safe(row["stored_path"] or "")
        return _cr36_parse_monthly_rows(text)

    def run_analysis(self):
        client_id = self.selected_client_id()
        if not client_id:
            messagebox.showwarning("Attenzione", "Seleziona un cliente.")
            return
        client = self.db.get_client(client_id)
        docs = self.selected_document()
        if not any(docs.values()):
            messagebox.showwarning("Documenti mancanti", "Carica prima Bilancio/Centrale Rischi/Estratti conto in Gestione Documenti.")
            return

        result = analyze_credit_documents(client, docs)
        cr_rows = self._read_cr_rows(docs)
        cr_kpi = _bt_build_cr36_kpi(cr_rows)
        credit = _bt_credit_score_from_kpi(result, cr_kpi)
        estimated_amount = result.get("estimated_amount") or 0
        simulation = compute_financing_simulation(estimated_amount, years=5, tan=0.082)

        docs_lines = []
        for key, row in docs.items():
            label = key.replace("_", " ").title()
            if row:
                docs_lines.append(f"- {label}: {row['title'] or row['original_filename'] or 'Documento'}")
            else:
                docs_lines.append(f"- {label}: non presente")

        monthly_lines = []
        for r in cr_rows:
            monthly_lines.append(
                f"{r.get('label','n.d.')}: accordato {_bt_money(r.get('accordato'))}, utilizzato {_bt_money(r.get('utilizzato'))}, "
                f"utilizzo {_bt_pct(r.get('utilizzo_pct'))}, banche {int(r.get('intermediari') or 0)}, rapporti {int(r.get('rapporti') or 0)}, "
                f"sconfini {_bt_money(r.get('sconfinamenti'))}, scaduti {_bt_money(r.get('scaduti'))}, sofferenze {_bt_money(r.get('sofferenze'))}."
            )

        sections = [
            [
                "1. Executive summary creditizia",
                f"Cliente: {client['denominazione'] if client else 'Cliente'}.",
                f"Score integrato: {credit['score']}/100. Rating: {credit['rating']}. Semaforo: {credit['risk']}. MCC stimata: {credit['mcc']}.",
                credit["descrizione"],
                f"Mesi CR analizzati: {cr_kpi['months_count']} su 36. Ultimo mese: {cr_kpi['latest_period']}.",
                "Documenti utilizzati:" + chr(10) + chr(10).join(docs_lines),
            ],
            [
                "2. KPI economico-finanziari",
                f"Ricavi: {_bt_money(credit['ricavi'])}; EBITDA/MOL: {_bt_money(credit['ebitda'])}; EBITDA margin: {_bt_pct(credit['ebitda_margin'])}.",
                f"Utile netto: {_bt_money(credit['utile'])}; patrimonio netto: {_bt_money(credit['pn'])}.",
                f"Debito bancario/CR utilizzata: {_bt_money(credit['debiti_banche'])}; Debt/Equity: {_bt_ratio(credit['debt_equity'])}; Debito/EBITDA: {_bt_ratio(credit['debt_ebitda'])}.",
            ],
            [
                "3. KPI Centrale Rischi 36 mesi",
                f"Ultimo accordato: {_bt_money(cr_kpi['latest_accordato'])}; ultimo utilizzato: {_bt_money(cr_kpi['latest_utilizzato'])}; utilizzo: {_bt_pct(cr_kpi['latest_utilizzo_pct'])}.",
                f"Utilizzato medio 3 mesi: {_bt_money(cr_kpi['avg_utilizzato_3m'])}; 6 mesi: {_bt_money(cr_kpi['avg_utilizzato_6m'])}; 12 mesi: {_bt_money(cr_kpi['avg_utilizzato_12m'])}; 36 mesi: {_bt_money(cr_kpi['avg_utilizzato_36m'])}.",
                f"Picco 36 mesi: {_bt_money(cr_kpi['max_utilizzato_36m'])}; minimo 36 mesi: {_bt_money(cr_kpi['min_utilizzato_36m'])}; trend 36 mesi: {_bt_pct(cr_kpi['trend_utilizzato_36m'])}.",
                f"Sconfinamenti 36 mesi: {_bt_money(cr_kpi['sconfinamenti_36m'])}; scaduti: {_bt_money(cr_kpi['scaduti_36m'])}; sofferenze: {_bt_money(cr_kpi['sofferenze_36m'])}.",
            ],
            [
                "4. Tabella mensile 36 mesi",
                chr(10).join(monthly_lines) if monthly_lines else "Nessun mese riconosciuto. Verificare che la CR sia testuale/OCR.",
            ],
            [
                "5. Tabelle rate mensili distinte per banca",
                "La rata mensile stimata e' il calo dell'utilizzato rispetto al mese precedente disponibile per la stessa banca. Se l'utilizzato aumenta o resta stabile, la rata stimata viene posta a zero.",
                _bt_bank_schedule_lines(cr_rows),
            ],
            [
                "6. Sintesi per intermediario",
                _bt_bank_summary_lines(cr_rows),
            ],
            [
                "7. Indici e valutazione descrittiva del merito creditizio",
                "Indici integrati: EBITDA margin, Debt/Equity, Debito/EBITDA, utilizzo accordato CR, trend utilizzo 36 mesi, anomalie andamentali, presenza scaduti/sconfini/sofferenze.",
                f"Valutazione: {credit['rating']}. {credit['descrizione']}",
                "La fascia MCC e' indicativa e richiede verifica ufficiale su portale, modulo andamentale ed eventi pregiudizievoli.",
            ],
            [
                "8. Migliorie suggerite",
                "1) Ridurre utilizzo linee se superiore a 85% dell'accordato; target banca: utilizzo stabile sotto 75-80%.",
                "2) Azzerare scaduti, sconfini e anomalie prima di richiesta nuova finanza.",
                "3) Allegare sempre ageing clienti, estratti conto 12 mesi, CR aggiornata, bilancio e situazione infrannuale.",
                "4) Se Debito/EBITDA > 4x: preferire consolidamento M/L, allungamento durata e riduzione linee breve non autoliquidanti.",
                "5) Se EBITDA margin basso: piano margini con taglio costi, revisione prezzi e budget 12 mesi.",
            ],
            [
                "9. Simulazione finanziamento",
                f"Importo indicativo: {_bt_money(estimated_amount)}. Rata simulata 5 anni TAN 8,20%: {_bt_money(simulation['monthly_payment'])}. Interessi totali: {_bt_money(simulation['total_interest'])}.",
            ],
        ]
        self.current_result = {"result": result, "cr_rows": cr_rows, "cr_kpi": cr_kpi, "credit": credit}
        self.set_report(sections, "Banca Top 36M per Banca - Valutazione creditizia completa")
        self.draw_chart(cr_rows, credit)

    def draw_chart(self, rows, credit):
        c = self.chart_canvas
        c.delete("all")
        width = int(c.winfo_width() or 380)
        height = int(c.winfo_height() or 260)
        c.create_text(16, 16, anchor="nw", text="Banca Top 36M per Banca", font=("Segoe UI", 12, "bold"), fill=TEXT_COLOR)
        color = SUCCESS_COLOR if credit.get("risk") == "Verde" else WARNING_COLOR if credit.get("risk") == "Giallo" else "#c23b22"
        c.create_rectangle(16, 42, width - 16, 66, fill="#ebeff7", outline="#d0d7e7")
        filled = 16 + (width - 32) * (credit.get("score", 0) / 100.0)
        c.create_rectangle(16, 42, filled, 66, fill=color, outline=color)
        c.create_text(width - 20, 54, anchor="e", text=f"Score {credit.get('score',0)}/100", font=("Segoe UI", 10, "bold"), fill=TEXT_COLOR)

        shown = list(rows or [])[:12]
        if not shown:
            c.create_text(16, 95, anchor="nw", text="Nessuna CR 36 mesi letta. Caricare CR testuale/OCR.", font=("Segoe UI", 9), fill=MUTED_TEXT)
            return
        max_val = max([_bt_to_float(r.get("utilizzato")) for r in shown] + [1])
        base_y = height - 32
        x = 24
        bar_w = max(12, min(26, int((width - 60) / max(len(shown), 1)) - 4))
        step = max(bar_w + 4, int((width - 60) / max(len(shown), 1)))
        for r in reversed(shown):
            val = _bt_to_float(r.get("utilizzato"))
            h = (val / max_val) * 120 if max_val else 0
            c.create_rectangle(x, base_y - h, x + bar_w, base_y, fill=PRIMARY_COLOR, outline=PRIMARY_COLOR)
            label = str(r.get("period", ""))[5:] + "/" + str(r.get("period", ""))[2:4]
            c.create_text(x + bar_w/2, base_y + 10, text=label, font=("Segoe UI", 7), fill=TEXT_COLOR)
            x += step
        c.create_text(16, 78, anchor="nw", text="Grafico: utilizzato CR ultimi 12 mesi letti", font=("Segoe UI", 8), fill=MUTED_TEXT)

# === FINE BANCA TOP 36M PER BANCA PATCH ===


# === PATCH 36M DETTAGLIATA DEFINITIVA ===
# Correzione: non limitare l'analisi a 3 mesi.
# Il parser qui sotto legge fino a 36 mesi reali quando presenti nel PDF CR.
# Se riceve in input un report gia' generato con soli 3 mesi, mantiene quei 3 mesi ma segnala che serve la CR originale.

_BT_MONTHS_FINAL = {
    "gennaio": 1, "febbraio": 2, "marzo": 3, "aprile": 4, "maggio": 5, "giugno": 6,
    "luglio": 7, "agosto": 8, "settembre": 9, "ottobre": 10, "novembre": 11, "dicembre": 12,
    "gen": 1, "feb": 2, "mar": 3, "apr": 4, "mag": 5, "giu": 6,
    "lug": 7, "ago": 8, "set": 9, "ott": 10, "nov": 11, "dic": 12,
}


def _btf_float(value):
    try:
        if value is None:
            return 0.0
        if isinstance(value, (int, float)):
            return float(value)
        s = str(value).strip().replace("EUR", "").replace("€", "").replace(" ", "")
        if not s:
            return 0.0
        if "," in s:
            s = s.replace(".", "").replace(",", ".")
        else:
            parts = s.split(".")
            if len(parts) > 2:
                s = "".join(parts)
        return float(s)
    except Exception:
        return 0.0


def _btf_money(value):
    try:
        return format_currency(_btf_float(value))
    except Exception:
        return ("€ " + f"{_btf_float(value):,.0f}").replace(",", ".")


def _btf_pct(value):
    try:
        return f"{float(value or 0) * 100:.1f}%".replace(".", ",")
    except Exception:
        return "n.d."


def _btf_ratio(value):
    try:
        return f"{float(value):.2f}x".replace(".", ",")
    except Exception:
        return "n.d."


def _btf_div(a, b):
    a = _btf_float(a)
    b = _btf_float(b)
    return None if b == 0 else a / b


def _btf_read_text(path):
    try:
        return _cr36_read_text(path)
    except Exception:
        try:
            return extract_pdf_text(path)
        except Exception:
            return ""


def _btf_clean_text(text):
    try:
        return _cr36_clean_text(text or "")
    except Exception:
        return text or ""


def _btf_parse_amounts(text):
    vals = []
    for raw in re.findall(r"(?<!\d)(?:\d{1,3}(?:\.\d{3})+|\d{4,})(?:,\d{1,2})?(?!\d)", text or ""):
        v = _btf_float(raw)
        if 1_000 <= v <= 80_000_000 and int(v) not in range(2020, 2035):
            vals.append(v)
    return vals


def _btf_extract_month_blocks(text):
    """Estrae mesi dalla CR originale.

    Supporta:
    - DATA DI RIFERIMENTO: marzo 2026
    - mese/anno in formato mm/yyyy o yyyy-mm vicino a blocchi CR
    """
    txt = _btf_clean_text(text)
    if not txt:
        return []

    patterns = [
        re.compile(r"DATA\s+DI\s+RIFERIMENTO\s*:?\s*([A-Za-zàèéìòù]+)\s+(\d{4})", re.IGNORECASE),
        re.compile(r"RIFERIMENTO\s*:?\s*([A-Za-zàèéìòù]+)\s+(\d{4})", re.IGNORECASE),
    ]

    matches = []
    for pat in patterns:
        matches.extend(list(pat.finditer(txt)))
    matches = sorted(matches, key=lambda m: m.start())

    blocks = []
    for i, m in enumerate(matches):
        month_name = m.group(1).lower().strip()
        year = int(m.group(2))
        month = _BT_MONTHS_FINAL.get(month_name, 0)
        if not month:
            continue
        start = m.start()
        end = matches[i + 1].start() if i + 1 < len(matches) else len(txt)
        blocks.append({
            "period": f"{year}-{month:02d}",
            "label": f"{month_name} {year}",
            "year": year,
            "month": month,
            "text": txt[start:end],
        })

    # Deduplica e unisce pagine dello stesso mese.
    by_period = {}
    for b in blocks:
        if b["period"] not in by_period:
            by_period[b["period"]] = b
        else:
            by_period[b["period"]]["text"] += "\n" + b["text"]

    return sorted(by_period.values(), key=lambda x: (x["year"], x["month"]), reverse=True)[:36]


def _btf_extract_bank_chunks(block_text):
    chunks = re.split(r"(?=Intermediario\s*:\s*)", block_text or "", flags=re.IGNORECASE)
    out = []
    for ch in chunks:
        if "Intermediario" not in ch:
            continue
        m = re.search(r"Intermediario\s*:\s*([^\n]+)", ch, flags=re.IGNORECASE)
        name = (m.group(1).strip() if m else "Intermediario n.d.")[:120]
        amounts = _btf_parse_amounts(ch)
        useful = sorted(set(round(v) for v in amounts if v >= 1_000), reverse=True)
        # Euristica prudente: prende i valori principali del blocco banca.
        accordato = float(sum(useful[:3])) if useful else 0.0
        utilizzato = accordato
        operativo = accordato
        upper = ch.upper()
        maxval = max(amounts) if amounts else 0.0
        out.append({
            "intermediario": name,
            "accordato": accordato,
            "utilizzato": utilizzato,
            "accordato_operativo": operativo,
            "sconfinamenti": maxval if "SCONFIN" in upper else 0.0,
            "scaduti": maxval if "SCADUT" in upper or "RATE" in upper else 0.0,
            "sofferenze": maxval if "SOFFEREN" in upper else 0.0,
        })
    return out


def _btf_estimate_month(block_text):
    banks = _btf_extract_bank_chunks(block_text)
    if banks:
        return {
            "banks": banks,
            "accordato": sum(_btf_float(b.get("accordato")) for b in banks),
            "utilizzato": sum(_btf_float(b.get("utilizzato")) for b in banks),
            "accordato_operativo": sum(_btf_float(b.get("accordato_operativo")) for b in banks),
            "sconfinamenti": sum(_btf_float(b.get("sconfinamenti")) for b in banks),
            "scaduti": sum(_btf_float(b.get("scaduti")) for b in banks),
            "sofferenze": sum(_btf_float(b.get("sofferenze")) for b in banks),
            "intermediari": len(set(b.get("intermediario") for b in banks)),
            "rapporti": len(banks),
        }

    amounts = _btf_parse_amounts(block_text)
    useful = sorted(set(round(v) for v in amounts if v >= 1_000), reverse=True)
    total = float(sum(useful[:25])) if useful else 0.0
    upper = (block_text or "").upper()
    return {
        "banks": [],
        "accordato": total,
        "utilizzato": total,
        "accordato_operativo": total,
        "sconfinamenti": max(amounts) if amounts and "SCONFIN" in upper else 0.0,
        "scaduti": max(amounts) if amounts and ("SCADUT" in upper or "RATE" in upper) else 0.0,
        "sofferenze": max(amounts) if amounts and "SOFFEREN" in upper else 0.0,
        "intermediari": len(set(re.findall(r"Intermediario\s*:\s*([^\n]+)", block_text or "", flags=re.IGNORECASE))),
        "rapporti": len(re.findall(r"RISCHI\s+A\s+SCADENZA|RISCHI\s+A\s+REVOCA|FACTORING|LEASING|GARANZIE|SOFFERENZE", block_text or "", flags=re.IGNORECASE)),
    }


def _cr36_parse_monthly_rows(text):
    """OVERRIDE definitivo: massimo 36 mesi, non 3."""
    blocks = _btf_extract_month_blocks(text)
    rows = []
    for b in blocks:
        vals = _btf_estimate_month(b["text"])
        accordato = _btf_float(vals.get("accordato"))
        utilizzato = _btf_float(vals.get("utilizzato"))
        rows.append({
            "period": b["period"],
            "label": b["label"],
            "month": b["month"],
            "year": b["year"],
            "banks": vals.get("banks") or [],
            "accordato": accordato,
            "utilizzato": utilizzato,
            "accordato_operativo": _btf_float(vals.get("accordato_operativo")),
            "saldo_medio": utilizzato,
            "sconfinamenti": _btf_float(vals.get("sconfinamenti")),
            "scaduti": _btf_float(vals.get("scaduti")),
            "sofferenze": _btf_float(vals.get("sofferenze")),
            "garanzie": 0.0,
            "intermediari": int(vals.get("intermediari") or 0),
            "rapporti": int(vals.get("rapporti") or 0),
            "utilizzo_pct": (_btf_div(utilizzato, accordato) or 0.0),
        })
    return rows[:36]


def _btf_avg(rows, key):
    vals = [_btf_float(r.get(key)) for r in rows if _btf_float(r.get(key)) > 0]
    return sum(vals) / len(vals) if vals else 0.0


def _btf_max(rows, key):
    vals = [_btf_float(r.get(key)) for r in rows]
    return max(vals) if vals else 0.0


def _btf_min(rows, key):
    vals = [_btf_float(r.get(key)) for r in rows if _btf_float(r.get(key)) > 0]
    return min(vals) if vals else 0.0


def _btf_trend(rows, key):
    if len(rows) < 6:
        return None
    recent = _btf_avg(rows[:3], key)
    old = _btf_avg(rows[-3:], key)
    return None if old == 0 else (recent - old) / old


def _btf_kpi(rows):
    rows = list(rows or [])[:36]
    latest = rows[0] if rows else {}
    return {
        "months_count": len(rows),
        "latest_period": latest.get("label", "n.d."),
        "latest_accordato": _btf_float(latest.get("accordato")),
        "latest_utilizzato": _btf_float(latest.get("utilizzato")),
        "latest_utilizzo_pct": _btf_div(latest.get("utilizzato"), latest.get("accordato")) or 0.0,
        "avg_3m": _btf_avg(rows[:3], "utilizzato"),
        "avg_6m": _btf_avg(rows[:6], "utilizzato"),
        "avg_12m": _btf_avg(rows[:12], "utilizzato"),
        "avg_36m": _btf_avg(rows, "utilizzato"),
        "max_36m": _btf_max(rows, "utilizzato"),
        "min_36m": _btf_min(rows, "utilizzato"),
        "trend_36m": _btf_trend(rows, "utilizzato"),
        "sconfinamenti_36m": sum(_btf_float(r.get("sconfinamenti")) for r in rows),
        "scaduti_36m": sum(_btf_float(r.get("scaduti")) for r in rows),
        "sofferenze_36m": sum(_btf_float(r.get("sofferenze")) for r in rows),
        "max_intermediari": _btf_max(rows, "intermediari"),
        "max_rapporti": _btf_max(rows, "rapporti"),
    }


def _btf_bank_schedule(rows):
    chronological = sorted(list(rows or [])[:36], key=lambda r: str(r.get("period", "")))
    last_used = {}
    out = []
    for row in chronological:
        banks = row.get("banks") or []
        if not banks:
            banks = [{
                "intermediario": "Totale CR non dettagliato",
                "accordato": row.get("accordato"),
                "utilizzato": row.get("utilizzato"),
                "sconfinamenti": row.get("sconfinamenti"),
                "scaduti": row.get("scaduti"),
                "sofferenze": row.get("sofferenze"),
            }]
        for b in banks:
            name = b.get("intermediario") or "Intermediario n.d."
            used = _btf_float(b.get("utilizzato"))
            prev = last_used.get(name)
            rata = max(0.0, prev - used) if prev is not None else 0.0
            last_used[name] = used
            out.append({
                "period": row.get("period"),
                "label": row.get("label"),
                "intermediario": name,
                "accordato": _btf_float(b.get("accordato")),
                "utilizzato": used,
                "rata": rata,
                "sconfinamenti": _btf_float(b.get("sconfinamenti")),
                "scaduti": _btf_float(b.get("scaduti")),
                "sofferenze": _btf_float(b.get("sofferenze")),
            })
    return sorted(out, key=lambda x: (x["intermediario"], x["period"]))


def _btf_bank_lines(rows):
    schedule = _btf_bank_schedule(rows)
    if not schedule:
        return "Nessun dettaglio banca disponibile. Caricare la Centrale Rischi originale testuale/OCR."
    lines = []
    current = None
    for item in schedule:
        if item["intermediario"] != current:
            current = item["intermediario"]
            lines.append("")
            lines.append(current)
            lines.append("Mese | Accordato | Utilizzato | Rata mensile stimata | Anomalie")
        anom = []
        if item["sconfinamenti"]:
            anom.append("sconfini " + _btf_money(item["sconfinamenti"]))
        if item["scaduti"]:
            anom.append("scaduti/rate " + _btf_money(item["scaduti"]))
        if item["sofferenze"]:
            anom.append("sofferenze " + _btf_money(item["sofferenze"]))
        lines.append(f"{item['label']} | {_btf_money(item['accordato'])} | {_btf_money(item['utilizzato'])} | {_btf_money(item['rata'])} | {', '.join(anom) if anom else 'regolare'}")
    return "\n".join(lines).strip()


def _btf_score(result, kpi):
    ind = (result or {}).get("indicators", {}) or {}
    ricavi = _btf_float(ind.get("ricavi"))
    ebitda = _btf_float(ind.get("ebitda"))
    utile = _btf_float(ind.get("utile"))
    pn = _btf_float(ind.get("patrimonio_netto"))
    debito = max(_btf_float(ind.get("debiti_banche")), kpi.get("latest_utilizzato", 0))
    ebitda_margin = _btf_div(ebitda, ricavi)
    debt_equity = _btf_div(debito, pn)
    debt_ebitda = _btf_div(debito, ebitda)

    score = 50
    if ebitda_margin is not None:
        score += 12 if ebitda_margin >= 0.12 else 7 if ebitda_margin >= 0.07 else 2 if ebitda_margin > 0 else -12
    score += 8 if utile > 0 else -10
    if debt_equity is not None:
        score += 12 if debt_equity <= 1 else 6 if debt_equity <= 3 else -10
    if debt_ebitda is not None:
        score += 10 if debt_ebitda <= 3 else 4 if debt_ebitda <= 5 else -10
    util = kpi.get("latest_utilizzo_pct", 0)
    if util:
        score += 6 if util <= 0.75 else 2 if util <= 0.90 else -6
    if kpi.get("sconfinamenti_36m", 0):
        score -= 12
    if kpi.get("scaduti_36m", 0):
        score -= 10
    if kpi.get("sofferenze_36m", 0):
        score -= 30
    if kpi.get("months_count", 0) >= 24:
        score += 4

    score = max(0, min(100, int(round(score))))
    if score >= 78:
        rating = "FORTE / BANCABILE"
        risk = "Verde"
        mcc = "2-3 indicativa"
        descr = "Merito creditizio positivo: il profilo appare presentabile a banca, salvo anomalie andamentali non rilevate dal testo."
    elif score >= 62:
        rating = "BUONO / ATTENZIONE"
        risk = "Giallo"
        mcc = "3-4 indicativa"
        descr = "Merito creditizio intermedio: finanziabile con prudenza, da rafforzare con documenti aggiornati e riduzione delle anomalie."
    else:
        rating = "DEBOLE / CRITICO"
        risk = "Rosso"
        mcc = "4-5 indicativa"
        descr = "Merito creditizio debole: prima della richiesta banca servono interventi su anomalie, debito o sostenibilita."
    return {
        "score": score,
        "rating": rating,
        "risk": risk,
        "mcc": mcc,
        "descr": descr,
        "ricavi": ricavi,
        "ebitda": ebitda,
        "utile": utile,
        "pn": pn,
        "debito": debito,
        "ebitda_margin": ebitda_margin,
        "debt_equity": debt_equity,
        "debt_ebitda": debt_ebitda,
    }


def _cr36_build_report(client, docs, rows):
    rows = list(rows or [])[:36]
    kpi = _btf_kpi(rows)
    client_name = client["denominazione"] if client else "Cliente"
    mese_lines = []
    for r in rows:
        mese_lines.append(
            f"{r.get('label','n.d.')}: accordato {_btf_money(r.get('accordato'))}, utilizzato {_btf_money(r.get('utilizzato'))}, "
            f"utilizzo {_btf_pct(_btf_div(r.get('utilizzato'), r.get('accordato')) or 0)}, "
            f"banche {int(r.get('intermediari') or 0)}, rapporti {int(r.get('rapporti') or 0)}, "
            f"sconfini {_btf_money(r.get('sconfinamenti'))}, scaduti/rate {_btf_money(r.get('scaduti'))}, sofferenze {_btf_money(r.get('sofferenze'))}."
        )

    if kpi["months_count"] < 12:
        avviso = "ATTENZIONE: sono stati riconosciuti meno di 12 mesi. Probabilmente stai caricando un report gia' generato oppure un PDF non OCR. Per avere 36 mesi carica la Centrale Rischi originale Banca d'Italia."
    else:
        avviso = "La lettura copre un orizzonte adeguato per valutazione andamentale."

    sections = [
        ["1. Executive summary", f"Cliente: {client_name}.", f"Mesi analizzati: {kpi['months_count']} su 36. Ultimo mese: {kpi['latest_period']}.", avviso],
        ["2. KPI 36 mesi", f"Ultimo accordato: {_btf_money(kpi['latest_accordato'])}; ultimo utilizzato: {_btf_money(kpi['latest_utilizzato'])}; utilizzo: {_btf_pct(kpi['latest_utilizzo_pct'])}.", f"Media utilizzato 3M: {_btf_money(kpi['avg_3m'])}; 6M: {_btf_money(kpi['avg_6m'])}; 12M: {_btf_money(kpi['avg_12m'])}; 36M: {_btf_money(kpi['avg_36m'])}.", f"Picco 36M: {_btf_money(kpi['max_36m'])}; minimo 36M: {_btf_money(kpi['min_36m'])}; trend: {_btf_pct(kpi['trend_36m']) if kpi['trend_36m'] is not None else 'n.d.'}.", f"Sconfinamenti: {_btf_money(kpi['sconfinamenti_36m'])}; scaduti/rate: {_btf_money(kpi['scaduti_36m'])}; sofferenze: {_btf_money(kpi['sofferenze_36m'])}.", f"Max intermediari: {int(kpi['max_intermediari'])}; max rapporti: {int(kpi['max_rapporti'])}."],
        ["3. Tabella mese per mese", "\n".join(mese_lines) if mese_lines else "Nessun mese riconosciuto."],
        ["4. Tabelle per banca/intermediario e rate mensili", "La rata mensile stimata e' il calo dell'utilizzato rispetto al mese precedente disponibile per la stessa banca/intermediario.", _btf_bank_lines(rows)],
        ["5. Analisi descrittiva dettagliata", "La valutazione considera: continuita dei rapporti, utilizzo accordato, picchi di utilizzo, sconfini, scaduti/rate, sofferenze, numero intermediari e volatilita dell'utilizzato.", "Se i mesi riconosciuti sono pochi, il problema non e' il limite del report ma il testo disponibile nel PDF caricato: usare il PDF CR originale o OCR."],
        ["6. Raccomandazioni operative", "1) Allegare CR originale 36 mesi, bilancio, situazione aggiornata, estratti conto 12 mesi e ageing clienti/fornitori.", "2) Spiegare in nota gestionale ogni sconfino, scaduto o picco di utilizzo.", "3) Tenere utilizzo linee sotto 75-80% dell'accordato.", "4) Se emergono rate scadute o sconfini, chiuderli prima di richiesta nuova finanza.", "5) Preparare piano rientro e cash flow 12 mesi."],
    ]
    return {"title": "Analisi CR 36 mesi dettagliata", "sections": sections, "rows": rows, "kpi": kpi}


class ReportBancaTop36MDettagliataWindow(ReportBaseWindow):
    def __init__(self, master, db: Database, preselected_client_id: int | None = None):
        super().__init__(master, db, "Banca Top 36M Dettagliata", ["Bilancio", "Situazione aggiornata", "Bozza Bilancio", "Centrale Rischi", "Estratti conto", "Report", "Visura camerale", "Visura"], preselected_client_id)
        self.doc_combo.pack_forget()
        self.current_payload = None

    def refresh_documents(self):
        pass

    def selected_document(self):
        cid = self.selected_client_id()
        return {
            "bilancio": pick_first_document_for_categories(self.db, cid, ["Bilancio", "Bilanci", "Situazione aggiornata", "Bozza Bilancio"]),
            "cr": pick_first_document_for_categories(self.db, cid, ["Centrale Rischi", "Centrale Rischi 36 mesi", "CR"]),
            "estratti_conto": pick_first_document_for_categories(self.db, cid, ["Estratti conto", "Estratti conto 12 mesi"]),
            "visura": pick_first_document_for_categories(self.db, cid, ["Visura camerale", "Visura"]),
            "report": pick_first_document_for_categories(self.db, cid, ["Report"]),
        }

    def open_selected_document(self):
        for row in self.selected_document().values():
            if row and row.get("stored_path"):
                open_path(row["stored_path"])
                return
        messagebox.showwarning("Documento", "Nessun documento trovato per il cliente selezionato.")

    def run_analysis(self):
        cid = self.selected_client_id()
        if not cid:
            messagebox.showwarning("Cliente", "Seleziona un cliente.")
            return
        client = self.db.get_client(cid)
        docs = self.selected_document()
        if not any(docs.values()):
            messagebox.showwarning("Documenti", "Carica prima i documenti in Gestione Documenti.")
            return
        base = analyze_credit_documents(client, docs)
        cr_row = docs.get("cr")
        cr_text = _btf_read_text(cr_row["stored_path"]) if cr_row and cr_row.get("stored_path") else ""
        rows = _cr36_parse_monthly_rows(cr_text)
        kpi = _btf_kpi(rows)
        credit = _btf_score(base, kpi)
        sim = compute_financing_simulation(base.get("estimated_amount") or 0, years=5, tan=0.082)

        report = _cr36_build_report(client, docs, rows)
        extra_sections = [
            ["7. Valutazione merito creditizio", f"Score: {credit['score']}/100. Rating: {credit['rating']}. Semaforo: {credit['risk']}. MCC stimata: {credit['mcc']}.", credit["descr"], f"EBITDA margin: {_btf_pct(credit['ebitda_margin'])}; Debt/Equity: {_btf_ratio(credit['debt_equity'])}; Debito/EBITDA: {_btf_ratio(credit['debt_ebitda'])}.", f"Ricavi: {_btf_money(credit['ricavi'])}; EBITDA: {_btf_money(credit['ebitda'])}; utile: {_btf_money(credit['utile'])}; patrimonio netto: {_btf_money(credit['pn'])}; debito bancario/CR: {_btf_money(credit['debito'])}."],
            ["8. Simulazione e struttura operazione banca", f"Importo indicativo: {_btf_money(base.get('estimated_amount'))}. Rata simulata 5 anni TAN 8,20%: {_btf_money(sim['monthly_payment'])}. Interessi totali: {_btf_money(sim['total_interest'])}.", "Struttura consigliata: linee autoliquidanti per crediti commerciali; chirografario/MLT solo per investimenti o consolidamento; MCC come garanzia rafforzativa se score e andamentale sono coerenti."],
            ["9. Piano migliorativo", "Azzerare anomalie CR; ridurre utilizzo linee sotto 75-80%; creare cash flow 12 mesi; predisporre ageing clienti/fornitori; allegare nota su ogni mese critico; confrontare CR con estratti conto e bilancio."],
        ]
        sections = report["sections"] + extra_sections
        self.current_payload = {"base": base, "rows": rows, "kpi": kpi, "credit": credit}
        self.set_report(sections, "Banca Top 36M Dettagliata - Merito creditizio completo")
        self.draw_chart(rows, credit)

    def draw_chart(self, rows, credit):
        c = self.chart_canvas
        c.delete("all")
        w = int(c.winfo_width() or 390)
        h = int(c.winfo_height() or 260)
        c.create_text(16, 16, anchor="nw", text="Banca Top 36M Dettagliata", font=("Segoe UI", 12, "bold"), fill=TEXT_COLOR)
        color = SUCCESS_COLOR if credit.get("risk") == "Verde" else WARNING_COLOR if credit.get("risk") == "Giallo" else "#c23b22"
        c.create_rectangle(16, 42, w - 16, 66, fill="#ebeff7", outline="#d0d7e7")
        c.create_rectangle(16, 42, 16 + (w - 32) * (credit.get("score", 0) / 100), 66, fill=color, outline=color)
        c.create_text(w - 20, 54, anchor="e", text=f"Score {credit.get('score',0)}/100", font=("Segoe UI", 10, "bold"), fill=TEXT_COLOR)
        shown = list(rows or [])[:12]
        if not shown:
            c.create_text(16, 95, anchor="nw", text="Nessuna CR letta. Caricare la CR originale Banca d'Italia testuale/OCR.", font=("Segoe UI", 9), fill=MUTED_TEXT)
            return
        max_val = max([_btf_float(r.get("utilizzato")) for r in shown] + [1])
        base_y = h - 32
        x = 24
        step = max(18, int((w - 60) / max(len(shown), 1)))
        bar_w = max(10, step - 4)
        for r in reversed(shown):
            val = _btf_float(r.get("utilizzato"))
            bh = (val / max_val) * 120 if max_val else 0
            c.create_rectangle(x, base_y - bh, x + bar_w, base_y, fill=PRIMARY_COLOR, outline=PRIMARY_COLOR)
            lab = str(r.get("period", ""))[5:] + "/" + str(r.get("period", ""))[2:4]
            c.create_text(x + bar_w / 2, base_y + 10, text=lab, font=("Segoe UI", 7), fill=TEXT_COLOR)
            x += step

