# === PATCH ANTEPRIMA DOCUMENTI CLIENTE CON SCROLL MOUSE ===
# Aggiunge anteprima testuale del documento quando viene selezionato nella scheda cliente
# e nella finestra "Inserisci Richiesta". La preview usa scrollbar verticale e rotellina mouse.

def _doc_preview_extract_text(path: str, max_chars: int = 300000) -> str:
    p = Path(path or "")
    if not path or not p.exists():
        return "File non trovato o percorso non disponibile."
    try:
        text = extract_model_file_content(str(p), max_chars=max_chars + 1)
    except Exception:
        text = ""
    text = (text or "").strip()
    if not text:
        text = (
            f"Anteprima testuale non disponibile per: {p.name}\n\n"
            "Il file e' comunque archiviato correttamente. Usa il pulsante 'Apri documento' "
            "per visualizzarlo con il programma predefinito del computer."
        )
    if len(text) > max_chars:
        text = text[:max_chars] + "\n\n[Anteprima interrotta per dimensione elevata. Aprire il file per consultarlo integralmente.]"
    return text


def _doc_preview_set_text(text_widget, content: str) -> None:
    try:
        text_widget.configure(state="normal")
        text_widget.delete("1.0", tk.END)
        text_widget.insert("1.0", content or "")
        text_widget.configure(state="disabled")
        text_widget.yview_moveto(0)
    except Exception:
        pass


def _doc_preview_bind_mousewheel(widget, scroll_target=None) -> None:
    target = scroll_target or widget

    def _on_mousewheel(event):
        try:
            if getattr(event, "num", None) == 4:
                target.yview_scroll(-3, "units")
            elif getattr(event, "num", None) == 5:
                target.yview_scroll(3, "units")
            else:
                delta = getattr(event, "delta", 0)
                if delta:
                    target.yview_scroll(int(-1 * (delta / 120)) or (-1 if delta > 0 else 1), "units")
            return "break"
        except Exception:
            return None

    def _bind_one(w):
        try:
            w.bind("<Enter>", lambda _e: target.focus_set(), add="+")
            w.bind("<MouseWheel>", _on_mousewheel, add="+")
            w.bind("<Button-4>", _on_mousewheel, add="+")
            w.bind("<Button-5>", _on_mousewheel, add="+")
        except Exception:
            pass

    _bind_one(widget)
    try:
        for child in widget.winfo_children():
            _bind_one(child)
    except Exception:
        pass


def _doc_preview_insert_box(parent, height: int = 13):
    box = ttk.LabelFrame(parent, text="Anteprima documento selezionato", padding=8)
    box.pack(fill="both", expand=True, pady=(8, 0))
    box.rowconfigure(0, weight=1)
    box.columnconfigure(0, weight=1)
    preview = ScrolledText(box, wrap="word", height=height, font=("Segoe UI", 9))
    preview.grid(row=0, column=0, sticky="nsew")
    preview.configure(state="disabled")
    _doc_preview_bind_mousewheel(preview)
    _doc_preview_set_text(preview, "Seleziona un documento dall'elenco per visualizzarne l'anteprima qui.\n\nPuoi scorrere con la barra laterale oppure con la rotellina del mouse.")
    return preview, box


