def _client_detail_update_document_preview(self):
    preview = getattr(self, "client_document_preview", None)
    tree = getattr(self, "client_document_tree", None)
    if preview is None or tree is None:
        return
    selection = tree.selection()
    if not selection:
        _doc_preview_set_text(preview, "Seleziona un documento dall'elenco per visualizzarne l'anteprima.")
        return
    try:
        row = self.db.get_document(int(selection[0]))
    except Exception:
        row = None
    if not row:
        _doc_preview_set_text(preview, "Documento non trovato nel database.")
        return
    path = row["stored_path"] or ""
    header = (
        f"Titolo: {row['title'] or '-'}\n"
        f"File: {row['original_filename'] or Path(path).name or '-'}\n"
        f"Percorso: {path or '-'}\n"
        + "-" * 80 + "\n\n"
    )
    _doc_preview_set_text(preview, header + _doc_preview_extract_text(path))


def _client_detail_populate_documents_with_preview(self):
    for widget in self.tab_documents.winfo_children():
        widget.destroy()

    paned = ttk.PanedWindow(self.tab_documents, orient=tk.VERTICAL)
    paned.pack(fill="both", expand=True)

    list_frame = ttk.LabelFrame(paned, text="Documenti del cliente", padding=10)
    preview_frame = ttk.LabelFrame(paned, text="Anteprima documento selezionato", padding=10)
    paned.add(list_frame, weight=1)
    paned.add(preview_frame, weight=2)

    rows = self.db.list_documents_linked(self.client_id)
    tree, holder = create_treeview_with_scrollbars(list_frame, ("titolo", "resp", "file", "data"), show="headings")
    self.client_document_tree = tree
    tree.heading("titolo", text="Titolo")
    tree.heading("resp", text="Responsabile")
    tree.heading("file", text="File")
    tree.heading("data", text="Data")
    tree.column("titolo", width=280)
    tree.column("resp", width=190)
    tree.column("file", width=250)
    tree.column("data", width=130, anchor="center")
    for row in rows:
        tree.insert(
            "",
            "end",
            iid=str(row["id"]),
            values=(row["title"] or "", row["collaborator_name"] or "", row["original_filename"] or "", (row["uploaded_at"] or "")[:10]),
        )

    bar = ttk.Frame(list_frame)
    bar.pack(fill="x", pady=(8, 0))
    ttk.Button(bar, text="Apri documento", command=lambda: self._open_document_from_tree(tree)).pack(side="right")
    try:
        ttk.Button(bar, text="Elimina documento", command=lambda: self.delete_document_from_tree(tree)).pack(side="right", padx=(0, 8))
    except Exception:
        pass

    preview_frame.rowconfigure(0, weight=1)
    preview_frame.columnconfigure(0, weight=1)
    self.client_document_preview = ScrolledText(preview_frame, wrap="word", height=18, font=("Segoe UI", 9))
    self.client_document_preview.grid(row=0, column=0, sticky="nsew")
    self.client_document_preview.configure(state="disabled")
    _doc_preview_bind_mousewheel(self.client_document_preview)
    _doc_preview_set_text(
        self.client_document_preview,
        "Seleziona un documento dall'elenco superiore per visualizzarne l'anteprima.\n\n"
        "Puoi scorrere il contenuto con la barra laterale o con la rotellina del mouse.",
    )

    tree.bind("<<TreeviewSelect>>", lambda _e: self.update_document_preview(), add="+")
    tree.bind("<Double-1>", lambda _e: self._open_document_from_tree(tree), add="+")


