# === PATCH GESTIONE DOCUMENTI: ANTEPRIMA SOTTO ELENCO + SELEZIONE GIALLA ===
# Nella finestra "Gestione Documenti" mostra l'anteprima nell'area inferiore,
# abilita scrollbar e rotellina mouse e rende gialla la riga selezionata.

def _document_management_set_preview_text(self, content: str) -> None:
    preview = getattr(self, "document_management_preview", None)
    if preview is None:
        return
    try:
        preview.configure(state="normal")
        preview.delete("1.0", tk.END)
        preview.insert("1.0", content or "")
        preview.configure(state="disabled")
        preview.yview_moveto(0)
    except Exception:
        pass


def _document_management_highlight_selection(self) -> None:
    tree = getattr(self, "tree", None)
    if tree is None:
        return
    try:
        selected = set(tree.selection())
        for item in tree.get_children():
            tree.item(item, tags=("selected_yellow",) if item in selected else ())
        tree.tag_configure("selected_yellow", background="#fff3a3", foreground="#111827")
    except Exception:
        pass


def _document_management_update_preview(self, *_args) -> None:
    tree = getattr(self, "tree", None)
    if tree is None:
        return
    _document_management_highlight_selection(self)
    selection = tree.selection()
    if not selection:
        _document_management_set_preview_text(
            self,
            "Seleziona un documento dall'elenco superiore per visualizzarne l'anteprima qui.\n\n"
            "La riga selezionata viene evidenziata in giallo. Puoi scorrere l'anteprima con la barra laterale "
            "oppure con la rotellina del mouse."
        )
        return
    try:
        row = self.db.get_document(int(selection[0]))
    except Exception:
        row = None
    if not row:
        _document_management_set_preview_text(self, "Documento non trovato nel database.")
        return

    path = row["stored_path"] or ""
    title = row["title"] or "-"
    filename = row["original_filename"] or Path(path).name or "-"
    uploaded = (row["uploaded_at"] or "")[:19].replace("T", " ")
    collaborator = row["collaborator_name"] if "collaborator_name" in row.keys() else ""
    notes = row["notes"] or ""

    multi_note = ""
    if len(selection) > 1:
        multi_note = f"Nota: hai selezionato {len(selection)} documenti. L'anteprima mostra il primo selezionato.\n\n"

    header = (
        multi_note
        + f"Titolo: {title}\n"
        + f"File: {filename}\n"
        + f"Data caricamento: {uploaded or '-'}\n"
        + (f"Responsabile: {collaborator}\n" if collaborator else "")
        + f"Percorso: {path or '-'}\n"
        + (f"Note: {notes}\n" if notes else "")
        + "-" * 90
        + "\n\n"
    )
    try:
        body = _doc_preview_extract_text(path, max_chars=500000)
    except Exception:
        body = safe_read_document_text(path, max_chars=500000) or "Anteprima non disponibile. Usa 'Apri file' per consultare il documento originale."
    _document_management_set_preview_text(self, header + body)


